INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 1, 'COMO el rey David era viejo, y entrado en días, cubríanle de vestidos, mas no se calentaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 2, 'Dijéronle por tanto sus siervos: Busquen á mi señor el rey una moza virgen, para que esté delante del rey, y lo abrigue, y duerma á su lado, y calentará á mi señor el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 3, 'Y buscaron una moza hermosa por todo el término de Israel, y hallaron á Abisag Sunamita, y trajéronla al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 4, 'Y la moza era hermosa, la cual calentaba al rey, y le servía: mas el rey nunca la conoció.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 5, 'Entonces Adonía hijo de Haggith se levantó, diciendo: Yo reinaré. E hízose de carros y gente de á caballo, y cincuenta hombres que corriesen delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 6, 'Y su padre nunca lo entristeció en todos sus días con decirle: ¿Por qué haces así? Y también éste era de hermoso parecer; y habíalo engendrado después de Absalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 7, 'Y tenía tratos con Joab hijo de Sarvia, y con Abiathar sacerdote, los cuales ayudaban á Adonía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 8, 'Mas Sadoc sacerdote, y Benaía hijo de Joiada, y Nathán profeta, y Semei, y Reihi, y todos los grandes de David, no seguían á Adonía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 9, 'Y matando Adonía ovejas y vacas y animales engordados junto á la peña de Zoheleth, que está cerca de la fuente de Rogel, convidó á todos sus hermanos los hijos del rey, y á todos los varones de Judá, siervos del rey:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 10, 'Mas no convidó á Nathán profeta, ni á Benaía, ni á los grandes, ni á Salomón su hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 11, 'Y habló Nathán á Bath-sheba madre de Salomón, diciendo: ¿No has oído que reina Adonía hijo de Haggith, sin saberlo David nuestro señor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 12, 'Ven pues ahora, y toma mi consejo, para que guardes tu vida, y la vida de tu hijo Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 13, 'Ve, y entra al rey David, y dile: Rey señor mío, ¿no has tú jurado á tu sierva, diciendo: Salomón tu hijo reinará después de mí, y él se sentará en mi trono? ¿por qué pues reina Adonía?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 14, 'Y estando tú aún hablando con el rey, yo entraré tras ti, y acabaré tus razones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 15, 'Entonces Bath-sheba entró al rey á la cámara: y el rey era muy viejo; y Abisag Sunamita servía al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 16, 'Y Bath-sheba se inclinó, é hizo reverencia al rey. Y el rey dijo: ¿Qué tienes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 17, 'Y ella le respondió: Señor mío, tú juraste á tu sierva por Jehová tu Dios, diciendo: Salomón tu hijo reinará después de mí, y él se sentará en mi trono;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 18, 'Y he aquí ahora Adonía reina: y tú, mi señor rey, ahora no lo supiste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 19, 'Ha matado bueyes, y animales engordados, y muchas ovejas, y ha convidado á todos los hijos del rey, y á Abiathar sacerdote, y á Joab general del ejército; mas á Salomón tu siervo no ha convidado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 20, 'Entre tanto, rey señor mío, los ojos de todo Israel están sobre ti, para que les declares quién se ha de sentar en el trono de mi señor el rey después de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 21, 'De otra suerte acontecerá, cuando mi señor el rey durmiere con sus padres, que yo y mi hijo Salomón seremos tenidos por culpables.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 22, 'Y estando aún hablando ella con el rey, he aquí Nathán profeta, que vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 23, 'Y dieron aviso al rey, diciendo: He aquí Nathán profeta: el cual como entró al rey, postróse delante del rey inclinando su rostro á tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 24, 'Y dijo Nathán: Rey señor mío, ¿has tú dicho: Adonía reinará después de mí, y él se sentará en mi trono?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 25, 'Porque hoy ha descendido, y ha matado bueyes, y animales engordados, y muchas ovejas, y ha convidado á todos los hijos del rey, y á los capitanes del ejército, y también á Abiathar sacerdote; y he aquí, están comiendo y bebiendo delante de él, y han dicho: ¡Viva el rey Adonía!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 26, 'Mas ni á mí tu siervo, ni á Sadoc sacerdote, ni á Benaía hijo de Joiada, ni á Salomón tu siervo, ha convidado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 27, '¿Es este negocio ordenado por mi señor el rey, sin haber declarado á tu siervo quién se había de sentar en el trono de mi señor el rey después de él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 28, 'Entonces el rey David respondió, y dijo: Llamadme á Bath-sheba. Y ella entró á la presencia del rey, y púsose delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 29, 'Y el rey juró, diciendo: Vive Jehová, que ha redimido mi alma de toda angustia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 30, 'Que como yo te he jurado por Jehová Dios de Israel, diciendo: Tu hijo Salomón reinará después de mí, y él se sentará en mi trono en lugar mío; que así lo haré hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 31, 'Entonces Bath-sheba se inclinó al rey, su rostro á tierra, y haciendo reverencia al rey, dijo: Viva mi señor el rey David para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 32, 'Y el rey David dijo: Llamadme á Sadoc sacerdote, y á Nathán profeta, y á Benaía hijo de Joiada. Y ellos entraron á la presencia del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 33, 'Y el rey les dijo: Tomad con vosotros los siervos de vuestro señor, y haced subir á Salomón mi hijo en mi mula, y llevadlo á Gihón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 34, 'Y allí lo ungirán Sadoc sacerdote y Nathán profeta por rey sobre Israel; y tocaréis trompeta, diciendo: ¡Viva el rey Salomón!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 35, 'Después iréis vosotros detrás de él, y vendrá y se sentará en mi trono, y él reinará por mí; porque á él he ordenado para que sea príncipe sobre Israel y sobre Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 36, 'Entonces Benaía hijo de Joiada respondió al rey, y dijo: Amén. Así lo diga Jehová, Dios de mi señor el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 37, 'De la manera que Jehová ha sido con mi señor el rey, así sea con Salomón; y él haga mayor su trono que el trono de mi señor el rey David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 38, 'Y descendió Sadoc sacerdote, y Nathán profeta, y Benaía hijo de Joiada, y los Ceretheos y los Peletheos, é hicieron subir á Salomón en la mula del rey David, y lleváronlo á Gihón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 39, 'Y tomando Sadoc sacerdote el cuerno del aceite del tabernáculo, ungió á Salomón: y tocaron trompeta, y dijo todo el pueblo: ¡Viva el rey Salomón!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 40, 'Después subió todo el pueblo en pos de él, y cantaba la gente con flautas, y hacían grandes alegrías, que parecía que la tierra se hundía con el clamor de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 41, 'Y oyólo Adonía, y todos los convidados que con él estaban, cuando ya habían acabado de comer. Y oyendo Joab el sonido de la trompeta, dijo: ¿Por qué se alborota la ciudad con estruendo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 42, 'Estando aún él hablando, he aquí Jonathán hijo de Abiathar sacerdote vino, al cual dijo Adonía: Entra, porque tú eres hombre de esfuerzo, y traerás buenas nuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 43, 'Y Jonathán respondió, y dijo á Adonía: Ciertamente nuestro señor el rey David ha hecho rey á Salomón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 44, 'Y el rey ha enviado con él á Sadoc sacerdote y á Nathán profeta, y á Benaía hijo de Joiada, y también á los Ceretheos y á los Peletheos, los cuales le hicieron subir en la mula del rey;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 45, 'Y Sadoc sacerdote y Nathán profeta lo han ungido en Gihón por rey: y de allá han subido con alegrías, y la ciudad está llena de estruendo. Este es el alboroto que habéis oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 46, 'Y también Salomón se ha sentado en el trono del reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 47, 'Y aun los siervos del rey han venido á bendecir á nuestro señor el rey David, diciendo: Dios haga bueno el nombre de Salomón más que tu nombre, y haga mayor su trono que el tuyo. Y el rey adoró en la cama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 48, 'Y también el rey habló así: Bendito sea Jehová Dios de Israel, que ha dado hoy quien se siente en mi trono, viéndolo mis ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 49, 'Ellos entonces se estremecieron, y levantáronse todos los convidados que estaban con Adonía, y fuése cada uno por su camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 50, 'Mas Adonía, temiendo de la presencia de Salomón, levantóse y fuése, y cogió los cornijales del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 51, 'Y fué hecho saber á Salomón, diciendo: He aquí que Adonía tiene miedo del rey Salomón: pues ha cogido los cornijales del altar, diciendo: Júreme hoy el rey Salomón que no matará á cuchillo á su siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 52, 'Y Salomón dijo: Si él fuere virtuoso, ni uno de sus cabellos caerá en tierra: mas si se hallare mal en él, morirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 1, 53, 'Y envió el rey Salomón, y trajéronlo del altar; y él vino, é inclinóse al rey Salomón. Y Salomón le dijo: Vete á tu casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 1, 'Y LLEGARONSE los días de David para morir, y mandó á Salomón su hijo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 2, 'Yo voy el camino de toda la tierra: esfuérzate, y sé varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 3, 'Guarda la ordenanza de Jehová tu Dios, andando en sus caminos, y observando sus estatutos y mandamientos, y sus derechos y sus testimonios, de la manera que está escrito en la ley de Moisés, para que seas dichoso en todo lo que hicieres, y en todo aquello á que te tornares;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 4, 'Para que confirme Jehová la palabra que me habló, diciendo: Si tus hijos guardaren su camino, andando delante de mí con verdad, de todo su corazón, y de toda su alma, jamás, dice, faltará á ti varón del trono de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 5, 'Y ya sabes tú lo que me ha hecho Joab hijo de Sarvia, lo que hizo á dos generales del ejército de Israel, á Abner hijo de Ner, y á Amasa hijo de Jether, los cuales él mató, derramando en paz la sangre de guerra, y poniendo la sangre de guerra en su talabarte que tenía sobre sus lomos, y en sus zapatos que tenía en sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 6, 'Tú pues harás conforme á tu sabiduría; no dejarás descender sus canas á la huesa en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 7, 'Mas á los hijos de Barzillai Galaadita harás misericordia, que sean de los convidados á tu mesa; porque ellos vinieron así á mí, cuando iba huyendo de Absalom tu hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 8, 'También tienes contigo á Semei hijo de Gera, hijo de Benjamín, de Bahurim, el cual me maldijo con una maldición fuerte el día que yo iba á Mahanaim. Mas él mismo descendió á recibirme al Jordán, y yo le juré por Jehová, diciendo: Yo no te mataré á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 9, 'Empero ahora no lo absolverás: que hombre sabio eres, y sabes cómo te has de haber con él: y harás descender sus canas con sangre á la sepultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 10, 'Y David durmió con sus padres, y fué sepultado en la ciudad de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 11, 'Los días que reinó David sobre Israel fueron cuarenta años: siete años reinó en Hebrón, y treinta y tres años reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 12, 'Y se sentó Salomón en el trono de David su padre, y fué su reino firme en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 13, 'Entonces Adonía hijo de Haggith vino á Bath-sheba madre de Salomón; y ella dijo: ¿Es tu venida de paz? Y él respondió: Sí, de paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 14, 'En seguida dijo: Una palabra tengo que decirte. Y ella dijo: Di.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 15, 'Y él dijo: Tú sabes que el reino era mío, y que todo Israel había puesto en mí su rostro, para que yo reinara: mas el reino fué traspasado, y vino á mi hermano; porque por Jehová era suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 16, 'Y ahora yo te hago una petición: no me hagas volver mi rostro. Y ella le dijo: Habla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 17, 'El entonces dijo: Yo te ruego que hables al rey Salomón, (porque él no te hará volver tu rostro,) para que me dé á Abisag Sunamita por mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 18, 'Y Bath-sheba dijo: Bien; yo hablaré por ti al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 19, 'Y vino Bath-sheba al rey Salomón para hablarle por Adonía. Y el rey se levantó á recibirla, é inclinóse á ella, y volvió á sentarse en su trono, é hizo poner una silla á la madre del rey, la cual se sentó á su diestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 20, 'Y ella dijo: Una pequeña petición pretendo de ti; no me hagas volver mi rostro. Y el rey le dijo: Pide, madre mía, que yo no te haré volver el rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 21, 'Y ella dijo: Dése Abisag Sunamita por mujer á tu hermano Adonía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 22, 'Y el rey Salomón respondió, y dijo á su madre: ¿Por qué pides á Abisag Sunamita para Adonía? Demanda también para él el reino, porque él es mi hermano mayor; y tiene también á Abiathar sacerdote, y á Joab hijo de Sarvia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 23, 'Y el rey Salomón juró por Jehová, diciendo: Así me haga Dios y así me añada, que contra su vida ha hablado Adonía esta palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 24, 'Ahora pues, vive Jehová, que me ha confirmado y me ha puesto sobre el trono de David mi padre, y que me ha hecho casa, como me había dicho, que Adonía morirá hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 25, 'Entonces el rey Salomón envió por mano de Benaía hijo de Joiada, el cual dió sobre él, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 26, 'Y á Abiathar sacerdote dijo el rey: Vete á Anathoth á tus heredades, que tú eres digno de muerte; mas no te mataré hoy, por cuanto has llevado el arca del Señor Jehová delante de David mi padre, y además has sido trabajado en todas las cosas en que fué trabajado mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 27, 'Así echó Salomón á Abiathar del sacerdocio de Jehová, para que se cumpliese la palabra de Jehová que había dicho sobre la casa de Eli en Silo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 28, 'Y vino la noticia hasta Joab: porque también Joab se había adherido á Adonía, si bien no se había adherido á Absalom. Y huyó Joab al tabernáculo de Jehová, y asióse á los cornijales del altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 29, 'Y fué hecho saber á Salomón que Joab había huído al tabernáculo de Jehová, y que estaba junto al altar. Entonces envió Salomón á Benaía hijo de Joiada, diciendo: Ve, y da sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 30, 'Y entró Benaía al tabernáculo de Jehová, y díjole: El rey ha dicho que salgas. Y él dijo: No, sino aquí moriré. Y Benaía volvió con esta respuesta al rey, diciendo: Así habló Joab, y así me respondió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 31, 'Y el rey le dijo: Haz como él ha dicho; mátale y entiérralo, y quita de mí y de la casa de mi padre la sangre que Joab ha derramado injustamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 32, 'Y Jehová hará tornar su sangre sobre su cabeza: que él ha muerto dos varones más justos y mejores que él, á los cuales mató á cuchillo sin que mi padre David supiese nada: á Abner hijo de Ner, general del ejército de Israel, y á Amasa hijo de Jether, general de ejército de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 33, 'La sangre pues de ellos recaerá sobre la cabeza de Joab, y sobre la cabeza de su simiente para siempre: mas sobre David y sobre su simiente, y sobre su casa y sobre su trono, habrá perpetuamente paz de parte de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 34, 'Entonces Benaía hijo de Joiada subió, y dió sobre él, y matólo; y fué sepultado en su casa en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 35, 'Y el rey puso en su lugar á Benaía hijo de Joiada sobre el ejército: y á Sadoc puso el rey por sacerdote en lugar de Abiathar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 36, 'Después envió el rey, é hizo venir á Semei, y díjole: Edifícate una casa en Jerusalem, y mora ahí, y no salgas de allá á una parte ni á otra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 37, 'Porque sabe de cierto que el día que salieres, y pasares el torrente de Cedrón, sin duda morirás, y tu sangre será sobre tu cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 38, 'Y Semei dijo al rey: La palabra es buena; como el rey mi señor ha dicho, así lo hará tu siervo. Y habitó Semei en Jerusalem muchos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 39, 'Pero pasados tres años, aconteció que se le huyeron á Semei dos siervos á Achîs, hijo de Maachâ, rey de Gath. Y dieron aviso á Semei, diciendo: He aquí que tus siervos están en Gath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 40, 'Levantóse entonces Semei, y enalbardó su asno, y fué á Gath, á Achîs, á procurar sus siervos. Fué pues Semei, y volvió sus siervos de Gath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 41, 'Díjose luego á Salomón como Semei había ido de Jerusalem hasta Gath, y que había vuelto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 42, 'Entonces el rey envió, é hizo venir á Semei, y díjole: ¿No te conjuré yo por Jehová, y te protesté, diciendo: El día que salieres, y fueres acá ó acullá, sabe de cierto que has de morir? Y tú me dijiste: La palabra es buena, yo la obedezco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 43, '¿Por qué pues no guardaste el juramento de Jehová, y el mandamiento que yo te impuse?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 44, 'Dijo además el rey á Semei: Tú sabes todo el mal, el cual tu corazón bien sabe, que cometiste contra mi padre David; Jehová pues, ha tornado el mal sobre tu cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 45, 'Y el rey Salomón será bendito, y el trono de David será firme perpetuamente delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 2, 46, 'Entonces el rey mandó á Benaía hijo de Joiada, el cual salió é hirióle; y murió. Y el reino fué confirmado en la mano de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 1, 'Y SALOMON hizo parentesco con Faraón rey de Egipto, porque tomó la hija de Faraón, y trájola á la ciudad de David, entre tanto que acababa de edificar su casa, y la casa de Jehová, y los muros de Jerusalem alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 2, 'Hasta entonces el pueblo sacrificaba en los altos; porque no había casa edificada al nombre de Jehová hasta aquellos tiempos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 3, 'Mas Salomón amó á Jehová, andando en los estatutos de su padre David: solamente sacrificaba y quemaba perfumes en los altos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 4, 'E iba el rey á Gabaón, porque aquél era el alto principal, y sacrificaba allí, mil holocaustos sacrificaba Salomón sobre aquel altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 5, 'Y aparecióse Jehová á Salomón en Gabaón una noche en sueños, y díjo le Dios: Pide lo que quisieres que yo te dé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 6, 'Y Salomón dijo: Tú hiciste gran misericordia á tu siervo David mi padre, según que él anduvo delante de ti en verdad, en justicia, y con rectitud de corazón para contigo: y tú le has guardado esta tu grande misericordia, que le diste hijo que se sentase en su trono, como sucede en este día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 7, 'Ahora pues, Jehová Dios mío, tú has puesto á mí tu siervo por rey en lugar de David mi padre: y yo soy mozo pequeño, que no sé cómo entrar ni salir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 8, 'Y tu siervo está en medio de tu pueblo al cual tú escogiste; un pueblo grande, que no se puede contar ni numerar por su multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 9, 'Da pues á tu siervo corazón dócil para juzgar á tu pueblo, para discernir entre lo bueno y lo malo: porque ¿quién podrá gobernar este tu pueblo tan grande?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 10, 'Y agradó delante de Adonai que Salomón pidiese esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 11, 'Y díjole Dios: Porque has demandado esto, y no pediste para ti muchos días, ni pediste para ti riquezas, ni pediste la vida de tus enemigos, mas demandaste para ti inteligencia para oir juicio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 12, 'He aquí lo he hecho conforme á tus palabras: he aquí que te he dado corazón sabio y entendido, tanto que no haya habido antes de ti otro como tú, ni después de ti se levantará otro como tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 13, 'Y aun también te he dado las cosas que no pediste, riquezas y gloria: tal, que entre los reyes ninguno haya como tú en todos tus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 14, 'Y si anduvieres en mis caminos, guardando mis estatutos y mis mandamientos, como anduvo David tu padre, yo alargaré tus días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 15, 'Y como Salomón despertó, vió que era sueño: y vino á Jerusalem, y presentóse delante del arca del pacto de Jehová, y sacrificó holocaustos, é hizo pacíficos; hizo también banquete á todos sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 16, 'En aquella sazón vinieron dos mujeres rameras al rey, y presentáronse delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 17, 'Y dijo la una mujer: ¡Ah, señor mío! yo y esta mujer morábamos en una misma casa, y yo parí estando con ella en la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 18, 'Y aconteció al tercer día después que yo parí, que ésta parió también, y morábamos nosotras juntas; ninguno de fuera estaba en casa, sino nosotras dos en la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 19, 'Y una noche el hijo de esta mujer murió, porque ella se acostó sobre él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 20, 'Y levantóse á media noche, y tomó á mi hijo de junto á mí, estando yo tu sierva durmiendo, y púsolo á su lado, y púsome á mi lado su hijo muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 21, 'Y como yo me levanté por la mañana para dar el pecho á mi hijo, he aquí que estaba muerto: mas observéle por la mañana, y vi que no era mi hijo, que yo había parido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 22, 'Entonces la otra mujer dijo: No; mi hijo es el que vive, y tu hijo es el muerto. Y la otra volvió á decir: No; tu hijo es el muerto, y mi hijo es el que vive. Así hablaban delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 23, 'El rey entonces dijo: Esta dice: Mi hijo es el que vive, y tu hijo es el muerto: y la otra dice: No, mas el tuyo es el muerto, y mi hijo es el que vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 24, 'Y dijo el rey: Traedme un cuchillo. Y trajeron al rey un cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 25, 'En seguida el rey dijo: Partid por medio el niño vivo, y dad la mitad á la una, y la otra mitad á la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 26, 'Entonces la mujer cuyo era el hijo vivo, habló al rey (porque sus entrañas se le conmovieron por su hijo), y dijo: ¡Ah, señor mío! dad á ésta el niño vivo, y no lo matéis. Mas la otra dijo: Ni á mí ni á ti; partidlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 27, 'Entonces el rey respondió, y dijo: Dad á aquélla el hijo vivo, y no lo matéis: ella es su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 3, 28, 'Y todo Israel oyó aquel juicio que había dado el rey: y temieron al rey, porque vieron que había en él sabiduría de Dios para juzgar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 1, 'FUÉ pues el rey Salomón rey sobre todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 2, 'Y estos fueron los príncipes que tuvo: Azarías hijo de Sadoc, sacerdote;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 3, 'Elioreph y Ahía, hijos de Sisa, escribas; Josaphat hijo de Ahilud, canciller;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 4, 'Benaía hijo de Joiada era sobre el ejército; y Sadoc y Abiathar eran los sacerdotes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 5, 'Azaría hijo de Nathán era sobre los gobernadores; Zabud hijo de Nathán era principal oficial, amigo del rey;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 6, 'Y Ahisar era mayordomo; y Adoniram hijo de Abda era sobre el tributo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 7, 'Y tenía Salomón doce gobernadores sobre todo Israel, los cuales mantenían al rey y á su casa. Cada uno de ellos estaba obligado á abastecer por un mes en el año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 8, 'Y estos son los nombres de ellos: el hijo de Hur en el monte de Ephraim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 9, 'El hijo de Decar, en Maccas, y en Saalbim, y en Beth-semes, y en Elón, y en Beth-hanan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 10, 'El hijo de Hesed, en Aruboth; éste tenía también á Sochô y toda la tierra de Ephet.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 11, 'El hijo de Abinadab, en todos los términos de Dor: éste tenía por mujer á Thaphat hija de Salomón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 12, 'Baana hijo de Ahilud, en Taanach y Megiddo, y en toda Beth-san, que es cerca de Zaretán, por bajo de Jezreel, desde Beth-san hasta Abel-mehola, y hasta la otra parte de Jocmeam;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 13, 'El hijo de Geber, en Ramoth de Galaad; éste tenía también las ciudades de Jair hijo de Manasés, las cuales estaban en Galaad; tenía también la provincia de Argob, que era en Basán, sesenta grandes ciudades con muro y cerraduras de bronce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 14, 'Ahinadab hijo de Iddo, en Mahanaim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 15, 'Ahimaas en Nephtalí; éste tomó también por mujer á Basemath hija de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 16, 'Baana hijo de Husai, en Aser y en Aloth;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 17, 'Josaphat hijo de Pharua, en Issachâr;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 18, 'Semei hijo de Ela, en Benjamín;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 19, 'Geber hijo de Uri, en la tierra de Galaad, la tierra de Sehón rey de los Amorrheos, y de Og rey de Basán; éste era el único gobernador en aquella tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 20, 'Judá é Israel eran muchos, como la arena que está junto á la mar en multitud, comiendo y bebiendo y alegrándose.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 21, 'Y Salomón señoreaba sobre todos los reinos, desde el río de la tierra de los Filisteos hasta el término de Egipto: y traían presentes, y sirvieron á Salomón todos los días que vivió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 22, 'Y la despensa de Salomón era cada día treinta coros de flor de harina, y sesenta coros de harina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 23, 'Diez bueyes engordados, y veinte bueyes de pasto, y cien ovejas; sin los ciervos, cabras, búfalos, y aves engordadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 24, 'Porque él señoreaba en toda la región que estaba de la otra parte del río, desde Tiphsa hasta Gaza, sobre todos los reyes de la otra parte del río; y tuvo paz por todos lados en derredor suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 25, 'Y Judá é Israel vivían seguros, cada uno debajo de su parra y debajo de su higuera, desde Dan hasta Beer-seba, todos los días de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 26, 'Tenía además de esto Salomón cuarenta mil caballos en sus caballerizas para sus carros, y doce mil jinetes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 27, 'Y estos gobernadores mantenían al rey Salomón, y á todos los que á la mesa del rey Salomón venían, cada uno un mes; y hacían que nada faltase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 28, 'Hacían también traer cebada y paja para los caballos y para las bestias de carga, al lugar donde él estaba, cada uno conforme al cargo que tenía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 29, 'Y dió Dios á Salomón sabiduría, y prudencia muy grande, y anchura de corazón como la arena que está á la orilla del mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 30, 'Que fué mayor la sabiduría de Salomón que la de todos los orientales, y que toda la sabiduría de los Egipcios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 31, 'Y aun fué más sabio que todos los hombres; más que Ethán Ezrahita, y que Emán y Calchôl y Darda, hijos de Mahol: y fué nombrado entre todas las naciones de alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 32, 'Y propuso tres mil parábolas; y sus versos fueron mil y cinco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 33, 'También disertó de los árboles, desde el cedro del Líbano hasta el hisopo que nace en la pared. Asimismo disertó de los animales, de las aves, de los reptiles, y de los peces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 4, 34, 'Y venían de todos los pueblos á oir la sabiduría de Salomón, y de todos los reyes de la tierra, donde había llegado la fama de su sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 1, 'HIRAM rey de Tiro envió también sus siervos á Salomón, luego que oyó que lo habían ungido por rey en lugar de su padre: porque Hiram había siempre amado á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 2, 'Entonces Salomón envió á decir á Hiram:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 3, 'Tú sabes como mi padre David no pudo edificar casa al nombre de Jehová su Dios, por las guerras que le cercaron, hasta que Jehová puso sus enemigos bajo las plantas de sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 4, 'Ahora Jehová mi Dios me ha dado reposo por todas partes; que ni hay adversarios, ni mal encuentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 5, 'Yo por tanto he determinado ahora edificar casa al nombre de Jehová mi Dios, como Jehová lo habló á David mi padre, diciendo: Tu hijo, que yo pondré en lugar tuyo en tu trono, él edificará casa á mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 6, 'Manda pues ahora que me corten cedros del Líbano; y mis siervos estarán con los tuyos, y yo te daré por tus siervos el salario que tú dijeres: porque tú sabes bien que ninguno hay entre nosotros que sepa labrar la madera como los Sidonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 7, 'Y como Hiram oyó las palabras de Salomón, holgóse en gran manera, y dijo: Bendito sea hoy Jehová, que dió hijo sabio á David sobre este pueblo tan grande.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 8, 'Y envió Hiram á decir á Salomón: He oído lo que me mandaste á decir: yo haré todo lo que te pluguiere acerca de la madera de cedro, y la madera de haya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 9, 'Mis siervos la llevarán desde el Líbano á la mar; y yo la pondré en balsas por la mar hasta el lugar que tú me señalares, y allí se desatará, y tú la tomarás: y tú harás mi voluntad en dar de comer á mi familia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 10, 'Dió pues Hiram á Salomón madera de cedro y madera de haya todo lo que quiso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 11, 'Y Salomón daba á Hiram veinte mil coros de trigo para el sustento de su familia, y veinte coros de aceite limpio: esto daba Salomón á Hiram cada un año.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 12, 'Dió pues Jehová á Salomón sabiduría como le había dicho: y hubo paz entre Hiram y Salomón, é hicieron alianza entre ambos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 13, 'Y el rey Salomón impuso tributo á todo Israel, y el tributo fué de treinta mil hombres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 14, 'Los cuales enviaba al Líbano de diez mil en diez mil, cada mes por su turno, viniendo así á estar un mes en el Líbano, y dos meses en sus casas: y Adoniram estaba sobre aquel tributo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 15, 'Tenía también Salomón setenta mil que llevaban las cargas, y ochenta mil cortadores en el monte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 16, 'Sin los principales oficiales de Salomón que estaban sobre la obra, tres mil y trescientos, los cuales tenían cargo del pueblo que hacía la obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 17, 'Y mandó el rey que trajesen grandes piedras, piedras de precio, para los cimientos de la casa, y piedras labradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 5, 18, 'Y los albañiles de Salomón y los de Hiram, y los aparejadores, cortaron y aparejaron la madera y la cantería para labrar la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 1, 'Y FUÉ en el año cuatrocientos ochenta después que los hijos de Israel salieron de Egipto, en el cuarto año del principio del reino de Salomón sobre Israel, en el mes de Ziph, que es el mes segundo, que él comenzó á edificar la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 2, 'La casa que el rey Salomón edificó á Jehová, tuvo sesenta codos de largo y veinte de ancho, y treinta codos de alto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 3, 'Y el pórtico delante del templo de la casa, de veinte codos de largo, según la anchura de la casa, y su ancho era de diez codos delante de la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 4, 'E hizo á la casa ventanas anchas por de dentro, y estrechas por de fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 5, 'Edificó también junto al muro de la casa aposentos alrededor, contra las paredes de la casa en derredor del templo y del oráculo: é hizo cámaras alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 6, 'El aposento de abajo era de cinco codos de ancho, y el de en medio de seis codos de ancho, y el tercero de siete codos de ancho: porque por de fuera había hecho disminuciones á la casa en derredor, para no trabar las vigas de las paredes de la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 7, 'Y la casa cuando se edificó, fabricáronla de piedras que traían ya acabadas; de tal manera que cuando la edificaban, ni martillos ni hachas se oyeron en la casa, ni ningún otro instrumento de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 8, 'La puerta del aposento de en medio estaba al lado derecho de la casa: y subíase por un caracol al de en medio, y del aposento de en medio al tercero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 9, 'Labró pues la casa, y acabóla; y cubrió la casa con artesonados de cedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 10, 'Y edificó asimismo el aposento en derredor de toda la casa, de altura de cinco codos, el cual se apoyaba en la casa con maderas de cedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 11, 'Y fué palabra de Jehová á Salomón, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 12, 'Esta casa que tú edificas, si anduvieres en mis estatutos, é hicieres mis derechos, y guardares todos mis mandamientos andando en ellos, yo tendré firme contigo mi palabra que hablé á David tu padre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 13, 'Y habitaré en medio de los hijos de Israel, y no dejaré á mi pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 14, 'Así que, Salomón labró la casa, y acabóla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 15, 'Y aparejó las paredes de la casa por de dentro con tablas de cedro, vistiéndola de madera por dentro, desde el solado de la casa hasta las paredes de la techumbre: cubrió también el pavimento con madera de haya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 16, 'Asimismo hizo al cabo de la casa un edificio de veinte codos de tablas de cedro, desde el solado hasta lo más alto; y fabricóse en la casa un oráculo, que es el lugar santísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 17, 'Y la casa, á saber, el templo de dentro, tenía cuarenta codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 18, 'Y la casa estaba cubierta de cedro por de dentro, y tenía entalladuras de calabazas silvestres y de botones de flores. Todo era cedro; ninguna piedra se veía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 19, 'Y adornó el oráculo por de dentro en medio de la casa, para poner allí el arca del pacto de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 20, 'Y el oráculo estaba en la parte de adentro, el cual tenía veinte codos de largo, y otros veinte de ancho, y otros veinte de altura; y vistiólo de oro purísimo: asimismo cubrió el altar de cedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 21, 'De suerte que vistió Salomón de oro puro la casa por de dentro, y cerró la entrada del oráculo con cadenas de oro, y vistiólo de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 22, 'Cubrió pues de oro toda la casa hasta el cabo; y asimismo vistió de oro todo el altar que estaba delante del oráculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 23, 'Hizo también en el oráculo dos querubines de madera de oliva, cada uno de altura de diez codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 24, 'La una ala del querubín tenía cinco codos, y la otra ala del querubín otros cinco codos: así que había diez codos desde la punta de la una ala hasta la punta de la otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 25, 'Asimismo el otro querubín tenía diez codos; porque ambos querubines eran de un tamaño y de una hechura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 26, 'La altura del uno era de diez codos, y asimismo el otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 27, 'Y puso estos querubines dentro de la casa de adentro: los cuales querubines extendían sus alas, de modo que el ala del uno tocaba á la pared, y el ala del otro querubín tocaba á la otra pared, y las otras dos alas se tocaban la una á la otra en la mitad de la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 28, 'Y vistió de oro los querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 29, 'Y esculpió todas las paredes de la casa alrededor de diversas figuras, de querubines, de palmas, y de botones de flores, por de dentro y por de fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 30, 'Y cubrió de oro el piso de la casa, de dentro y de fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 31, 'Y á la entrada del oráculo hizo puertas de madera de oliva; y el umbral y los postes eran de cinco esquinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 32, 'Las dos puertas eran de madera de oliva; y entalló en ellas figuras de querubines y de palmas y de botones de flores, y cubriólas de oro: cubrió también de oro los querubines y las palmas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 33, 'Igualmente hizo á la puerta del templo postes de madera de oliva cuadrados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 34, 'Pero las dos puertas eran de madera de haya; y los dos lados de la una puerta eran redondos, y los otros dos lados de la otra puerta también redondos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 35, 'Y entalló en ellas querubines y palmas y botones de flores, y cubriólas de oro ajustado á las entalladuras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 36, 'Y edificó el atrio interior de tres órdenes de piedras labradas, y de un orden de vigas de cedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 37, 'En el cuarto año, en el mes de Ziph, se echaron los cimientos de la casa de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 6, 38, 'Y en el undécimo año, en el mes de Bul, que es el mes octavo, fué acabada la casa con todas sus pertenencias, y con todo lo necesario. Edificóla pues, en siete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 1, 'DESPUÉS edificó Salomón su propia casa en trece años, y acabóla toda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 2, 'Asimismo edificó la casa del bosque del Líbano, la cual tenía cinco codos de longitud, y cincuenta codos de anchura, y treinta codos de altura, sobre cuatro órdenes de columnas de cedro, con vigas de cedro sobre las columnas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 3, 'Y estaba cubierta de tablas de cedro arriba sobre las vigas, que se apoyaban en cuarenta y cinco columnas: cada hilera tenía quince columnas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 4, 'Y había tres órdenes de ventanas, una ventana contra la otra en tres órdenes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 5, 'Y todas la puertas y postes eran cuadrados: y las unas ventanas estaban frente á las otras en tres órdenes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 6, 'También hizo un pórtico de columnas, que tenía de largo cincuenta codos, y treinta codos de ancho; y aqueste pórtico estaba delante de aquellas otras, con sus columnas y maderos correspondientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 7, 'Hizo asimismo el pórtico del trono en que había de juzgar, el pórtico del juicio, y vistiólo de cedro de suelo á suelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 8, 'Y en la casa en que él moraba, había otro atrio dentro del pórtico, de obra semejante á esta. Edificó también Salomón una casa para la hija de Faraón, que había tomado por mujer, de la misma obra de aquel pórtico.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 9, 'Todas aquellas obras fueron de piedras de precio, cortadas y aserradas con sierras según las medidas, así por de dentro como por de fuera, desde el cimiento hasta los remates, y asimismo por de fuera hasta el gran atrio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 10, 'El cimiento era de piedras de precio, de piedras grandes, de piedras de diez codos, y de piedras de ocho codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 11, 'De allí arriba eran también piedras de precio, labradas conforme á sus medidas, y obra de cedro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 12, 'Y en el gran atrio alrededor había tres órdenes de piedras labradas, y un orden de vigas de cedro: y así el atrio interior de la casa de Jehová, y el atrio de la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 13, 'Y envió el rey Salomón, é hizo venir de Tiro á Hiram,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 14, 'Hijo de una viuda de la tribu de Nephtalí, y su padre había sido de Tiro: trabajaba él en bronce, lleno de sabiduría y de inteligencia y saber en toda obra de metal. Este pues vino al rey Salomón, é hizo toda su obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 15, 'Y vació dos columnas de bronce, la altura de cada cual era de diez y ocho codos: y rodeaba á una y á otra columna un hilo de doce codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 16, 'Hizo también dos capiteles de fundición de bronce, para que fuesen puestos sobre las cabezas de las columnas: la altura de un capitel era de cinco codos, y la del otro capitel de cinco codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 17, 'Había trenzas á manera de red, y unas cintas á manera de cadenas, para los capiteles que se habían de poner sobre las cabezas de las columnas: siete para cada capitel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 18, 'Y cuando hubo hecho las columnas, hizo también dos órdenes de granadas alrededor en el un enredado, para cubrir los capiteles que estaban en las cabezas de las columnas con las granadas: y de la misma forma hizo en el otro capitel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 19, 'Los capiteles que estaban sobre las columnas en el pórtico, tenían labor de flores por cuatro codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 20, 'Tenían también los capiteles de sobre las dos columnas, doscientas granadas en dos órdenes alrededor en cada capitel, encima del vientre del capitel, el cual vientre estaba delante del enredado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 21, 'Estas columnas erigió en el pórtico del templo: y cuando hubo alzado la columna de la mano derecha, púsole por nombre Jachîn: y alzando la columna de la mano izquierda, llamó su nombre Boaz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 22, 'Y puso en las cabezas de las columnas labor en forma de azucenas; y así se acabó la obra de las columnas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 23, 'Hizo asimismo un mar de fundición, de diez codos del un lado al otro, perfectamente redondo: su altura era de cinco codos, y ceñíalo alrededor un cordón de treinta codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 24, 'Y cercaban aquel mar por debajo de su labio en derredor unas bolas como calabazas, diez en cada codo, que ceñían el mar alrededor en dos órdenes, las cuales habían sido fundidas cuando él fué fundido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 25, 'Y estaba asentado sobre doce bueyes: tres miraban al norte, y tres miraban al poniente, y tres miraban al mediodía, y tres miraban al oriente; sobre éstos se apoyaba el mar, y las traseras de ellos estaban hacia la parte de adentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 26, 'El grueso del mar era de un palmo, y su labio era labrado como el labio de un cáliz, ó de flor de lis: y cabían en él dos mil batos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 27, 'Hizo también diez basas de bronce, siendo la longitud de cada basa de cuatro codos, y la anchura de cuatro codos, y de tres codos la altura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 28, 'La obra de las basas era esta: tenían unas cintas, las cuales estaban entre molduras:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 29, 'Y sobre aquellas cintas que estaban entre las molduras, figuras de leones, y de bueyes, y de querubines; y sobre las molduras de la basa, así encima como debajo de los leones y de los bueyes, había unas añadiduras de bajo relieve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 30, 'Cada basa tenía cuatro ruedas de bronce con mesas de bronce; y en sus cuatro esquinas había unos hombrillos, los cuales nacían de fundición á cada un lado de aquellas añadiduras, para estar debajo de la fuente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 31, 'Y la boca del pie de la fuente entraba un codo en el remate que salía para arriba de la basa; y era su boca redonda, de la hechura del mismo remate, y éste de codo y medio. Había también sobre la boca entalladuras con sus cintas, las cuales eran cuadradas, no redondas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 32, 'Las cuatro ruedas estaban debajo de las cintas, y los ejes de las ruedas nacían en la misma basa. La altura de cada rueda era de un codo y medio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 33, 'Y la hechura de las ruedas era como la hechura de las ruedas de un carro: sus ejes, sus rayos, y sus cubos, y sus cinchos, todo era de fundición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 34, 'Asimismo los cuatro hombrillos á las cuatro esquinas de cada basa: y los hombrillos eran de la misma basa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 35, 'Y en lo alto de la basa había medio codo de altura redondo por todas partes: y encima de la basa sus molduras y cintas, las cuales eran de ella misma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 36, 'E hizo en las tablas de las molduras, y en las cintas, entalladuras de querubines, y de leones, y de palmas, con proporción en el espacio de cada una, y alrededor otros adornos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 37, 'De esta forma hizo diez basas fundidas de una misma manera, de una misma medida, y de una misma entalladura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 38, 'Hizo también diez fuentes de bronce: cada fuente contenía cuarenta batos, y cada una era de cuatro codos; y asentó una fuente sobre cada una de las diez basas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 39, 'Y puso las cinco basas á la mano derecha de la casa, y las otras cinco á la mano izquierda: y asentó el mar al lado derecho de la casa, al oriente, hacia el mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 40, 'Asimismo hizo Hiram fuentes, y tenazas, y cuencos. Así acabó toda la obra que hizo á Salomón para la casa de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 41, 'Es á saber, dos columnas, y los vasos redondos de los capiteles que estaban en lo alto de las dos columnas; y dos redes que cubrían los dos vasos redondos de los capiteles que estaban sobre la cabeza de las columnas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 42, 'Y cuatrocientas granadas para las dos redes, dos órdenes de granadas en cada red, para cubrir los dos vasos redondos que estaban sobre las cabezas de las columnas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 43, 'Y las diez basas, y las diez fuentes sobre las basas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 44, 'Y un mar, y doce bueyes debajo del mar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 45, 'Y calderos, y paletas, y cuencos; y todos los vasos que Hiram hizo al rey Salomón, para la casa de Jehová de metal acicalado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 46, 'Todo lo hizo fundir el rey en la llanura del Jordán, en tierra arcillosa, entre Succoth y Sarthán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 47, 'Y dejó Salomón sin inquirir el peso del metal de todos los vasos, por la grande multitud de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 48, 'Entonces hizo Salomón todos los vasos que pertenecían á la casa de Jehová: un altar de oro, y una mesa sobre la cual estaban los panes de la proposición, también de oro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 49, 'Y cinco candeleros de oro purísimo á la mano derecha, y otros cinco á la izquierda, delante del oráculo; con las flores, y las lámparas, y despabiladeras de oro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 50, 'Asimismo los cántaros, vasos, tazas, cucharillas, é incensarios, de oro purísimo; también de oro los quiciales de las puertas de la casa de adentro, del lugar santísimo, y los de las puertas del templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 7, 51, 'Así se acabó toda la obra que dispuso hacer el rey Salomón para la casa de Jehová. Y metió Salomón lo que David su padre había dedicado, es á saber, plata, y oro, y vasos, y púsolo todo en guarda en las tesorerías de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 1, 'ENTONCES juntó Salomón los ancianos de Israel, y á todas las cabezas de las tribus, y á los príncipes de las familias de los hijos de Israel, al rey Salomón en Jerusalem para traer el arca del pacto de Jehová de la ciudad de David, que es Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 2, 'Y se juntaron al rey Salomón todos los varones de Israel en el mes de Ethanim, que es el mes séptimo, en el día solemne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 3, 'Y vinieron todos los ancianos de Israel, y los sacerdotes tomaron el arca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 4, 'Y llevaron el arca de Jehová, y el tabernáculo del testimonio, y todos los vasos sagrados que estaban en el tabernáculo; los cuales llevaban los sacerdotes y Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 5, 'Y el rey Salomón, y toda la congregación de Israel que á él se había juntado, estaban con él delante del arca, sacrificando ovejas y bueyes, que por la multitud no se podían contar ni numerar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 6, 'Y los sacerdotes metieron el arca del pacto de Jehová en su lugar, en el oráculo de la casa, en el lugar santísimo, debajo de las alas de los querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 7, 'Porque los querubines tenían extendidas las alas sobre el lugar del arca, y así cubrían los querubines el arca y sus varas por encima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 8, 'E hicieron salir las varas; que las cabezas de las varas se dejaban ver desde el santuario delante del oráculo, mas no se veían desde afuera: y así se quedaron hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 9, 'En el arca ninguna cosa había más de las dos tablas de piedra que había allí puesto Moisés en Horeb, donde Jehová hizo la alianza con los hijos de Israel, cuando salieron de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 10, 'Y como los sacerdotes salieron del santuario, la nube hinchió la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 11, 'Y los sacerdotes no pudieron estar para ministrar por causa de la nube; porque la gloria de Jehová había henchido la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 12, 'Entonces dijo Salomón: Jehová ha dicho que él habitaría en la oscuridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 13, 'Yo he edificado casa por morada para ti, asiento en que tú habites para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 14, 'Y volviendo el rey su rostro, bendijo á toda la congregación de Israel; y toda la congregación de Israel estaba en pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 15, 'Y dijo: Bendito sea Jehová Dios de Israel, que habló de su boca á David mi padre, y con su mano lo ha cumplido, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 16, 'Desde el día que saqué mi pueblo Israel de Egipto, no he escogido ciudad de todas las tribus de Israel para edificar casa en la cual estuviese mi nombre, aunque escogí á David para que presidiese en mi pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 17, 'Y David mi padre tuvo en el corazón edificar casa al nombre de Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 18, 'Mas Jehová dijo á David mi padre: Cuanto á haber tú tenido en el corazón edificar casa á mi nombre, bien has hecho en tener tal voluntad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 19, 'Empero tú no edificarás la casa, sino tu hijo que saldrá de tus lomos, él edificará casa á mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 20, 'Y Jehová ha verificado su palabra que había dicho; que me he levantado yo en lugar de David mi padre, y heme sentado en el trono de Israel, como Jehová había dicho, y he edificado la casa al nombre de Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 21, 'Y he puesto en ella lugar para el arca, en la cual está el pacto de Jehová, que él hizo con nuestros padres cuando los sacó de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 22, 'Púsose luego Salomón delante del altar de Jehová, en presencia de toda la congregación de Israel, y extendiendo sus manos al cielo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 23, 'Dijo: Jehová Dios de Israel, no hay Dios como tú, ni arriba en los cielos ni abajo en la tierra, que guardas el pacto y la misericordia á tus siervos, los que andan delante de ti de todo su corazón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 24, 'Que has guardado á tu siervo David mi padre lo que le dijiste: dijístelo con tu boca, y con tu mano lo has cumplido, como aparece este día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 25, 'Ahora pues, Jehová Dios de Israel, cumple á tu siervo David mi padre lo que le prometiste, diciendo: No faltará varón de ti delante de mí, que se siente en el trono de Israel, con tal que tus hijos guarden su camino, que anden delante de mí como tú has delante de mí andado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 26, 'Ahora pues, oh Dios de Israel, verifíquese tu palabra que dijiste á tu siervo David mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 27, 'Empero ¿es verdad que Dios haya de morar sobre la tierra? He aquí que los cielos, los cielos de los cielos, no te pueden contener: ¿cuánto menos esta casa que yo he edificado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 28, 'Con todo, tú atenderás á la oración de tu siervo, y á su plegaria, oh Jehová Dios mío, oyendo propicio el clamor y oración que tu siervo hace hoy delante de ti:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 29, 'Que estén tus ojos abiertos de noche y de día sobre esta casa, sobre este lugar del cual has dicho: Mi nombre estará allí; y que oigas la oración que tu siervo hará en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 30, 'Oye pues la oración de tu siervo, y de tu pueblo Israel; cuando oraren en este lugar, también tú lo oirás en el lugar de tu habitación, desde los cielos: que oigas y perdones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 31, 'Cuando alguno hubiere pecado contra su prójimo, y le tomaren juramento haciéndole jurar, y viniere el juramento delante de tu altar en esta casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 32, 'Tú oirás desde el cielo, y obrarás, y juzgarás á tus siervos, condenando al impío, tornando su proceder sobre su cabeza, y justificando al justo para darle conforme á su justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 33, 'Cuando tu pueblo Israel hubiere caído delante de sus enemigos, por haber pecado contra ti, y á ti se volvieren, y confesaren tu nombre, y oraren, y te rogaren y suplicaren en esta casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 34, 'Oyelos tú en los cielos, y perdona el pecado de tu pueblo Israel, y vuélvelos á la tierra que diste á sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 35, 'Cuando el cielo se cerrare, y no lloviere, por haber ellos pecado contra ti, y te rogaren en este lugar, y confesaren tu nombre, y se volvieren del pecado, cuando los hubieres afligido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 36, 'Tú oirás en los cielos, y perdonarás el pecado de tus siervos y de tu pueblo Israel, enseñándoles el buen camino en que anden; y darás lluvias sobre tu tierra, la cual diste á tu pueblo por heredad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 37, 'Cuando en la tierra hubiere hambre, ó pestilencia, ó tizoncillo, ó niebla, ó langosta, ó pulgón: si sus enemigos los tuvieren cercados en la tierra de su domicilio; cualquiera plaga ó enfermedad que sea;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 38, 'Toda oración y toda súplica que hiciere cualquier hombre, ó todo tu pueblo Israel, cuando cualquiera sintiere la plaga de su corazón, y extendiere sus manos á esta casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 39, 'Tú oirás en los cielos, en la habitación de tu morada, y perdonarás, y obrarás, y darás á cada uno conforme á sus caminos, cuyo corazón tú conoces; (porque sólo tú conoces el corazón de todos los hijos de los hombres;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 40, 'Para que te teman todos los días que vivieren sobre la haz de la tierra que tú diste á nuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 41, 'Asimismo el extranjero, que no es de tu pueblo Israel, que hubiere venido de lejanas tierras á causa de tu nombre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 42, '(Porque oirán de tu grande nombre, y de tu mano fuerte, y de tu brazo extendido,) y viniere á orar á esta casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 43, 'Tú oirás en los cielos, en la habitación de tu morada, y harás conforme á todo aquello por lo cual el extranjero hubiere á ti clamado: para que todos los pueblos de la tierra conozcan tu nombre, y te teman, como tu pueblo Israel, y entiendan que tu nombre es invocado sobre esta casa que yo edifiqué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 44, 'Si tu pueblo saliere en batalla contra sus enemigos por el camino que tú los enviares, y oraren á Jehová hacia la ciudad que tú elegiste, y hacia la casa que yo edifiqué á tu nombre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 45, 'Tú oirás en los cielos su oración y su súplica, y les harás derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 46, 'Si hubieren pecado contra ti, (porque no hay hombre que no peque) y tú estuvieres airado contra ellos, y los entregares delante del enemigo, para que los cautiven y lleven á tierra enemiga, sea lejos ó cerca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 47, 'Y ellos volvieren en sí en la tierra donde fueren cautivos; si se convirtieren, y oraren á ti en la tierra de los que los cautivaron, y dijeren: Pecamos, hemos hecho lo malo, hemos cometido impiedad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 48, 'Y si se convirtieren á ti de todo su corazón y de toda su alma, en la tierra de sus enemigos que los hubieren llevado cautivos, y oraren á ti hacia su tierra, que tú diste á sus padres, hacia la ciudad que tú elegiste y la casa que yo he edificado á tu nombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 49, 'Tú oirás en los cielos, en la habitación de tu morada, su oración y su súplica, y les harás derecho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 50, 'Y perdonarás á tu pueblo que había pecado contra ti, y todas sus infracciones con que se habrán contra ti rebelado; y harás que hayan de ellos misericordia los que los hubieren llevado cautivos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 51, 'Porque ellos son tu pueblo y tu heredad, que tú sacaste de Egipto, de en medio del horno de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 52, 'Que tus ojos estén abiertos á la oración de tu siervo, y á la plegaria de tu pueblo Israel, para oirlos en todo aquello por lo que te invocaren:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 53, 'Pues que tú los apartaste para ti por tu heredad de todos los pueblos de la tierra, como lo dijiste por mano de Moisés tu siervo, cuando sacaste á nuestros padres de Egipto, oh Señor Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 54, 'Y fué, que como acabó Salomón de hacer á Jehová toda esta oración y súplica, levantóse de estar de rodillas delante del altar de Jehová con sus manos extendidas al cielo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 55, 'Y puesto en pie, bendijo á toda la congregación de Israel, diciendo en voz alta:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 56, 'Bendito sea Jehová, que ha dado reposo á su pueblo Israel, conforme á todo lo que él había dicho; ninguna palabra de todas sus promesas que expresó por Moisés su siervo, ha faltado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 57, 'Sea con nosotros Jehová nuestro Dios, como fué con nuestros padres; y no nos desampare, ni nos deje;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 58, 'Incline nuestro corazón hacia sí, para que andemos en todos sus caminos, y guardemos sus mandamientos y sus estatutos y sus derechos, los cuales mandó á nuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 59, 'Y que estas mis palabras con que he orado delante de Jehová estén cerca de Jehová nuestro Dios de día y de noche, para que él proteja la causa de su siervo, y de su pueblo Israel, cada cosa en su tiempo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 60, 'A fin de que todos los pueblos de la tierra sepan que Jehová es Dios, y que no hay otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 61, 'Sea pues perfecto vuestro corazón para con Jehová nuestro Dios, andando en sus estatutos, y guardando sus mandamientos, como el día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 62, 'Entonces el rey, y todo Israel con él, sacrificaron víctimas delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 63, 'Y sacrificó Salomón por sacrificios pacíficos, los cuales ofreció á Jehová veinte y dos mil bueyes, y ciento veinte mil ovejas. Así dedicaron el rey y todos los hijos de Israel la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 64, 'Aquel mismo día santificó el rey el medio del atrio que estaba delante de la casa de Jehová: porque ofreció allí los holocaustos, y los presentes, y los sebos de los pacíficos; por cuanto el altar de bronce que estaba delante de Jehová era pequeño, y no cupieran en él los holocaustos, y los presentes, y los sebos de los pacíficos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 65, 'En aquel tiempo Salomón hizo fiesta, y con él todo Israel, una grande congregación, desde como entran en Hamath hasta el río de Egipto, delante de Jehová nuestro Dios, por siete días y otros siete días, esto es, por catorce días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 8, 66, 'Y el octavo día despidió al pueblo: y ellos bendiciendo al rey, se fueron á sus estancias alegres y gozosos de corazón por todos los beneficios que Jehová había hecho á David su siervo, y á su pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 1, 'Y COMO Salomón hubo acabado la obra de la casa de Jehová, y la casa real, y todo lo que Salomón quiso hacer,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 2, 'Jehová apareció á Salomón la segunda vez, como le había aparecido en Gabaón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 3, 'Y díjole Jehová: Yo he oído tu oración y tu ruego, que has hecho en mi presencia. Yo he santificado esta casa que tú has edificado, para poner mi nombre en ella para siempre; y en ella estarán mis ojos y mi corazón todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 4, 'Y si tú anduvieres delante de mí, como anduvo David tu padre, en integridad de corazón y en equidad, haciendo todas las cosas que yo te he mandado, y guardando mis estatutos y mis derechos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 5, 'Yo afirmaré el trono de tu reino sobre Israel para siempre, como hablé á David tu padre, diciendo: No faltará de ti varón en el trono de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 6, 'Mas si obstinadamente os apartareis de mí vosotros y vuestros hijos, y no guardareis mis mandamientos y mis estatutos que yo he puesto delante de vosotros, sino que fuereis y sirviereis á dioses ajenos, y los adorareis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 7, 'Yo cortaré á Israel de sobre la haz de la tierra que les he entregado; y esta casa que he santificado á mi nombre, yo la echaré de delante de mí, é Israel será por proverbio y fábula á todos los pueblos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 8, 'Y esta casa que estaba en estima, cualquiera que pasare por ella se pasmará, y silbará, y dirá: ¿Por qué ha hecho así Jehová á esta tierra, y á esta casa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 9, 'Y dirán: Por cuanto dejaron á Jehová su Dios, que había sacado á sus padres de tierra de Egipto, y echaron mano á dioses ajenos, y los adoraron, y los sirvieron: por eso ha traído Jehová sobre ellos todo aqueste mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 10, 'Y aconteció al cabo de veinte años, en que Salomón había edificado las dos casas, la casa de Jehová y la casa real,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 11, '(Para las cuales Hiram rey de Tiro, había traído á Salomón madera de cedro y de haya, y cuanto oro él quiso), que el rey Salomón dió á Hiram veinte ciudades en tierra de Galilea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 12, 'Y salió Hiram de Tiro para ver las ciudades que Salomón le había dado, y no le contentaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 13, 'Y dijo: ¿Qué ciudades son estas que me has dado, hermano? Y púsoles por nombre, la tierra de Cabul, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 14, 'Y había Hiram enviado al rey ciento y veinte talentos de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 15, 'Y esta es la razón del tributo que el rey Salomón impuso para edificar la casa de Jehová, y su casa, y á Millo, y el muro de Jerusalem, y á Hasor, y Megiddo, y Gezer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 16, 'Faraón el rey de Egipto había subido y tomado á Gezer, y quemádola, y había muerto los Cananeos que habitaban la ciudad, y dádola en don á su hija la mujer de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 17, 'Restauró pues Salomón á Gezer, y á la baja Beth-oron,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 18, 'Y á Baalath, y á Tadmor en tierra del desierto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 19, 'Asimismo todas las ciudades donde Salomón tenía municiones, y las ciudades de los carros, y las ciudades de la gente de á caballo, y todo lo que Salomón deseó edificar en Jerusalem, en el Líbano, y en toda la tierra de su señorío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 20, 'A todos los pueblos que quedaron de los Amorrheos, Hetheos, Pherezeos, Heveos, Jebuseos, que no fueron de los hijos de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 21, 'A sus hijos que quedaron en la tierra después de ellos, que los hijos de Israel no pudieron acabar, hizo Salomón que sirviesen con tributo hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 22, 'Mas á ninguno de los hijos de Israel impuso Salomón servicio, sino que eran hombres de guerra, ó sus criados, ó sus príncipes, ó sus capitanes, ó comandantes de sus carros, ó su gente de á caballo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 23, 'Y los que Salomón había hecho jefes y prepósitos sobre las obras, eran quinientos y cincuenta, los cuales estaban sobre el pueblo que trabajaba en aquella obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 24, 'Y subió la hija de Faraón de la ciudad de David á su casa que Salomón le había edificado: entonces edificó él á Millo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 25, 'Y ofrecía Salomón tres veces cada un año holocaustos y pacíficos sobre el altar que él edificó á Jehová, y quemaba perfumes sobre el que estaba delante de Jehová, después que la casa fué acabada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 26, 'Hizo también el rey Salomón navíos en Ezión-geber, que es junto á Elath en la ribera del mar Bermejo, en la tierra de Edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 27, 'Y envió Hiram en ellos á sus siervos, marineros y diestros en la mar, con los siervos de Salomón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 9, 28, 'Los cuales fueron á Ophir, y tomaron de allí oro, cuatrocientos y veinte talentos, y trajéronlo al rey Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 1, 'Y OYENDO la reina de Seba la fama de Salomón en el nombre de Jehová, vino á probarle con preguntas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 2, 'Y vino á Jerusalem con muy grande comitiva, con camellos cargados de especias, y oro en grande abundancia, y piedras preciosas: y como vino á Salomón, propúsole todo lo que en su corazón tenía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 3, 'Y Salomón le declaró todas sus palabras: ninguna cosa se le escondió al rey, que no le declarase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 4, 'Y cuando la reina de Seba vió toda la sabiduría de Salomón, y la casa que había edificado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 5, 'Asimismo la comida de su mesa, el asiento de sus siervos, el estado y vestidos de los que le servían, sus maestresalas, y sus holocaustos que sacrificaba en la casa de Jehová, quedóse enajenada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 6, 'Y dijo al rey: Verdad es lo que oí en mi tierra de tus cosas y de tu sabiduría;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 7, 'Mas yo no lo creía, hasta que he venido, y mis ojos han visto, que ni aun la mitad fué lo que se me dijo: es mayor tu sabiduría y bien que la fama que yo había oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 8, 'Bienaventurados tus varones, dichosos estos tus siervos, que están continuamente delante de ti, y oyen tu sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 9, 'Jehová tu Dios sea bendito, que se agradó de ti para ponerte en el trono de Israel; porque Jehová ha amado siempre á Israel, y te ha puesto por rey, para que hagas derecho y justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 10, 'Y dió ella al rey ciento y veinte talentos de oro, y muy mucha especiería, y piedras preciosas: nunca vino tan grande copia de especias, como la reina de Seba dió al rey Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 11, 'La flota de Hiram que había traído el oro de Ophir, traía también de Ophir muy mucha madera de brasil, y piedras preciosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 12, 'Y de la madera de brasil hizo el rey balaustres para la casa de Jehová, y para las casas reales, arpas también y salterios para los cantores: nunca vino tanta madera de brasil, ni se ha visto hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 13, 'Y el rey Salomón dió á la reina de Seba todo lo que quiso, y todo lo que pidió, además de lo que Salomón le dió como de mano del rey Salomón. Y ella se volvió, y se fué á su tierra con sus criados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 14, 'El peso del oro que Salomón tenía de renta cada un año, era seiscientos sesenta y seis talentos de oro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 15, 'Sin lo de los mercaderes, y de la contratación de especias, y de todos los reyes de Arabia, y de los principales de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 16, 'Hizo también el rey Salomón doscientos paveses de oro extendido: seiscientos siclos de oro gastó en cada pavés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 17, 'Asimismo trescientos escudos de oro extendido, en cada uno de los cuales gastó tres libras de oro: y púsolos el rey en la casa del bosque del Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 18, 'Hizo también el rey un gran trono de marfil, el cual cubrió de oro purísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 19, 'Seis gradas tenía el trono, y lo alto de él era redondo por el respaldo: y de la una parte y de la otra tenía apoyos cerca del asiento, junto á los cuales estaban colocados dos leones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 20, 'Estaban también doce leones puestos allí sobre las seis gradas, de la una parte y de la otra: en ningún otro reino se había hecho trono semejante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 21, 'Y todos los vasos de beber del rey Salomón eran de oro, y asimismo toda la vajilla de la casa del bosque del Líbano era de oro fino: no había plata; en tiempo de Salomón no era de estima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 22, 'Porque el rey tenía la flota que salía á la mar, á Tharsis, con la flota de Hiram: una vez en cada tres años venía la flota de Tharsis, y traía oro, plata, marfil, simios y pavos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 23, 'Así excedía el rey Salomón á todos los reyes de la tierra en riquezas y en sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 24, 'Toda la tierra procuraba ver la cara de Salomón, para oir su sabiduría, la cual Dios había puesto en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 25, 'Y todos le llevaban cada año sus presentes: vasos de oro, vasos de plata, vestidos, armas, aromas, caballos y acémilas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 26, 'Y juntó Salomón carros y gente de á caballo; y tenía mil cuatrocientos carros, y doce mil jinetes, los cuales puso en las ciudades de los carros, y con el rey en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 27, 'Y puso el rey en Jerusalem plata como piedras, y cedros como los cabrahigos que están por los campos en abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 28, 'Y sacaban caballos y lienzos á Salomón de Egipto: porque la compañía de los mercaderes del rey compraban caballos y lienzos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 10, 29, 'Y venía y salía de Egipto, el carro por seiscientas piezas de plata, y el caballo por ciento y cincuenta; y así los sacaban por mano de ellos, todos los reyes de los Hetheos, y de Siria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 1, 'EMPERO el rey Salomón amó, á más de la hija de Faraón, muchas mujeres extranjeras: á las de Moab, á las de Ammón, á las de Idumea, á las de Sidón, y á las Hetheas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 2, 'Gentes de las cuales Jehová había dicho á los hijos de Israel: No entraréis á ellas, ni ellas entrarán á vosotros; porque ciertamente harán inclinar vuestros corazones tras sus dioses. A éstas pues se juntó Salomón con amor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 3, 'Y tuvo setecientas mujeres reinas, y trescientas concubinas; y sus mujeres torcieron su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 4, 'Y ya que Salomón era viejo, sus mujeres inclinaron su corazón tras dioses ajenos; y su corazón no era perfecto con Jehová su Dios, como el corazón de su padre David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 5, 'Porque Salomón siguió á Astaroth, diosa de los Sidonios, y á Milcom, abominación de los Ammonitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 6, 'E hizo Salomón lo malo en los ojos de Jehová, y no fué cumplidamente tras Jehová como David su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 7, 'Entonces edificó Salomón un alto á Chêmos, abominación de Moab, en el monte que está enfrente de Jerusalem; y á Moloch, abominación de los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 8, 'Y así hizo para todas sus mujeres extranjeras, las cuales quemaban perfumes, y sacrificaban á sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 9, 'Y enojóse Jehová contra Salomón, por cuanto estaba su corazón desviado de Jehová Dios de Israel, que le había aparecido dos veces,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 10, 'Y le había mandado acerca de esto, que no siguiese dioses ajenos: mas él no guardó lo que le mandó Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 11, 'Y dijo Jehová á Salomón: Por cuanto ha habido esto en ti, y no has guardado mi pacto y mis estatutos que yo te mandé, romperé el reino de ti, y lo entregaré á tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 12, 'Empero no lo haré en tus días, por amor de David tu padre: romperélo de la mano de tu hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 13, 'Sin embargo no romperé todo el reino, sino que daré una tribu á tu hijo, por amor de David mi siervo, y por amor de Jerusalem que yo he elegido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 14, 'Y Jehová suscitó un adversario á Salomón, á Adad, Idumeo, de la sangre real, el cual estaba en Edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 15, 'Porque cuando David estaba en Edom, y subió Joab el general del ejército á enterrar los muertos, y mató á todos los varones de Edom,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 16, '(Porque seis meses habitó allí Joab, y todo Israel, hasta que hubo acabado á todo el sexo masculino en Edom;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 17, 'Entonces huyó Adad, y con él algunos varones Idumeos de los siervos de su padre, y fuése á Egipto; era entonces Adad muchacho pequeño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 18, 'Y levantáronse de Madián, y vinieron á Parán; y tomando consigo hombres de Parán, viniéronse á Egipto, á Faraón rey de Egipto, el cual le dió casa, y le señaló alimentos, y aun le dió tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 19, 'Y halló Adad grande gracia delante de Faraón, el cual le dió por mujer á la hermana de su esposa, á la hermana de la reina Thaphnes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 20, 'Y la hermana de Thaphnes le parió á su hijo Genubath, al cual destetó Thaphnes dentro de la casa de Faraón; y estaba Genubath en casa de Faraón entre los hijos de Faraón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 21, 'Y oyendo Adad en Egipto que David había dormido con sus padres, y que era muerto Joab general del ejército, Adad dijo á Faraón: Déjame ir á mi tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 22, 'Y respondióle Faraón: ¿Por qué? ¿qué te falta conmigo, que procuras irte á tu tierra? Y él respondió: Nada; con todo, ruégote que me dejes ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 23, 'Despertóle también Dios por adversario á Rezón, hijo de Eliada, el cual había huído de su amo Adad-ezer, rey de Soba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 24, 'Y había juntado gente contra él, y habíase hecho capitán de una compañía, cuando David deshizo á los de Soba. Después se fueron á Damasco, y habitaron allí é hiciéronle rey en Damasco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 25, 'Y fué adversario á Israel todos los días de Salomón; y fué otro mal con el de Adad, porque aborreció á Israel, y reinó sobre la Siria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 26, 'Asimismo Jeroboam hijo de Nabat, Ephrateo de Sereda, siervo de Salomón, (su madre se llamaba Serva, mujer viuda) alzó su mano contra el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 27, 'Y la causa por qué éste alzó mano contra el rey, fué esta: Salomón edificando á Millo, cerró el portillo de la ciudad de David su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 28, 'Y el varón Jeroboam era valiente y esforzado; y viendo Salomón al mancebo que era hombre activo, encomendóle todo el cargo de la casa de José.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 29, 'Aconteció pues en aquel tiempo, que saliendo Jeroboam de Jerusalem, topóle en el camino el profeta Ahías Silonita; y él estaba cubierto con una capa nueva; y estaban ellos dos solos en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 30, 'Y trabando Ahías de la capa nueva que tenía sobre sí, rompióla en doce pedazos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 31, 'Y dijo á Jeroboam: Toma para ti los diez pedazos; porque así dijo Jehová Dios de Israel: He aquí que yo rompo el reino de la mano de Salomón, y á ti daré diez tribus;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 32, '(Y él tendrá una tribu, por amor de David mi siervo, y por amor de Jerusalem, ciudad que yo he elegido de todas las tribus de Israel:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 33, 'Por cuanto me han dejado, y han adorado á Astharoth diosa de los Sidonios, y á Chêmos dios de Moab, y á Moloch dios de los hijos de Ammón; y no han andado en mis caminos, para hacer lo recto delante de mis ojos, y mis estatutos, y mis derechos, como hizo David su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 34, 'Empero no quitaré nada de su reino de sus manos, sino que lo retendré por caudillo todos los días de su vida, por amor de David mi siervo, al cual yo elegí, y él guardó mis mandamientos y mis estatutos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 35, 'Mas yo quitaré el reino de la mano de su hijo, y darélo á ti, las diez tribus.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 36, 'Y á su hijo daré una tribu, para que mi siervo David tenga lámpara todos los días delante de mí en Jerusalem, ciudad que yo me elegí para poner en ella mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 37, 'Yo pues te tomaré á ti, y tú reinarás en todas las cosas que deseare tu alma, y serás rey sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 38, 'Y será que, si prestares oído á todas las cosas que te mandare, y anduvieres en mis caminos, é hicieres lo recto delante de mis ojos, guardando mis estatutos y mis mandamientos, como hizo David mi siervo, yo seré contigo, y te edificaré casa firme, como la edifiqué á David, y yo te entregaré á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 39, 'Y yo afligiré la simiente de David á causa de esto, mas no para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 40, 'Procuró por tanto Salomón de matar á Jeroboam, pero levantándose Jeroboam, huyó á Egipto, á Sisac rey de Egipto, y estuvo en Egipto hasta la muerte de Salomóm.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 41, 'Lo demás de los hechos de Salomón, y todas las cosas que hizo, y su sabiduría, ¿no están escritas en el libro de los hechos de Salomón?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 42, 'Y los días que Salomón reinó en Jerusalem sobre todo Israel, fueron cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 11, 43, 'Y durmió Salomón con sus padres, y fué sepultado en la ciudad de su padre David: y reinó en su lugar Roboam su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 1, 'Y FUÉ Roboam á Sichêm; porque todo Israel había venido á Sichêm para hacerlo rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 2, 'Y aconteció, que como lo oyó Jeroboam hijo de Nabat, que estaba en Egipto, porque había huído de delante del rey Salomón, y habitaba en Egipto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 3, 'Enviaron y llamáronle. Vino pues Jeroboam y toda la congregación de Israel, y hablaron á Roboam, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 4, 'Tu padre agravó nuestro yugo, mas ahora tú disminuye algo de la dura servidumbre de tu padre, y del yugo pesado que puso sobre nosotros, y te serviremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 5, 'Y él les dijo: Idos, y de aquí á tres días volved á mí. Y el pueblo se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 6, 'Entonces el rey Roboam tomó consejo con los ancianos que habían estado delante de Salomón su padre cuando vivía, y dijo: ¿Cómo aconsejáis vosotros que responda á este pueblo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 7, 'Y ellos le hablaron, diciendo: Si tú fueres hoy siervo de este pueblo, y lo sirvieres, y respondiéndole buenas palabras les hablares, ellos te servirán para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 8, 'Mas él, dejado el consejo de los viejos que ellos le habían dado, tomó consejo con los mancebos que se habían criado con él, y estaban delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 9, 'Y díjoles: ¿Cómo aconsejáis vosotros que respondamos á este pueblo, que me ha hablado, diciendo: Disminuye algo del yugo que tu padre puso sobre nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 10, 'Entonces los mancebos que se habían criado con él, le respondieron, diciendo: Así hablarás á este pueblo que te ha dicho estas palabras: Tu padre agravó nuestro yugo; mas tú disminúyenos algo: así les hablarás: El menor dedo de los míos es más grueso que los lomos de mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 11, 'Ahora pues, mi padre os cargó de pesado yugo, mas yo añadiré á vuestro yugo; mi padre os hirió con azotes, mas yo os heriré con escorpiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 12, 'Y al tercer día vino Jeroboam con todo el pueblo á Roboam; según el rey lo había mandado, diciendo: Volved á mí al tercer día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 13, 'Y el rey respondió al pueblo duramente, dejado el consejo de los ancianos que ellos le habían dado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 14, 'Y hablóles conforme al consejo de los mancebos, diciendo: Mi padre agravó vuestro yugo, pero yo añadiré á vuestro yugo; mi padre os hirió con azotes, mas yo os heriré con escorpiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 15, 'Y no oyó el rey al pueblo; porque era ordenación de Jehová, para confirmar su palabra, que Jehová había hablado por medio de Ahías Silonita á Jeroboam hijo de Nabat.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 16, 'Y cuando todo el pueblo vió que el rey no les había oído, respondióle estas palabras, diciendo: ¿Qué parte tenemos nosotros con David? No tenemos heredad en el hijo de Isaí. ¡Israel, á tus estancias! ¡Provee ahora en tu casa, David! Entonces Israel se fué á sus estancias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 17, 'Mas reinó Roboam sobre los hijos de Israel que moraban en las ciudades de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 18, 'Y el rey Roboam envió á Adoram, que estaba sobre los tributos; pero apedreóle todo Israel, y murió. Entonces el rey Roboam se esforzó á subir en un carro, y huir á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 19, 'Así se apartó Israel de la casa de David hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 20, 'Y aconteció, que oyendo todo Israel que Jeroboam había vuelto, enviaron y llamáronle á la congregación, é hiciéronle rey sobre todo Israel, sin quedar tribu alguna que siguiese la casa de David, sino sólo la tribu de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 21, 'Y como Roboam vino á Jerusalem, juntó toda la casa de Judá y la tribu de Benjamín, ciento y ochenta mil hombres escogidos de guerra, para hacer guerra á la casa de Israel, y reducir el reino á Roboam hijo de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 22, 'Mas fué palabra de Jehová á Semeías varón de Dios, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 23, 'Habla á Roboam hijo de Salomón, rey de Judá, y á toda la casa de Judá y de Benjamín, y á los demás del pueblo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 24, 'Así ha dicho Jehová: No vayáis, ni peleéis contra vuestros hermanos los hijos de Israel; volveos cada uno á su casa; porque este negocio yo lo he hecho. Y ellos oyeron la palabra de Dios, y volviéronse, y fuéronse, conforme á la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 25, 'Y reedificó Jeroboam á Sichêm en el monte de Ephraim, y habitó en ella; y saliendo de allí, reedificó á Penuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 26, 'Y dijo Jeroboam en su corazón: Ahora se volverá el reino á la casa de David,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 27, 'Si este pueblo subiere á sacrificar á la casa de Jehová en Jerusalem: porque el corazón de este pueblo se convertirá á su señor Roboam rey de Judá, y me matarán á mí, y se tornarán á Roboam rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 28, 'Y habido consejo, hizo el rey dos becerros de oro, y dijo al pueblo: Harto habéis subido á Jerusalem: he aquí tus dioses, oh Israel, que te hicieron subir de la tierra de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 29, 'Y puso el uno en Beth-el, y el otro puso en Dan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 30, 'Y esto fué ocasión de pecado; porque el pueblo iba á adorar delante del uno, hasta Dan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 31, 'Hizo también casa de altos, é hizo sacerdotes de la clase del pueblo, que no eran de los hijos de Leví.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 32, 'Entonces instituyó Jeroboam solemnidad en el mes octavo, á los quince del mes, conforme á la solemnidad que se celebraba en Judá; y sacrificó sobre altar. Así hizo en Beth-el, sacrificando á los becerros que había hecho. Ordenó también en Beth-el sacerdotes de los altos que él había fabricado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 12, 33, 'Sacrificó pues sobre el altar que él había hecho en Beth-el, á los quince del mes octavo, el mes que él había inventado de su corazón; é hizo fiesta á los hijos de Israel, y subió al altar para quemar perfumes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 1, 'Y HE aquí que un varón de Dios por palabra de Jehová vino de Judá á Beth-el; y estando Jeroboam al altar para quemar perfumes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 2, 'El clamó contra el altar por palabra de Jehová, y dijo: Altar, altar, así ha dicho Jehová: He aquí que á la casa de David nacerá un hijo, llamado Josías, el cual sacrificará sobre ti á los sacerdotes de los altos que queman sobre ti perfumes; y sobre ti quemarán huesos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 3, 'Y aquel mismo día dió una señal, diciendo: Esta es la señal de que Jehová ha hablado: he aquí que el altar se quebrará, y la ceniza que sobre él está se derramará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 4, 'Y como el rey Jeroboam oyó la palabra del varón de Dios, que había clamado contra el altar de Beth-el, extendiendo su mano desde el altar, dijo: ¡Prendedle! Mas la mano que había extendido contra él, se le secó, que no la pudo tornar á sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 5, 'Y el altar se rompió, y derramóse la ceniza del altar, conforme á la señal que el varón de Dios había dado por palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 6, 'Entonces respondiendo el rey, dijo al varón de Dios: Te pido que ruegues á la faz de Jehová tu Dios, y ora por mí, que mi mano me sea restituída. Y el varón de Dios oró á la faz de Jehová, y la mano del rey se le recuperó y tornóse como antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 7, 'Y el rey dijo al varón de Dios: Ven conmigo á casa, y comerás, y yo te daré un presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 8, 'Mas el varón de Dios dijo al rey: Si me dieses la mitad de tu casa, no iría contigo, ni comería pan ni bebería agua en este lugar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 9, 'Porque así me está mandado por palabra de Jehová, diciendo: No comas pan, ni bebas agua, ni vuelvas por el camino que fueres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 10, 'Fuése pues por otro camino, y no volvió por el camino por donde había venido á Beth-el.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 11, 'Moraba á la sazón en Beth-el un viejo profeta, al cual vino su hijo, y contóle todo lo que el varón de Dios había hecho aquel día en Beth-el: contáronle también á su padre las palabras que había hablado al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 12, 'Y su padre les dijo: ¿Por qué camino fué? Y sus hijos le mostraron el camino por donde se había tornado el varón de Dios, que había venido de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 13, 'Y él dijo á sus hijos: Enalbardadme el asno. Y ellos le enalbardaron el asno, y subió en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 14, 'Y yendo tras el varón de Dios, hallóle que estaba sentado debajo de un alcornoque: y díjole: ¿Eres tú el varón de Dios que viniste de Judá? Y él dijo: Yo soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 15, 'Díjole entonces: Ven conmigo á casa, y come del pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 16, 'Mas él respondió: No podré volver contigo, ni iré contigo; ni tampoco comeré pan ni beberé agua contigo en este lugar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 17, 'Porque por palabra de Dios me ha sido dicho: No comas pan ni bebas agua allí, ni vuelvas por el camino que fueres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 18, 'Y el otro le dijo: Yo también soy profeta como tú, y un ángel me ha hablado por palabra de Jehová, diciendo: Vuélvele contigo á tu casa, para que coma pan y beba agua. Empero mintióle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 19, 'Entonces volvió con él, y comió del pan en su casa, y bebió del agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 20, 'Y aconteció que, estando ellos á la mesa, fué palabra de Jehová al profeta que le había hecho volver;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 21, 'Y clamó al varón de Dios que había venido de Judá, diciendo: Así dijo Jehová: Por cuanto has sido rebelde al dicho de Jehová, y no guardaste el mandamiento que Jehová tu Dios te había prescrito,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 22, 'Sino que volviste, y comiste del pan y bebiste del agua en el lugar donde Jehová te había dicho no comieses pan ni bebieses agua, no entrará tu cuerpo en el sepulcro de tus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 23, 'Y como hubo comido del pan y bebido, el profeta que le había hecho volver le enalbardó un asno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 24, 'Y yéndose, topóle un león en el camino, y matóle; y su cuerpo estaba echado en el camino, y el asno estaba junto á él, y el león también estaba junto al cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 25, 'Y he aquí unos que pasaban, y vieron el cuerpo que estaba echado en el camino, y el león que estaba junto al cuerpo: y vinieron, y dijéronlo en la ciudad donde el viejo profeta habitaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 26, 'Y oyéndolo el profeta que le había vuelto del camino, dijo: El varón de Dios es, que fué rebelde al dicho de Jehová: por tanto Jehová le ha entregado al león, que le ha quebrantado y muerto, conforme á la palabra de Jehová que él le dijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 27, 'Y habló á sus hijos, y díjoles: Enalbardadme un asno. Y ellos se lo enalbardaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 28, 'Y él fué, y halló su cuerpo tendido en el camino, y el asno y el león estaban junto al cuerpo: el león no había comido el cuerpo, ni dañado al asno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 29, 'Y tomando el profeta el cuerpo del varón de Dios, púsolo sobre el asno, y llevóselo. Y el profeta viejo vino á la ciudad, para endecharle y enterrarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 30, 'Y puso su cuerpo en su sepulcro; y endecháronle, diciendo: ¡Ay, hermano mío!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 31, 'Y después que le hubieron enterrado, habló á sus hijos, diciendo: Cuando yo muriere, enterradme en el sepulcro en que está sepultado el varón de Dios; poned mis huesos junto á los suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 32, 'Porque sin duda vendrá lo que él dijo á voces por palabra de Jehová contra el altar que está en Beth-el, y contra todas las casas de los altos que están en las ciudades de Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 33, 'Después de esto no se tornó Jeroboam de su mal camino: antes volvió á hacer sacerdotes de los altos de la clase del pueblo, y quien quería se consagraba, y era de los sacerdotes de los altos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 13, 34, 'Y esto fué causa de pecado á la casa de Jeroboam; por lo cual fué cortada y raída de sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 1, 'EN aquel tiempo Abías hijo de Jeroboam cayó enfermo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 2, 'Y dijo Jeroboam á su mujer: Levántate ahora, disfrázate, porque no te conozcan que eres la mujer de Jeroboam, y ve á Silo; que allá está Ahías profeta, el que me dijo que yo había de ser rey sobre este pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 3, 'Y toma en tu mano diez panes, y turrones, y una botija de miel, y ve á él; que te declare lo que ha de ser de este mozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 4, 'Y la mujer de Jeroboam hízolo así; y levantóse, y fué á Silo, y vino á casa de Ahías. Y no podía ya ver Ahías, que sus ojos se habían oscurecido á causa de su vejez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 5, 'Mas Jehová había dicho á Ahías: He aquí que la mujer de Jeroboam vendrá á consultarte por su hijo, que está enfermo: así y así le has de responder; pues será que cuando ella viniere, vendrá disimulada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 6, 'Y como Ahías oyó el sonido de sus pies cuando entraba por la puerta, dijo: Entra, mujer de Jeroboam; ¿por qué te finges otra? empero yo soy enviado á ti con revelación dura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 7, 'Ve, y di á Jeroboam: Así dijo Jehová Dios de Israel: Por cuanto yo te levanté de en medio del pueblo, y te hice príncipe sobre mi pueblo Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 8, 'Y rompí el reino de la casa de David, y te lo entregué á ti; y tú no has sido como David mi siervo, que guardó mis mandamientos y anduvo en pos de mí con todo su corazón, haciendo solamente lo derecho delante de mis ojos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 9, 'Antes hiciste lo malo sobre todos los que han sido antes de ti: que fuiste y te hiciste dioses ajenos y de fundición para enojarme, y á mí me echaste tras tus espaldas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 10, 'Por tanto, he aquí que yo traigo mal sobre la casa de Jeroboam, y yo talaré de Jeroboam todo meante á la pared, así el guardado como el desamparado en Israel; y barreré la posteridad de la casa de Jeroboam, como es barrido el estiércol, hasta que sea acabada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 11, 'El que muriere de los de Jeroboam en la ciudad, le comerán los perros; y el que muriere en el campo, comerlo han las aves del cielo; porque Jehová lo ha dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 12, 'Y tú levántate, y vete á tu casa; que en entrando tu pie en la ciudad, morirá el mozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 13, 'Y todo Israel lo endechará, y le enterrarán; porque sólo él de los de Jeroboam entrará en sepultura; por cuanto se ha hallado en él alguna cosa buena de Jehová Dios de Israel, en la casa de Jeroboam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 14, 'Y Jehová se levantará un rey sobre Israel, el cual talará la casa de Jeroboam en este día; ¿y qué, si ahora?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 15, 'Y Jehová sacudirá á Israel, al modo que la caña se agita en las aguas: y él arrancará á Israel de esta buena tierra que había dado á sus padres, y esparcirálos de la otra parte del río, por cuanto han hecho sus bosques, enojando á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 16, 'Y él entregará á Israel por los pecados de Jeroboam, el cual pecó, y ha hecho pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 17, 'Entonces la mujer de Jeroboam se levantó, y se fué, y vino á Thirsa: y entrando ella por el umbral de la casa, el mozo murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 18, 'Y enterráronlo, y endechólo todo Israel, conforme á la palabra de Jehová, que él había hablado por mano de su siervo Ahías profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 19, 'Los otros hechos de Jeroboam, qué guerras hizo, y cómo reinó, todo está escrito en el libro de las historias de los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 20, 'El tiempo que reinó Jeroboam fueron veintidós años; y habiendo dormido con sus padres, reinó en su lugar Nadab su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 21, 'Y Roboam hijo de Salomón reinó en Judá. De cuarenta y un años era Roboam cuando comenzó á reinar, y diecisiete años reinó en Jerusalem, ciudad que Jehová eligió de todas las tribus de Israel para poner allí su nombre. El nombre de su madre fué Naama, Ammonita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 22, 'Y Judá hizo lo malo en los ojos de Jehová, y enojáronle más que todo lo que sus padres habían hecho en sus pecados que cometieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 23, 'Porque ellos también se edificaron altos, estatuas, y bosques, en todo collado alto, y debajo de todo árbol frondoso:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 24, 'Y hubo también sodomitas en la tierra, é hicieron conforme á todas las abominaciones de las gentes que Jehová había echado delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 25, 'Al quinto año del rey Roboam subió Sisac rey de Egipto contra Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 26, 'Y tomó los tesoros de la casa de Jehová, y los tesoros de la casa real, y saqueólo todo: llevóse también todos los escudos de oro que Salomón había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 27, 'Y en lugar de ellos hizo el rey Roboam escudos de metal, y diólos en manos de los capitanes de los de la guardia, quienes custodiaban la puerta de la casa real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 28, 'Y cuando el rey entraba en la casa de Jehová, los de la guardia los llevaban; y poníanlos después en la cámara de los de la guardia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 29, 'Lo demás de los hechos de Roboam, y todas las cosas que hizo, ¿no están escritas en las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 30, 'Y hubo guerra entre Roboam y Jeroboam todos los días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 14, 31, 'Y durmió Roboam con sus padres, y fué sepultado con sus padres en la ciudad de David. El nombre de su madre fué Naama, Ammonita. Y reinó en su lugar Abiam su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 1, 'EN el año dieciocho del rey Jeroboam hijo de Nabat, Abiam comenzó á reinar sobre Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 2, 'Reinó tres años en Jerusalem. El nombre de su madre fué Maachâ, hija de Abisalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 3, 'Y anduvo en todos los pecados de su padre, que había éste hecho antes de él; y no fué su corazón perfecto con Jehová su Dios, como el corazón de David su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 4, 'Mas por amor de David, dióle Jehová su Dios lámpara en Jerusalem, levantándole á su hijo después de él, y sosteniendo á Jerusalem:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 5, 'Por cuanto David había hecho lo recto ante los ojos de Jehová, y de ninguna cosa que le mandase se había apartado en todos los días de su vida, excepto el negocio de Uría Hetheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 6, 'Y hubo guerra entre Roboam y Jeroboam todos los días de su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 7, 'Lo demás de los hechos de Abiam, y todas las cosas que hizo, ¿no están escritas en el libro de las crónicas de los reyes de Judá? Y hubo guerra entre Abiam y Jeroboam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 8, 'Y durmió Abiam con sus padres, y sepultáronlo en la ciudad de David: y reinó Asa su hijo en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 9, 'En el año veinte de Jeroboam rey de Israel, Asa comenzó á reinar sobre Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 10, 'Y reinó cuarenta y un años en Jerusalem; el nombre de su madre fué Maachâ, hija de Abisalom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 11, 'Y Asa hizo lo recto ante los ojos de Jehová, como David su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 12, 'Porque quitó los sodomitas de la tierra, y quitó todas las suciedades que sus padres habían hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 13, 'Y también privó á su madre Maachâ de ser princesa, porque había hecho un ídolo en un bosque. Además deshizo Asa el ídolo de su madre, y quemólo junto al torrente de Cedrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 14, 'Empero los altos no se quitaron: con todo, el corazón de Asa fué perfecto para con Jehová toda su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 15, 'También metió en la casa de Jehová lo que su padre había dedicado, y lo que él dedicó: oro, y plata, y vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 16, 'Y hubo guerra entre Asa y Baasa rey de Israel, todo el tiempo de ambos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 17, 'Y subió Baasa rey de Israel contra Judá, y edificó á Rama, para no dejar salir ni entrar á ninguno de Asa, rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 18, 'Entonces tomando Asa toda la plata y oro que había quedado en los tesoros de la casa de Jehová, y los tesoros de la casa real, entrególos en las manos de sus siervos, y enviólos el rey Asa á Ben-adad, hijo de Tabrimón, hijo de Hezión, rey de Siria, el cual residía en Damasco, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 19, 'Alianza hay entre mí y ti, y entre mi padre y el tuyo: he aquí yo te envío un presente de plata y oro: ve, y rompe tu alianza con Baasa rey de Israel, para que me deje.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 20, 'Y Ben-adad consintió con el rey Asa, y envió los príncipes de los ejércitos que tenía contra las ciudades de Israel, é hirió á Ahión, y á Dan, y á Abel-beth-maachâ, y á toda Cinneroth, con toda la tierra de Nephtalí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 21, 'Y oyendo esto Baasa, dejó de edificar á Rama, y estúvose en Thirsa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 22, 'Entonces el rey Asa convocó á todo Judá, sin exceptuar ninguno; y quitaron de Rama la piedra y la madera con que Baasa edificaba, y edificó el rey Asa con ello á Gabaa de Benjamín, y á Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 23, 'Lo demás de todos los hechos de Asa, y toda su fortaleza, y todas las cosas que hizo, y las ciudades que edificó, ¿no está todo escrito en el libro de las crónicas de los reyes de Judá? Mas en el tiempo de su vejez enfermó de sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 24, 'Y durmió Asa con sus padres, y fué sepultado con sus padres en la ciudad de David su padre: y reinó en su lugar Josaphat su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 25, 'Y Nadab, hijo de Jeroboam, comenzó á reinar sobre Israel en el segundo año de Asa rey de Judá; y reinó sobre Israel dos años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 26, 'E hizo lo malo ante los ojos de Jehová, andando en el camino de su padre, y en sus pecados con que hizo pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 27, 'Y Baasa hijo de Ahía, el cual era de la casa de Issachâr, hizo conspiración contra él: é hiriólo Baasa en Gibbethón, que era de los Filisteos: porque Nadab y todo Israel tenían cercado á Gibbethón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 28, 'Matólo pues Baasa en el tercer año de Asa rey de Judá, y reinó en lugar suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 29, 'Y como él vino al reino, hirió toda la casa de Jeroboam, sin dejar alma viviente de los de Jeroboam, hasta raerlo, conforme á la palabra de Jehová que él habló por su siervo Ahías Silonita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 30, 'Por los pecados de Jeroboam que él había cometido, y con los cuales hizo pecar á Israel; y por su provocación con que provocó á enojo á Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 31, 'Lo demás de los hechos de Nadab, y todas las cosas que hizo, ¿no está todo escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 32, 'Y hubo guerra entre Asa y Baasa rey de Israel, todo el tiempo de ambos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 33, 'En el tercer año de Asa rey de Judá, comenzó á reinar Baasa hijo de Ahía sobre todo Israel en Thirsa; y reinó veinticuatro años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 15, 34, 'E hizo lo malo á los ojos de Jehová, y anduvo en el camino de Jeroboam, y en su pecado con que hizo pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 1, 'Y FUÉ palabra de Jehová á Jehú hijo de Hanani contra Baasa, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 2, 'Pues que yo te levanté del polvo, y te puse por príncipe sobre mi pueblo Israel, y tú has andado en el camino de Jeroboam, y has hecho pecar á mi pueblo Israel, provocándome á ira con sus pecados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 3, 'He aquí yo barreré la posteridad de Baasa, y la posteridad de su casa: y pondré tu casa como la casa de Jeroboam hijo de Nabat.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 4, 'El que de Baasa fuere muerto en la ciudad, le comerán los perros; y el que de él fuere muerto en el campo, comerlo han las aves del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 5, 'Lo demás de los hechos de Baasa, y las cosas que hizo, y su fortaleza, ¿no está todo escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 6, 'Y durmió Baasa con sus padres, y fué sepultado en Thirsa; y reinó en su lugar Ela su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 7, 'Empero la palabra de Jehová por mano de Jehú profeta, hijo de Hanani, había sido contra Baasa y también contra su casa, con motivo de todo lo malo que hizo á los ojos de Jehová, provocándole á ira con las obras de sus manos, para que fuese hecha como la casa de Jeroboam; y porque lo había herido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 8, 'En el año veintiséis de Asa rey de Judá, comenzó á reinar Ela hijo de Baasa sobre Israel en Thirsa; y reinó dos años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 9, 'E hizo conjuración contra él su siervo Zimri, comandante de la mitad de los carros. Y estando él en Thirsa, bebiendo y embriagado en casa de Arsa su mayordomo en Thirsa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 10, 'Vino Zimri, y lo hirió y mató, en el año veintisiete de Asa rey de Judá; y reinó en lugar suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 11, 'Y luego que llegó á reinar y estuvo sentado en su trono, hirió toda la casa de Baasa, sin dejar en ella meante á la pared, ni sus parientes ni amigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 12, 'Así rayó Zimri toda la casa de Baasa, conforme á la palabra de Jehová, que había proferido contra Baasa por medio del profeta Jehú;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 13, 'Por todos los pecados de Baasa, y los pecados de Ela su hijo, con que ellos pecaron é hicieron pecar á Israel, provocando á enojo á Jehová Dios de Israel con sus vanidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 14, 'Los demás hechos de Ela, y todas las cosas que hizo, ¿no está todo escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 15, 'En el año veintisiete de Asa rey de Judá, comenzó á reinar Zimri, y reinó siete días en Thirsa; y el pueblo había asentado campo sobre Gibbethón, ciudad de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 16, 'Y el pueblo que estaba en el campo oyó decir: Zimri ha hecho conjuración, y ha muerto al rey. Entonces todo Israel levantó el mismo día por rey sobre Israel á Omri, general del ejército, en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 17, 'Y subió Omri de Gibbethón, y con él todo Israel, y cercaron á Thirsa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 18, 'Mas viendo Zimri tomada la ciudad, metióse en el palacio de la casa real, y pegó fuego á la casa consigo: así murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 19, 'Por sus pecados que él había cometido, haciendo lo malo á los ojos de Jehová, y andando en los caminos de Jeroboam, y en su pecado que cometió, haciendo pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 20, 'Los demás hechos de Zimri, y su conspiración que formó, ¿no está todo escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 21, 'Entonces el pueblo de Israel fué dividido en dos partes: la mitad del pueblo seguía á Thibni hijo de Gineth, para hacerlo rey: y la otra mitad seguía á Omri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 22, 'Mas el pueblo que seguía á Omri, pudo más que el que seguía á Thibni hijo de Gineth; y Thibni murió, y Omri fué rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 23, 'En el año treinta y uno de Asa rey de Judá, comenzó á reinar Omri sobre Israel, y reinó doce años: en Thirsa reinó seis años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 24, 'Y compró él de Semer el monte de Samaria por dos talentos de plata, y edificó en el monte: y llamó el nombre de la ciudad que edificó, Samaria, del nombre de Semer, señor que fué de aquel monte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 25, 'Y Omri hizo lo malo á los ojos de Jehová, é hizo peor que todos los que habían sido antes de él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 26, 'Pues anduvo en todos los caminos de Jeroboam hijo de Nabat, y en su pecado con que hizo pecar á Israel, provocando á ira á Jehová Dios de Israel con sus ídolos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 27, 'Lo demás de los hechos de Omri, y todas las cosas que hizo, y sus valentías que ejecutó, ¿no está todo escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 28, 'Y Omri durmió con sus padres, y fué sepultado en Samaria; y reinó en lugar suyo Achâb, su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 29, 'Y comenzó á reinar Achâb hijo de Omri sobre Israel el año treinta y ocho de Asa rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 30, 'Y reinó Achâb hijo de Omri sobre Israel en Samaria veintidós años. Y Achâb hijo de Omri hizo lo malo á los ojos de Jehová sobre todos los que fueron antes de él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 31, 'Porque le fué ligera cosa andar en los pecados de Jeroboam hijo de Nabat, y tomó por mujer á Jezabel hija de Ethbaal rey de los Sidonios, y fué y sirvió á Baal, y lo adoró.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 32, 'E hizo altar á Baal, en el templo de Baal que él edificó en Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 33, 'Hizo también Achâb un bosque; y añadió Achâb haciendo provocar á ira á Jehová Dios de Israel, más que todos los reyes de Israel que antes de él habían sido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 16, 34, 'En su tiempo Hiel de Beth-el reedificó á Jericó. En Abiram su primogénito echó el cimiento, y en Segub su hijo postrero puso sus puertas; conforme á la palabra de Jehová que había hablado por Josué hijo de Nun.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 1, 'ENTONCES Elías Thisbita, que era de los moradores de Galaad, dijo á Achâb: Vive Jehová Dios de Israel, delante del cual estoy, que no habrá lluvia ni rocío en estos años, sino por mi palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 2, 'Y fué á él palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 3, 'Apártate de aquí, y vuélvete al oriente, y escóndete en el arroyo de Cherith, que está delante del Jordán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 4, 'Y beberás del arroyo; y yo he mandado á los cuervos que te den allí de comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 5, 'Y él fué, é hizo conforme á la palabra de Jehová; pues se fué y asentó junto al arroyo de Cherith, que está antes del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 6, 'Y los cuervos le traían pan y carne por la mañana, y pan y carne á la tarde; y bebía del arroyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 7, 'Pasados algunos días, secóse el arroyo; porque no había llovido sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 8, 'Y fué á él palabra de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 9, 'Levántate, vete á Sarepta de Sidón, y allí morarás: he aquí yo he mandado allí á una mujer viuda que te sustente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 10, 'Entonces él se levantó, y se fué á Sarepta. Y como llegó á la puerta de la ciudad, he aquí una mujer viuda que estaba allí cogiendo serojas; y él la llamó, y díjole: Ruégote que me traigas una poca de agua en un vaso, para que beba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 11, 'Y yendo ella para traérsela, él la volvió á llamar, y díjole: Ruégote que me traigas también un bocado de pan en tu mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 12, 'Y ella respondió: Vive Jehová Dios tuyo, que no tengo pan cocido; que solamente un puñado de harina tengo en la tinaja, y un poco de aceite en una botija: y ahora cogía dos serojas, para entrarme y aderezarlo para mí y para mi hijo, y que lo comamos, y nos muramos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 13, 'Y Elías le dijo: No hayas temor; ve, haz como has dicho: empero hazme á mí primero de ello una pequeña torta cocida debajo de la ceniza, y tráemela; y después harás para ti y para tu hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 14, 'Porque Jehová Dios de Israel ha dicho así: La tinaja de la harina no escaseará, ni se disminuirá la botija del aceite, hasta aquel día que Jehová dará lluvia sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 15, 'Entonces ella fué, é hizo como le dijo Elías; y comió él, y ella y su casa, muchos días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 16, 'Y la tinaja de la harina no escaseó, ni menguó la botija del aceite, conforme á la palabra de Jehová que había dicho por Elías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 17, 'Después de estas cosas aconteció que cayó enfermo el hijo del ama de la casa, y la enfermedad fué tan grave, que no quedó en él resuello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 18, 'Y ella dijo á Elías: ¿Qué tengo yo contigo, varón de Dios? ¿has venido á mí para traer en memoria mis iniquidades, y para hacerme morir mi hijo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 19, 'Y él le dijo: Dame acá tu hijo. Entonces él lo tomó de su regazo, y llevólo á la cámara donde él estaba, y púsole sobre su cama;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 20, 'Y clamando á Jehová, dijo: Jehová Dios mío, ¿aun á la viuda en cuya casa yo estoy hospedado has afligido, matándole su hijo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 21, 'Y midióse sobre el niño tres veces, y clamó á Jehová, y dijo: Jehová Dios mío, ruégote que vuelva el alma de este niño á sus entrañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 22, 'Y Jehová oyó la voz de Elías, y el alma del niño volvió á sus entrañas, y revivió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 23, 'Tomando luego Elías al niño, trájolo de la cámara á la casa, y diólo á su madre, y díjole Elías: Mira, tu hijo vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 17, 24, 'Entonces la mujer dijo á Elías: Ahora conozco que tú eres varón de Dios, y que la palabra de Jehová es verdad en tu boca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 1, 'PASADOS muchos días, fué palabra de Jehová á Elías en el tercer año, diciendo: Ve, muéstrate á Achâb, y yo daré lluvia sobre la haz de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 2, 'Fué pues Elías á mostrarse á Achâb. Había á la sazón grande hambre en Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 3, 'Y Achâb llamó á Abdías su mayordomo, el cual Abdías era en grande manera temeroso de Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 4, 'Porque cuando Jezabel destruía á los profetas de Jehová, Abdías tomó cien profetas, los cuales escondió de cincuenta en cincuenta por cuevas, y sustentólos á pan y agua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 5, 'Y dijo Achâb á Abdías: Ve por el país á todas las fuentes de aguas, y á todos los arroyos; que acaso hallaremos grama con que conservemos la vida á los caballos y á las acémilas, para que no nos quedemos sin bestias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 6, 'Y partieron entre sí el país para recorrerlo: Achâb fué de por sí por un camino, y Abdías fué separadamente por otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 7, 'Y yendo Abdías por el camino, topóse con Elías; y como le conoció, postróse sobre su rostro, y dijo: ¿No eres tú mi señor Elías?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 8, 'Y él respondió: Yo soy; ve, di á tu amo: He aquí Elías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 9, 'Pero él dijo: ¿En qué he pecado, para que tú entregues tu siervo en mano de Achâb para que me mate?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 10, 'Vive Jehová tu Dios, que no ha habido nación ni reino donde mi señor no haya enviado á buscarte; y respondiendo ellos: No está aquí, él ha conjurado á reinos y naciones si no te han hallado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 11, '¿Y ahora tú dices: Ve, di á tu amo: Aquí está Elías?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 12, 'Y acontecerá que, luego que yo me haya partido de ti, el espíritu de Jehová te llevará donde yo no sepa; y viniendo yo, y dando las nuevas á Achâb, y no hallándote él, me matará; y tu siervo teme á Jehová desde su mocedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 13, '¿No ha sido dicho á mi señor lo que hice, cuando Jezabel mataba á los profetas de Jehová que escondí cien: varones de los profetas de Jehová: que escondí cien varones de los profetas de Jehová de cincuenta en cincuenta en cuevas, y los mantuve á pan y agua?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 14, '¿Y ahora dices tú: Ve, di á tu amo: Aquí está Elías: para que él me mate?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 15, 'Y díjole Elías: Vive Jehová de los ejércitos, delante del cual estoy, que hoy me mostraré á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 16, 'Entonces Abdías fué á encontrarse con Achâb, y dióle el aviso; y Achâb vino á encontrarse con Elías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 17, 'Y como Achâb vió á Elías, díjole Achâb: ¿Eres tú el que alborotas á Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 18, 'Y él respondió: Yo no he alborotado á Israel, sino tú y la casa de tu padre, dejando los mandamientos de Jehová, y siguiendo á los Baales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 19, 'Envía pues ahora y júntame á todo Israel en el monte de Carmelo, y los cuatrocientos y cincuenta profetas de Baal, y los cuatrocientos profetas de los bosques, que comen de la mesa de Jezabel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 20, 'Entonces Achâb envió á todos los hijos de Israel, y juntó los profetas en el monte de Carmelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 21, 'Y acercándose Elías á todo el pueblo, dijo: ¿Hasta cuándo claudicaréis vosotros entre dos pensamientos? Si Jehová es Dios, seguidle; y si Baal, id en pos de él. Y el pueblo no respondió palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 22, 'Y Elías tornó á decir al pueblo: Sólo yo he quedado profeta de Jehová; mas de los profetas de Baal hay cuatrocientos y cincuenta hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 23, 'Dénsenos pues dos bueyes, y escójanse ellos el uno, y córtenlo en pedazos, y pónganlo sobre leña, mas no pongan fuego debajo; y yo aprestaré el otro buey, y pondrélo sobre leña, y ningún fuego pondré debajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 24, 'Invocad luego vosotros en el nombre de vuestros dioses, y yo invocaré en el nombre de Jehová: y el Dios que respondiere por fuego, ése sea Dios. Y todo el pueblo respondió, diciendo: Bien dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 25, 'Entonces Elías dijo á los profetas de Baal: Escogeos el un buey, y haced primero, pues que vosotros sois los más: é invocad en el nombre de vuestros dioses, mas no pongáis fuego debajo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 26, 'Y ellos tomaron el buey que les fué dado, y aprestáronlo, é invocaron en el nombre de Baal desde la mañana hasta el medio día, diciendo: ¡Baal, respóndenos! Mas no había voz, ni quien respondiese; entre tanto, ellos andaban saltando cerca del altar que habían hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 27, 'Y aconteció al medio día, que Elías se burlaba de ellos, diciendo: Gritad en alta voz, que dios es: quizá está conversando, ó tiene algún empeño, ó va de camino; acaso duerme, y despertará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 28, 'Y ellos clamaban á grandes voces, y sajábanse con cuchillos y con lancetas conforme á su costumbre, hasta chorrear la sangre sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 29, 'Y como pasó el medio día, y ellos profetizaran hasta el tiempo del sacrificio del presente, y no había voz, ni quien respondiese ni escuchase;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 30, 'Elías dijo entonces á todo el pueblo: Acercaos á mí. Y todo el pueblo se llegó á él: y él reparó el altar de Jehová que estaba arruinado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 31, 'Y tomando Elías doce piedras, conforme al número de las tribus de los hijos de Jacob, al cual había sido palabra de Jehová, diciendo: Israel será tu nombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 32, 'Edificó con las piedras un altar en el nombre de Jehová: después hizo una reguera alrededor del altar, cuanto cupieran dos satos de simiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 33, 'Compuso luego la leña, y cortó el buey en pedazos, y púsolo sobre la leña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 34, 'Y dijo: Henchid cuatro cántaros de agua, y derramadla sobre el holocausto y sobre la leña. Y dijo: Hacedlo otra vez; y otra vez lo hicieron. Dijo aún: Hacedlo la tercera vez; é hiciéronlo la tercera vez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 35, 'De manera que las aguas corrían alrededor del altar; y había también henchido de agua la reguera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 36, 'Y como llegó la hora de ofrecerse el holocausto, llegóse el profeta Elías, y dijo: Jehová Dios de Abraham, de Isaac, y de Israel, sea hoy manifiesto que tú eres Dios en Israel, y que yo soy tu siervo, y que por mandato tuyo he hecho todas estas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 37, 'Respóndeme, Jehová, respóndeme; para que conozca este pueblo que tú, oh Jehová, eres el Dios, y que tú volviste atrás el corazón de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 38, 'Entonces cayó fuego de Jehová, el cual consumió el holocausto, y la leña, y las piedras, y el polvo, y aun lamió las aguas que estaban en la reguera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 39, 'Y viéndolo todo el pueblo, cayeron sobre sus rostros, y dijeron: ¡Jehová es el Dios! ¡Jehová es el Dios!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 40, 'Y díjoles Elías: Prended á los profetas de Baal, que no escape ninguno. Y ellos los prendieron; y llevólos Elías al arroyo de Cisón, y allí los degolló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 41, 'Y entonces Elías dijo á Achâb: Sube, come y bebe; porque una grande lluvia suena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 42, 'Y Achâb subió á comer y á beber. Y Elías subió á la cumbre del Carmelo; y postrándose en tierra, puso su rostro entre las rodillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 43, 'Y dijo á su criado: Sube ahora, y mira hacia la mar. Y él subió, y miró, y dijo: No hay nada. Y él le volvió á decir: Vuelve siete veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 44, 'Y á la séptima vez dijo: Yo veo una pequeña nube como la palma de la mano de un hombre, que sube de la mar. Y él dijo: Ve, y di á Achâb: Unce y desciende, porque la lluvia no te ataje.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 45, 'Y aconteció, estando en esto, que los cielos se oscurecieron con nubes y viento; y hubo una gran lluvia. Y subiendo Achâb, vino á Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 18, 46, 'Y la mano de Jehová fué sobre Elías, el cual ciñó sus lomos, y vino corriendo delante de Achâb hasta llegar á Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 1, 'Y Achâb dió la nueva á Jezabel de todo lo que Elías había hecho, de como había muerto á cuchillo á todos los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 2, 'Entonces envió Jezabel á Elías un mensajero, diciendo: Así me hagan los dioses, y así me añadan, si mañana á estas horas yo no haya puesto tu persona como la de uno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 3, 'Viendo pues el peligro, levantóse y fuése por salvar su vida, y vino á Beer-seba, que es en Judá, y dejó allí su criado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 4, 'Y él se fué por el desierto un día de camino, y vino y sentóse debajo de un enebro; y deseando morirse, dijo: Baste ya, oh Jehová, quita mi alma; que no soy yo mejor que mis padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 5, 'Y echándose debajo del enebro, quedóse dormido: y he aquí luego un ángel que le tocó, y le dijo: Levántate, come.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 6, 'Entonces él miró, y he aquí á su cabecera una torta cocida sobre las ascuas, y un vaso de agua: y comió y bebió y volvióse á dormir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 7, 'Y volviendo el ángel de Jehová la segunda vez, tocóle, diciendo: Levántate, come: porque gran camino te resta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 8, 'Levantóse pues, y comió y bebió; y caminó con la fortaleza de aquella comida cuarenta días y cuarenta noches, hasta el monte de Dios, Horeb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 9, 'Y allí se metió en una cueva, donde tuvo la noche. Y fué á él palabra de Jehová, el cual le dijo: ¿Qué haces aquí, Elías?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 10, 'Y él respondió: Sentido he un vivo celo por Jehová Dios de los ejércitos; porque los hijos de Israel han dejado tu alianza, han derribado tus altares, y han muerto á cuchillo tus profetas: y yo solo he quedado, y me buscan para quitarme la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 11, 'Y él le dijo: Sal fuera, y ponte en el monte delante de Jehová. Y he aquí Jehová que pasaba, y un grande y poderoso viento que rompía los montes, y quebraba las peñas delante de Jehová: mas Jehová no estaba en el viento. Y tras el viento un terremoto: mas Jehová no estaba en el terremoto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 12, 'Y tras el terremoto un fuego: mas Jehová no estaba en el fuego. Y tras el fuego un silvo apacible y delicado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 13, 'Y cuando lo oyó Elías, cubrió su rostro con su manto, y salió, y paróse á la puerta de la cueva. Y he aquí llegó una voz á él, diciendo: ¿Qué haces aquí, Elías?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 14, 'Y él respondió: Sentido he un vivo celo por Jehová Dios de los ejércitos; porque los hijos de Israel han dejado tu alianza, han derribado tus altares, y han muerto á cuchillo tus profetas: y yo solo he quedado, y me buscan para quitarme la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 15, 'Y díjole Jehová: Ve, vuélvete por tu camino, por el desierto de Damasco: y llegarás, y ungirás á Hazael por rey de Siria;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 16, 'Y á Jehú hijo de Nimsi, ungirás por rey sobre Israel; y á Eliseo hijo de Saphat, de Abel-mehula, ungirás para que sea profeta en lugar de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 17, 'Y será, que el que escapare del cuchillo, de Hazael, Jehú lo matará; y el que escapare del cuchillo de Jehú, Eliseo lo matará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 18, 'Y yo haré que queden en Israel siete mil; todas rodillas que no se encorvaron á Baal, y bocas todas que no lo besaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 19, 'Y partiéndose él de allí, halló á Eliseo hijo de Saphat, que araba con doce yuntas delante de sí; y él era uno de los doce gañanes. Y pasando Elías por delante de él, echó sobre él su manto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 20, 'Entonces dejando él los bueyes, vino corriendo en pos de Elías, y dijo: Ruégote que me dejes besar mi padre y mi madre, y luego te seguiré. Y él le dijo: Ve, vuelve: ¿qué te he hecho yo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 19, 21, 'Y volvióse de en pos de él, y tomó un par de bueyes, y matólos, y con el arado de los bueyes coció la carne de ellos, y dióla al pueblo que comiesen. Después se levantó, y fué tras Elías, y servíale.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 1, 'ENTONCES Ben-adad rey de Siria juntó á todo su ejército, y con él treinta y dos reyes, con caballos y carros: y subió, y puso cerco á Samaria, y combatióla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 2, 'Y envió mensajeros á la ciudad á Achâb rey de Israel, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 3, 'Así ha dicho Ben-adad: Tu plata y tu oro es mío, y tus mujeres y tus hijos hermosos son míos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 4, 'Y el rey de Israel respondió, y dijo: Como tú dices, rey señor mío, yo soy tuyo, y todo lo que tengo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 5, 'Y volviendo los mensajeros otra vez, dijeron: Así dijo Ben-adad: Yo te envié á decir: Tu plata y tu oro, y tus mujeres y tus hijos me darás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 6, 'Además mañana á estas horas enviaré yo á ti mis siervos, los cuales escudriñarán tu casa, y las casas de tus siervos; y tomarán con sus manos, y llevarán todo lo precioso que tuvieres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 7, 'Entonces el rey de Israel llamó á todos los ancianos de la tierra, y díjoles: Entended, y ved ahora cómo éste no busca sino mal: pues que ha enviado á mí por mis mujeres y mis hijos, y por mi plata y por mi oro; y yo no se lo he negado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 8, 'Y todos los ancianos y todo el pueblo le respondieron: No le obedezcas, ni hagas lo que te pide.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 9, 'Entonces él respondió á los embajadores de Ben-adad: Decid al rey mi señor: Haré todo lo que mandaste á tu siervo al principio; mas esto no lo puedo hacer. Y los embajadores fueron, y diéronle la respuesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 10, 'Y Ben-adad tornó á enviarle á decir: Así me hagan los dioses, y así me añadan, que el polvo de Samaria no bastará á los puños de todo el pueblo que me sigue.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 11, 'Y el rey de Israel respondió, y dijo: Decidle, que no se alabe el que se ciñe, como el que ya se desciñe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 12, 'Y como él oyó esta palabra, estando bebiendo con los reyes en las tiendas, dijo á sus siervos: Poned. Y ellos pusieron contra la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 13, 'Y he aquí un profeta se llegó á Achâb rey de Israel; y le dijo: Así ha dicho Jehová: ¿Has visto esta grande multitud? he aquí yo te la entregaré hoy en tu mano, para que conozcas que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 14, 'Y respondió Achâb: ¿Por mano de quién? Y él dijo: Así ha dicho Jehová: Por mano de los criados de los príncipes de las provincias. Y dijo Achâb: ¿Quién comenzará la batalla? Y él respondió: Tú.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 15, 'Entonces él reconoció los criados de los príncipes de las provincias, los cuales fueron doscientos treinta y dos. Luego reconoció todo el pueblo, todos los hijos de Israel, que fueron siete mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 16, 'Y salieron á medio día. Y estaba Ben-adad bebiendo, borracho en las tiendas, él y los reyes, los treinta y dos reyes que habían venido en su ayuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 17, 'Y los criados de los príncipes de las provincias salieron los primeros. Y había Ben-adad enviado quien le dió aviso, diciendo: Han salido hombres de Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 18, 'El entonces dijo: Si han salido por paz, tomadlos vivos; y si han salido para pelear, tomadlos vivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 19, 'Salieron pues de la ciudad los criados de los príncipes de las provincias, y en pos de ellos el ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 20, 'E hirió cada uno al que venía contra sí: y huyeron los Siros, siguiéndolos los de Israel. Y el rey de Siria, Ben-adad, se escapó en un caballo con alguna gente de caballería.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 21, 'Y salió el rey de Israel, é hirió la gente de á caballo, y los carros; y deshizo los Siros con grande estrago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 22, 'Llegándose luego el profeta al rey de Israel, le dijo: Ve, fortalécete, y considera y mira lo que has de hacer; porque pasado el año, el rey de Siria ha de venir contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 23, 'Y los siervos del rey de Siria le dijeron: Sus dioses son dioses de los montes, por eso nos han vencido; mas si peleáremos con ellos en la llanura, se verá si no los vencemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 24, 'Haz pues así: Saca á los reyes cada uno de su puesto, y pon capitanes en lugar de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 25, 'Y tú, fórmate otro ejército como el ejército que perdiste, caballos por caballos, y carros por carros; luego pelearemos con ellos en campo raso, y veremos si no los vencemos. Y él les dió oído, é hízolo así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 26, 'Pasado el año, Ben-adad reconoció los Siros, y vino á Aphec á pelear contra Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 27, 'Y los hijos de Israel fueron también inspeccionados, y tomando provisiones fuéronles al encuentro; y asentaron campo lo hijos de Israel delante de ellos, como dos rebañuelos de cabras; y los Siros henchían la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 28, 'Llegándose entonces el varón de Dios al rey de Israel, hablóle diciendo: Así dijo Jehová: Por cuanto los Siros han dicho, Jehová es Dios de los montes, no Dios de los valles, yo entregaré toda esta grande multitud en tu mano, para que conozcáis que yo soy Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 29, 'Siete días tuvieron asentado campo los unos delante de los otros, y al séptimo día se dió la batalla: y mataron los hijos de Israel de los Siros en un día cien mil hombres de á pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 30, 'Los demás huyeron á Aphec, á la ciudad: y el muro cayó sobre veinte y siete mil hombres que habían quedado. También Ben-adad vino huyendo á la ciudad, y escondíase de cámara en cámara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 31, 'Entonces sus siervos le dijeron: He aquí, hemos oído de los reyes de la casa de Israel que son reyes clementes: pongamos pues ahora sacos en nuestros lomos, y sogas en nuestras cabezas, y salgamos al rey de Israel: por ventura te salvará la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 32, 'Ciñeron pues sus lomos de sacos, y sogas á sus cabezas, y vinieron al rey de Israel, y dijéronle: Tu siervo Ben-adad dice: Ruégote que viva mi alma. Y él respondió: Si él vive aún, mi hermano es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 33, 'Esto tomaron aquellos hombres por buen agüero, y presto tomaron esta palabra de su boca, y dijeron: ¡Tu hermano Ben-adad! Y él dijo: Id, y traedle. Ben-adad entonces se presentó á Achâb, y él le hizo subir en un carro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 34, 'Y díjole Ben-adad: Las ciudades que mi padre tomó al tuyo, yo las restituiré; y haz plazas en Damasco para ti, como mi padre las hizo en Samaria. Y yo, dijo Achâb, te dejaré partir con esta alianza. Hizo pues con él alianza, y dejóle ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 35, 'Entonces un varón de los hijos de los profetas dijo á su compañero por palabra de Dios: Hiéreme ahora. Mas el otro varón no quiso herirle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 36, 'Y él le dijo: Por cuanto no has obedecido á la palabra de Jehová, he aquí en apartándote de mí, te herirá un león. Y como se apartó de él, topóle un león, é hirióle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 37, 'Encontróse luego con otro hombre, y díjole: Hiéreme ahora. Y el hombre le dió un golpe, é hízole una herida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 38, 'Y el profeta se fué, y púsose delante del rey en el camino, y disfrazóse con un velo sobre los ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 39, 'Y como el rey pasaba, él dió voces al rey, y dijo: Tu siervo salió entre la tropa: y he aquí apartándose uno, trájome un hombre, diciendo: Guarda á este hombre, y si llegare á faltar, tu vida será por la suya, ó pagarás un talento de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 40, 'Y como tu siervo estaba ocupado á una parte y á otra, él desapareció. Entonces el rey de Israel le dijo: Esa será tu sentencia: tú la has pronunciado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 41, 'Pero él se quitó presto el velo de sobre sus ojos, y el rey de Israel conoció que era de los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 42, 'Y él le dijo: Así ha dicho Jehová: Por cuanto soltaste de la mano el hombre de mi anatema, tu vida será por la suya, y tu pueblo por el suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 20, 43, 'Y el rey de Israel se fué á su casa triste y enojado, y llegó á Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 1, 'PASADOS estos negocios, aconteció que Naboth de Jezreel tenía en Jezreel una viña junto al palacio de Achâb rey de Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 2, 'Y Achâb habló á Naboth, diciendo: Dame tu viña para un huerto de legumbres, porque está cercana, junto á mi casa, y yo te daré por ella otra viña mejor que esta; ó si mejor te pareciere, te pagaré su valor en dinero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 3, 'Y Naboth respondió á Achâb: Guárdeme Jehová de que yo te dé á ti la heredad de mis padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 4, 'Y vínose Achâb á su casa triste y enojado, por la palabra que Naboth de Jezreel le había respondido, diciendo: No te daré la heredad de mis padres. Y acostóse en su cama, y volvió su rostro, y no comió pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 5, 'Y vino á él su mujer Jezabel, y díjole: ¿Por qué está tan triste tu espíritu, y no comes pan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 6, 'Y él respondió: Porque hablé con Naboth de Jezreel, y díjele que me diera su viña por dinero, ó que, si más quería, le daría otra viña por ella; y él respondió: Yo no te daré mi viña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 7, 'Y su mujer Jezabel le dijo: ¿Eres tú ahora rey sobre Israel? Levántate, y come pan, y alégrate: yo te daré la viña de Naboth de Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 8, 'Entonces ella escribió cartas en nombre de Achâb, y sellólas con su anillo y enviólas á los ancianos y á los principales que moraban en su ciudad con Naboth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 9, 'Y las cartas que escribió decían así: Proclamad ayuno, y poned á Naboth á la cabecera del pueblo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 10, 'Y poned dos hombres perversos delante de él, que atestigüen contra él, y digan: Tú has blasfemado á Dios y al rey. Y entonces sacadlo, y apedreadlo, y muera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 11, 'Y los de su ciudad, los ancianos y los principales que moraban en su ciudad, lo hicieron como Jezabel les mandó, conforme á lo escrito en las cartas que ella les había enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 12, 'Y promulgaron ayuno, y asentaron á Naboth á la cabecera del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 13, 'Vinieron entonces dos hombres perversos, y sentáronse delante de él: y aquellos hombres de Belial atestiguaron contra Naboth delante del pueblo, diciendo: Naboth ha blasfemado á Dios y al rey. Y sacáronlo fuera de la ciudad, y apedreáronlo con piedras, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 14, 'Después enviaron á decir á Jezabel: Naboth ha sido apedreado y muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 15, 'Y como Jezabel oyó que Naboth había sido apedreado y muerto, dijo á Achâb: Levántate y posee la viña de Naboth de Jezreel, que no te la quiso dar por dinero; porque Naboth no vive, sino que es muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 16, 'Y oyendo Achâb que Naboth era muerto, levantóse para descender á la viña de Naboth de Jezreel, para tomar posesión de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 17, 'Entonces fué palabra de Jehová á Elías Thisbita, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 18, 'Levántate, desciende á encontrarte con Achâb rey de Israel, que está en Samaria: he aquí él está en la viña de Naboth, á la cual ha descendido para tomar posesión de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 19, 'Y hablarle has, diciendo: Así ha dicho Jehová: ¿No mataste y también has poseído? Y tornarás á hablarle, diciendo: Así ha dicho Jehová: En el mismo lugar donde lamieron los perros la sangre de Naboth, los perros lamerán también tu sangre, la tuya misma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 20, 'Y Achâb dijo á Elías: ¿Me has hallado, enemigo mío? Y él respondió: Hete encontrado, porque te has vendido á mal hacer delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 21, 'He aquí yo traigo mal sobre ti, y barreré tu posteridad, y talaré de Achâb todo meante á la pared, al guardado y al desamparado en Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 22, 'Y yo pondré tu casa como la casa de Jeroboam hijo de Nabat, y como la casa de Baasa hijo de Ahía; por la provocación con que me provocaste á ira, y con que has hecho pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 23, 'De Jezabel también ha hablado Jehová, diciendo: Los perros comerán á Jezabel en la barbacana de Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 24, 'El que de Achâb fuere muerto en la ciudad, perros le comerán: y el que fuere muerto en el campo, comerlo han las aves del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 25, '(A la verdad ninguno fué como Achâb, que se vendiese á hacer lo malo á los ojos de Jehová; porque Jezabel su mujer lo incitaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 26, 'El fué en grande manera abominable, caminando en pos de los ídolos, conforme á todo lo que hicieron los Amorrheos, á los cuales lanzó Jehová delante de los hijos de Israel.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 27, 'Y acaeció cuando Achâb oyó estas palabras, que rasgó sus vestidos, y puso saco sobre su carne, y ayunó, y durmió en saco, y anduvo humillado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 28, 'Entonces fué palabra de Jehová á Elías Thisbita, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 21, 29, '¿No has visto como Achâb se ha humillado delante de mí? Pues por cuanto se ha humillado delante de mí, no traeré el mal en sus días: en los días de su hijo traeré el mal sobre su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 1, 'TRES años pasaron sin guerra entre los Siros é Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 2, 'Y aconteció al tercer año, que Josaphat rey de Judá descendió al rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 3, 'Y el rey de Israel dijo á sus siervos: ¿No sabéis que es nuestra Ramoth de Galaad? y nosotros callamos en orden á tomarla de mano del rey de Siria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 4, 'Y dijo á Josaphat: ¿Quieres venir conmigo á pelear contra Ramoth de Galaad? Y Josaphat respondió al rey de Israel: Como yo, así tú; y como mi pueblo, así tu pueblo; y como mis caballos, tus caballos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 5, 'Y dijo luego Josaphat al rey de Israel: Yo te ruego que consultes hoy la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 6, 'Entonces el rey de Israel juntó los profetas, como cuatrocientos hombres, á los cuales dijo: ¿Iré á la guerra contra Ramoth de Galaad, ó la dejaré? Y ellos dijeron: Sube; porque el Señor la entregará en mano del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 7, 'Y dijo Josaphat: ¿Hay aún aquí algún profeta de Jehová, por el cual consultemos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 8, 'Y el rey de Israel respondió á Josaphat: Aun hay un varón por el cual podríamos consultar á Jehová, Michêas, hijo de Imla: mas yo le aborrezco porque nunca me profetiza bien, sino solamente mal. Y Josaphat dijo: No hable el rey así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 9, 'Entonces el rey de Israel llamó á un eunuco, y díjole: trae presto á Michêas hijo de Imla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 10, 'Y el rey de Israel y Josaphat rey de Judá estaban sentados cada uno en su silla, vestidos de sus ropas reales, en la plaza junto á la entrada de la puerta de Samaria; y todos los profetas profetizaban delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 11, 'Y Sedechîas hijo de Chânaana se había hecho unos cuernos de hierro, y dijo: Así ha dicho Jehová: Con éstos acornearás á los Siros hasta acabarlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 12, 'Y todos los profetas profetizaban de la misma manera, diciendo: Sube á Ramoth de Galaad, y serás prosperado; que Jehová la dará en mano del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 13, 'Y el mensajero que había ido á llamar á Michêas, hablóle, diciendo: He aquí las palabras de los profetas á una boca anuncian al rey bien: sea ahora tu palabra conforme á la palabra de alguno de ellos, y anuncia bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 14, 'Y Michêas respondió: Vive Jehová, que lo que Jehová me hablare, eso diré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 15, 'Vino pues al rey, y el rey le dijo: Michêas, ¿iremos á pelear contra Ramoth de Galaad, ó la dejaremos? Y él respondió: Sube, que serás prosperado, y Jehová la entregará en mano del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 16, 'Y el rey le dijo: ¿Hasta cuántas veces he de conjurarte que no me digas sino la verdad en el nombre de Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 17, 'Entonces él dijo: Yo ví á todo Israel esparcido por los montes, como ovejas que no tienen pastor: y Jehová dijo: Estos no tienen señor: vuélvase cada uno á su casa en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 18, 'Y el rey de Israel dijo á Josaphat: ¿No te lo había yo dicho? Ninguna cosa buena profetizará él acerca de mí, sino solamente mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 19, 'Entonces él dijo: Oye pues palabra de Jehová: Yo vi á Jehová sentado en su trono, y todo el ejército de los cielos estaba junto á él, á su diestra y á su siniestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 20, 'Y Jehová dijo: ¿Quién inducirá á Achâb, para que suba y caiga en Ramoth de Galaad? Y uno decía de una manera; y otro decía de otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 21, 'Y salió un espíritu, y púsose delante de Jehová, y dijo: Yo le induciré. Y Jehová le dijo: ¿De qué manera?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 22, 'Y él dijo: Yo saldré, y seré espíritu de mentira en boca de todos sus profetas. Y él dijo: inducirlo has, y aun saldrás con ello; sal pues, y hazlo así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 23, 'Y ahora, he aquí Jehová ha puesto espíritu de mentira en la boca de todos estos tus profetas, y Jehová ha decretado el mal acerca de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 24, 'Llegándose entonces Sedechîas hijo de Chânaana, hirió á Michêas en la mejilla, diciendo: ¿Por dónde se fué de mí el espíritu de Jehová para hablarte á ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 25, 'Y Michêas respondió: He aquí tú lo verás en aquel día, cuando te irás metiendo de cámara en cámara por esconderte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 26, 'Entonces el rey de Israel dijo: Toma á Michêas, y vuélvelo á Amón gobernador de la ciudad, y á Joas hijo del rey;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 27, 'Y dirás: Así ha dicho el rey: Echad á éste en la cárcel, y mantenedle con pan de angustia y con agua de aflicción, hasta que yo vuelva en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 28, 'Y dijo Michêas: Si llegares á volver en paz, Jehová no ha hablado por mí. En seguida dijo: Oid, pueblos todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 29, 'Subió pues el rey de Israel con Josaphat rey de Judá á Ramoth de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 30, 'Y el rey de Israel dijo á Josaphat: Yo me disfrazaré, y entraré en la batalla: y tú vístete tus vestidos. Y el rey de Israel se disfrazó, y entró en la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 31, 'Mas el rey de Siria había mandado á sus treinta y dos capitanes de los carros, diciendo: No peleéis vosotros ni con grande ni con chico, sino sólo contra el rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 32, 'Y como los capitanes de los carros vieron á Josaphat, dijeron: Ciertamente éste es el rey de Israel; y viniéronse á él para pelear con él; mas el rey Josaphat dió voces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 33, 'Viendo entonces los capitanes de los carros que no era el rey de Israel, apartáronse de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 34, 'Y un hombre disparando su arco á la ventura, hirió al rey de Israel por entre las junturas de la armadura; por lo que dijo él á su carretero: Toma la vuelta, y sácame del campo, que estoy herido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 35, 'Mas la batalla había arreciado aquel día, y el rey estuvo en su carro delante de los Siros, y á la tarde murió: y la sangre de la herida corría por el seno del carro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 36, 'Y á puesta del sol salió un pregón por el campo, diciendo: ¡Cada uno á su ciudad, y cada cual á su tierra!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 37, 'Y murió pues el rey, y fué traído á Samaria; y sepultaron al rey en Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 38, 'Y lavaron el carro en el estanque de Samaria; lavaron también sus armas; y los perros lamieron su sangre, conforme á la palabra de Jehová que había hablado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 39, 'Lo demás de los hechos de Achâb, y todas las cosas que ejecutó, y la casa de marfil que hizo, y todas las ciudades que edificó, ¿no está escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 40, 'Y durmió Achâb con sus padres, y reinó en su lugar Ochôzías su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 41, 'Y Josaphat hijo de Asa comenzó á reinar sobre Judá en el cuarto año de Achâb rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 42, 'Y era Josaphat de treinta y cinco años cuando comenzó á reinar, y reinó veinticinco años en Jerusalem. El nombre de su madre fué Azuba hija de Silai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 43, 'Y anduvo en todo el camino de Asa su padre, sin declinar de él, haciendo lo recto en los ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 44, '(22-45) Y Josaphat hizo paz con el rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 45, '(22-46) Lo demás de los hechos de Josaphat, y sus hazañas, y las guerras que hizo, ¿no está escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 46, '(22-47) Barrió también de la tierra el resto de los sodomitas que habían quedado en el tiempo de su padre Asa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 47, '(22-48) No había entonces rey en Edom; presidente había en lugar de rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 48, '(22-49) Había Josaphat hecho navíos en Tharsis, los cuales habían de ir á Ophir por oro; mas no fueron, porque se rompieron en Ezion-geber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 49, '(22-50) Entonces Ochôzías hijo de Achâb dijo á Josaphat: Vayan mis siervos con los tuyos en los navíos. Mas Josaphat no quiso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 50, '(22-51) Y durmió Josaphat con sus padres, y fué sepultado con sus padres en la ciudad de David su padre; y en su lugar reinó Joram su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 51, '(22-52) Y Ochôzías hijo de Achâb comenzó á reinar sobre Israel en Samaria, el año diecisiete de Josaphat rey de Judá; y reinó dos años sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 52, '(22-53) E hizo lo malo en los ojos de Jehová, y anduvo en el camino de su padre, y en el camino de su madre, y en el camino de Jeroboam hijo de Nabat, que hizo pecar á Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1KI', '1 Reyes', 22, 53, '(22-54) Porque sirvió á Baal, y lo adoró, y provocó á ira á Jehová Dios de Israel, conforme á todas las cosas que su padre había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 1, 'DESPUÉS de la muerte de Achâb rebelóse Moab contra Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 2, 'Y Ochôzías cayó por las celosías de una sala de la casa que tenía en Samaria; y estando enfermo envió mensajeros, y díjoles: Id, y consultad á Baal-zebub dios de Ecrón, si tengo de sanar de esta mi enfermedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 3, 'Entonces el ángel de Jehová habló á Elías Thisbita, diciendo: Levántate, y sube á encontrarte con los mensajeros del rey de Samaria, y les dirás: ¿No hay Dios en Israel, que vosotros vais á consultar á Baal-zebub dios de Ecrón?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 4, 'Por tanto así ha dicho Jehová: Del lecho en que subiste no descenderás, antes morirás ciertamente. Y Elías se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 5, 'Y como los mensajeros se volvieron al rey, él les dijo: ¿Por qué pues os habéis vuelto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 6, 'Y ellos le respondieron: Encontramos un varón que nos dijo: Id, y volveos al rey que os envió, y decidle: Así ha dicho Jehová: ¿No hay Dios en Israel, que tú envías á consultar á Baal-zebub dios de Ecrón? Por tanto, del lecho en que subiste no descenderás, antes morirás de cierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 7, 'Entonces él les dijo: ¿Qué hábito era el de aquel varón que encontrasteis, y os dijo tales palabras?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 8, 'Y ellos le respondieron: Un varón velloso, y ceñía sus lomos con un cinto de cuero. Entonces él dijo: Elías Thisbita es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 9, 'Y envió luego á él un capitán de cincuenta con sus cincuenta, el cual subió á él; y he aquí que él estaba sentado en la cumbre del monte. Y él le dijo: Varón de Dios, el rey ha dicho que desciendas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 10, 'Y Elías respondió, y dijo al capitán de cincuenta: Si yo soy varón de Dios, descienda fuego del cielo, y consúmate con tus cincuenta. Y descendió fuego del cielo, que lo consumió á él y á sus cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 11, 'Volvió el rey á enviar á él otro capitán de cincuenta con sus cincuenta; y hablóle, y dijo: Varon de Dios, el rey ha dicho así: Desciende presto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 12, 'Y respondióle Elías, y dijo: Si yo soy varón de Dios, descienda fuego del cielo, y consúmate con tus cincuenta. Y descendió fuego del cielo, que lo consumió á él y á sus cincuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 13, 'Y volvió á enviar el tercer capitán de cincuenta con sus cincuenta: y subiendo aquel tercer capitán de cincuenta, hincóse de rodillas delante de Elías, y rogóle, diciendo: Varón de Dios, ruégote que sea de valor delante de tus ojos mi vida y la vida de estos tus cincuenta siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 14, 'He aquí ha descendido fuego del cielo, y ha consumido los dos primeros capitanes de cincuenta, con sus cincuenta; sea ahora mi vida de valor delante de tus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 15, 'Entonces el ángel de Jehová dijo á Elías: Desciende con él; no hayas de él miedo. Y él se levantó, y descendió con él al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 16, 'Y díjole: Así ha dicho Jehová: Pues que enviaste mensajeros á consultar á Baal-zebub dios de Ecrón, ¿no hay Dios en Israel para consultar en su palabra? No descenderás, por tanto, del lecho en que subiste, antes morirás de cierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 17, 'Y murió conforme á la palabra de Jehová que había hablado Elías; y reinó en su lugar Joram, en el segundo año de Joram, hijo de Josaphat rey de Judá; porque Ochôzías no tenía hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 1, 18, 'Y lo demás de los hechos de Ochôzías, ¿no está escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 1, 'Y ACONTECIO que, cuando quiso Jehová alzar á Elías en un torbellino al cielo, Elías venía con Eliseo de Gilgal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 2, 'Y dijo Elías á Eliseo: Quédate ahora aquí, porque Jehová me ha enviado á Beth-el. Y Eliseo dijo: Vive Jehová, y vive tu alma, que no te dejaré. Descendieron pues á Beth-el.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 3, 'Y saliendo á Eliseo los hijos de los profetas que estaban en Beth-el, dijéronle: ¿Sabes cómo Jehová quitará hoy á tu señor de tu cabeza? Y él dijo: Sí, yo lo sé; callad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 4, 'Y Elías le volvió á decir: Eliseo, quédate aquí ahora, porque Jehová me ha enviado á Jericó. Y él dijo: Vive Jehová, y vive tu alma, que no te dejaré. Vinieron pues á Jericó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 5, 'Y llegáronse á Eliseo los hijos de los profetas que estaban en Jericó, y dijéronle: ¿Sabes cómo Jehová quitará hoy á tu señor de tu cabeza? Y él respondió: Sí, yo lo sé; callad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 6, 'Y Elías le dijo: Ruégote que te quedes aquí, porque Jehová me ha enviado al Jordán. Y él dijo: Vive Jehová, y vive tu alma, que no te dejaré. Fueron pues ambos á dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 7, 'Y vinieron cincuenta varones de los hijos de los profetas, y paráronse enfrente á lo lejos: y ellos dos se pararon junto al Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 8, 'Tomando entonces Elías su manto, doblólo, é hirió las aguas, las cuales se apartaron á uno y á otro lado, y pasaron ambos en seco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 9, 'Y como hubieron pasado, Elías dijo á Eliseo: Pide lo que quieres que haga por ti, antes que sea quitado de contigo. Y dijo Eliseo: Ruégote que las dos partes de tu espíritu sean sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 10, 'Y él le dijo: Cosa difícil has pedido. Si me vieres cuando fuere quitado de ti, te será así hecho; mas si no, no.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 11, 'Y aconteció que, yendo ellos hablando, he aquí, un carro de fuego con caballos de fuego apartó á los dos: y Elías subió al cielo en un torbellino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 12, 'Y viéndolo Eliseo, clamaba: ¡Padre mío, padre mío, carro de Israel y su gente de á caballo! Y nunca más le vió, y trabando de sus vestidos, rompiólos en dos partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 13, 'Alzó luego el manto de Elías que se le había caído, y volvió, y paróse á la orilla del Jordán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 14, 'Y tomando el manto de Elías que se le había caído, hirió las aguas, y dijo: ¿Dónde está Jehová, el Dios de Elías? Y así que hubo del mismo modo herido las aguas, apartáronse á uno y á otro lado, y pasó Eliseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 15, 'Y viéndole los hijos de los profetas que estaban en Jericó de la otra parte, dijeron: El espíritu de Elías reposó sobre Eliseo. Y viniéronle á recibir, é inclináronse á él hasta la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 16, 'Y dijéronle: He aquí hay con tus siervos cincuenta varones fuertes: vayan ahora y busquen á tu señor; quizá lo ha levantado el espíritu de Jehová, y lo ha echado en algún monte ó en algún valle. Y él les dijo: No enviéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 17, 'Mas ellos le importunaron, hasta que avergonzándose, dijo: Enviad. Entonces ellos enviaron cincuenta hombres, los cuales lo buscaron tres días, mas no lo hallaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 18, 'Y cuando volvieron á él, que se había quedado en Jericó, él les dijo: ¿No os dije yo que no fueseis?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 19, 'Y los hombres de la ciudad dijeron á Eliseo: He aquí el asiento de esta ciudad es bueno, como mi señor ve; mas las aguas son malas, y la tierra enferma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 20, 'Entonces él dijo: Traedme una botija nueva, y poned en ella sal. Y trajéronsela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 21, 'Y saliendo él á los manaderos de las aguas, echó dentro la sal, y dijo: Así ha dicho Jehová: Yo sané estas aguas, y no habrá más en ellas muerte ni enfermedad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 22, 'Y fueron sanas las aguas hasta hoy, conforme á la palabra que habló Eliseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 23, 'Después subió de allí á Beth-el; y subiendo por el camino, salieron los muchachos de la ciudad, y se burlaban de él, diciendo: ¡Calvo, sube! ¡calvo, sube!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 24, 'Y mirando él atrás, viólos, y maldíjolos en el nombre de Jehová. Y salieron dos osos del monte, y despedazaron de ellos cuarenta y dos muchachos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 2, 25, 'De allí fué al monte de Carmelo, y de allí volvió á Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 1, 'Y JORAM hijo de Achâb comenzó á reinar en Samaria sobre Israel el año dieciocho de Josaphat rey de Judá; y reinó doce años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 2, 'E hizo lo malo en ojos de Jehová, aunque no como su padre y su madre; porque quitó las estatuas de Baal que su padre había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 3, 'Mas allegóse á los pecados de Jeroboam, hijo de Nabat, que hizo pecar á Israel; y no se apartó de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 4, 'Entonces Mesa rey de Moab era propietario de ganados, y pagaba al rey de Israel cien mil corderos y cien mil carneros con sus vellones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 5, 'Mas muerto Achâb, el rey de Moab se rebeló contra el rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 6, 'Y salió entonces de Samaria el rey Joram, é inspeccionó á todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 7, 'Y fué y envió á decir á Josaphat rey de Judá: El rey de Moab se ha rebelado contra mí: ¿irás tú conmigo á la guerra contra Moab? Y él respondió: Iré, porque como yo, así tú; como mi pueblo, así tu pueblo; como mis caballos, así también tus caballos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 8, 'Y dijo: ¿Por qué camino iremos? Y él respondió: Por el camino del desierto de Idumea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 9, 'Partieron pues el rey de Israel, y el rey de Judá, y el rey de Idumea; y como anduvieron rodeando por el desierto siete días de camino, faltóles el agua para el ejército, y para las bestias que los seguían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 10, 'Entonces el rey de Israel dijo: ¡Ah! que ha llamado Jehová estos tres reyes para entregarlos en manos de los Moabitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 11, 'Mas Josaphat dijo: ¿No hay aquí profeta de Jehová, para que consultemos á Jehová por él? Y uno de los siervos del rey de Israel respondió y dijo: Aquí está Eliseo hijo de Saphat, que daba agua á manos á Elías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 12, 'Y Josaphat dijo: Este tendrá palabra de Jehová. Y descendieron á él el rey de Israel, y Josaphat, y el rey de Idumea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 13, 'Entonces Eliseo dijo al rey de Israel: ¿Qué tengo yo contigo? Ve á los profetas de tu padre, y á los profetas de tu madre. Y el rey de Israel le respondió: No; porque ha juntado Jehová estos tres reyes para entregarlos en manos de los Moabitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 14, 'Y Eliseo dijo: Vive Jehová de los ejércitos, en cuya presencia estoy, que si no tuviese respeto al rostro de Josaphat rey de Judá, no mirara á ti, ni te viera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 15, 'Mas ahora traedme un tañedor. Y mientras el tañedor tocaba, la mano de Jehová fué sobre Eliseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 16, 'Y dijo: Así ha dicho Jehová: Haced en este valle muchas acequias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 17, 'Porque Jehová ha dicho así: No veréis viento, ni veréis lluvia, y este valle será lleno de agua, y beberéis vosotros, y vuestras bestias, y vuestros ganados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 18, 'Y esto es cosa ligera en los ojos de Jehová; dará también á los Moabitas en vuestras manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 19, 'Y vosotros heriréis á toda ciudad fortalecida y á toda villa hermosa, y talaréis todo buen árbol, y cegaréis todas las fuentes de aguas, y destruiréis con piedras toda tierra fértil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 20, 'Y aconteció que por la mañana, cuando se ofrece el sacrificio, he aquí vinieron aguas por el camino de Idumea, y la tierra fué llena de aguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 21, 'Y todos los de Moab, como oyeron que los reyes subían á pelear contra ellos, juntáronse desde todos los que ceñían talabarte arriba, y pusiéronse en la frontera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 22, 'Y como se levantaron por la mañana, y lució el sol sobre las aguas, vieron los de Moab desde lejos las aguas rojas como sangre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 23, 'Y dijeron: ¡Sangre es esta de espada! Los reyes se han revuelto, y cada uno ha muerto á su compañero. Ahora pues, ¡Moab, á la presa!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 24, 'Mas cuando llegaron al campo de Israel, levantáronse los Israelitas é hirieron á los de Moab, los cuales huyeron delante de ellos: siguieron empero hiriendo todavía á los de Moab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 25, 'Y asolaron las ciudades, y en todas las heredades fértiles echó cada uno su piedra, y las llenaron; cegaron también todas las fuentes de las aguas, y derribaron todos los buenos árboles; hasta que en Kir-hareseth solamente dejaron sus piedras; porque los honderos la cercaron, y la hirieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 26, 'Y cuando el rey de Moab vió que la batalla lo vencía, tomó consigo setecientos hombres que sacaban espada, para romper contra el rey de Idumea: mas no pudieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 3, 27, 'Entonces arrebató á su primogénito que había de reinar en su lugar, y sacrificóle en holocausto sobre el muro. Y hubo grande enojo en Israel; y retiráronse de él, y volviéronse á su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 1, 'UNA mujer, de las mujeres de los hijos de los profetas, clamó á Eliseo, diciendo: Tu siervo mi marido es muerto; y tú sabes que tu siervo era temeroso de Jehová: y ha venido el acreedor para tomarse dos hijos míos por siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 2, 'Y Eliseo le dijo: ¿Qué te haré yo? Declárame qué tienes en casa. Y ella dijo: Tu sierva ninguna cosa tiene en casa, sino una botija de aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 3, 'Y él le dijo: Ve, y pide para ti vasos prestados de todos tus vecinos, vasos vacíos, no pocos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 4, 'Entra luego, y cierra la puerta tras ti y tras tus hijos; y echa en todos los vasos, y en estando uno lleno, ponlo aparte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 5, 'Y partióse la mujer de él, y cerró la puerta tras sí y tras sus hijos; y ellos le llegaban los vasos, y ella echaba del aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 6, 'Y como los vasos fueron llenos, dijo á un hijo suyo: Tráeme aún otro vaso. Y él dijo: No hay más vasos. Entonces cesó el aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 7, 'Vino ella luego, y contólo al varón de Dios, el cual dijo: Ve, y vende el aceite, y paga á tus acreedores; y tú y tus hijos vivid de lo que quedare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 8, 'Y aconteció también que un día pasaba Eliseo por Sunem; y había allí una mujer principal, la cual le constriñó á que comiese del pan: y cuando por allí pasaba, veníase á su casa á comer del pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 9, 'Y ella dijo á su marido: He aquí ahora, yo entiendo que éste que siempre pasa por nuestra casa, es varón de Dios santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 10, 'Yo te ruego que hagas una pequeña cámara de paredes, y pongamos en ella cama, y mesa, y silla, y candelero, para que cuando viniere á nosotros, se recoja en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 11, 'Y aconteció que un día vino él por allí, y recogióse en aquella cámara, y durmió en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 12, 'Entonces dijo á Giezi su criado: Llama á esta Sunamita. Y como él la llamó, pareció ella delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 13, 'Y dijo él á Giezi: Dile: He aquí tú has estado solícita por nosotros con todo este esmero: ¿qué quieres que haga por ti? ¿has menester que hable por ti al rey, ó al general del ejército? Y ella respondió: Yo habito en medio de mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 14, 'Y él dijo: ¿Qué pues haremos por ella? Y Giezi respondió: He aquí ella no tiene hijo, y su marido es viejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 15, 'Dijo entonces: Llámala. Y él la llamó, y ella se paró á la puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 16, 'Y él le dijo: A este tiempo según el tiempo de la vida, abrazarás un hijo. Y ella dijo: No, señor mío, varón de Dios, no hagas burla de tu sierva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 17, 'Mas la mujer concibió, y parió un hijo á aquel tiempo que Eliseo le había dicho, según el tiempo de la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 18, 'Y como el niño fué grande, aconteció que un día salió á su padre, á los segadores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 19, 'Y dijo á su padre: ¡Mi cabeza, mi cabeza! Y él dijo á un criado: Llévalo á su madre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 20, 'Y habiéndole él tomado, y traídolo á su madre, estuvo sentado sobre sus rodillas hasta medio día, y murióse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 21, 'Ella entonces subió, y púsolo sobre la cama del varón de Dios, y cerrándole la puerta, salióse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 22, 'Llamando luego á su marido, díjole: Ruégote que envíes conmigo á alguno de los criados y una de las asnas, para que yo vaya corriendo al varón de Dios, y vuelva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 23, 'Y él dijo: ¿Para qué has de ir á él hoy? No es nueva luna, ni sábado. Y ella respondió: Paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 24, 'Después hizo enalbardar una borrica, y dijo al mozo: Guía y anda; y no me hagas detener para que suba, sino cuando yo te lo dijere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 25, 'Partióse pues, y vino al varón de Dios al monte del Carmelo. Y cuando el varón de Dios la vió de lejos, dijo á su criado Giezi: He aquí la Sunamita:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 26, 'Ruégote que vayas ahora corriendo á recibirla, y dile: ¿Tienes paz? ¿y tu marido, y tu hijo? Y ella dijo: Paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 27, 'Y luego que llegó al varón de Dios en el monte, asió de sus pies. Y llegóse Giezi para quitarla; mas el varón de Dios le dijo: Déjala, porque su alma está en amargura, y Jehová me ha encubierto el motivo, y no me lo ha revelado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 28, 'Y ella dijo: ¿Pedí yo hijo á mi señor? ¿No dije yo, que no me burlases?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 29, 'Entonces dijo él á Giezi: Ciñe tus lomos, y toma mi bordón en tu mano, y ve; y si alguno te encontrare, no lo saludes; y si alguno te saludare, no le respondas: y pondrás mi bordón sobre el rostro del niño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 30, 'Y dijo la madre del niño: Vive Jehová, y vive tu alma, que no te dejaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 31, 'El entonces se levantó, y siguióla. Y Giezi había ido delante de ellos, y había puesto el bordón sobre el rostro del niño, mas ni tenía voz ni sentido; y así se había vuelto para encontrar á Eliseo; y declaróselo, diciendo: El mozo no despierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 32, 'Y venido Eliseo á la casa, he aquí el niño que estaba tendido muerto sobre su cama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 33, 'Entrando él entonces, cerró la puerta sobre ambos, y oró á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 34, 'Después subió, y echóse sobre el niño, poniendo su boca sobre la boca de él, y sus ojos sobre sus ojos, y sus manos sobre las manos suyas; así se tendió sobre él, y calentóse la carne del joven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 35, 'Volviéndose luego, paséose por la casa á una parte y á otra, y después subió, y tendióse sobre él; y el joven estornudó siete veces, y abrió sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 36, 'Entonces llamó él á Giezi, y díjole: Llama á esta Sunamita. Y él la llamó. Y entrando ella, él le dijo: Toma tu hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 37, 'Y así que ella entró, echóse á sus pies, é inclinóse á tierra: después tomó su hijo, y salióse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 38, 'Y Eliseo se volvió á Gilgal. Había entonces grande hambre en la tierra. Y los hijos de los profetas estaban con él, por lo que dijo á su criado: Pon una grande olla, y haz potaje para los hijos de los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 39, 'Y salió uno al campo á coger hierbas, y halló una como parra montés, y cogió de ella una faldada de calabazas silvestres: y volvió, y cortólas en la olla del potaje: porque no sabía lo que era.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 40, 'Echóse después para que comieran los hombres; pero sucedió que comiendo ellos de aquel guisado, dieron voces, diciendo: ¡Varón de Dios, la muerte en la olla! Y no lo pudieron comer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 41, 'El entonces dijo: Traed harina. Y esparcióla en la olla, y dijo: Echa de comer á la gente. Y no hubo más mal en la olla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 42, 'Vino entonces un hombre de Baal-salisa, el cual trajo al varón de Dios panes de primicias, veinte panes de cebada, y trigo nuevo en su espiga. Y él dijo: Da á la gente para que coman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 43, 'Y respondió su sirviente: ¿Cómo he de poner esto delante de cien hombres? Mas él tornó á decir: Da á la gente para que coman, porque así ha dicho Jehová: Comerán, y sobrará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 4, 44, 'Entonces él lo puso delante de ellos, y comieron, y sobróles, conforme á la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 1, 'NAAMAN, general del ejército del rey de Siria, era gran varón delante de su señor, y en alta estima, porque por medio de él había dado Jehová salvamento á la Siria. Era este hombre valeroso en extremo, pero leproso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 2, 'Y de Siria habían salido cuadrillas, y habían llevado cautiva de la tierra de Israel una muchacha; la cual sirviendo á la mujer de Naamán,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 3, 'Dijo á su señora: Si rogase mi señor al profeta que está en Samaria, él lo sanaría de su lepra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 4, 'Y entrando Naamán á su señor, declaróselo, diciendo: Así y así ha dicho una muchacha que es de la tierra de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 5, 'Y díjole el rey de Siria: Anda, ve, y yo enviaré letras al rey de Israel. Partió pues él, llevando consigo diez talentos de plata, y seis mil piezas de oro, y diez mudas de vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 6, 'Tomó también letras para el rey de Israel, que decían así: Luego en llegando á ti estas letras, sabe por ellas que yo envío á ti mi siervo Naamán, para que lo sanes de su lepra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 7, 'Y luego que el rey de Israel leyó las cartas, rasgó sus vestidos, y dijo: ¿Soy yo Dios, que mate y dé vida, para que éste envíe á mí á que sane un hombre de su lepra? Considerad ahora, y ved cómo busca ocasión contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 8, 'Y como Eliseo, varón de Dios oyó que el rey de Israel había rasgado sus vestidos, envió á decir al rey: ¿Por qué has rasgado tus vestidos? Venga ahora á mí, y sabrá que hay profeta en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 9, 'Y vino Naamán con sus caballos y con su carro, y paróse á las puertas de la casa de Eliseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 10, 'Entonces Eliseo le envió un mensajero, diciendo: Ve, y lávate siete veces en el Jordán, y tu carne se te restaurará, y serás limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 11, 'Y Naamán se fué enojado, diciendo: He aquí yo decía para mí: Saldrá él luego, y estando en pie invocará el nombre de Jehová su Dios, y alzará su mano, y tocará el lugar, y sanará la lepra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 12, 'Abana y Pharphar, ríos de Damasco, ¿no son mejores que todas las aguas de Israel? Si me lavare en ellos, ¿no seré también limpio? Y volvióse, y fuése enojado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 13, 'Mas sus criados se llegaron á él, y habláronle, diciendo: Padre mío, si el profeta te mandara alguna gran cosa, ¿no la hicieras? ¿cuánto más, diciéndote: Lávate, y serás limpio?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 14, 'El entonces descendió, y zambullóse siete veces en el Jordán, conforme á la palabra del varón de Dios: y su carne se volvió como la carne de un niño, y fué limpio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 15, 'Y volvió al varón de Dios, él y toda su compañía, y púsose delante de él, y dijo: He aquí ahora conozco que no hay Dios en toda la tierra, sino en Israel. Ruégote que recibas algún presente de tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 16, 'Mas él dijo: Vive Jehová, delante del cual estoy, que no lo tomaré. E importunándole que tomase, él nunca quiso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 17, 'Entonces Naamán dijo: Ruégote pues, ¿no se dará á tu siervo una carga de un par de acémilas de aquesta tierra? porque de aquí adelante tu siervo no sacrificará holocausto ni sacrificio á otros dioses, sino á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 18, 'En esto perdone Jehová á tu siervo: que cuando mi señor entrare en el templo de Rimmón, y para adorar en él se apoyare sobre mi mano, si yo también me inclinare en el templo de Rimmón, si en el templo de Rimmón me inclino, Jehová perdone en esto á tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 19, 'Y él le dijo: Vete en paz. Partióse pues de él, y caminó como el espacio de una milla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 20, 'Entonces Giezi, criado de Eliseo el varón de Dios, dijo entre sí: He aquí mi señor estorbó á este Siro Naamán, no tomando de su mano las cosas que había traído. Vive Jehová, que correré yo tras él, y tomaré de él alguna cosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 21, 'Y siguió Giezi á Naamán: y como le vió Naamán que venía corriendo tras él, apeóse del carro para recibirle, y dijo: ¿Va bien?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 22, 'Y él dijo: Bien. Mi señor me envía á decir: He aquí vinieron á mí en esta hora del monte de Ephraim dos mancebos de los hijos de los profetas: ruégote que les des un talento de plata, y sendas mudas de vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 23, 'Y Naamán dijo: Ruégote que tomes dos talentos. Y él le constriñó, y ató dos talentos de plata en dos sacos, y dos mudas de vestidos, y púsolo á cuestas á dos de sus criados, que lo llevasen delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 24, 'Y llegado que hubo á un lugar secreto, él lo tomó de mano de ellos, y guardólo en casa: luego mandó á los hombres que se fuesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 25, 'Y él entró, y púsose delante de su señor. Y Eliseo le dijo: ¿De dónde vienes, Giezi? Y él dijo: Tu siervo no ha ido á ninguna parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 26, 'El entonces le dijo: ¿No fué también mi corazón, cuando el hombre volvió de su carro á recibirte? ¿es tiempo de tomar plata, y de tomar vestidos, olivares, viñas, ovejas, bueyes, siervos y siervas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 5, 27, 'La lepra de Naamán se te pegará á ti, y á tu simiente para siempre. Y salió de delante de él leproso, blanco como la nieve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 1, 'LOS hijos de los profetas dijeron á Eliseo: He aquí, el lugar en que moramos contigo nos es estrecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 2, 'Vamos ahora al Jordán, y tomemos de allí cada uno una viga, y hagámonos allí lugar en que habitemos. Y él dijo: Andad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 3, 'Y dijo uno: Rogámoste que quieras venir con tus siervos. Y él respondió: Yo iré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 4, 'Fuése pues con ellos; y como llegaron al Jordán, cortaron la madera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 5, 'Y aconteció que derribando uno un árbol, cayósele el hacha en el agua; y dió voces, diciendo: ¡Ah, señor mío, que era emprestada!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 6, 'Y el varón de Dios dijo: ¿Dónde cayó? Y él le mostró el lugar. Entonces cortó él un palo, y echólo allí; é hizo nadar el hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 7, 'Y dijo: Tómalo. Y él tendió la mano, y tomólo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 8, 'Tenía el rey de Siria guerra contra Israel, y consultando con sus siervos, dijo: En tal y tal lugar estará mi campamento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 9, 'Y el varón de Dios envió á decir al rey de Israel: Mira que no pases por tal lugar, porque los Siros van allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 10, 'Entonces el rey de Israel envió á aquel lugar que el varón de Dios había dicho y amonestádole; y guardóse de allí, no una vez ni dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 11, 'Y el corazón del rey de Siria fué turbado de esto; y llamando á sus siervos, díjoles: ¿No me declararéis vosotros quién de los nuestros es del rey de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 12, 'Entonces uno de los siervos dijo: No, rey, señor mío; sino que el profeta Eliseo está en Israel, el cual declara al rey de Israel las palabras que tú hablas en tu más secreta cámara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 13, 'Y él dijo: Id, y mirad dónde está, para que yo envíe á tomarlo. Y fuéle dicho: He aquí él está en Dothán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 14, 'Entonces envió el rey allá gente de á caballo, y carros, y un grande ejército, los cuales vinieron de noche, y cercaron la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 15, 'Y levantándose de mañana el que servía al varón de Dios, para salir, he aquí el ejército que tenía cercada la ciudad, con gente de á caballo y carros. Entonces su criado le dijo: ¡Ah, señor mío! ¿qué haremos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 16, 'Y él le dijo: No hayas miedo: porque más son los que están con nosotros que los que están con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 17, 'Y oró Eliseo, y dijo: Ruégote, oh Jehová, que abras sus ojos para que vea. Entonces Jehová abrió los ojos del mozo, y miró: y he aquí que el monte estaba lleno de gente de á caballo, y de carros de fuego alrededor de Eliseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 18, 'Y luego que los Siros descendieron á él, oró Eliseo á Jehová, y dijo: Ruégote que hieras á esta gente con ceguedad. E hiriólos con ceguedad, conforme al dicho de Eliseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 19, 'Después les dijo Eliseo: No es este el camino, ni es esta la ciudad; seguidme, que yo os guiaré al hombre que buscáis. Y guiólos á Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 20, 'Y así que llegaron á Samaria, dijo Eliseo: Jehová, abre los ojos de éstos, para que vean. Y Jehová abrió sus ojos, y miraron, y halláronse en medio de Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 21, 'Y cuando el rey de Israel los hubo visto, dijo á Eliseo: ¿Herirélos, padre mío?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 22, 'Y él le respondió: No los hieras; ¿herirías tú á los que tomaste cautivos con tu espada y con tu arco? Pon delante de ellos pan y agua, para que coman y beban, y se vuelvan á sus señores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 23, 'Entonces les fué aparejada grande comida: y como hubieron comido y bebido, enviólos, y ellos se volvieron á su señor. Y nunca más vinieron cuadrillas de Siria á la tierra de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 24, 'Después de esto aconteció, que Ben-adad rey de Siria juntó todo su ejército, y subió, y puso cerco á Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 25, 'Y hubo grande hambre en Samaria, teniendo ellos cerco sobre ella; tanto, que la cabeza de un asno era vendida por ochenta piezas de plata, y la cuarta de un cabo de estiércol de palomas por cinco piezas de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 26, 'Y pasando el rey de Israel por el muro, una mujer le dió voces, y dijo: Salva, rey señor mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 27, 'Y él dijo: Si no te salva Jehová, ¿de dónde te tengo de salvar yo? ¿del alfolí, ó del lagar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 28, 'Y díjole el rey: ¿Qué tienes? Y ella respondió: Esta mujer me dijo: Da acá tu hijo, y comámoslo hoy, y mañana comeremos el mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 29, 'Cocimos pues mi hijo, y le comimos. El día siguiente yo le dije: Da acá tu hijo, y comámoslo. Mas ella ha escondido su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 30, 'Y como el rey oyó las palabras de aquella mujer, rasgó sus vestidos, y pasó así por el muro: y llegó á ver el pueblo el saco que traía interiormente sobre su carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 31, 'Y él dijo: Así me haga Dios, y así me añada, si la cabeza de Eliseo hijo de Saphat quedare sobre él hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 32, 'Estaba á la sazón Eliseo sentado en su casa, y con él estaban sentados los ancianos: y el rey envió á él un hombre. Mas antes que el mensajero viniese á él, dijo él á los ancianos: ¿No habéis visto como este hijo del homicida me envía á quitar la cabeza? Mirad pues, y cuando viniere el mensajero, cerrad la puerta, é impedidle la entrada: ¿no viene tras él el ruido de los pies de su amo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 6, 33, 'Aun estaba él hablando con ellos, y he aquí el mensajero que descendía á él; y dijo: Ciertamente este mal de Jehová viene. ¿Para qué tengo de esperar más á Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 1, 'DIJO entonces Eliseo: Oid palabra de Jehová: Así dijo Jehová: Mañana á estas horas valdrá el seah de flor de harina un siclo, y dos seah de cebada un siclo, á la puerta de Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 2, 'Y un príncipe sobre cuya mano el rey se apoyaba, respondió al varón de Dios, y dijo: Si Jehová hiciese ahora ventanas en el cielo, ¿sería esto así? Y él dijo: He aquí tú lo verás con tus ojos, mas no comerás de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 3, 'Y había cuatro hombres leprosos á la entrada de la puerta, los cuales dijeron el uno al otro: ¿Para qué nos estamos aquí hasta que muramos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 4, 'Si tratáremos de entrar en la ciudad, por el hambre que hay en la ciudad moriremos en ella; y si nos quedamos aquí, también moriremos. Vamos pues ahora, y pasémonos al ejército de los Siros: si ellos nos dieren la vida, viviremos; y si nos dieren la muerte, moriremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 5, 'Levantáronse pues en el principio de la noche, para irse al campo de los Siros; y llegando á las primeras estancias de los Siros, no había allí hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 6, 'Porque el Señor había hecho que en el campo de los Siros se oyese estruendo de carros, ruido de caballos, y estrépito de grande ejército; y dijéronse los unos á los otros: He aquí el rey de Israel ha pagado contra nosotros á los reyes de los Heteos, y á los reyes de los Egipcios, para que vengan contra nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 7, 'Y así se habían levantado y huído al principio de la noche, dejando sus tiendas, sus caballos, sus asnos, y el campo como se estaba; y habían huído por salvar las vidas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 8, 'Y como los leprosos llegaron á las primeras estancias, entráronse en una tienda, y comieron y bebieron, y tomaron de allí plata, y oro, y vestido, y fueron, y escondiéronlo: y vueltos, entraron en otra tienda, y de allí también tomaron, y fueron, y escondieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 9, 'Y dijéronse el uno al otro: No hacemos bien: hoy es día de buena nueva, y nosotros callamos: y si esperamos hasta la luz de la mañana, nos alcanzará la maldad. Vamos pues ahora, entremos, y demos la nueva en casa del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 10, 'Y vinieron, y dieron voces á los guardas de la puerta de la ciudad, y declaráronles, diciendo: Nosotros fuimos al campo de los Siros, y he aquí que no había allí hombre, ni voz de hombre, sino caballos atados, asnos también atados, y el campo como se estaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 11, 'Y los porteros dieron voces, y declaráronlo dentro, en el palacio del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 12, 'Y levantóse el rey de noche, y dijo á sus siervos: Yo os declararé lo que nos han hecho los Siros. Ellos saben que tenemos hambre, y hanse salido de las tiendas y escondídose en el campo, diciendo: Cuando hubieren salido de la ciudad, los tomaremos vivos, y entraremos en la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 13, 'Entonces respondió uno de sus siervos, y dijo: Tomen ahora cinco de los caballos que han quedado en la ciudad, (porque ellos también son como toda la multitud de Israel que ha quedado en ella; también ellos son como toda la multitud de Israel que ha perecido;) y enviemos, y veamos qué hay.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 14, 'Tomaron pues dos caballos de un carro, y envió el rey tras el campo de los Siros, diciendo: Id, y ved.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 15, 'Y ellos fueron, y siguiéronlos hasta el Jordán: y he aquí, todo el camino estaba lleno de vestidos y enseres que los Siros habían arrojado con la premura. Y volvieron los mensajeros, é hiciéronlo saber al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 16, 'Entonces el pueblo salió, y saquearon el campo de los Siros. Y fué vendido un seah de flor de harina por un siclo, y dos seah de cebada por un siclo, conforme á la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 17, 'Y el rey puso á la puerta a aquel príncipe sobre cuya mano él se apoyaba: y atropellóle el pueblo á la entrada, y murió, conforme á lo que había dicho el varón de Dios, lo que habló cuando el rey descendió á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 18, 'Aconteció pues de la manera que el varón de Dios había hablado al rey, diciendo: Dos seah de cebada por un siclo, y el seah de flor de harina será vendido por un siclo mañana á estas horas, á la puerta de Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 19, 'A lo cual aquel príncipe había respondido al varón de Dios, diciendo: Aunque Jehová hiciese ventanas en el cielo, ¿pudiera ser eso? Y él dijo: He aquí tú lo verás con tus ojos, mas no comerás de ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 7, 20, 'Y vínole así; porque el pueblo le atropelló á la entrada, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 1, 'Y HABLO Eliseo á aquella mujer á cuyo hijo había hecho vivir, diciendo: Levántate, vete tú y toda tu casa á vivir donde pudieres; porque Jehová ha llamado el hambre, la cual vendrá también sobre la tierra siete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 2, 'Entonces la mujer se levantó, é hizo como el varón de Dios le dijo: y partióse ella con su familia, y vivió en tierra de los Filisteos siete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 3, 'Y como fueron pasados los siete años, la mujer volvió de la tierra de los Filisteos: después salió para clamar al rey por su casa, y por sus tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 4, 'Y había el rey hablado con Giezi, criado del varón de Dios, diciéndole: Ruégote que me cuentes todas las maravillas que ha hecho Eliseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 5, 'Y contando él al rey cómo había hecho vivir á un muerto, he aquí la mujer, á cuyo hijo había hecho vivir, que clamaba al rey por su casa y por sus tierras. Entonces dijo Giezi: Rey señor mío, esta es la mujer, y este es su hijo, al cual Eliseo hizo vivir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 6, 'Y preguntando el rey á la mujer, ella se lo contó. Entonces el rey le dió un eunuco, diciéndole: Hazle volver todas las cosas que eran suyas, y todos los frutos de la tierras desde el día que dejó el país hasta ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 7, 'Eliseo se fué luego á Damasco, y Ben-adad rey de Siria estaba enfermo, al cual dieron aviso, diciendo: El varón de Dios ha venido aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 8, 'Y el rey dijo á Hazael: Toma en tu mano un presente, y ve á recibir al varón de Dios, y consulta por él á Jehová, diciendo: ¿Tengo de sanar de esta enfermedad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 9, 'Tomó pues Hazael en su mano un presente de todos los bienes de Damasco, cuarenta camellos cargados, y saliólo á recibir: y llegó, y púsose delante de él, y dijo: Tu hijo Ben-adad, rey de Siria, me ha enviado á ti, diciendo: ¿Tengo de sanar de esta enfermedad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 10, 'Y Eliseo le dijo: Ve, dile: Seguramente vivirás. Empero Jehová me ha mostrado que él ha de morir ciertamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 11, 'Y el varón de Dios le volvió el rostro afirmadamente, y estúvose así una gran pieza; y lloró el varón de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 12, 'Entonces díjole Hazael: ¿Por qué llora mi señor? Y él respondió: Porque sé el mal que has de hacer á los hijos de Israel: á sus fortalezas pegarás fuego, y á sus mancebos matarás á cuchillo, y estrellarás á sus niños, y abrirás á sus preñadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 13, 'Y Hazael dijo: ¿Por qué? ¿es tu siervo perro, que hará esta gran cosa? Y respondió Eliseo: Jehová me ha mostrado que tú has de ser rey de Siria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 14, 'Y él se partió de Eliseo, y vino á su señor, el cual le dijo: ¿Qué te ha dicho Eliseo? Y él respondió: Díjome que seguramente vivirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 15, 'El día siguiente tomó un paño basto, y metiólo en agua, y tendiólo sobre el rostro de Ben-adad, y murió: y reinó Hazael en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 16, 'En el quinto año de Joram hijo de Achâb rey de Israel, y siendo Josaphat rey de Judá, comenzó á reinar Joram hijo de Josaphat rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 17, 'De treinta y dos años era cuando comenzó á reinar, y ocho años reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 18, 'Y anduvo en el camino de los reyes de Israel, como hizo la casa de Achâb, porque una hija de Achâb fué su mujer; é hizo lo malo en ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 19, 'Con todo eso, Jehová no quiso cortar á Judá, por amor de David su siervo, como le había prometido darle lámpara de sus hijos perpetuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 20, 'En su tiempo se rebeló Edom de debajo de la mano de Judá, y pusieron rey sobre sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 21, 'Joram por tanto pasó á Seir, y todos sus carros con él: y levantándose de noche hirió á los Idumeos, los cuales le habían cercado, y á los capitanes de los carros: y el pueblo huyó á sus estancias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 22, 'Sustrájose no obstante Edom de bajo la mano de Judá, hasta hoy. Rebelóse además Libna en el mismo tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 23, 'Lo demás de los hechos de Joram, y todas las cosas que hizo, ¿no está escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 24, 'Y durmió Joram con sus padres, y fué sepultado con sus padres en la ciudad de David: y reinó en lugar suyo Ochôzías, su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 25, 'En el año doce de Joram hijo de Achâb rey de Israel, comenzó á reinar Ochôzías hijo de Joram rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 26, 'De veintidós años era Ochôzías cuando comenzó á reinar, y reinó un año en Jerusalem. El nombre de su madre fué Athalía hija de Omri rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 27, 'Y anduvo en el camino de la casa de Achâb, é hizo lo malo en ojos de Jehová, como la casa de Achâb: porque era yerno de la casa de Achâb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 28, 'Y fué á la guerra con Joram hijo de Achâb á Ramoth de Galaad, contra Hazael rey de Siria; y los Siros hirieron á Joram.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 8, 29, 'Y el rey Joram se volvió á Jezreel, para curarse de las heridas que los Siros le hicieron delante de Ramoth, cuando peleó contra Hazael rey de Siria. Y descendió Ochôzías hijo de Joram rey de Judá, á visitar á Joram hijo de Achâb en Jezreel, porque estaba enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 1, 'ENTONCES el profeta Eliseo llamó á uno de los hijos de los profetas, y díjole: Ciñe tus lomos, y toma esta alcuza de aceite en tu mano, y ve á Ramoth de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 2, 'Y cuando llegares allá, verás allí á Jehú hijo de Josaphat hijo de Nimsi; y entrando, haz que se levante de entre sus hermanos, y mételo en la recámara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 3, 'Toma luego la alcuza de aceite, y derrámala sobre su cabeza, y di: Así dijo Jehová: Yo te he ungido por rey sobre Israel. Y abriendo la puerta, echa á huir, y no esperes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 4, 'Fué pues el mozo, el mozo del profeta, á Ramoth de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 5, 'Y como él entró, he aquí los príncipes del ejército que estaban sentados. Y él dijo: Príncipe, una palabra tengo que decirte. Y Jehú dijo: ¿A cuál de todos nosotros? Y él dijo: A ti, príncipe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 6, 'Y él se levantó, y entróse en casa; y el otro derramó el aceite sobre su cabeza, y díjole: Así dijo Jehová Dios de Israel: Yo te he ungido por rey sobre el pueblo de Jehová, sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 7, 'Y herirás la casa de Achâb tu señor, para que yo vengue la sangre de mis siervos los profetas, y la sangre de todos los siervos de Jehová, de la mano de Jezabel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 8, 'Y perecerá toda la casa de Achâb, y talaré de Achâb todo meante á la pared, así al guardado como al desamparado en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 9, 'Y yo pondré la casa de Achâb como la casa de Jeroboam hijo de Nabat, y como la casa de Baasa hijo de Ahía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 10, 'Y á Jezabel comerán perros en el campo de Jezreel, y no habrá quien la sepulte. En seguida abrió la puerta, y echó á huir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 11, 'Después salió Jehú á los siervos de su señor, y dijéronle: ¿Hay paz? ¿para qué entró á ti aquel loco? Y él les dijo: Vosotros conocéis al hombre y sus palabras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 12, 'Y ellos dijeron: Mentira; decláranoslo ahora. Y él dijo: Así y así me habló, diciendo: Así ha dicho Jehová: Yo te he ungido por rey sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 13, 'Entonces tomaron prestamente su ropa, y púsola cada uno debajo de él en un trono alto, y tocaron corneta, y dijeron: Jehú es rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 14, 'Así conjuró Jehú hijo de Josaphat hijo de Nimsi, contra Joram. (Estaba Joram guardando á Ramoth de Galaad con todo Israel, por causa de Hazael rey de Siria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 15, 'Habíase empero vuelto el rey Joram á Jezreel, para curarse de las heridas que los Siros le habían hecho, peleando contra Hazael rey de Siria.) Y Jehú dijo: Si es vuestra voluntad, ninguno escape de la ciudad, para ir á dar las nuevas en Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 16, 'Entonces Jehú cabalgó, y fuése á Jezreel, porque Joram estaba allí enfermo. También Ochôzías rey de Judá había descendido á visitar á Joram.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 17, 'Y el atalaya que estaba en la torre de Jezreel, vió la cuadrilla de Jehú, que venía, y dijo: Yo veo una cuadrilla. Y Joram dijo: Toma uno de á caballo, y envía á reconocerlos, y que les diga: ¿Hay paz?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 18, 'Fué pues el de á caballo á reconocerlos, y dijo: El rey dice así: ¿Hay paz? Y Jehú le dijo: ¿Qué tienes tú que ver con la paz? vuélvete tras mí. El atalaya dió luego aviso, diciendo: El mensajero llegó hasta ellos, y no vuelve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 19, 'Entonces envió otro de á caballo, el cual llegando á ellos, dijo: El rey dice así: ¿Hay paz? Y Jehú respondió: ¿Qué tienes tú que ver con la paz? vuélvete tras mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 20, 'El atalaya volvió á decir: También éste llegó á ellos y no vuelve: mas el marchar del que viene es como el marchar de Jehú hijo de Nimsi, porque viene impetuosamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 21, 'Entonces Joram dijo: Unce. Y uncido que fué su carro, salió Joram rey de Israel, y Ochôzías rey de Judá, cada uno en su carro, y salieron á encontrar á Jehú, al cual hallaron en la heredad de Naboth de Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 22, 'Y en viendo Joram á Jehú, dijo: ¿Hay paz, Jehú? Y él respondió: ¿Qué paz, con las fornicaciones de Jezabel tu madre, y sus muchas hechicerías?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 23, 'Entonces Joram volviendo la mano huyó, y dijo á Ochôzías: ¡Traición, Ochôzías!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 24, 'Mas Jehú flechó su arco, é hirió á Joram entre las espaldas, y la saeta salió por su corazón, y cayó en su carro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 25, 'Dijo luego Jehú á Bidkar su capitán: Tómalo y échalo á un cabo de la heredad de Naboth de Jezreel. Acuérdate que cuando tú y yo íbamos juntos con la gente de Achâb su padre, Jehová pronunció esta sentencia sobre él, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 26, 'Que yo he visto ayer las sangres de Naboth, y las sangres de sus hijos, dijo Jehová; y tengo de darte la paga en esta heredad, dijo Jehová. Tómale pues ahora, y échalo en la heredad, conforme á la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 27, 'Y viendo esto Ochôzías rey de Judá, huyó por el camino de la casa del huerto. Y siguiólo Jehú, diciendo: Herid también á éste en el carro. Y le hirieron á la subida de Gur, junto á Ibleam. Y él huyó á Megiddo, y murió allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 28, 'Y sus siervos le llevaron en un carro á Jerusalem, y allá le sepultaron con sus padres, en su sepulcro en la ciudad de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 29, 'En el undécimo año de Joram hijo de Achâb, comenzó á reinar Ochôzías sobre Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 30, 'Vino después Jehú á Jezreel: y como Jezabel lo oyó, adornó sus ojos con alcohol, y atavió su cabeza, y asomóse á una ventana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 31, 'Y como entraba Jehú por la puerta, ella dijo: ¿Sucedió bien á Zimri, que mató á su señor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 32, 'Alzando él entonces su rostro hacia la ventana, dijo: ¿Quién es conmigo? ¿quién? Y miraron hacia él dos ó tres eunucos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 33, 'Y él les dijo: Echadla abajo. Y ellos la echaron: y parte de su sangre fué salpicada en la pared, y en los caballos; y él la atropelló.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 34, 'Entró luego, y después que comió y bebió, dijo: Id ahora á ver aquella maldita, y sepultadla; que es hija de rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 35, 'Empero cuando fueron para sepultarla, no hallaron de ella más que la calavera, y los pies, y las palmas de las manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 36, 'Y volvieron, y dijéronselo. Y él dijo: La palabra de Dios es ésta, la cual él habló por mano de su siervo Elías Thisbita, diciendo: En la heredad de Jezreel comerán los perros las carnes de Jezabel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 9, 37, 'Y el cuerpo de Jezabel fué cual estiércol sobre la faz de la tierra en la heredad de Jezreel; de manera que nadie pueda decir: Esta es Jezabel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 1, 'Y TENIA Achâb en Samaria setenta hijos; y escribió letras Jehú, y enviólas á Samaria á los principales de Jezreel, á los ancianos y á los ayos de Achâb, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 2, 'Luego en llegando estas letras á vosotros lo que tenéis los hijos de vuestro señor, y los que tenéis carros y gente de á caballo, la ciudad pertrechada, y las armas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 3, 'Mirad cuál es el mejor y él más recto de los hijos de vuestro señor, y ponedlo en el trono de su padre, y pelead por la casa de vuestro señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 4, 'Mas ellos tuvieron gran temor, y dijeron: He aquí dos reyes no pudieron resistirle, ¿cómo le resistiremos nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 5, 'Y el mayordomo, y el presidente de la ciudad, y los ancianos, y los ayos, enviaron á decir á Jehú: Siervos tuyos somos, y haremos todo lo que nos mandares: no elegiremos por rey á ninguno; tú harás lo que bien te pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 6, 'El entonces les escribió la segunda vez diciendo: Si sois míos, y queréis obedecerme, tomad las cabezas de los varones hijos de vuestro señor, y venid mañana á estas horas á mí á Jezreel. Y los hijos del rey, setenta varones, estaban con los principales de la ciudad, que los criaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 7, 'Y como las letras llegaron á ellos, tomaron á los hijos del rey, y degollaron setenta varones, y pusieron sus cabezas en canastillos, y enviáronselas á Jezreel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 8, 'Y vino un mensajero que le dió las nuevas, diciendo: Traído han las cabezas de los hijos del rey. Y él le dijo: Ponedlas en dos montones á la entrada de la puerta hasta la mañana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 9, 'Venida la mañana, salió él, y estando en pie dijo á todo el pueblo: Vosotros sois justos: he aquí yo he conspirado contra mi señor, y lo he muerto: ¿mas quién ha muerto á todos estos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 10, 'Sabed ahora que de la palabra de Jehová que habló sobre la casa de Achâb, nada caerá en tierra: y que Jehová ha hecho lo que dijo por su siervo Elías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 11, 'Mató entonces Jehú á todos los que habían quedado de la casa de Achâb en Jezreel, y á todos sus príncipes, y á todos sus familiares, y á sus sacerdotes, que no le quedó ninguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 12, 'Y levantóse de allí, y vino á Samaria; y llegando él en el camino á una casa de esquileo de pastores,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 13, 'Halló allí á los hermanos de Ochôzías rey de Judá, y díjoles: ¿Quién sois vosotros? Y ellos dijeron: Somos hermanos de Ochôzías, y hemos venido á saludar á los hijos del rey, y á los hijos de la reina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 14, 'Entonces él dijo: Prendedlos vivos. Y después que los tomaron vivos, degolláronlos junto al pozo de la casa de esquileo, cuarenta y dos varones, sin dejar ninguno de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 15, 'Partiéndose luego de allí encontróse con Jonadab hijo de Rechâb; y después que lo hubo saludado, díjole: ¿Es recto tu corazón, como el mío es recto con el tuyo? Y Jonadab dijo: Lo es. Pues que lo es, dame la mano. Y él le dió su mano. Hízolo luego subir consigo en el carro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 16, 'Y díjole: Ven conmigo, y verás mi celo por Jehová. Pusiéronlo pues en su carro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 17, 'Y luego que hubo Jehú llegado á Samaria, mató á todos los que habían quedado de Achâb en Samaria, hasta extirparlos, conforme á la palabra de Jehová, que había hablado por Elías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 18, 'Y juntó Jehú todo el pueblo, y díjoles: Achâb sirvió poco á Baal; mas Jehú lo servirá mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 19, 'Llamadme pues luego á todos los profetas de Baal, á todos sus siervos, y á todos sus sacerdotes; que no falte uno, porque tengo un gran sacrifico para Baal; cualquiera que faltare, no vivirá. Esto hacía Jehú con astucia, para destruir á los que honraban á Baal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 20, 'Y dijo Jehú: Santificad un día solemne á Baal. Y ellos convocaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 21, 'Y envió Jehú por todo Israel, y vinieron todos los siervos de Baal, que no faltó ninguno que no viniese. Y entraron en el templo de Baal, y el templo de Baal se llenó de cabo á cabo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 22, 'Entonces dijo al que tenía el cargo de las vestiduras: Saca vestiduras para todos lo siervos de Baal. Y él les sacó vestimentas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 23, 'Y entró Jehú con Jonadab hijo de Rechâb en el templo de Baal, y dijo á los siervos de Baal: Mirad y ved que por dicha no haya aquí entre vosotros alguno de los siervos de Jehová, sino solos los siervos de Baal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 24, 'Y como ellos entraron para hacer sacrificios y holocaustos, Jehú puso fuera ochenta hombres, y díjoles: Cualquiera que dejare vivo alguno de aquellos hombres que yo he puesto en vuestras manos, su vida será por la del otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 25, 'Y después que acabaron ellos de hacer el holocausto, Jehú dijo á los de su guardia y á los capitanes: Entrad, y matadlos; que no escape ninguno. Y los hirieron á cuchillo: y dejáronlos tendidos los de la guardia y los capitanes, y fueron hasta la ciudad del templo de Baal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 26, 'Y sacaron las estatuas de la casa de Baal, y quemáronlas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 27, 'Y quebraron la estatua de Baal, y derribaron la casa de Baal, é hiciéronla necesaria, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 28, 'Así extinguió Jehú á Baal de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 29, 'Con todo eso Jehú no se apartó de los pecados de Jeroboam hijo de Nabat, que hizo pecar á Israel; á saber, de en pos de los becerros de oro que estaban en Beth-el y en Dan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 30, 'Y Jehová dijo á Jehú: Por cuanto has hecho bien ejecutando lo recto delante de mis ojos, é hiciste á la casa de Achâb conforme á todo lo que estaba en mi corazón, tus hijos se sentarán en el trono de Israel hasta la cuarta generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 31, 'Mas Jehú no cuidó de andar en la ley de Jehová Dios de Israel con todo su corazón, ni se apartó de los pecados de Jeroboam, el que había hecho pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 32, 'En aquellos días comenzó Jehová á talar en Israel: é hiriólos Hazael en todos los términos de Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 33, 'Desde el Jordán al nacimiento del sol, toda la tierra de Galaad, de Gad, de Rubén, y de Manasés, desde Aroer que está junto al arroyo de Arnón, á Galaad y á Basán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 34, 'Lo demás de los hechos de Jehú, y todas las cosas que hizo, y toda su valentía, ¿no está escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 35, 'Y durmió Jehú con sus padres, y sepultáronlo en Samaria: y reinó en su lugar Joachâz su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 10, 36, 'El tiempo que reinó Jehú sobre Israel en Samaria, fué veintiocho años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 1, 'Y ATHALIA madre de Ochôzías, viendo que su hijo era muerto, levantóse, y destruyó toda la simiente real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 2, 'Pero tomando Josaba hija del rey Joram, hermana de Ochôzías, á Joas hijo de Ochôzías, sacólo furtivamente de entre los hijos del rey, que se mataban, y ocultólo de delante de Athalía, á él y á su ama, en la cámara de las camas, y así no lo mataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 3, 'Y estuvo con ella escondido en la casa de Jehová seis años: y Athalía fué reina sobre el país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 4, 'Mas al séptimo año envió Joiada, y tomó centuriones, capitanes, y gente de la guardia, y metiólos consigo en la casa de Jehová: é hizo con ellos liga, juramentándolos en la casa de Jehová; y mostróles al hijo del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 5, 'Y mandóles, diciendo: Esto es lo que habéis de hacer: la tercera parte de vosotros, los que entrarán el sábado, tendrán la guardia de la casa del rey;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 6, 'Y la otra tercera parte estará á la puerta del sur, y la otra tercera parte á la puerta del postigo de los de la guardia: así guardaréis la casa, para que no sea allanada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 7, 'Y las dos partes de vosotros, es á saber, todos los que salen el sábado, tendréis la guarda de la casa de Jehová junto al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 8, 'Y estaréis alrededor del rey de todas partes, teniendo cada uno sus armas en las manos, y cualquiera que entrare dentro de estos órdenes, sea muerto. Y habéis de estar con el rey cuando saliere, y cuando entrare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 9, 'Los centuriones pues, hicieron todo como el sacerdote Joiada les mandó: y tomando cada uno los suyos, es á saber, los que habían de entrar el sábado, y los que habían salido el sábado, viniéronse á Joiada el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 10, 'Y el sacerdote dió á los centuriones las picas y los escudos que habían sido del rey David, que estaban en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 11, 'Y los de la guardia se pusieron en orden, teniendo cada uno sus armas en sus manos, desde el lado derecho de la casa hasta el lado izquierdo, junto al altar y el templo, en derredor del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 12, 'Sacando luego Joiada al hijo del rey, púsole la corona y el testimonio, é hiciéronle rey ungiéndole; y batiendo las manos dijeron: ¡Viva el rey!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 13, 'Y oyendo Athalía el estruendo del pueblo que corría, entró al pueblo en el templo de Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 14, 'Y como miró, he aquí el rey que estaba junto á la columna, conforme á la costumbre, y los príncipes y los trompetas junto al rey; y que todo el pueblo del país hacía alegrías, y que tocaban las trompetas. Entonces Athalía, rasgando sus vestidos, clamó á voz en grito: ¡Traición, traición!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 15, 'Mas el sacerdote Joiada mandó á los centuriones que gobernaban el ejército, y díjoles: Sacadla fuera del recinto del templo, y al que la siguiere, matadlo á cuchillo. (Porque el sacerdote dijo que no la matasen en el templo de Jehová.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 16, 'Diéronle pues lugar, y como iba el camino por donde entran los de á caballo á la casa del rey, allí la mataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 17, 'Entonces Joiada hizo alianza entre Jehová y el rey y el pueblo, que serían pueblo de Jehová: y asimismo entre el rey y el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 18, 'Y todo el pueblo de la tierra entró en el templo de Baal, y derribáronlo: asimismo despedazaron enteramente sus altares y sus imágenes, y mataron á Mathán sacerdote de Baal delante de los altares. Y el sacerdote puso guarnición sobre la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 19, 'Después tomó los centuriones, y capitanes, y los de la guardia, y á todo el pueblo de la tierra, y llevaron al rey desde la casa de Jehová, y vinieron por el camino de la puerta de los de la guardia á la casa del rey; y sentóse el rey sobre el trono de los reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 20, 'Y todo el pueblo de la tierra hizo alegrías, y la ciudad estuvo en reposo, habiendo sido Athalía muerta á cuchillo junto á la casa del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 11, 21, 'Era Joas de siete años cuando comenzó á reinar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 1, 'EN el séptimo año de Jehú comenzó á reinar Joas, y reinó cuarenta años en Jerusalem. El nombre de su madre fué Sibia, de Beer-seba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 2, 'Y Joas hizo lo recto en ojos de Jehová todo el tiempo que le dirigió el sacerdote Joiada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 3, 'Con todo eso los altos no se quitaron; que aún sacrificaba y quemaba el pueblo perfumes en los altos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 4, 'Y Joas dijo á los sacerdotes: Todo el dinero de las santificaciones que se suele traer á la casa de Jehová, el dinero de los que pasan en cuenta, el dinero por las personas, cada cual según su tasa, y todo el dinero que cada uno de su propia voluntad mete en la casa de Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 5, 'Recíbanlo los sacerdotes, cada uno de sus familiares, y reparen los portillos del templo donde quiera que se hallare abertura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 6, 'Pero el año veintitrés del rey Joas, no habían aún reparado los sacerdotes las aberturas del templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 7, 'Llamando entonces el rey Joas al pontífice Joiada y á los sacerdotes, díjoles: ¿Por qué no reparáis las aberturas del templo? Ahora pues, no toméis más el dinero de vuestros familiares, sino dadlo para reparar las roturas del templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 8, 'Y los sacerdotes consintieron en no tomar más dinero del pueblo, ni tener cargo de reparar las aberturas del templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 9, 'Mas el pontífice Joiada tomó un arca, é hízole en la tapa un agujero, y púsola junto al altar, á la mano derecha como se entra en le templo de Jehová; y los sacerdotes que guardaban la puerta, ponían allí todo el dinero que se metía en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 10, 'Y cuando veían que había mucho dinero en el arca, venía el notario del rey y el gran sacerdote, y contaban el dinero que hallaban en el templo de Jehová, y guardábanlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 11, 'Y daban el dinero suficiente en mano de los que hacían la obra, y de los que tenían el cargo de la casa de Jehová; y ellos lo expendían en pagar los carpinteros y maestros que reparaban la casa de Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 12, 'Y los albañiles y canteros; y en comprar la madera y piedra de cantería para reparar las aberturas de la casa de Jehová; y en todo lo que se gastaba en la casa para repararla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 13, 'Mas de aquel dinero que se traía á la casa de Jehová, no se hacían tazas de plata, ni salterios, ni jofainas, ni trompetas; ni ningún otro vaso de oro ni de plata se hacía para el templo de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 14, 'Porque lo daban á los que hacían la obra, y con él reparaban la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 15, 'Y no se tomaba en cuenta á los hombres en cuyas manos el dinero era entregado, para que ellos lo diesen á los que hacían la obra: porque lo hacían ellos fielmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 16, 'El dinero por el delito, y el dinero por los pecados, no se metía en la casa de Jehová; porque era de los sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 17, 'Entonces subió Hazael rey de Siria, y peleó contra Gath, y tomóla: y puso Hazael su rostro para subir contra Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 18, 'Por lo que tomó Joas rey de Judá todas las ofrendas que había dedicado Josaphat, y Joram y Ochôzías sus padres, reyes de Judá, y las que él había dedicado, y todo el oro que se halló en los tesoros de la casa de Jehová, y en la casa del rey, y enviólo á Hazael rey de Siria: y él se partió de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 19, 'Lo demás de los hechos de Joas, y todas las cosas que hizo, ¿no está escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 20, 'Y levantáronse sus siervos, y conspiraron en conjuración, y mataron á Joas en la casa de Millo, descendiendo él á Silla;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 12, 21, 'Pues Josachâr hijo de Simaath, y Jozabad hijo de Somer, sus siervos, hiriéronle, y murió. Y sepultáronle con sus padres en la ciudad de David, y reinó en su lugar Amasías su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 1, 'EN el año veintitrés de Joas hijo de Ochôzías, rey de Judá, comenzó á reinar Joachâz hijo de Jehú sobre Israel en Samaria; y reinó diecisiete años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 2, 'E hizo lo malo en ojos de Jehová, y siguió los pecados de Jeroboam hijo de Nabat, el que hizo pecar á Israel; y no se apartó de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 3, 'Y encendióse el furor de Jehová contra Israel, y entrególos en mano de Hazael rey de Siria, y en mano de Ben-adad hijo de Hazael, por largo tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 4, 'Mas Joachâz oró á la faz de Jehová, y Jehová lo oyó: porque miró la aflicción de Israel, pues el rey de Siria los afligía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 5, '(Y dió Jehová salvador á Israel, y salieron de bajo la mano de los Siros; y habitaron los hijos de Israel en sus estancias, como antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 6, 'Con todo eso no se apartaron de los pecados de la casa de Jeroboam, el que hizo pecar á Israel: en ellos anduvieron; y también el bosque permaneció en Samaria.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 7, 'Porque no le había quedado gente á Joachâz, sino cincuenta hombres de á caballo, y diez carros, y diez mil hombres de á pié; pues el rey de Siria los había destruído, y los había puesto como polvo para hollar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 8, 'Lo demás de los hechos de Joachâz, y todo lo que hizo, y sus valentías, ¿no está escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 9, 'Y durmió Joachâz con sus padres, y sepultáronlo en Samaria: y reinó en su lugar Joas su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 10, 'El año treinta y siete de Joas rey de Judá, comenzó á reinar Joas hijo de Joachâz sobre Israel en Samaria; y reinó dieciséis años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 11, 'E hizo lo malo en ojos de Jehová: no se apartó de todos los pecados de Jeroboam hijo de Nabat, el que hizo pecar á Israel; en ellos anduvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 12, 'Lo demás de los hechos de Joas, y todas las cosas que hizo, y su esfuerzo con que guerreó contra Amasías rey de Judá, ¿no está escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 13, 'Y durmió Joas con sus padres, y sentóse Jeroboam sobre su trono: y Joas fué sepultado en Samaria con los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 14, 'Estaba Eliseo enfermo de aquella su enfermedad de que murió. Y descendió á él Joas rey de Israel, y llorando delante de él, dijo: ¡Padre mío, padre mío, carro de Israel y su gente de á caballo!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 15, 'Y díjole Eliseo: Toma un arco y unas saetas. Tomóse él entonces un arco y unas saetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 16, 'Y dijo Eliseo al rey de Israel: Pon tu mano sobre el arco. Y puso él su mano sobre el arco. Entonces puso Eliseo sus manos sobre las manos del rey,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 17, 'Y dijo: Abre la ventana de hacia el oriente. Y como él la abrió dijo Eliseo: Tira. Y tirando él, dijo Eliseo: Saeta de salud de Jehová, y saeta de salud contra Siria: porque herirás á los Siros en Aphec, hasta consumirlos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 18, 'Y tornóle á decir: Toma las saetas. Y luego que el rey de Israel las hubo tomado, díjole: Hiere la tierra. Y él hirió tres veces, y cesó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 19, 'Entonces el varón de Dios, enojado con él, le dijo: A herir cinco ó seis veces, herirías á Siria, hasta no quedar ninguno: empero ahora tres veces herirás á Siria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 20, 'Y murió Eliseo, y sepultáronlo. Entrado el año vinieron partidas de Moabitas á la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 21, 'Y aconteció que al sepultar unos un hombre, súbitamente vieron una partida, y arrojaron al hombre en el sepulcro de Eliseo: y cuando llegó á tocar el muerto los huesos de Eliseo, revivió, y levantóse sobre sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 22, 'Hazael pues, rey de Siria, afligió á Israel todo el tiempo de Joachâz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 23, 'Mas Jehová tuvo misericordia de ellos, y compadecióse de ellos, y mirólos, por amor de su pacto con Abraham, Isaac y Jacob; y no quiso destruirlos ni echarlos de delante de sí hasta ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 24, 'Y murió Hazael rey de Siria, y reinó en su lugar Ben-adad su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 13, 25, 'Y volvió Joas hijo de Joachâz, y tomó de mano de Ben-adad hijo de Hazael, las ciudades que él había tomado de mano de Joachâz su padre en guerra. Tres veces lo batió Joas, y restituyó las ciudades á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 1, 'EN el año segundo de Joas hijo de Joachâz rey de Israel, comenzó á reinar Amasías hijo de Joas rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 2, 'Cuando comenzó á reinar era de veinticinco años, y veintinueve años reinó en Jerusalem: el nombre de su madre fué Joaddan, de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 3, 'Y él hizo lo recto en ojos de Jehová, aunque no como David su padre: hizo conforme á todas las cosas que había hecho Joas su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 4, 'Con todo eso los altos no fueron quitados; que el pueblo aun sacrificaba y quemaba perfumes en los altos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 5, 'Y luego que el reino fué confirmado en su mano, hirió á sus siervos, los que habían muerto al rey su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 6, 'Mas no mató á los hijos de los que le mataron, conforme á lo que está escrito en el libro de la ley de Moisés, donde Jehová mandó, diciendo: No matarán á los padres por los hijos, ni á los hijos por los padres: mas cada uno morirá por su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 7, 'Este hirió asimismo diez mil Idumeos en el valle de las Salinas, y tomó á Sela por guerra, y llamóla Jocteel, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 8, 'Entonces Amasías envió embajadores á Joas, hijo de Joachâz hijo de Jehú, rey de Israel, diciendo: Ven, y veámonos de rostro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 9, 'Y Joas rey de Israel envió á Amasías rey de Judá esta respuesta: El cardillo que está en el Líbano envió á decir al cedro que está en el Líbano: Da tu hija por mujer á mi hijo. Y pasaron las bestias fieras que están en el Líbano, y hollaron el cardillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 10, 'Ciertamente has herido á Edom, y tu corazón te ha envanecido: gloríate pues, mas estáte en tu casa. ¿Y por qué te entrometerás en un mal, para que caigas tú, y Judá contigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 11, 'Mas Amasías no dió oídos; por lo que subió Joas rey de Israel, y viéronse de rostro él y Amasías rey de Judá, en Beth-semes, que es de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 12, 'Y Judá cayó delante de Israel, y huyeron cada uno á sus estancias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 13, 'Además Joas rey de Israel tomó á Amasías rey de Judá, hijo de Joas hijo de Ochôzías, en Beth-semes: y vino á Jerusalem, y rompió el muro de Jerusalem desde la puerta de Ephraim hasta la puerta de la esquina, cuatrocientos codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 14, 'Y tomó todo el oro y la plata, y todos los vasos que fueron hallados en la casa de Jehová, y en los tesoros de la casa del rey, y los hijos en rehenes, y volvióse á Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 15, 'Lo demás de los hechos de Joas que ejecutó, y sus hazañas, y cómo peleó contra Amasías rey de Judá, ¿no está escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 16, 'Y durmió Joas con sus padres, y fué sepultado en Samaria con los reyes de Israel; y reinó en su lugar Jeroboam su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 17, 'Y Amasías hijo de Joas rey de Judá, vivió después de la muerte de Joas hijo de Joachâz rey de Israel, quince años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 18, 'Lo demás de los hechos de Amasías, ¿no está escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 19, 'E hicieron conspiración contra él en Jerusalem, y él huyó á Lachîs; mas enviaron tras él á Lachîs, y allá lo mataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 20, 'Trajéronlo luego sobre caballos, y sepultáronlo en Jerusalem con sus padres, en la ciudad de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 21, 'Entonces todo el pueblo de Judá tomó á Azarías, que era de diez y seis años, é hiciéronlo rey en lugar de Amasías su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 22, 'Edificó él á Elath, y la restituyó á Judá, después que el rey durmió con sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 23, 'El año quince de Amasías hijo de Joas rey de Judá, comenzó á reinar Jeroboam hijo de Joas sobre Israel en Samaria; y reinó cuarenta y un años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 24, 'E hizo lo malo en ojos de Jehová, y no se apartó de todos los pecados de Jeroboam hijo de Nabat, el que hizo pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 25, 'El restituyó los términos de Israel desde la entrada de Amath hasta la mar de la llanura, conforme á la palabra de Jehová Dios de Israel, la cual había él hablado por su siervo Jonás hijo de Amittai, profeta que fué de Gath-hepher.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 26, 'Por cuanto Jehová miró la muy amarga aflicción de Israel; que no había guardado ni desamparado, ni quien diese ayuda á Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 27, 'Y Jehová no había determinado raer el nombre de Israel de debajo del cielo: por tanto, los salvó por mano de Jeroboam hijo de Joas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 28, 'Y lo demás de los hechos de Jeroboam, y todas las cosas que hizo, y su valentía, y todas las guerras que hizo, y cómo restituyó á Judá en Israel á Damasco y á Hamath, ¿no está escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 14, 29, 'Y durmió Jeroboam con sus padres, los reyes de Israel, y reinó en su lugar Zachârías su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 1, 'EN el año veintisiete de Jeroboam, rey de Israel, comenzó á reinar Azarías hijo de Amasías rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 2, 'Cuando comenzó á reinar era de dieciséis años, y cincuenta y dos años reinó en Jerusalem; el nombre de su madre fué Jecolía, de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 3, 'E hizo lo recto en ojos de Jehová, conforme á todas las cosas que su padre Amasías había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 4, 'Con todo eso los altos no se quitaron; que el pueblo sacrificaba aún y quemaba perfumes en los altos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 5, 'Mas Jehová hirió al rey con lepra, y fué leproso hasta el día de su muerte, y habitó en casa separada, y Jotham hijo del rey tenía el cargo del palacio, gobernando al pueblo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 6, 'Lo demás de los hechos de Azarías, y todas las cosas que hizo, ¿no está escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 7, 'Y durmió Azarías con sus padres, y sepultáronlo con sus padres en la ciudad de David: y reinó en su lugar Jotham su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 8, 'En el año treinta y ocho de Azarías rey de Judá, reinó Zachârías hijo de Jeroboam sobre Israel seis meses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 9, 'E hizo lo malo en ojos de Jehová, como habían hecho sus padres: no se apartó de los pecados de Jeroboam hijo de Nabat, el que hizo pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 10, 'Contra él se conjuró Sallum hijo de Jabes, y lo hirió en presencia de su pueblo, y matólo, y reinó en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 11, 'Lo demás de los hechos de Zachârías, he aquí está escrito en el libro de las crónicas de los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 12, 'Y esta fué la palabra de Jehová que había hablado á Jehú, diciendo: Tus hijos hasta la cuarta generación se sentarán en el trono de Israel. Y fué así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 13, 'Sallum hijo de Jabes comenzó á reinar en el año treinta y nueve de Uzzía rey de Judá, y reinó el tiempo de un mes en Samaria;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 14, 'Pues subió Manahem hijo de Gadi, de Thirsa, y vino á Samaria, é hirió á Sallum hijo de Jabes en Samaria, y matólo, y reinó en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 15, 'Lo demás de los hechos de Sallum, y su conjuración con que conspiró, he aquí está escrito en el libro de las crónicas de los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 16, 'Entonces hirió Manahem á Tiphsa, y á todos los que estaban en ella, y también sus términos desde Thirsa; é hirióla porque no le habían abierto; y abrió á todas sus preñadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 17, 'En el año treinta y nueve de Azarías rey de Judá, reinó Manahem hijo de Gadi sobre Israel diez años, en Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 18, 'E hizo lo malo en ojos de Jehová: no se apartó en todo su tiempo de los pecados de Jeroboam hijo de Nabat, el que hizo pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 19, 'Y vino Phul rey de Asiria á la tierra; y dió Manahem á Phul mil talentos de plata porque le ayudara á confirmarse en el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 20, 'E impuso Manahem este dinero sobre Israel, sobre todos los poderosos y opulentos: de cada uno cincuenta siclos de plata, para dar al rey de Asiria, y el rey de Asiria se volvió, y no se detuvo allí en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 21, 'Lo demás de los hechos de Manahem, y todas las cosas que hizo, ¿no está escrito en el libro de las crónicas de los reyes de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 22, 'Y durmió Manahem con sus padres, y reinó en su lugar Pekaía su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 23, 'En el año cincuenta de Azarías rey de Judá, reinó Pekaía hijo de Manahem sobre Israel en Samaria, dos años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 24, 'E hizo lo malo en ojos de Jehová: no se apartó de los pecados de Jeroboam hijo de Nabat, el que hizo pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 25, 'Y conspiró contra él Peka hijo de Remalías, capitán suyo, é hiriólo en Samaria, en el palacio de la casa real, en compañía de Argob y de Ariph, y con cincuenta hombres de los hijos de los Galaaditas; y matólo, y reinó en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 26, 'Lo demás de los hechos de Pekaía, y todas las cosas que hizo, he aquí está escrito en el libro de las crónicas de los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 27, 'En el año cincuenta y dos de Azarías rey de Judá, reinó Peka hijo de Remalías sobre Israel en Samaria; y reinó veinte años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 28, 'E hizo lo malo en ojos de Jehová; no se apartó de los pecados de Jeroboam hijo de Nabat, el que hizo pecar á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 29, 'En los días de Peka rey de Israel, vino Tiglath-pileser rey de los Asirios, y tomó á Ahión, Abel-beth-maachâ, y Janoa, y Cedes, y Asor, y Galaad, y Galilea, y toda la tierra de Nephtalí; y trasportólos á Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 30, 'Y Oseas hijo de Ela hizo conjuración contra Peka hijo de Remalías, é hiriólo, y matólo, y reinó en su lugar, á los veinte años de Jotham hijo de Uzzía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 31, 'Lo demás de los hechos de Peka, y todo lo que hizo, he aquí está escrito en el libro de las crónicas de los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 32, 'En el segundo año de Peka hijo de Remalías rey de Israel, comenzó á reinar Jotham hijo de Uzzía rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 33, 'Cuando comenzó á reinar era de veinticinco años, y reinó dieciséis años en Jerusalem. El nombre de su madre fué Jerusa hija de Sadoc.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 34, 'Y él hizo lo recto en ojos de Jehová; hizo conforme á todas las cosas que había hecho su padre Uzzía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 35, 'Con todo eso los altos no fueron quitados; que el pueblo sacrificaba aún, y quemaba perfumes en los altos. Edificó él la puerta más alta de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 36, 'Lo demás de los hechos de Jotham, y todas las cosas que hizo, ¿no está escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 37, 'En aquel tiempo comenzó Jehová á enviar contra Judá á Resín rey de Siria, y á Peka hijo de Remalías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 15, 38, 'Y durmió Jotham con sus padres, y fué sepultado con sus padres en la ciudad de David su padre: y reinó en su lugar Achâz su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 1, 'EN el año diecisiete de Peka hijo de Remalías, comenzó á reinar Achâz hijo de Jotham rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 2, 'Cuando comenzó á reinar Achâz, era de veinte años, y reinó en Jerusalem dieciséis años: y no hizo lo recto en ojos de Jehová su Dios, como David su padre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 3, 'Antes anduvo en el camino de los reyes de Israel, y aun hizo pasar por el fuego á su hijo, según las abominaciones de las gentes que Jehová echó de delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 4, 'Asimismo sacrificó, y quemó perfumes en los altos, y sobre los collados, y debajo de todo árbol umbroso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 5, 'Entonces Resín rey de Siria, y Peka hijo de Remalías rey de Israel, subieron á Jerusalem para hacer guerra, y cercar á Achâz; mas no pudieron tomarla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 6, 'En aquel tiempo Resín rey de Siria restituyó Elath á Siria, y echó á los Judíos de Elath; y los Siros vinieron á Elath, y habitaron allí hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 7, 'Entonces Achâz envió embajadores á Tiglath-pileser rey de Asiria, diciendo: Yo soy tu siervo y tu hijo: sube, y defiéndeme de mano del rey de Siria, y de mano del rey de Israel, que se han levantado contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 8, 'Y tomando Achâz la plata y el oro que se halló en la casa de Jehová, y en los tesoros de la casa real, envió al rey de Asiria un presente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 9, 'Y atendióle el rey de Asiria; pues subió el rey de Asiria contra Damasco, y tomóla, y trasportó los moradores á Kir, y mató á Resín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 10, 'Y fué el rey Achâz á encontrar á Tiglath-pileser rey de Asiria en Damasco; y visto que hubo el rey Achâz el altar que estaba en Damasco, envió á Urías sacerdote el diseño y la descripción del altar, conforme á toda su hechura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 11, 'Y Urías el sacerdote edificó el altar; conforme á todo lo que el rey Achâz había enviado de Damasco, así lo hizo el sacerdote Urías, entre tanto que el rey Achâz venía de Damasco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 12, 'Y luego que vino el rey de Damasco, y hubo visto el altar, acercóse el rey á él, y sacrificó en él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 13, 'Y encendió su holocausto, y su presente, y derramó sus libaciones, y esparció la sangre de sus pacíficos junto al altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 14, 'Y el altar de bronce que estaba delante de Jehová, hízolo acercar delante de la frontera de la casa, entre el altar y el templo de Jehová, y púsolo al lado del altar hacia el aquilón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 15, 'Y mandó el rey Achâz al sacerdote Urías, diciendo: En el gran altar encenderás el holocausto de la mañana y el presente de la tarde, y el holocausto del rey y su presente, y asimismo el holocausto de todo el pueblo de la tierra y su presente y sus libaciones: y esparcirás sobre él toda la sangre de holocausto, y toda la sangre de sacrificio: y el altar de bronce será mío para preguntar en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 16, 'E hizo el sacerdote Urías conforme á todas las cosas que el rey Achâz le mandó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 17, 'Y cortó el rey Achâz las cintas de las basas, y quitóles las fuentes; quitó también el mar de sobre los bueyes de bronce que estaban debajo de él, y púsolo sobre el solado de piedra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 18, 'Asimismo la tienda del sábado que habían edificado en la casa, y el pasadizo de afuera del rey, mudólos del templo de Jehová, por causa del rey de Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 19, 'Lo demás de los hechos de Achâz que puso por obra, ¿no está todo escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 16, 20, 'Y durmió el rey Achâz con sus padres y fué sepultado con sus padres en la ciudad de David: y reinó en su lugar Ezechîas su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 1, 'EN el año duodécimo de Achâz rey de Judá, comenzó á reinar Oseas hijo de Ela en Samaria sobre Israel; y reinó nueve años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 2, 'E hizo lo malo en ojos de Jehová, aunque no como los reyes de Israel que antes de él habían sido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 3, 'Contra éste subió Salmanasar rey de los Asirios; y Oseas fué hecho su siervo, y pagábale tributo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 4, 'Mas el rey de Asiria halló que Oseas hacía conjuración: porque había enviado embajadores á So, rey de Egipto, y no pagaba tributo al rey de Asiria, como cada año: por lo que el rey de Asiria le detuvo, y le aprisionó en la casa de la cárcel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 5, 'Y el rey de Asiria partió contra todo el país, y subió contra Samaria, y estuvo sobre ella tres años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 6, 'En el año nueve de Oseas tomó el rey de Asiria á Samaria, y trasportó á Israel á Asiria, y púsolos en Hala, y en Habor, junto al río de Gozán, y en las ciudades de los Medos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 7, 'Porque como los hijos de Israel pecasen contra Jehová su Dios, que los sacó de tierra de Egipto de bajo la mano de Faraón rey de Egipto, y temiesen á dioses ajenos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 8, 'Y anduviesen en los estatutos de las gentes que Jehová había lanzado delante de los hijos de Israel, y en los de los reyes de Israel, que hicieron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 9, 'Y como los hijos de Israel paliasen cosas no rectas contra Jehová su Dios, edificándose altos en todas sus ciudades, desde las torres de las atalayas hasta las ciudades fuertes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 10, 'Y se levantasen estatuas y bosques en todo collado alto, y debajo de todo árbol umbroso,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 11, 'Y quemasen allí perfumes en todos los altos, á la manera de las gentes que había Jehová traspuesto delante de ellos, é hiciesen cosas muy malas para provocar á ira á Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 12, 'Pues servían á los ídolos, de los cuales Jehová les había dicho: Vosotros no habéis de hacer esto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 13, 'Jehová protestaba entonces contra Israel y contra Judá, por mano de todos los profetas, y de todos los videntes, diciendo: Volveos de vuestros malos caminos, y guardad mis mandamientos y mis ordenanzas, conforme á todas las leyes que yo prescribí á vuestros padres, y que os he enviado por mano de mis siervos los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 14, 'Mas ellos no obedecieron, antes endurecieron su cerviz, como la cerviz de sus padres, los cuales no creyeron en Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 15, 'Y desecharon sus estatutos, y su pacto que él había concertado con sus padres, y sus testimonios que él había protestado contra ellos; y siguieron la vanidad, y se hicieron vanos, y fueron en pos de las gentes que estaban alrededor de ellos, de las cuales les había Jehová mandado que no hiciesen á la manera de ellas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 16, 'Y dejaron todos los mandamientos de Jehová su Dios, é hiciéronse vaciadizos dos becerros, y también bosques, y adoraron á todo el ejército del cielo, y sirvieron á Baal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 17, 'E hicieron pasar á sus hijos y á sus hijas por fuego; y diéronse á adivinaciones y agüeros, y entregáronse á hacer lo malo en ojos de Jehová, provocándole á ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 18, 'Jehová por tanto se airó en gran manera contra Israel, y quitólos de delante de su rostro; que no quedó sino sólo la tribu de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 19, 'Mas ni aun Judá guardó los mandamientos de Jehová su Dios; antes anduvieron en los estatutos de Israel, los cuales habían ellos hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 20, 'Y desechó Jehová toda la simiente de Israel, y afligiólos, y entrególos en manos de saqueadores, hasta echarlos de su presencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 21, 'Porque cortó á Israel de la casa de David, y ellos se hicieron rey á Jeroboam hijo de Nabat; y Jeroboam rempujó á Israel de en pos de Jehová, é hízoles cometer gran pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 22, 'Y los hijos de Israel anduvieron en todos los pecados de Jeroboam que él hizo, sin apartarse de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 23, 'Hasta tanto que Jehová quitó á Israel de delante de su rostro, como lo había él dicho por mano de todos los profetas sus siervos: é Israel fué trasportado de su tierra á Asiria, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 24, 'Y trajo el rey de Asiria gente de Babilonia, y de Cutha, y de Ava, y de Hamath, y de Sepharvaim, y púsolos en las ciudades de Samaria, en lugar de los hijos de Israel; y poseyeron á Samaria, y habitaron en sus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 25, 'Y aconteció al principio, cuando comenzaron á habitar allí, que no temiendo ellos á Jehová, envió Jehová contra ellos leones que los mataban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 26, 'Entonces dijeron ellos al rey de Asiria: Las gentes que tú traspasaste y pusiste en las ciudades de Samaria, no saben la costumbre del Dios de aquella tierra, y él ha echado leones en ellos, y he aquí los matan, porque no saben la costumbre del Dios de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 27, 'Y el rey de Asiria mandó, diciendo: Llevad allí á alguno de los sacerdote que trajisteis de allá, y vayan y habiten allí, y enséñenles la costumbre del Dios del país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 28, 'Y vino uno de los sacerdotes que habían trasportado de Samaria, y habitó en Beth-el, y enseñóles cómo habían de temer á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 29, 'Mas cada nación se hizo sus dioses, y pusiéronlos en los templos de los altos que habían hecho los de Samaria; cada nación en su ciudad donde habitaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 30, 'Los de Babilonia hicieron á Succoth-benoth, y los de Cutha hicieron á Nergal, y los de Hamath hicieron á Asima;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 31, 'Los Heveos hicieron á Nibhaz y á Tharthac; y los de Sepharvaim quemaban sus hijos al fuego á Adra-melech y á Anamelech, dioses de Sepharvaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 32, 'Y temían á Jehová; é hicieron del pueblo bajo sacerdotes de los altos, quienes sacrificaban para ellos en los templos de los altos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 33, 'Temían á Jehová, y honraban á sus dioses, según la costumbre de las gentes de donde habían sido trasladados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 34, 'Hasta hoy hacen como primero; que ni temen á Jehová, ni guardan sus estatutos, ni sus ordenanzas, ni hacen según la ley y los mandamientos que prescribió Jehová á los hijos de Jacob, al cual puso el nombre de Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 35, 'Con los cuales había Jehová hecho pacto, y les mandó, diciendo: No temeréis á otros dioses, ni los adoraréis, ni les serviréis, ni les sacrificaréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 36, 'Mas á Jehová, que os sacó de tierra de Egipto con grande poder y brazo extendido, á éste temeréis, y á éste adoraréis, y á éste haréis sacrificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 37, 'Los estatutos y derechos y ley y mandamientos que os dió por escrito, cuidaréis siempre de ponerlos por obra, y no temeréis dioses ajenos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 38, 'Y no olvidaréis el pacto que hice con vosotros; ni temeréis dioses ajenos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 39, 'Mas temed á Jehová vuestro Dios, y él os librará de mano de todos vuestros enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 40, 'Empero ellos no escucharon; antes hicieron según su costumbre antigua.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 17, 41, 'Así temieron á Jehová aquellas gentes, y juntamente sirvieron á sus ídolos: y también sus hijos y sus nietos, según que hicieron sus padres, así hacen hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 1, 'EN el tercer año de Oseas hijo de Ela rey de Israel, comenzó á reinar Ezechîas hijo de Achâz rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 2, 'Cuando comenzó á reinar era de venticinco años, y reinó en Jerusalem veintinueve años. El nombre de su madre fué Abi hija de Zachârías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 3, 'Hizo lo recto en ojos de Jehová, conforme á todas las cosas que había hecho David su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 4, 'El quitó los altos, y quebró las imágenes, y taló los bosques, é hizo pedazos la serpiente de bronce que había hecho Moisés, porque hasta entonces le quemaban perfumes los hijos de Israel; y llamóle por nombre Nehustán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 5, 'En Jehová Dios de Israel puso su esperanza: después ni antes de él no hubo otro como él en todos los reyes de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 6, 'Porque se llegó á Jehová, y no se apartó de él, sino que guardó los mandamientos que Jehová prescribió á Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 7, 'Y Jehová fué con él; y en todas las cosas á que salía prosperaba. El se rebeló contra el rey de Asiria, y no le sirvió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 8, 'Hirió también á los Filisteos hasta Gaza y sus términos, desde las torres de las atalayas hasta la ciudad fortalecida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 9, 'En el cuarto año del rey Ezechîas, que era el año séptimo de Oseas hijo de Ela rey de Israel, subió Salmanasar rey de los Asirios contra Samaria, y cercóla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 10, 'Y tomáronla al cabo de tres años: esto es, en el sexto año de Ezechîas, el cual era el año nono de Oseas rey de Israel, fué Samaria tomada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 11, 'Y el rey de Asiria traspuso á Israel á Asiria, y púsolos en Hala, y en Habor, junto al río de Gozán, y en las ciudades de los Medos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 12, 'Por cuanto no habían atendido la voz de Jehová su Dios, antes habían quebrantado su pacto; y todas las cosas que Moisés siervo de Jehová había mandado, ni las habían escuchado, ni puesto por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 13, 'Y á los catorce años del rey Ezechîas, subió Sennachêrib rey de Asiria contra todas las ciudades fuertes de Judá, y tomólas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 14, 'Entonces Ezechîas rey de Judá envió á decir al rey de Asiria en Lachîs: Yo he pecado: vuélvete de mí, y llevaré todo lo que me impusieres. Y el rey de Asiria impuso á Ezechîas rey de Judá trescientos talentos de plata, y treinta talentos de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 15, 'Dió por tanto Ezechîas toda la plata que fué hallada en la casa de Jehová, y en los tesoros de la casa real.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 16, 'Entonces descompuso Ezechîas las puertas del templo de Jehová, y los quiciales que el mismo rey Ezechîas había cubierto de oro, y diólo al rey de Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 17, 'Después el rey de Asiria envió al rey Ezechîas, desde Lachîs contra Jerusalem, á Thartán y á Rabsaris y á Rabsaces, con un grande ejército: y subieron, y vinieron á Jerusalem. Y habiendo subido, vinieron y pararon junto al conducto del estanque de arriba, que es en el camino de la heredad del batanero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 18, 'Llamaron luego al rey, y salió á ellos Eliacim hijo de Hilcías, que era mayordomo, y Sebna escriba, y Joah hijo de Asaph, canciller.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 19, 'Y díjoles Rabsaces: Decid ahora á Ezechîas: Así dice el gran rey de Asiria: ¿Qué confianza es esta en que tú estás?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 20, 'Dices, (por cierto palabras de labios): Consejo tengo y esfuerzo para la guerra. Mas ¿en qué confías, que te has rebelado contra mí?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 21, 'He aquí tú confías ahora en este bordón de caña cascada, en Egipto, en el que si alguno se apoyare, entrarále por la mano, y se le pasará. Tal es Faraón rey de Egipto, para todos los que en él confían.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 22, 'Y si me decís: Nosotros confiamos en Jehová nuestro Dios: ¿no es aquél cuyos altos y altares ha quitado Ezechîas, y ha dicho á Judá y á Jerusalem: Delante de este altar adoraréis en Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 23, 'Por tanto, ahora yo te ruego que des rehenes á mi señor, el rey de Asiria, y yo te daré dos mil caballos, si tú pudieres dar jinetes para ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 24, '¿Cómo pues harás volver el rostro de un capitán el menor de los siervos de mi señor, aunque estés confiado en Egipto por sus carros y su gente de á caballo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 25, 'Además, ¿he venido yo ahora sin Jehová á este lugar, para destruirlo? Jehová me ha dicho: Sube á esta tierra, y destrúyela.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 26, 'Entonces dijo Eliacim hijo de Hilcías, y Sebna y Joah, á Rabsaces: Ruégote que hables á tus siervos siriaco, porque nosotros lo entendemos, y no hables con nosotros judaico á oídos del pueblo que está sobre el muro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 27, 'Y Rabsaces les dijo: ¿Hame enviado mi señor á ti y á tu señor para decir estas palabras, y no antes á los hombres que están sobre el muro, para comer su estiércol, y beber el agua de sus pies con vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 28, 'Paróse luego Rabsaces, y clamó á gran voz en judaico, y habló, diciendo: Oid la palabra del gran rey, el rey de Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 29, 'Así ha dicho el rey: No os engañe Ezechîas, porque no os podrá librar de mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 30, 'Y no os haga Ezechîas confiar en Jehová, diciendo: De cierto nos librará Jehová, y esta ciudad no será entregada en mano del rey de Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 31, 'No oigáis á Ezechîas, porque así dice el rey de Asiria: Haced conmigo paz, y salid á mí, y cada uno comerá de su vid, y de su higuera, y cada uno beberá las aguas de su pozo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 32, 'Hasta que yo venga, y os lleve á una tierra como la vuestra, tierra de grano y de vino, tierra de pan y de viñas, tierra de olivas, de aceite, y de miel; y viviréis, y no moriréis. No oigáis á Ezechîas, porque os engaña cuando dice: Jehová nos librará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 33, '¿Acaso alguno de los dioses de las gentes ha librado su tierra de la mano del rey de Asiria?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 34, '¿Dónde está el dios de Hamath, y de Arphad? ¿dónde el dios de Sepharvaim, de Hena, y de Hiva? ¿pudieron éstos librar á Samaria de mi mano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 35, '¿Qué dios de todos los dioses de las provincias ha librado á su provincia de mi mano, para que libre Jehová de mi mano á Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 36, 'Y el pueblo calló, que no le respondieron palabra: porque había mandamiento del rey, el cual había dicho: No le respondáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 18, 37, 'Entonces Eliacim hijo de Hilcías, que era mayordomo, y Sebna el escriba, y Joah hijo de Asaph, canciller, vinieron á Ezechîas, rotos sus vestidos, y recitáronle las palabras de Rabsaces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 1, 'Y COMO el rey Ezechîas lo oyó, rasgó sus vestidos, y cubrióse de saco, y entróse en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 2, 'Y envió á Eliacim el mayordomo, y á Sebna escriba, y á los ancianos de los sacerdotes, vestidos de sacos á Isaías profeta hijo de Amós,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 3, 'Que le dijesen: Así ha dicho Ezechîas: Este día es día de angustia, y de reprensión, y de blasfemia; porque los hijos han venido hasta la rotura, y la que pare no tiene fuerzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 4, 'Quizá oirá Jehová tu Dios todas las palabras de Rabsaces, al cual el rey de los Asirios su señor ha enviado para injuriar al Dios vivo, y á vituperar con palabras, las cuales Jehová tu Dios ha oído: por tanto, eleva oración por las reliquias que aun se hallan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 5, 'Vinieron pues los siervos del rey Ezechîas á Isaías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 6, 'E Isaías les respondió: Así diréis á vuestro señor: Así ha dicho Jehová; No temas por las palabras que has oído, con las cuales me han blasfemado los siervos del rey de Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 7, 'He aquí pondré yo en él un espíritu, y oirá rumor, y volveráse á su tierra: y yo haré que en su tierra caiga á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 8, 'Y regresando Rabsaces, halló al rey de Asiria combatiendo á Libna; porque había oído que se había partido de Lachîs.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 9, 'Y oyó decir de Thiraca rey de Ethiopía: He aquí es salido para hacerte guerra. Entonces volvió él, y envió embajadores á Ezechîas, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 10, 'Así diréis á Ezechîas rey de Judá: No te engañe tu Dios en quien tú confías, para decir: Jerusalem no será entregada en mano del rey de Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 11, 'He aquí tú has oído lo que han hecho los reyes de Asiria á todas las tierras, destruyéndolas; ¿y has tú de escapar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 12, '¿Libráronlas los dioses de las gentes, que mis padres destruyeron, es á saber, Gozán, y Harán, y Reseph, y los hijos de Edén que estaban en Thalasar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 13, '¿Dónde está el rey de Hamath, el rey de Arphad, el rey de la ciudad de Sepharvaim, de Hena, y de Hiva?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 14, 'Y tomó Ezechîas las letras de mano de los embajadores; y después que las hubo leído, subió á la casa de Jehová, y extendiólas Ezechîas delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 15, 'Y oró Ezechîas delante de Jehová, diciendo: Jehová Dios de Israel, que habitas entre los querubines, tú solo eres Dios de todos los reinos de la tierra; tú hiciste el cielo y la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 16, 'Inclina, oh Jehová, tu oído, y oye; abre, oh Jehová, tus ojos, y mira: y oye las palabras de Sennachêrib, que ha enviado á blasfemar al Dios viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 17, 'Es verdad, oh Jehová, que los reyes de Asiria han destruído las gentes y sus tierras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 18, 'Y que pusieron en el fuego á sus dioses, por cuanto ellos no eran dioses, sino obra de manos de hombres, madera ó piedra, y así los destruyeron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 19, 'Ahora pues, oh Jehová Dios nuestro, sálvanos, te suplico, de su mano, para que sepan todos los reinos de la tierra que tú solo, Jehová, eres Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 20, 'Entonces Isaías hijo de Amós envió á decir á Ezechîas: Así ha dicho Jehová, Dios de Israel: Lo que me rogaste acerca de Sennachêrib rey de Asiria, he oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 21, 'Esta es la palabra que Jehová ha hablado contra él: Hate menospreciado, hate escarnecido la virgen hija de Sión; ha movido su cabeza detrás de ti la hija de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 22, '¿A quién has injuriado y á quién has blasfemado? ¿y contra quién has hablado alto, y has alzado en alto tus ojos? Contra el Santo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 23, 'Por mano de tus mensajeros has proferido injuria contra el Señor, y has dicho: Con la multitud de mis carros he subido á las cumbres de los montes, á las cuestas del Líbano; y cortaré sus altos cedros, sus hayas escogidas; y entraré á la morada de su término, al monte de su Carmel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 24, 'Yo he cavado y bebido las aguas ajenas, y he secado con las plantas de mis pies todos los ríos de lugares bloqueados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 25, '¿Nunca has oído que mucho tiempo ha yo lo hice, y de días antiguos lo he formado? Y ahora lo he hecho venir, y fué para desolación de ciudades fuertes en montones de ruinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 26, 'Y sus moradores, cortos de manos, quebrantados y confusos, fueron cual hierba del campo, como legumbre verde, y heno de los tejados, que antes que venga á madurez es seco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 27, 'Yo he sabido tu asentarte, tu salir y tu entrar, y tu furor contra mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 28, 'Por cuanto te has airado contra mí, y tu estruendo ha subido á mis oídos, yo por tanto pondré mi anzuelo en tus narices, y mi bocado en tus labios, y te haré volver por el camino por donde viniste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 29, 'Y esto te será por señal Ezechîas: Este año comerás lo que nacerá de suyo, y el segundo año lo que nacerá de suyo; y el tercer año haréis sementera, y segaréis, y plantaréis viñas, y comeréis el fruto de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 30, 'Y lo que hubiere escapado, lo que habrá quedado de la casa de Judá, tornará á echar raíz abajo, y hará fruto arriba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 31, 'Porque saldrán de Jerusalem reliquias, y los que escaparán, del monte de Sión: el celo de Jehová de los ejércitos hará esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 32, 'Por tanto, Jehová dice así del rey de Asiria: No entrará en esta ciudad, ni echará saeta en ella; ni vendrá delante de ella escudo, ni será echado contra ella baluarte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 33, 'Por el camino que vino se volverá, y no entrará en esta ciudad, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 34, 'Porque yo ampararé á esta ciudad para salvarla, por amor de mí, y por amor de David mi siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 35, 'Y aconteció que la misma noche salió el ángel de Jehová, é hirió en el campo de los Asirios ciento ochenta y cinco mil; y como se levantaron por la mañana, he aquí los cuerpos de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 36, 'Entonces Sennachêrib, rey de Asiria se partió, y se fué y tornó á Nínive, donde se estuvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 19, 37, 'Y aconteció que, estando él adorando en el templo de Nisroch su dios, Adramelech y Saresar sus hijos lo hirieron á cuchillo; y huyéronse á tierra de Ararat. Y reinó en su lugar Esar-hadón su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 1, 'EN aquellos días cayó Ezechîas enfermo de muerte, y vino á él Isaías profeta hijo de Amós, y díjole: Jehová dice así: Dispón de tu casa, porque has de morir, y no vivirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 2, 'Entonces volvió él su rostro á la pared, y oró á Jehová, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 3, 'Ruégote, oh Jehová, ruégote hagas memoria de que he andado delante de ti en verdad é íntegro corazón, y que he hecho las cosas que te agradan. Y lloró Ezechîas con gran lloro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 4, 'Y antes que Isaías saliese hasta la mitad del patio, fué palabra de Jehová á Isaías, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 5, 'Vuelve, y di á Ezechîas, príncipe de mi pueblo: Así dice Jehová, el Dios de David tu padre: Yo he oído tu oración, y he visto tus lágrimas: he aquí yo te sano; al tercer día subirás á la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 6, 'Y añadiré á tus días quince años, y te libraré á ti y á esta ciudad de mano del rey de Asiria; y ampararé esta ciudad por amor de mí, y por amor de David mi siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 7, 'Y dijo Isaías: Tomad masa de higos. Y tomándola, pusieron sobre la llaga, y sanó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 8, 'Y Ezechîas había dicho á Isaías: ¿Qué señal tendré de que Jehová me sanará, y que subiré á la casa de Jehová al tercer día?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 9, 'Y respondió Isaías: Esta señal tendrás de Jehová, de que hará Jehová esto que ha dicho: ¿Avanzará la sombra diez grados, ó retrocederá diez grados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 10, 'Y Ezechîas respondió: Fácil cosa es que la sombra decline diez grados: pero, que la sombra vuelva atrás diez grados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 11, 'Entonces el profeta Isaías clamó á Jehová; é hizo volver la sombra por los grados que había descendido en el reloj de Achâz, diez grados atrás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 12, 'En aquel tiempo Berodach-baladán hijo de Baladán, rey de Babilonia, envió letras y presentes á Ezechîas, porque había oído que Ezechîas había caído enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 13, 'Y Ezechîas los oyó, y mostróles toda la casa de las cosas preciosas, plata, oro, y especiería, y preciosos ungüentos; y la casa de sus armas, y todo lo que había en sus tesoros: ninguna cosa quedó que Ezechîas no les mostrase, así en su casa como en todo su señorío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 14, 'Entonces el profeta Isaías vino al rey Ezechîas, y díjole: ¿Qué dijeron aquellos varones, y de dónde vinieron á ti? Y Ezechîas le respondió: De lejanas tierras han venido, de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 15, 'Y él le volvió á decir: ¿Qué vieron en tu casa? Y Ezechîas respondió: Vieron todo lo que había en mi casa; nada quedó en mis tesoros que no les mostrase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 16, 'Entonces Isaías dijo á Ezechîas: Oye palabra de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 17, 'He aquí vienen días, en que todo lo que está en tu casa, y todo lo que tus padres han atesorado hasta hoy, será llevado á Babilonia, sin quedar nada, dijo Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 18, 'Y de tus hijos que saldrán de ti, que habrás engendrado, tomarán; y serán eunucos en el palacio del rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 19, 'Entonces Ezechîas dijo á Isaías: La palabra de Jehová que has hablado, es buena. Después dijo: ¿Mas no habrá paz y verdad en mis días?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 20, 'Lo demás de los hechos de Ezechîas, y todo su vigor, y cómo hizo el estanque, y el conducto, y metió las aguas en la ciudad, ¿no está escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 20, 21, 'Y durmió Ezechîas con sus padres, y reinó en su lugar Manasés su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 1, 'DE doce años era Manasés cuando comenzó á reinar, y reinó en Jerusalem cincuenta y cinco años: el nombre de su madre fué Hepsiba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 2, 'E hizo lo malo en ojos de Jehová, según las abominaciones de las gentes que Jehová había echado delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 3, 'Porque él volvió á edificar los altos que Ezechîas su padre había derribado, y levantó altares á Baal, é hizo bosque, como había hecho Achâb rey de Israel: y adoró á todo el ejército del cielo, y sirvió á aquellas cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 4, 'Asimismo edificó altares en la casa de Jehová, de la cual Jehová había dicho: Yo pondré mi nombre en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 5, 'Y edificó altares para todo el ejército del cielo en los dos atrios de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 6, 'Y pasó á su hijo por fuego, y miró en tiempos, y fué agorero, é instituyó pythones y adivinos, multiplicando así el hacer lo malo en ojos de Jehová, para provocarlo á ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 7, 'Y puso una entalladura del bosque que él había hecho, en la casa de la cual había Jehová dicho á David y á Salomón su hijo: Yo pondré mi nombre para siempre en esta casa, y en Jerusalem, á la cual escogí de todas las tribus de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 8, 'Y no volveré á hacer que el pie de Israel sea movido de la tierra que dí á sus padres, con tal que guarden y hagan conforme á todas las cosas que yo les he mandado, y conforme á toda la ley que mi siervo Moisés les mandó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 9, 'Mas ellos no escucharon; y Manasés los indujo á que hiciesen más mal que las gentes que Jehová destruyó delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 10, 'Y habló Jehová por mano de sus siervos los profetas, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 11, 'Por cuanto Manasés rey de Judá ha hecho estas abominaciones, y ha hecho más mal que todo lo que hicieron los Amorrheos que fueron antes de él, y también ha hecho pecar á Judá en sus ídolos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 12, 'Por tanto, así ha dicho Jehová el Dios de Israel: He aquí yo traigo tal mal sobre Jerusalem y sobre Judá, que el que lo oyere, le retiñirán ambos oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 13, 'Y extenderé sobre Jerusalem el cordel de Samaria, y el plomo de la casa de Achâb: y yo limpiaré á Jerusalem como se limpia una escudilla, que después que la han limpiado, la vuelven sobre su haz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 14, 'Y desampararé las reliquias de mi heredad, y entregarlas he en manos de sus enemigos; y serán para saco y para robo á todos sus adversarios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 15, 'Por cuanto han hecho lo malo en mis ojos, y me han provocado á ira, desde el día que sus padres salieron de Egipto hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 16, 'Fuera de esto, derramó Manasés mucha sangre inocente en gran manera, hasta henchir á Jerusalem de cabo á cabo: además de su pecado con que hizo pecar á Judá, para que hiciese lo malo en ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 17, 'Lo demás de los hechos de Manasés, y todas las cosas que hizo, y su pecado que cometió, ¿no está todo escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 18, 'Y durmió Manasés con sus padres, y fué sepultado en el huerto de su casa, en el huerto de Uzza; y reinó en su lugar Amón su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 19, 'De veinte y dos años era Amón cuando comenzó á reinar, y reinó dos años en Jerusalem. El nombre de su madre fué Mesalemeth hija de Harus de Jotba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 20, 'E hizo lo malo en ojos de Jehová, como había hecho Manasés su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 21, 'Y anduvo en todos los caminos en que su padre anduvo, y sirvió á las inmundicias á las cuales había servido su padre, y á ellas adoró;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 22, 'Y dejó á Jehová el Dios de sus padres, y no anduvo en el camino de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 23, 'Y los siervos de Amón conspiraron contra él, y mataron al rey en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 24, 'Entonces el pueblo de la tierra hirió á todos los que habían conspirado contra el rey Amón; y puso el pueblo de la tierra por rey en su lugar á Josías su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 25, 'Lo demás de los hechos de Amón, que efectuara, ¿no está todo escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 21, 26, 'Y fué sepultado en su sepulcro en el huerto de Uzza, y reinó en su lugar Josías su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 1, 'CUANDO Josías comenzó á reinar era de ocho años, y reinó en Jerusalem treinta y un años. El nombre de su madre fué Idida hija de Adaía de Boscath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 2, 'E hizo lo recto en ojos de Jehová, y anduvo en todo el camino de David su padre, sin apartarse á diestra ni á siniestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 3, 'Y á los dieciocho años del rey Josías, fué que envió el rey á Saphán hijo de Azalía, hijo de Mesullam, escriba, á la casa de Jehová, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 4, 'Ve á Hilcías, sumo sacerdote: dile que recoja el dinero que se ha metido en la casa de Jehová, que han juntado del pueblo los guardianes de la puerta,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 5, 'Y que lo pongan en manos de los que hacen la obra, que tienen cargo de la casa de Jehová, y que lo entreguen á los que hacen la obra de la casa de Jehová, para reparar las aberturas de la casa:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 6, 'A los carpinteros, á los maestros y albañiles, para comprar madera y piedra de cantería para reparar la casa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 7, 'Y que no se les cuente el dinero cuyo manejo se les confiare, porque ellos proceden con fidelidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 8, 'Entonces dijo el sumo sacerdote Hilcías á Saphán escriba: El libro de la ley he hallado en la casa de Jehová. E Hilcías dió el libro á Saphán, y leyólo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 9, 'Viniendo luego Saphán escriba al rey, dió al rey la respuesta, y dijo: Tus siervos han juntado el dinero que se halló en el templo, y lo han entregado en poder de los que hacen la obra, que tienen cargo de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 10, 'Asimismo Saphán escriba declaró al rey, diciendo: Hilcías el sacerdote me ha dado un libro. Y leyólo Saphán delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 11, 'Y cuando el rey hubo oído las palabras del libro de la ley, rasgó sus vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 12, 'Luego mandó el rey á Hilcías el sacerdote, y á Ahicam hijo de Saphán, y á Achbor hijo de Michâía, y á Saphán escriba, y á Asaía siervo del rey, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 13, 'Id, y preguntad á Jehová por mí, y por el pueblo, y por todo Judá, acerca de las palabras de este libro que se ha hallado: porque grande ira de Jehová es la que ha sido encendida contra nosotros, por cuanto nuestros padres no escucharon las palabras de este libro, para hacer conforme á todo lo que nos fué escrito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 14, 'Entonces fué Hilcías el sacerdote, y Ahicam y Achbor y Saphán y Asaía, á Hulda profetisa, mujer de Sallum hijo de Ticva hijo de Araas, guarda de las vestiduras, la cual moraba en Jerusalem en la segunda parte de la ciudad, y hablaron con ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 15, 'Y ella les dijo: Así ha dicho Jehová el Dios de Israel: Decid al varón que os envió á mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 16, 'Así dijo Jehová: He aquí yo traigo mal sobre este lugar, y sobre los que en él moran, á saber, todas las palabras del libro que ha leído el rey de Judá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 17, 'Por cuanto me dejaron á mí, y quemaron perfumes á dioses ajenos, provocándome á ira en toda obra de sus manos; y mi furor se ha encendido contra este lugar, y no se apagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 18, 'Mas al rey de Judá que os ha enviado para que preguntaseis á Jehová, diréis así: Así ha dicho Jehová el Dios de Israel: Por cuanto oíste las palabras del libro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 19, 'Y tu corazón se enterneció, y te humillaste delante de Jehová, cuando oíste lo que yo he pronunciado contra este lugar y contra sus moradores, que vendrían á ser asolados y malditos, y rasgaste tus vestidos, y lloraste en mi presencia, también yo te he oído, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 22, 20, 'Por tanto, he aquí yo te recogeré con tus padres, y tú serás recogido á tu sepulcro en paz, y no verán tus ojos todo el mal que yo traigo sobre este lugar. Y ellos dieron al rey la respuesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 1, 'ENTONCES el rey envió, y juntaron á él todos los ancianos de Judá y de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 2, 'Y subió el rey á la casa de Jehová con todos los varones de Judá, y con todos los moradores de Jerusalem, con los sacerdotes y profetas y con todo el pueblo, desde el más chico hasta el más grande; y leyó, oyéndolo ellos, todas las palabras del libro del pacto que había sido hallado en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 3, 'Y poniéndose el rey en pie junto á la columna, hizo alianza delante de Jehová, de que irían en pos de Jehová, y guardarían sus mandamientos, y sus testimonios, y sus estatutos, con todo el corazón y con toda el alma, y que cumplirían las palabras de la alianza que estaban escritas en aquel libro. Y todo el pueblo confirmó el pacto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 4, 'Entonces mandó el rey al sumo sacerdote Hilcías, y á los sacerdotes de segundo orden, y á los guardianes de la puerta, que sacasen del templo de Jehová todos los vasos que habían sido hechos para Baal, y para el bosque, y para toda la milicia del cielo; y quemólos fuera de Jerusalem en el campo de Cedrón, é hizo llevar las cenizas de ellos á Beth-el.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 5, 'Y quitó á los Camoreos, que habían puesto los reyes de Judá para que quemasen perfumes en los altos en las ciudades de Judá, y en los alrededores de Jerusalem; y asimismo á los que quemaban perfumes á Baal, al sol y á la luna, y á los signos, y á todo el ejército del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 6, 'Hizo también sacar el bosque fuera de la casa de Jehová, fuera de Jerusalem, al torrente de Cedrón, y quemólo en el torrente de Cedrón, y tornólo en polvo, y echó el polvo de él sobre los sepulcros de los hijos del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 7, 'Además derribó las casas de los sodomitas que estaban en la casa de Jehová, en las cuales tejían las mujeres pabellones para el bosque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 8, 'E hizo venir todos los sacerdotes de las ciudades de Judá, y profanó los altos donde los sacerdotes quemaban perfumes, desde Gabaa hasta Beer-seba; y derribó los altares de las puertas que estaban á la entrada de la puerta de Josué, gobernador de la ciudad, que estaban á la mano izquierda, á la puerta de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 9, 'Empero los sacerdotes de los altos no subían al altar de Jehová en Jerusalem, mas comían panes sin levadura entre sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 10, 'Asimismo profanó á Topheth, que está en el valle del hijo de Hinnom, porque ninguno pasase su hijo ó su hija por fuego á Moloch.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 11, 'Quitó también los caballos que los reyes de Judá habían dedicado al sol á la entrada del templo de Jehová, junto á la cámara de Nathan-melech eunuco, el cual tenía cargo de los ejidos; y quemó al fuego los carros del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 12, 'Derribó además el rey los altares que estaban sobre la techumbre de la sala de Achâz, que los reyes de Judá habían hecho, y los altares que había hecho Manasés en los dos atrios de la casa de Jehová; y de allí corrió y arrojó el polvo en el torrente de Cedrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 13, 'Asimismo profanó el rey los altos que estaban delante de Jerusalem, á la mano derecha del monte de la destrucción, los cuales Salomón rey de Israel había edificado á Astharoth, abominación de los Sidonios, y á Chêmos abominación de Moab, y á Milcom abominación de los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 14, 'Y quebró las estatuas, y taló los bosques, é hinchió el lugar de ellos de huesos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 15, 'Igualmente el altar que estaba en Beth-el, y el alto que había hecho Jeroboam hijo de Nabat, el que hizo pecar á Israel, aquel altar y el alto destruyó; y quemó el alto, y lo tornó en polvo, y puso fuego al bosque.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 16, 'Y volvióse Josías, y viendo los sepulcros que estaban allí en el monte, envió y sacó los huesos de los sepulcros, y quemólos sobre el altar para contaminarlo, conforme á la palabra de Jehová que había profetizado el varón de Dios, el cual había anunciado estos negocios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 17, 'Y después dijo: ¿Qué título es este que veo? Y los de la ciudad le respondieron: Este es el sepulcro del varón de Dios que vino de Judá, y profetizó estas cosas que tú has hecho sobre el altar de Beth-el.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 18, 'Y él dijo: Dedjadlo; ninguno mueva sus huesos: y así fueron preservados sus huesos, y los huesos del profeta que había venido de Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 19, 'Y todas las casas de los altos que estaban en las ciudades de Samaria, las cuales habían hecho los reyes de Israel para provocar á ira, quitólas también Josías, é hizo de ellas como había hecho en Beth-el.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 20, 'Mató además sobre los altares á todos los sacerdotes de los altos que allí estaban, y quemó sobre ellos huesos de hombres, y volvióse á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 21, 'Entonces mandó el rey á todo el pueblo, diciendo: Haced la pascua á Jehová vuestro Dios, conforme á lo que está escrito en el libro de esta alianza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 22, 'No fué hecha tal pascua desde los tiempos de los jueces que gobernaron á Israel, ni en todos los tiempos de los reyes de Israel, y de los reyes de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 23, 'A los diez y ocho años del rey Josías fué hecha aquella pascua á Jehová en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 24, 'Asimismo barrió Josías los pythones, adivinos, y terapheos, y todas las abominaciones que se veían en la tierra de Judá y en Jerusalem, para cumplir las palabras de la ley que estaban escritas en el libro que el sacerdote Hilcías había hallado en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 25, 'No hubo tal rey antes de él que se convirtiese á Jehová de todo su corazón, y de toda su alma, y de todas su fuerzas, conforme á toda la ley de Moisés; ni después de él nació otro tal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 26, 'Con todo eso, no se volvió Jehová del ardor de su grande ira, con que se había encendido su enojo contra Judá, por todas las provocaciones con que Manasés le había irritado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 27, 'Y dijo Jehová: También he de quitar de mi presencia á Judá, como quité á Israel, y abominaré á esta ciudad que había escogido, á Jerusalem, y á la casa de la cual había yo dicho: Mi nombre será allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 28, 'Lo demás de los hechos de Josías, y todas las cosas que hizo, ¿no está todo escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 29, 'En aquellos días Faraón Nechâo rey de Egipto subió contra el rey de Asiria al río Eufrates, y salió contra él el rey Josías; pero aquél así que le vió, matólo en Megiddo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 30, 'Y sus siervos lo pusieron en un carro, y trajéronlo muerto de Megiddo á Jerusalem, y sepultáronlo en su sepulcro. Entonces el pueblo de la tierra tomó á Joachâz hijo de Josías, y ungiéronle y pusiéronlo por rey en lugar de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 31, 'De veintitrés años era Joachâz cuando comenzó á reinar, y reinó tres meses en Jerusalem. El nombre de su madre fué Amutal, hija de Jeremías de Libna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 32, 'Y él hizo lo malo en ojos de Jehová, conforme á todas las cosas que sus padres habían hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 33, 'Y echólo preso Faraón Nechâo en Ribla en la provincia de Hamath, reinando él en Jerusalem; é impuso sobre la tierra una multa de cien talentos de plata, y uno de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 34, 'Entonces Faraón Nechâo puso por rey á Eliacim hijo de Josías, en lugar de Josías su padre, y mudóle el nombre en el de Joacim; y tomó á Joachâz, y llevólo á Egipto, y murió allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 35, 'Y Joacim pagó á Faraón la plata y el oro; mas hizo apreciar la tierra para dar el dinero conforme al mandamiento de Faraón, sacando la plata y oro del pueblo de la tierra, de cada uno según la estimación de su hacienda, para dar á Faraón Nechâo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 36, 'De veinticinco años era Joacim cuando comenzó á Reinar, y once años reinó en Jerusalem. El nombre de su madre fué Zebuda hija de Pedaia, de Ruma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 23, 37, 'E hizo lo malo en ojos de Jehová, conforme á todas las cosas que sus padres habían hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 1, 'EN su tiempo subió Nabucodonosor rey de Babilonia, al cual sirvió Joacim tres años; volvióse luego, y se rebeló contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 2, 'Jehová empero envió contra él tropas de Caldeos, y tropas de Siros, y tropas de Moabitas, y tropas de Ammonitas; los cuales envió contra Judá para que la destruyesen, conforme á la palabra de Jehová que había hablado por sus siervos los profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 3, 'Ciertamente vino esto contra Judá por dicho de Jehová, para quitarla de su presencia, por los pecados de Manasés, conforme á todo lo que hizo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 4, 'Asimismo por la sangre inocente que derramó, pues hinchió á Jerusalem de sangre inocente: Jehová por tanto, no quiso perdonar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 5, 'Lo demás de los hechos de Joacim, y todas las cosas que hizo, ¿no está escrito en el libro de las crónicas de los reyes de Judá?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 6, 'Y durmió Joacim con sus padres, y reinó en su lugar Joachîn su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 7, 'Y nunca más el rey de Egipto salió de su tierra: porque el rey de Babilonia le tomó todo lo que era suyo, desde el río de Egipto hasta el río de Eufrates.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 8, 'De dieciocho años era Joachîn cuando comenzó á reinar, y reinó en Jerusalem tres meses. El nombre de su madre fué Neusta hija de Elnathán, de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 9, 'E hizo lo malo en ojos de Jehová, conforme á todas las cosas que había hecho su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 10, 'En aquel tiempo subieron los siervos de Nabucodonosor rey de Babilonia contra Jerusalem y la ciudad fué cercada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 11, 'Vino también Nabucodonosor rey de Babilonia contra la ciudad, cuando sus siervos la tenían cercada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 12, 'Entonces salió Joachîn rey de Judá al rey de Babilonia, él, y su madre, y sus siervos, y sus príncipes, y sus eunucos: y prendiólo el rey de Babilonia en el octavo año de su reinado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 13, 'Y sacó de allí todos los tesoros de la casa de Jehová, y los tesoros de la casa real, y quebró en piezas todos los vasos de oro que había hecho Salomón rey de Israel en la casa de Jehová, como Jehová había dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 14, 'Y llevó en cautiverio á toda Jerusalem, á todos los príncipes, y á todos los hombres valientes, hasta diez mil cautivos, y á todos los oficiales y herreros; que no quedó nadie, excepto los pobres del pueblo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 15, 'Asimismo trasportó á Joachîn á Babilonia, y á la madre del rey, y á las mujeres del rey, y á sus eunucos, y á los poderosos de la tierra; cautivos los llevó de Jerusalem á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 16, 'A todos los hombre de guerra, que fueron siete mil, y á los oficiales y herrreros, que fueron mil, y á todos los valientes para hacer la guerra, llevó cautivos el rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 17, 'Y el rey de Babilonia puso por rey en lugar de Joachîn á Mathanías su tío, y mudóle el nombre en el de Sedecías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 18, 'De veintiún años era Sedecías cuando comenzó á reinar, y reinó en Jerusalem once años. El nombre de su madre fué Amutal hija de Jeremías, de Libna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 19, 'E hizo lo malo en ojos de Jehová, conforme á todo lo que había hecho Joacim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 24, 20, 'Fué pues la ira de Jehová contra Jerusalem y Judá, hasta que los echó de su presencia. Y Sedecías se rebeló contra el rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 1, 'Y ACONTECIO á los nueve años de su reinado, en el mes décimo, á los diez del mes, que Nabucodonosor rey de Babilonia vino con todo su ejército contra Jerusalem, y cercóla; y levantaron contra ella ingenios alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 2, 'Y estuvo la ciudad cercada hasta el undécimo año del rey Sedecías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 3, 'A los nueve del mes prevaleció el hambre en la ciudad, que no hubo pan para el pueblo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 4, 'Abierta ya la ciudad, huyeron de noche todos los hombres de guerra por el camino de la puerta que estaba entre los dos muros, junto á los huertos del rey, estando los Caldeos alrededor de la ciudad; y el rey se fué camino de la campiña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 5, 'Y el ejército de los Caldeos siguió al rey, y tomólo en las llanuras de Jericó, habiéndose esparcido de él todo su ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 6, 'Tomado pues el rey, trajéronle al rey de Babilonia á Ribla, y profirieron contra él sentencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 7, 'Y degollaron á los hijos de Sedecías en presencia suya; y á Sedecías sacaron los ojos, y atado con cadenas lleváronlo á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 8, 'En el mes quinto, á los siete del mes, siendo el año diecinueve de Nabucodonosor rey de Babilonia, vino á Jerusalem Nabuzaradán, capitán de los de la guardia, siervo del rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 9, 'Y quemó la casa de Jehová, y la casa del rey, y todas las casas de Jerusalem; y todas las casas de los príncipes quemó á fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 10, 'Y todo el ejército de los Caldeos que estaba con el capitán de la guardia, derribó los muros de Jerusalem alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 11, 'Y á los del pueblo que habían quedado en la ciudad, y á los que se habían juntado al rey de Babilonia, y á los que habían quedado del vulgo, trasportólo Nabuzaradán, capitán de los de la guardia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 12, 'Mas de los pobres de la tierra dejó Nabuzaradán, capitán de los de la guardia, para que labrasen las viñas y las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 13, 'Y quebraron los Caldeos las columnas de bronce que estaban en la casa de Jehová, y las basas, y el mar de bronce que estaba en la casa de Jehová, y llevaron el metal de ello á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 14, 'Lleváronse también los calderos, y las paletas, y las tenazas, y los cucharones, y todos los vasos de metal con que ministraban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 15, 'Incensarios, cuencos, los que de oro, en oro, y los que de plata, en plata, todo lo llevó el capitán de los de la guardia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 16, 'Las dos columnas, un mar, y las basas que Salomón había hecho para la casa de Jehová: no había peso de todos estos vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 17, 'La altura de la una columna era diez y ocho codos y tenía encima un capitel de bronce, y la altura del capitel era de tres codos; y sobre el capitel había un enredado y granadas alrededor, todo de bronce: y semejante obra había en la otra columna con el enredado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 18, 'Tomó entonces el capitán de los de la guardia á Saraías primer sacerdote, y á Sophonías segundo sacerdote, y tres guardas de la vajilla;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 19, 'Y de la ciudad tomó un eunuco, el cual era maestre de campo, y cinco varones de los continuos del rey, que se hallaron en la ciudad; y al principal escriba del ejército, que hacía la reseña de la gente del país; y sesenta varones del pueblo de la tierra, que se hallaron en la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 20, 'Estos tomó Nabuzaradán, capitán de los de la guardia, y llevólos á Ribla al rey de Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 21, 'Y el rey de Babilonia los hirió y mató en Ribla, en tierra de Hamath. Así fué trasportado Judá de sobre su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 22, 'Y al pueblo que Nabucodonosor rey de Babilonia dejó en tierra de Judá, puso por gobernador á Gedalías, hijo de Ahicam hijo de Saphán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 23, 'Y oyendo todos los príncipes del ejército, ellos y su gente, que el rey de Babilonia había puesto por gobernador á Gedalías, viniéronse á él en Mizpa, es á saber, Ismael hijo de Nathanías, y Johanán hijo de Carea, y Saraía hijo de Tanhumet Netofatita, y Jaazanías hijo de Maachâti, ellos con los suyos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 24, 'Entonces Gedalías les hizo juramento, á ellos y á los suyos, y díjoles: No temáis de ser siervos de los Caldeos; habitad en la tierra, y servid al rey de Babilonia, y os irá bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 25, 'Mas en el mes séptimo vino Ismael hijo de Nathanías, hijo de Elisama, de la estirpe real, y con él diez varones, é hirieron á Gedalías, y murió: y también á los Judíos y Caldeos que estaban con él en Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 26, 'Y levantándose todo el pueblo, desde el menor hasta el mayor, con los capitanes del ejército, fuéronse á Egipto por temor de los Caldeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 27, 'Y aconteció á los treinta y siete años de la trasportación de Joachîn rey de Judá, en el mes duodécimo, á los veinte y siete del mes, que Evil-merodach rey de Babilonia, en el primer año de su reinado, levantó la cabeza de Joachîn rey de Judá, sacándolo de la casa de la cárcel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 28, 'Y hablóle bien, y puso su asiento sobre el asiento de los reyes que con él estaban en Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 29, 'Y mudóle los vestidos de su prisión, y comió siempre delante de él todos los días de su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2KI', '2 Reyes', 25, 30, 'Y fuéle diariamente dada su comida de parte del rey de continuo, todos los días de su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 1, 'ADAM, Seth, Enos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 2, 'Cainán, Mahalaleel, Jared,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 3, 'Enoch, Mathusalem, Lamech,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 4, 'Noé, Sem, Châm, y Japhet.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 5, 'Los hijos de Japhet: Gomer, Magog, Dadai, Javán, Tubal, Mesec, y Thiras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 6, 'Los hijos de Gomer: Askenaz, Riphath, y Thogorma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 7, 'Los hijos de Javán: Elisa, Tharsis, Chîthim, y Dodanim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 8, 'Los hijos de Châm: Chûs, Misraim, Phuth, y Canaán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 9, 'Los hijos de Chûs: Seba, Havila, Sabtha, Raema, y Sabtechâ. Y los hijos de Raema: Seba y Dedán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 10, 'Chûs engendró á Nimrod: éste comenzó á ser poderoso en la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 11, 'Misram engendró á Ludim, Ananim, Laabim, Nephtuim,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 12, 'Phetrusim y Casluim: de éstos salieron los Filisteos, y los Caphtoreos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 13, 'Canaán engendró á Sidón, su primogénito;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 14, 'Y al Hetheo, y al Jebuseo, y al Amorrheo, y al Gergeseo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 15, 'Y al Heveo, y al Araceo, y al Sineo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 16, 'Al Aradeo, y al Samareo, y al Hamatheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 17, 'Los hijos de Sem: Elam, Assur, Arphaxad, Lud, Aram, Hus, Hul, Gether, y Mesec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 18, 'Arphaxad engendró á Sela, y Sela engendró á Heber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 19, 'Y á Heber nacieron dos hijos: el nombre del uno fué Peleg, por cuanto en sus días fué dividida la tierra; y el nombre de su hermano fué Joctán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 20, 'Y Joctán engendró á Elmodad, Seleph, Asarmaveth, y Jera,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 21, 'A Adoram también, á Uzal, Dicla,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 22, 'Hebal, Abimael, Seba,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 23, 'Ophir, Havila, y Jobab: todos hijos de Joctán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 24, 'Sem, Arphaxad, Sela,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 25, 'Heber, Peleg, Reu,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 26, 'Serug, Nachôr, Thare,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 27, 'Y Abram, el cual es Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 28, 'Los hijos de Abraham: Isaac é Ismael.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 29, 'Y estas son sus descendencias: el primogénito de Ismael, Nabajoth; después Cedar, Adbeel, Misam,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 30, 'Misma, Duma, Maasa, Hadad, Thema, Jetur, Naphis, y Cedma. Estos son los hijos de Ismael.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 31, 'Y Cethura, concubina de Abraham, parió á Zimram, Jocsán, Medán, Madián, Isbac, y á Súa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 32, 'Los hijos de Jobsán: Seba y Dedán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 33, 'Los hijos de Madián: Epha, Epher, Henoch, Abida, y Eldaa; todos estos fueron hijos de Cethura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 34, 'Y Abraham engendró á Isaac: y los hijos de Isaac fueron Esaú é Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 35, 'Los hijos de Esaú: Eliphas, Rehuel, Jeus, Jalam, y Cora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 36, 'Los hijos de Eliphas: Themán, Omar, Sephi, Hatham, Chênas, Timna, y Amalec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 37, 'Los hijos de Rehuel: Nahath, Zera, Samma, y Mizza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 38, 'Los hijos de Seir: Lotán, Sobal, Sibeón, Ana, Disón, Eser, y Disán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 39, 'Los hijos de Lotán: Hori, y Homam: y Timna fué hermana de Lotán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 40, 'Los hijos de Sobal: Alian, Manahach, Ebal, Sephi y Oman. Los hijos de Sibehom: Aia, y Ana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 41, 'Disón fué hijo de Ana: y los hijos de Disón; Hamrán, Hesbán, Ithran y Chêrán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 42, 'Los hijos de Eser: Bilham, Zaaván, y Jaacán. Los hijos de Disán: Hus y Arán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 43, 'Y estos son los reyes que reinaron en la tierra de Edom, antes que reinase rey sobre los hijos de Israel Belah, hijo de Beor; y el nombre de su ciudad fué Dinaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 44, 'Y muerto Belah, reinó en su lugar Jobab, hijo de Zera, de Bosra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 45, 'Y muerto Jobab reinó en su lugar Husam, de la tierra de los Themanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 46, 'Muerto Husam, reinó en su lugar Adad, hijo de Bedad, el cual hirió á Madián en la campaña de Moab: y el nombre de su ciudad fué Avith.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 47, 'Muerto Adad, reinó en su lugar Samla, de Masreca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 48, 'Muerto también Samla, reinó en su lugar Saúl de Rehoboth, que está junto al río.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 49, 'Y muerto Saúl, reinó en su lugar Baal-hanán, hijo de Achbor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 50, 'Y muerto Baal-hanán, reinó en su lugar Adad, el nombre de cuya ciudad fué Pai; y el nombre de su mujer Meetabel, hija de Matred, y ésta de Mezaab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 51, 'Muerto Adad, sucedieron los duques en Edom: el duque Timna, el duque Alia, el duque Jetheth,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 52, 'El duque Oholibama, el duque Ela, el duque Phinón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 53, 'El duque Chênaz, el duque Themán, el duque Mibzar,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 1, 54, 'El duque Magdiel, el duque Iram. Estos fueron los duques de Edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 1, 'ESTOS son los hijos de Israel: Rubén, Simeón, Leví, Judá, Issachâr, Zabulón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 2, 'Dan, José, Benjamín, Nephtalí, Gad, y Aser.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 3, 'Los hijos de Judá: Er, Onán, y Sela. Estos tres le nacieron de la hija de Sua, Cananea. Y Er, primogénito de Judá, fué malo delante de Jehová; y matólo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 4, 'Y Thamar su nuera le parió á Phares y á Zara. Todos los hijos de Judá fueron cinco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 5, 'Los hijos de Phares: Hesrón y Hamul.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 6, 'Y los hijos de Zara: Zimri, Ethán, Hemán, y Calcol, y Darda; en todos cinco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 7, 'Hijo de Chârmi fué Achâr, el que alborotó á Israel, porque prevaricó en el anatema.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 8, 'Azaría fué hijo de Ethán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 9, 'Los hijos que nacieron á Hesrón: Jerameel, Ram, y Chêlubai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 10, 'Y Ram engendró á Aminadab; y Aminadab engendró á Nahasón, príncipe de los hijos de Judá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 11, 'Y Nahasón engendró á Salma, y Salma engendró á Booz;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 12, 'Y Booz engendró á Obed, y Obed engendró á Isaí;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 13, 'E Isaí engendró á Eliab, su primogénito, y el segundo Abinadab, y Sima el tercero;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 14, 'El cuarto Nathanael, el quinto Radai;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 15, 'El sexto Osem, el séptimo David:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 16, 'De los cuales Sarvia y Abigail fueron hermanas. Los hijos de Sarvia fueron tres: Abisai, Joab, y Asael.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 17, 'Abigail engendró á Amasa, cuyo padre fué Jether Ismaelita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 18, 'Caleb hijo de Hesrón engendró á Jerioth de su mujer Azuba. Y los hijos de ella fueron Jeser, Sobad, y Ardón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 19, 'Y muerta Azuba, tomó Caleb por mujer á Ephrata, la cual le parió á Hur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 20, 'Y Hur engendró á Uri, y Uri engendró á Bezaleel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 21, 'Después entró Hesrón á la hija de Machîr padre de Galaad, la cual tomó siendo él de sesenta años, y ella le parió á Segub.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 22, 'Y Segub engendró á Jair, el cual tuvo veintitrés ciudades en la tierra de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 23, 'Y Gesur y Aram tomaron las ciudades de Jair de ellos, y á Cenath con sus aldeas, sesenta lugares. Todos estos fueron de los hijos de Machîr padre de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 24, 'Y muerto Hesrón en Caleb de Ephrata, Abia mujer de Hesrón le parió á Ashur padre de Tecoa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 25, 'Y los hijos de Jerameel primogénito de Hesrón fueron Ram su primogénito, Buna, Orem, Osem, y Achîa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 26, 'Y tuvo Jerameel otra mujer llamada Atara, que fué madre de Onam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 27, 'Y los hijos de Ram primogénito de Jerameel fueron Maas, Jamín, y Acar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 28, 'Y los hijos de Onam fueron Sammai, y Jada. Los hijos de Sammai: Nadab, y Abisur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 29, 'Y el nombre de la mujer de Abisur fué Abihail, la cual le parió á Abán, y á Molib.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 30, 'Y los hijos de Nadab: Seled y Aphaim. Y Seled murió sin hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 31, 'E Isi fué hijo fué hijo de Aphaim; y Sesam, hijo de Isi; é hijo de Sesam, Alai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 32, 'Los hijos de Jada hermano de Simmai: Jether y Jonathán. Y murió Jether sin hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 33, 'Y los hijos de Jonathán: Peleth, y Zaza. Estos fueron los hijos de Jerameel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 34, 'Y Sesán no tuvo hijos, sino hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 35, 'Y tuvo Sesán un siervo Egipcio, llamado Jarha, al cual dió Sesán por mujer á su hija; y ella le parió á Athai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 36, 'Y Athai engendró á Nathán, y Nathán engendró á Zabad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 37, 'Y Zabad engendró á Ephlal, y Ephlal engendró á Obed;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 38, 'Y Obed engendró á Jehú, y Jehú engendró á Azarías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 39, 'Y Azarías engendró á Heles, Heles engedró á Elasa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 40, 'Elasa engendró á Sismai, y Sismai engendró á Sallum;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 41, 'Y Sallum engendró á Jecamía, y Jecamía engendró á Elisama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 42, 'Los hijos de Caleb hermano de Jerameel fueron Mesa su primogénito, que fué el padre de Ziph; y los hijos de Maresa padre de Hebrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 43, 'Y los hijos de Hebrón: Core, y Thaphua, y Recem, y Sema.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 44, 'Y Sema engendró á Raham, padre de Jorcaam; y Recem engendró á Sammai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 45, 'Maón fué hijo de Sammai, y Maón padre de Beth-zur.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 46, 'Y Epha, concubina de Caleb, le parió á Harán, y á Mosa, y á Gazez. Y Harán engendró á Gazez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 47, 'Y los hijos de Joddai: Regem, Jotham, Gesán, Pelet, Epho, y Saaph.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 48, 'Maachâ, concubina de Caleb, le parió á Sebet, y á Thirana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 49, 'Y también le parió á Saaph padre de Madmannah, y á Seva padre de Macbena, y padre de Ghiba. Y Achsa fué hija de Caleb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 50, 'Estos fueron los hijos de Caleb, hijo de Hur, primogénito de Ephrata: Sobal, padre de Chîriath-jearim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 51, 'Salma, padre de Beth-lehem; Hareph, padre de Beth-gader.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 52, 'Y los hijos de Sobal padre de Chîriath-jearim fueron Haroeh, la mitad de los Manahethitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 53, 'Y las familias de Chîriath-jearim fueron los Ithreos, y los Phuteos, y los Samatheos, y los Misraiteos; de los cuales salieron los Soratitas, y los Estaolitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 54, 'Los hijos de Salma: Beth-lehem, y los Nethophatitas, los cuales son las coronas de la casa de Joab, y de la mitad de los Manahethitas, los Soraitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 2, 55, 'Y las familias de los escribas, que moraban en Jabes, fueron los Thiratheos, Simatheos, Sucatheos; los cuales son los Cineos que vinieron de Hamath, padre de la casa de Rechâb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 1, 'ESTOS son los hijos de David, que le nacieron en Hebrón: Amnón el primogénito, de Achînoam Jezreelita; el segundo Daniel, de Abigail de Carmelo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 2, 'El tercero, Absalom, hijo de Maachâ hija de Talmai rey de Gesur; el cuarto, Adonías hijo de Aggith;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 3, 'El quinto, Sephatías, de Abithal; el sexto, Itream, de Egla su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 4, 'Estos seis le nacieron en Hebrón, donde reinó siete años y seis meses: y en Jerusalem reinó treinta y tres años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 5, 'Estos cuatro le nacieron en Jerusalem: Simma, Sobab, Nathán, y Salomón, de Beth-sua hija de Ammiel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 6, 'Y otros nueve: Ibaar, Elisama, y Eliphelet,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 7, 'Noga, Nepheg, y Japhia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 8, 'Elisama, Eliada, y Eliphelet.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 9, 'Todos estos fueron los hijos de David, sin los hijos de las concubinas. Y Thamar fué hermana de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 10, 'Hijo de Salomón fué Roboam, cuyo hijo fué Abía, del cual fué hijo Asa, cuyo hijo fué Josaphat;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 11, 'De quien fué hijo Joram, cuyo hijo fué Ochôzias, hijo del cual fué Joas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 12, 'Del cual fué hijo Amasías, cuyo hijo fué Azarías, é hijo de éste Jotham;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 13, 'E hijo del cual fué Achâz, del que fué hijo Ezechîas, cuyo hijo fué Manasés;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 14, 'Del cual fué hijo Amón, cuyo hijo fué Josías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 15, 'Y los hijos de Josías: Johanán su primogénito, el segundo Joacim, el tercero Sedecías, el cuarto Sallum.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 16, 'Los hijos de Joacim: Jechônías su hijo, hijo del cual fué Sedecías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 17, 'Y los hijos de Jechônías: Asir, Salathiel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 18, 'Mechiram, Pedaía, Seneaser, y Jecamía, Hosama, y Nedabía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 19, 'Y los hijos de Pedaía: Zorobabel, y Simi. Y los hijos de Zorobabel: Mesullam, Hananías, y Selomith su hermana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 20, 'Y de Mesullam: Hasuba, Ohel, y Berechîas, Hasadía, y Jusabhesed; cinco en todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 21, 'Los hijos de Hananías: Pelatías, y Jesaías, hijo de Rephaías, hijo de Arnán, hijo de Obdías, hijo de Sechânías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 22, 'Hijo de Sechânías: Hattus, Igheal, Barias, Nearías, y Saphat; seis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 23, 'Los hijos de Nearías fueron estos tres: Elioenai, Ezechîas, y Azricam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 3, 24, 'Los hijos de Elioenai fueron estos siete: Odavias, Eliasib, Pelaías, Accub, Johanán, Dalaías, y Anani.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 1, 'LOS hijos de Judá: Phares, Hesrón, Carmi, Hur, y Sobal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 2, 'Y Reaías hijo de Sobal, engendró á Jahath; y Jahath engendró á Ahumai y á Laad. Estas son las familias de los Sorathitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 3, 'Y estas son las del padre de Etham: Jezreel, Isma, é Ibdas. Y el nombre de su hermana fué Haslelponi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 4, 'Y Penuel fué padre de Gedor, y Ezer padre de Husa. Estos fueron los hijos de Hur, primogénito de Ephrata, padre de Beth-lehem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 5, 'Y Asur padre de Tecoa tuvo dos mujeres, á saber, Helea, y Naara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 6, 'Y Naara le parió á Auzam, y á Hepher, á Themeni, y á Ahastari. Estos fueron los hijos de Naara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 7, 'Y los hijos de Helea: Sereth, Jesohar, Ethnán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 8, 'Y Cos engendró á Anob, y á Sobeba, y la familia de Aharhel hijo de Arum.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 9, 'Y Jabes fué más ilustre que sus hermanos, al cual su madre llamó Jabes, diciendo: Por cuanto le parí en dolor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 10, 'E invocó Jabes al Dios de Israel, diciendo: ¡Oh si me dieras bendición, y ensancharas mi término, y si tu mano fuera conmigo, y me libraras de mal, que no me dañe! E hizo Dios que le viniese lo que pidió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 11, 'Y Caleb hermano de Sua engendró á Machîr, el cual fué padre de Esthón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 12, 'Y Esthón engendró á Beth-rapha, á Phasea, y á Tehinna, padre de la ciudad de Naas: estos son los varones de Rechâ.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 13, 'Los hijos de Cenes: Othniel, y Seraiah. Los hijos de Othniel: Hathath,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 14, 'Y Maonathi, el cual engendró á, Ophra: y Seraiah engendró á Joab, padre de los habitantes en el valle llamado de Carisim, porque fueron artífices.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 15, 'Los hijos de Caleb hijo de Jephone: Iru, Ela, y Naham; é hijo de Ela, fué Cenez.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 16, 'Los hijos de Jaleleel: Zip, Ziphas, Tirias, y Asareel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 17, 'Y los hijos de Ezra: Jeter, Mered, Epher, y Jalón: también engendró á Mariam, y Sammai, y á Isba, padre de Esthemoa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 18, 'Y su mujer Judaía le parió á Jered padre de Gedor, y á Heber padre de Sochô, y á Icuthiel padre de Zanoa. Estos fueron los hijos de Bethia hija de Faraón, con la cual casó Mered.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 19, 'Y los hijos de la mujer de Odías, hermana de Naham, fueron el padre de Keila de Garmi, y Esthemoa de Maachâti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 20, 'Y los hijos de Simón: Amnón, y Rinna, hijo de Hanán, y Tilón. Y los hijos de Isi: Zoheth, y Benzoheth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 21, 'Los hijos de Sela, hijo de Judá: Er, padre de Lechâ, y Laada, padre de Maresa, y de la familia de la casa del oficio del lino en la casa de Asbea;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 22, 'Y Joacim, y los varones de Chôzeba, y Joas, y Saraph, los cuales moraron en Moab, y Jasubi-lehem, que son palabras antiguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 23, 'Estos fueron alfareros y se hallaban en medio de plantíos y cercados, los cuales moraron allá con el rey en su obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 24, 'Los hijos de Simeón: Nemuel, Jamín, Jarib, Zera, Saúl;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 25, 'También Sallum su hijo, Mibsam su hijo, y Misma su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 26, 'Los hijos de Misma: Hamuel su hijo, Zachûr su hijo, y Simi su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 27, 'Los hijos de Simi fueron diez y seis, y seis hijas: mas sus hermanos no tuvieron muchos hijos, ni multiplicaron toda su familia como los hijos de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 28, 'Y habitaron en Beer-seba, y en Molada, y en Hasar-sual,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 29, 'Y en Bala, y en Esem, y en Tholad,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 30, 'Y en Bethuel, y en Horma, y en Siclag.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 31, 'Y en Beth-marchâboth, y en Hasasusim, y en Beth-birai, y en Saaraim. Estas fueron sus ciudades hasta el reino de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 32, 'Y sus aldeas fueron Etam, Ain, Rimmón, y Tochên, y Asán, cinco pueblos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 33, 'Y todos su villajes que estaban en contorno de estas ciudades hasta Baal. Esta fué su habitación, y esta su descendencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 34, 'Y Mesobab, y Jamlech, y Josías hijo de Amasías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 35, 'Joel, y Jehú hijo de Josibias, hijo de Seraíah, hijo de Aziel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 36, 'Y Elioenai, Jacoba, Jesohaía, Asaías, Adiel, Jesimiel, Benaías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 37, 'Y Ziza hijo de Siphi, hijo de Allón, hijo de Jedaía, hijo de Simri, hijo de Semaías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 38, 'Estos por sus nombres son los principales que vinieron en sus familias, y que fueron multiplicados muy mucho en las casas de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 39, 'Y llegaron hasta la entrada de Gador hasta el oriente del valle, buscando pastos para sus ganados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 40, 'Y hallaron gruesos y buenos pastos, y tierra ancha y espaciosa, y quieta y reposada, porque los de Châm la habitaban de antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 41, 'Y estos que han sido escritos por sus nombres, vinieron en días de Ezechîas rey de Judá, y desbarataron sus tiendas y estancias que allí hallaron, y destruyéronlos, hasta hoy, y habitaron allí en lugar de ellos; por cuanto había allí pastos para sus ganados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 42, 'Y asimismo quinientos hombres de ellos, de los hijos de Simeón, se fueron al monte de seir, llevando por capitanes á Pelatía, y á Nearías, y á Rephaías, y á Uzziel, hijos de Isi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 4, 43, 'E hirieron á las reliquias que habían quedado de Amalec, y habitaon allí hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 1, 'Y LOS hijos de Rubén, primogénito de Israel, (porque él era el primogénito, mas como violó el lecho de su padre, sus derechos de primogenitura fueron dados á los hijos de José, hijo de Israel; y no fué contado por primogénito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 2, 'Porque Judá fué el mayorazgo sobre sus hermanos, y el príncipe de ellos: mas el derecho de primogenitura fué de José.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 3, 'Fueron pues los hijos de Rubén, primogénito de Israel: Enoch, Phallu, Esrón y Charmi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 4, 'Los hijos de Joel: Semaías su hijo, Gog su hijo, Simi su hijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 5, 'Michâ su hijo, Recaía su hijo, Baal su hijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 6, 'Beera su hijo, el cual fué trasportado por Thiglath-pilneser rey de los Asirios. Este era principal de los Rubenitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 7, 'Y sus hermanos por sus familias, cuando eran contados en sus descendencias, tenían por príncipes á Jeiel y á Zachârías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 8, 'Y Bela hijo de Azaz, hijo de Sema, hijo de Joel, habitó en Aroer hasta Nebo y Baal-meón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 9, 'Habitó también desde el oriente hasta la entrada del desierto desde el río Eufrates: porque tenía muchos ganados en la tierra de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 10, 'Y en los días de Saúl trajeron guerra contra los Agarenos, los cuales cayeron en su mano; y ellos habitaron en sus tiendas sobre toda la haz oriental de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 11, 'Y los hijos de Gad habitaron enfrente de ellos en la tierra de Basán hasta Salca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 12, 'Y Joel fué el principal en Basán, el segundo Sephán, luego Janai, después Saphat.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 13, 'Y sus hermanos, según las familias de sus padres, fueron Michâel, Mesullam, Seba, Jorai, Jachân, Zia, y Heber; en todos siete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 14, 'Estos fueron los hijos de Abihail hijo de Huri, hijo de Jaroa, hijo de Galaad, hijo de Michâel, hijo de Jesiaí, hijo de Jaddo, hijo de Buz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 15, 'También Ahí, hijo de Abdiel, hijo de Guni, fué principal en la casa de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 16, 'Los cuales habitaron en Galaad, en Basán, y en sus aldeas, y en todos los ejidos de Sarón hasta salir de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 17, 'Todos estos fueron contados por sus generaciones en días de Jothán rey de Judá, y en días de Jeroboam rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 18, 'Los hijos de Rubén, y de Gad, y la media tribu de Manasés, hombres valientes, hombres que traían escudo y espada, que entesaban arco, y diestros en guerra, en cuarenta y cuatro mil setecientos y sesenta que salían á batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 19, 'Y tuvieron guerra los Agarenos, y Jethur, y Naphis, y Nodab.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 20, 'Y fueron ayudados contra ellos, y los Agarenos se dieron en sus manos, y todos los que con ellos estaban; porque clamaron á Dios en la guerra, y fuéles favorable, porque esperaron en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 21, 'Y tomaron sus ganados, cincuenta mil camellos, y doscientas cincuenta mil ovejas, dos mil asnos, y cien mil personas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 22, 'Y cayeron muchos heridos, porque la guerra era de Dios; y habitaron en sus lugares hasta la transmigración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 23, 'Y los hijos de la media tribu de Manasés habitaron en la tierra, desde Basán hasta Baal-Hermón, y Senir y el monte de Hermón, multiplicados en gran manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 24, 'Y estas fueron las cabezas de las casas de sus padres: Epher, Isi, y Eliel, Azriel, y Jeremías, y Odavia, y Jadiel, hombres valientes y de esfuerzo, varones de nombre y cabeceras de las casas de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 25, 'Mas se rebelaron contra el Dios de sus padres, y fornicaron siguiendo los dioses de los pueblos de la tierra, á los cuales había Jehová quitado de delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 5, 26, 'Por lo cual el Dios de Israel excitó el espíritu de Phul rey de los Asirios, y el espíritu de Thiglath-pilneser rey de los Asirios, el cual trasportó á los Rubenitas y Gaditas y á la media tribu de Manasés, y llevólos á Halad, y á Habor y á Ara, y al río de Gozán, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 1, 'LOS hijos de Leví: Gersón, Coath, y Merari.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 2, 'Los hijos de Coath: Amram, Ishar, Hebrón y Uzziel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 3, 'Los hijos de Amram: Aarón, Moisés, y Mariam. Los hijos de Aarón: Nadab, Abiú, Eleazar, é Ithamar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 4, 'Eleazar engendró á Phinees, y Phinees engendró á Abisua:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 5, 'Y Abisua engendró á Bucci, y Bucci engendró á Uzzi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 6, 'Y Uzzi engendró á Zeraías, y Zeraías engendró á Meraioth;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 7, 'Y Meraioth engendró á Amarías, y Amarías engendró á Achîtob;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 8, 'Y Achîtob engendró á Sadoc, y Sadoc engendró á Achîmaas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 9, 'Y Achîmaas engendró á Azarías, y Azarías engendró á Johanán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 10, 'Y Johanan engendró á Azarías, el que tuvo el sacerdocio en la casa que Salomón edificó en Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 11, 'Y Azarías engendró á Amarías, y Amarías engendró á Achîtob;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 12, 'Y Achîtob engendró á Sadoc, y Sadoc engendró á Sallum;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 13, 'Y Sallum engendró á Hilcías, é Hilcías engendró á Azarías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 14, 'Y Azarías engendró á Seraíah, y Seraíah, engendró á Josadec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 15, 'Y Josadec fué cautivo cuando Jehová trasportó á Judá y á Jerusalem, por mano de Nabucodonosor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 16, 'Los hijos de Leví: Gersón, Coath, y Merari.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 17, 'Y estos son los nombres de los hijos de Gersón: Libni, y Simi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 18, 'Los hijos de Coath: Amram, Ishar, Hebrón, y Uzziel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 19, 'Los hijos de Merari: Mahali, y Musi. Estas son las familias de Leví, según sus descendencias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 20, 'Gersón: Libni su hijo, Joath su hijo, Zimma su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 21, 'Joab su hijo, Iddo su hijo, Zera su hijo, Jeothrai su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 22, 'Los hijos de Coath: Aminadab su hijo, Coré su hijo, Asir su hijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 23, 'Elcana su hijo, Abiasaph su hijo, Asir su hijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 24, 'Thahath su hijo, Uriel su hijo, Uzzia su hijo, y Saúl su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 25, 'Los hijos de Elcana: Amasai, Achîmoth, y Elcana.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 26, 'Los hijos de Elcana: Sophai su hijo, Nahath su hijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 27, 'Eliab su hijo, Jeroham su hijo, Elcana su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 28, 'Los hijos de Samuel: el primogénito Vasni, y Abías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 29, 'Los hijos de Merari: Mahali, Libni su hijo, Simi su hijo, Uzza su hijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 30, 'Sima su hijo, Haggía su hijo, Assía su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 31, 'Estos son á los que David dió cargo de las cosas de la música de la casa de Jehová, después que el arca tuvo reposo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 32, 'Los cuales servían delante de la tienda del tabernáculo del testimonio en cantares, hasta que Salomón edificó la casa de Jehová en Jerusalem: después estuvieron en su ministerio según su costumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 33, 'Estos pues con sus hijos asistían: de los hijos de Coath, Hemán cantor, hijo de Joel, hijo de Samuel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 34, 'Hijo de Elcana, hijo de Jeroham, hijo de Eliel, hijo de Thoa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 35, 'Hijo de Suph, hijo de Elcana, hijo Mahath, hijo de Amasai;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 36, 'Hijo de Elcana, hijo de Joel, hijo de Azarías, hijo de Sophonías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 37, 'Hijo de Thahat, hijo de Asir, hijo de Abiasaph, hijo de Core;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 38, 'Hijo de Ishar, hijo de Coath, hijo de Leví, hijo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 39, 'Y su hermano Asaph, el cual estaba á su mano derecha: Asaph, hijo de Berachîas, hijo de Sima;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 40, 'Hijo de Michâel, hijo de Baasías, hijo de Malchîas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 41, 'Hijo de Athanai, hijo de Zera, hijo de Adaia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 42, 'Hijo de Ethán, hijo de Zimm, hijo de Simi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 43, 'Hijo de Jahat, hijo de Gersón, hijo de Leví.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 44, 'Mas los hijos de Merari sus hermanos estaban á la mano siniestra, es á saber, Ethán hijo de Chîsi, hijo de Abdi, hijo de Maluch;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 45, 'Hijo de Hasabías, hijo de Amasías, hijo de Hilcías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 46, 'Hijo de Amasai, hijo de Bani, hijo de Semer;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 47, 'Hijo de Mahali, hijo de Musi, hijo de Merari, hijo de Leví.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 48, 'Y sus hermanos los Levitas fueron puestos sobre todo el ministerio del tabernáculo de la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 49, 'Mas Aarón y sus hijos ofrecían perfume sobre el altar del holocausto, y sobre el altar del perfume, en toda la obra del lugar santísimo, y para hacer las expiaciones sobre Israel, conforme á todo lo que Moisés siervo de Dios había mandado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 50, 'Y los hijos de Aarón son estos: Eleazar su hijo, Phinees su hijo, Abisua su hijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 51, 'Bucci su hijo, Uzzi su hijo, Zeraías su hijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 52, 'Meraioth su hijo, Amarías su hijo, Achîtob su hijo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 53, 'Sadoc su hijo, Achîmaas su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 54, 'Y estas son sus habitaciones, conforme á sus domicilios y sus términos, las de los hijos de Aarón por las familias de los Coathitas, porque de ellos fué la suerte:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 55, 'Les dieron pues á Hebrón en tierra de Judá, y sus ejidos alrededor de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 56, 'Mas el territorio de la ciudad y sus aldeas se dieron á Caleb, hijo de Jephone.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 57, 'Y á los hijos de Aarón dieron las ciudades de Judá de acogimiento, es á saber, á Hebrón, y á Libna con sus ejidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 58, 'A Jathir, y Esthemoa con sus ejidos, y á Hilem con sus ejidos, y á Debir con sus ejidos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 59, 'A Asán con sus ejidos, y á Beth-semes con sus ejidos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 60, 'Y de la tribu de Benjamín, á Geba, con sus ejidos, y á Alemeth con sus ejidos, y á Anathoth con sus ejidos. Todas sus ciudades fueron trece ciudades, repartidas por sus linajes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 61, 'A los hijos de Coath, que quedaron de su parentela, dieron diez ciudades de la media tribu de Manasés por suerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 62, 'Y á los hijos de Gersón, por sus linajes, dieron de la tribu de Aser, y de la tribu de Nephtalí, y de la tribu de Manasés en Basán, trece ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 63, 'Y á los hijos de Merari, por sus linajes, de la tribu de Rubén, y de la tribu de Gad, y de la tribu de Zabulón, se dieron por suerte doce ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 64, 'Y dieron los hijos de Israel á los Levitas ciudades con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 65, 'Y dieron por suerte de la tribu de los hijos de Judá, y de la tribu de los hijos de Simeón, y de la tribu de los hijos de Benjamín, las ciudades que nombraron por sus nombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 66, 'Y á los linajes de los hijos de Coath dieron ciudades con sus términos de la tribu de Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 67, 'Y diéronles las ciudades de acogimiento, á Sichêm con sus ejidos en el monte de Ephraim, y á Gezer con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 68, 'Y á Jocmeam con sus ejidos, y á Beth-oron con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 69, 'Y á Ajalón con sus ejidos, y á Gath-rimmón con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 70, 'De la media tribu de Manasés, á Aner con sus ejidos, y á Bilam con sus ejidos, para los del linaje de los hijos de Coath que habían quedado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 71, 'Y á los hijos de Gersón dieron de la familia de la media tribu de Manasés, á Golan en Basán con sus ejidos y á Astaroth con sus ejidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 72, 'Y de la tribu de Issachâr, á Cedes con sus ejidos, á Dobrath con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 73, 'Y á Ramoth con sus ejidos, y á Anem con sus ejidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 74, 'Y de la tribu de Aser á Masal con sus ejidos, y á Abdón con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 75, 'Y á Ucoc con sus ejidos, y á Rehob con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 76, 'Y de la tribu de Nephtalí, á Cedes en Galilea con sus ejidos, y á Ammón con sus ejidos, á Chîriath-jearim con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 77, 'Y á los hijos de Merari que habían quedado, dieron de la tribu de Zabulón á Rimmono con sus ejidos, y á Thabor con sus ejidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 78, 'Y de la otra parte del Jordán de Jericó, al oriente del Jordán, dieron, de la tribu de Rubén, á Beser en el desierto con sus ejidos; y á Jasa con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 79, 'Y á Chêdemoth con sus ejidos, y á Mephaath con sus ejidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 80, 'Y de la tribu de Gad, á Ramot en Galaad con sus ejidos, y á Mahanaim con sus ejidos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 6, 81, 'Y á Hesbón con sus ejidos, y á Jacer con sus ejidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 1, 'LOS hijos de Issachâr, cuatro: Thola, Phúa, Jabsub, y Simrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 2, 'Los hijos de Thola: Uzzi, Rephaías, Jeriel, Jamai, Jibsam y Samuel, cabezas en las familias de sus padres. De Thola fueron contados por sus linajes en el tiempo de David, veintidós mil seiscientos hombres muy valerosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 3, 'Hijo de Uzzi fué Izrahías; y los hijos de Izrahías: Michâel, Obadías, Joel, é Isías: todos, cinco príncipes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 4, 'Y había con ellos en sus linajes, por las familias de sus padres, treinta y seis mil hombres de guerra: por que tuvieron muchas mujeres é hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 5, 'Y sus hermanos por todas las familias de Issachâr, contados todos por sus genealogías, eran ochenta y siete mil hombres valientes en extremo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 6, 'Los hijos de Benjamín fueron tres: Bela, Bechêr, y Jediael.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 7, 'Los hijos de Bela: Esbon, Uzzi, Uzziel, Jerimoth, é Iri; cinco cabezas de casas de linajes, hombres de gran valor, y de cuya descendencia fueron contados veintidós mil treinta y cuatro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 8, 'Los hijos de Bechêr: Zemira, Joas, Eliezer, Elioenai, Omri, Jerimoth, Abías, Anathoth y Alemeth; todos estos fueron hijos de Bechêr.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 9, 'Y contados por sus descendencias, por sus linajes, los que eran cabezas de sus familias, resultaron veinte mil y doscientos hombres de grande esfuerzo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 10, 'Hijo de Jediael fué Bilhán; y los hijos de Bilhán: Jebús, Benjamín, Aod, Chênaana, Zethán, Tharsis, y Ahisahar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 11, 'Todos estos fueron hijos de Jediael, cabezas de familias, hombres muy valerosos, diecisiete mil y doscientos que salían á combatir en la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 12, 'Y Suppim y Huppim fueron hijos de Hir: y Husim, hijo de Aher.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 13, 'Los hijos de Nephtalí: Jaoel, Guni, Jezer, y Sallum, hijos de Bilha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 14, 'Los hijos de Manasés: Asriel, el cual le parió su concubina la Sira: (la cual también le parió á Machîr, padre de Galaad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 15, 'Y Machîr tomó por mujer la hermana de Huppim y Suppim, cuya hermana tuvo por nombre Maachâ:) y el nombre del segundo fué Salphaad. Y Salphaad tuvo hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 16, 'Y Maachâ mujer de Machîr le parió un hijo, y llamóle Peres; y el nombre de su hermano fué Seres, cuyos hijos fueron Ulam y Recem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 17, 'Hijo de Ulam fué Bedán. Estos fueron los hijos de Galaad, hijo de Machîr, hijo de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 18, 'Y su hermana Molechêt parió á Ischôd, y á Abiezer, y Mahala.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 19, 'Y los hijos de Semida fueron Ahián, Sechêm, Licci, y Aniam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 20, 'Los hijos de Ephraim: Suthela, Bered su hijo, Thahath, Elada su hijo, Thahat su hijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 21, 'Zabad su hijo, y Suthela su hijo, Ezer, y Ela0d. Mas los hijos de gath, naturales de aquella tierra, los mataron, porque vinieron á tomarles sus ganados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 22, 'Y Ephraim su padre hizo duelo por muchos días, y vinieron sus hermanos á consolarlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 23, 'Entrando él después á su mujer ella concibió, y parió un hijo, al cual puso por nombre Bería; por cuanto había estado en aflicción en su casa');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 24, 'Y su hija fué Seera, la cual edificó á Beth-oron la baja y la alta, y á Uzzen-seera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 25, 'Hijo de este Bería fué Repha y Reseph, y Thela su hijo, y Taán su hijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 26, 'Laadán su hijo, Ammiud su hijo, Elisama su hijo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 27, 'Nun su hijo, Josué su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 28, 'Y la heredad y habitación de ellos fué Beth-el con sus aldeas: y hacia el oriente Naarán, y á la parte del occidente Gezer y sus aldeas: asimismo Sichêm con sus aldeas, hasta Asa y sus aldeas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 29, 'Y á la parte de los hijos de Manasés, Beth-seán con sus aldeas, Thanach con sus aldeas, Megiddo con sus aldeas, Dor con sus aldeas. En estos lugares habitaron los hijos de José, hijo de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 30, 'Los hijos de Aser: Imna, Isua, Isui, Bería, y su hermana Sera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 31, 'Los hijos de Bería: Heber, y Machîel, el cual fué padre de Birzabith.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 32, 'Y Heber engendró á Japhlet, Semer, Hotham, y Sua hermana de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 33, 'Los hijos de Japhlet: Pasac, Bimhal, y Asvath. Aquestos los hijos de Japhlet.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 34, 'Y los hijos de Semer: Ahi, Roega, Jehubba, y Aram.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 35, 'Los hijos de Helem su hermano: Sopha, Imna, Selles, y Amal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 36, 'Los hijos de Sopha: Sua, Harnapher, Sual, Beri, Imra,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 37, 'Beser, Hod, Samma, Silsa, Ithrán y Beera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 38, 'Los hijos de Jether: Jephone, Pispa, y Ara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 39, 'Y los hijos de Ulla; Ara, y Haniel, y Resia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 7, 40, 'Y todos estos fueron hijos de Aser, cabezas de familias paternas, escogidos, esforzados, cabezas de príncipes: y contados que fueron por sus linajes entre los de armas tomar, el número de ellos fué veintiséis mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 1, 'BENJAMIN engendró á Bela su primogénito, Asbel el segundo, Ara el tercero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 2, 'Noha el cuarto, y Rapha el quinto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 3, 'Y los hijos de Bela fueron Addar, Gera, Abiud,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 4, 'Abisua, Naamán, Ahoa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 5, 'Y Gera, Sephuphim, y Huram.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 6, 'Y estos son los hijos de Ehud, estos las cabezas de padres que habitaron en Gabaa, y fueron trasportados á Manahath:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 7, 'Es á saber: Naamán, Achîas, y Gera: éste los trasportó, y engendró á Uzza, y á Ahihud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 8, 'Y Saharaim engendró hijos en la provincia de Moab, después que dejó á Husim y á Baara que eran sus mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 9, 'Engendró pues de Chôdes su mujer, á Jobab, Sibias, Mesa, Malchâm,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 10, 'Jeus, Sochîas, y Mirma. Estos son sus hijos, cabezas de familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 11, 'Mas de Husim engendró á Abitob, y á Elphaal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 12, 'Y los hijos de Elphaal: Heber, Misam, y Semeb, (el cual edificó á Ono, y á Loth con sus aldeas,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 13, 'Berías también, y Sema, que fueron las cabezas de las familias de los moradores de Ajalón, los cuales echaron á los moradores de Gath;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 14, 'Y Ahío, Sasac, Jeremoth;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 15, 'Zebadías, Arad, Heder;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 16, 'Michâel, Ispha, y Joa, hijos de Berías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 17, 'Y Zebadías, Mesullam, Hizchî, Heber;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 18, 'Ismari, Izlia, y Jobab, hijos de Elphaal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 19, 'Y Jacim, Zichri, Zabdi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 20, 'Elioenai, Silithai, Eliel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 21, 'Adaías, Baraías, y Simrath, hijos de Simi;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 22, 'E Isphán, Heber, Eliel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 23, 'Adón, Zichri, Hanán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 24, 'Hananía, Belam, Anathothías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 25, 'Iphdaías, y Peniel, hijos de Sasac;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 26, 'Y Samseri, Seharías, Atalía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 27, 'Jaarsías, Elías, Zichri, hijos de Jeroham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 28, 'Estos fueron jefes principales de familias por sus linajes, y habitaron en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 29, 'Y en Gabaón habitaron Abiga-baón, la mujer del cual se llamó Maachâ:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 30, 'Y su hijo primogénito, Abdón, luego Sur, Chîs, Baal, Nadab,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 31, 'Gedor, Ahíe, y Zechêr.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 32, 'Y Micloth engendró á Simea. Estos también habitaron con sus hermanos en Jerusalem, enfrente de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 33, 'Y Ner engendró á Cis, y Cis engendró á Saúl, y Saúl engendró á Jonathán, Malchî-súa, Abinadab, y Esbaal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 34, 'Hijo de Jonathán fué Merib-baal, y Merib-baal engendró á Michâ.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 35, 'Los hijos de Michâ: Phitón, Melech, Thaarea y Ahaz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 36, 'Y Ahaz engendró á Joadda; y Joadda engendró á Elemeth, y á Azmaveth, y á Zimri; y Zimri engendró á Mosa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 37, 'Y Mosa engendró á Bina, hijo del cual fué Rapha, hijo del cual fué Elasa, cuyo hijo fué Asel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 38, 'Y los hijos de Asel fueron seis, cuyos nombres son Azricam, Bochru, Ismael, Searías, Obadías, y Hanán: todos estos fueron hijos de Asel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 39, 'Y los hijos de Esec su hermano: Ulam su primogénito, Jehus el segundo, Elipheleth el tercero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 8, 40, 'Y fueron los hijos de Ulam hombres valientes y vigorosos, flecheros diestros, los cuales tuvieron muchos hijos y nietos, ciento y cincuenta. Todos estos fueron de los hijos de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 1, 'Y CONTADO todo Israel por el orden de los linajes, fueron escritos en el libro de los reyes de Israel y de Judá, que fueron trasportados á Babilonia por su rebelión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 2, 'Los primeros moradores que entraron en sus posesiones en sus ciudades, fueron así de Israel, como de los sacerdotes, Levitas, y Nethineos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 3, 'Y habitaron en Jerusalem de los hijos de Judá, de los hijos de Benjamín, de los hijos de Ephraim y Manasés:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 4, 'Urai hijo de Amiud, hijo de Omri, hijo de Imrai, hijo de Bani, de los hijos de Phares hijo de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 5, 'Y de Siloni, Asaías el primogénito, y sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 6, 'Y de los hijos de Zara, Jehuel y sus hermanos, seiscientos noventa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 7, 'Y de los hijos de Benjamín: Sallu hijo de Mesullam, hijo de Odavía, hijo de Asenua;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 8, 'E Ibnías hijo de Jeroham, y Ela hijo de Uzzi, hijo de Michri; y Mesullam hijo de Sephatías, hijo de Rehuel, hijo de Ibnías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 9, 'Y sus hermanos por sus linajes fueron nuevecientos cincuenta y seis. Todos estos hombres fueron cabezas de familia en las casas de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 10, 'Y de los sacerdotes: Jedaía, Joiarib, Joachîm;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 11, 'Y Azarías hijo de Hilcías, hijo de Mesullam, hijo de Sadoc, hijo de Meraioth, hijo de Achîtob, príncipe de la casa de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 12, 'Y Adaías hijo de Jeroham, hijo de Phasur, hijo de Machîas; y Masai hijo de Adiel, hijo de Jazera, hijo de Mesullam, hijo de Mesillemith, hijo de Immer;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 13, 'Y sus hermanos, cabezas de las casas de sus padres, en número de mil setecientos sesenta, hombres de grande eficacia en la obra del ministerio en la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 14, 'Y de los Levitas: Semeías, hijo de Hassub, hijo de Azricam, hijo de Hasabías, de los hijos de Merari;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 15, 'Y Bacbaccar, Heres, y Galal, y Mattanía hijo de Michâs, hijo de Zichri, hijo de Asaph;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 16, 'Y Obadías hijo de Semeías, hijo de Galal, hijo de Iduthum: y Berachîas hijo de Asa, hijo de Elcana, el cual habitó en las aldeas de Nethophati.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 17, 'Y los porteros: Sallum, Accub, Talmon, Ahiman, y sus hermanos. Sallum era el jefe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 18, 'Y hasta ahora entre las cuadrillas de los hijos de Leví han sido estos los porteros en la puerta del rey que está al oriente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 19, 'Y Sallum hijo de Core, hijo de Abiasath, hijo de Corah, y sus hermanos los Coraitas por la casa de su padre, tuvieron cargo de la obra del ministerio, guardando las puertas del tabernáculo; y sus padres fueron sobre la cuadrilla de Jehová guardas de la entrada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 20, 'Y Phinees hijo de Eleazar fué antes capitán sobre ellos, siendo Jehová con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 21, 'Y Zacarías hijo de Meselemia era portero de la puerta del tabernáculo del testimonio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 22, 'Todos estos, escogidos para guardas en las puertas, eran doscientos doce cuando fueron contados por el orden de sus linajes en sus villas, á los cuales constituyó en su oficio David y Samuel el vidente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 23, 'Así ellos y sus hijos eran porteros por sus turnos á las puertas de la casa de Jehová, y de la casa del tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 24, 'Y estaban los porteros á los cuatro vientos, al oriente, al occidente, al septentrión, y al mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 25, 'Y sus hermanos que estaban en sus aldeas, venían cada siete días por sus tiempos con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 26, 'Porque cuatro principales de los porteros Levitas estaban en el oficio, y tenían cargo de las cámaras, y de los tesoros de la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 27, 'Estos moraban alrededor de la casa de Dios, porque tenían cargo de la guardia, y el de abrir aquélla todas las mañanas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 28, 'Algunos de estos tenían cargo de los vasos del ministerio, los cuales se metían por cuenta, y por cuenta se sacaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 29, 'Y otros de ellos tenían cargo de la vajilla, y de todos los vasos del santuario, y de la harina, y del vino, y del aceite, y del incienso, y de los aromas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 30, 'Y algunos de los hijos de los sacerdotes hacían los ungüentos aromáticos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 31, 'Y Mathathías, uno de los Levitas, primogénito de Sallum Coraita, tenía cargo de las cosas que se hacían en sartén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 32, 'Y algunos de los hijos de Coath, y de sus hermanos, tenían el cargo de los panes de la proposición, los cuales ponían por orden cada sábado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 33, 'Y de estos había cantores, principales de familias de los Levitas, los cuales estaban en sus cámaras exentos; porque de día y de noche estaban en aquella obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 34, 'Estos eran jefes de familias de los Levitas por sus linajes, jefes que habitaban en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 35, 'Y en Gabaón habitaban Jehiel padre de Gabaón, el nombre de cuya mujer era Maachâ;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 36, 'Y su hijo primogénito Abdón, luego Sur, Chîs, Baal, Ner, Nadab;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 37, 'Gedor, Ahio, Zachârias, y Micloth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 38, 'Y Micloth engendró á Samaán. Y estos habitaban también en Jerusalem con sus hermanos enfrente de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 39, 'Y Ner engendró á Cis, y Cis engendró á Saúl, y Saúl engendró á Jonathán, Malchîsua, Abinadab, y Esbaal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 40, 'E hijo de Jonathán fué Merib-baal, y Merib-baal engendró á Michâ.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 41, 'Y los hijos de Michâ: Phitón, Melech, Tharea, y Ahaz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 42, 'Ahaz engendró á Jara, y Jara engendró á Alemeth, Azmaveth, y Zimri: y Zimri engendró á Mosa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 43, 'Y Mosa engendró á Bina, cuyo hijo fué Rephaía, del que fué hijo Elasa, cuyo hijo fué Asel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 9, 44, 'Y Asel tuvo seis hijos, los nombres de los cuales son: Azricam, Bochru, Ismael, Seraía, Obadías, y Hanán: estos fueron los hijos de Asel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 1, 'LOS Filisteos pelearon con Israel; y huyeron delante de ellos los Israelitas, y cayeron heridos en el monte de Gilboa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 2, 'Y los Filisteos siguieron á Saúl y á sus hijos; y mataron los Filisteos á Jonathán, y á Abinadab, y á Malchîsua, hijos de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 3, 'Y agravóse la batalla sobre Saúl, y le alcanzaron los flecheros, y fué de los flecheros herido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 4, 'Entonces dijo Saúl á su escudero: Saca tu espada, y pásame con ella, porque no vengan estos incircuncisos, y hagan escarnio de mí; mas su escudero no quiso, porque tenía gran miedo. Entonces Saúl tomó la espada, y echóse sobre ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 5, 'Y como su escudero vió á Saúl muerto, él también se echó sobre su espada, y matóse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 6, 'Así murió Saúl, y sus tres hijos; y toda su casa murió juntamente con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 7, 'Y viendo todos los de Israel que habitaban en el valle, que habían huído, y que Saúl y sus hijos eran muertos, dejaron sus ciudades, y huyeron: y vinieron los Filisteos, y habitaron en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 8, 'Y fué que viniendo el día siguiente los Filisteos á despojar los muertos, hallaron á Saúl y á sus hijos tendidos en el monte de Gilboa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 9, 'Y luego que le hubieron desnudado, tomaron su cabeza y sus armas, y enviáronlo todo á la tierra de los Filisteos por todas partes, para que fuese denunciado á sus ídolos y al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 10, 'Y pusieron sus armas en el templo de su dios, y colgaron la cabeza en el templo de Dagón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 11, 'Y oyendo todos los de Jabes de Galaad lo que los Filisteos habían hecho de Saúl,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 12, 'Levantáronse todos los hombres valientes, y tomaron el cuerpo de Saúl, y los cuerpos de sus hijos, y trajéronlos á Jabes; y enterraron sus huesos debajo del alcornoque en Jabes, y ayunaron siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 13, 'Así murió Saúl por su rebelión con que prevaricó contra Jehová, contra la palabra de Jehová, la cual no guardó; y porque consultó al pythón, preguntándo le,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 10, 14, 'Y no consultó á Jehová: por esta causa lo mató, y traspasó el reino á David, hijo de Isaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 1, 'ENTONCES todo Israel se juntó á David en Hebrón, diciendo: He aquí nosotros somos tu hueso y tu carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 2, 'Y además antes de ahora, aun mientras Saúl reinaba, tú sacabas y metías á Israel. También Jehová tu Dios te ha dicho: Tú apacentarás mi pueblo Israel, y tú serás príncipe sobre Israel mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 3, 'Y vinieron todos los ancianos de Israel al rey en Hebrón, y David hizo con ellos alianza delante de Jehová; y ungieron á David por rey sobre Israel, conforme á la palabra de Jehová por mano de Samuel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 4, 'Entonces se fué David con todo Israel á Jerusalem, la cual es Jebus; y allí era el Jebuseo habitador de aquella tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 5, 'Y los moradores de Jebus dijeron á David: No entrarás acá. Mas David tomó la fortaleza de Sión, que es la ciudad de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 6, 'Y David había dicho: El que primero hiriere al Jebuseo, será cabeza y jefe. Entonces Joab hijo de Sarvia subió el primero, y fué hecho jefe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 7, 'Y David habitó en la fortaleza, y por esto le llamaron la ciudad de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 8, 'Y edificó la ciudad alrededor, desde Millo hasta la cerca: y Joab reparó el resto de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 9, 'Y David iba adelantando y creciendo, y Jehová de los ejércitos era con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 10, 'Estos son los principales de los valientes que David tuvo, y los que le ayudaron en su reino, con todo Israel, para hacerle rey sobre Israel, conforme á la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 11, 'Y este es le número de los valientes que David tuvo: Jasobam hijo de Hachmoni, caudillo de los treinta, el cual blandió su lanza una vez contra trescientos, á los cuales mató.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 12, 'Tras de éste fué Eleazar hijo de Dodo, Ahohita, el cual era de los tres valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 13, 'Este estuvo con David en Pasdammin, estando allí juntos en batalla los Filisteos: y había allí una suerte de tierra llena de cebada, y huyendo el pueblo delante de los Filisteos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 14, 'Pusiéronse ellos en medio de la haza, y la defendieron, y vencieron á los Filisteos; y favoreciólos Jehová con grande salvamento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 15, 'Y tres de los treinta principales descendieron á la peña á David, á la cueva de Adullam, estando el campo de los Filisteos en el valle de Raphaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 16, 'Y David estaba entonces en la fortaleza, y había á la sazón guarnición de Filisteos en Beth-lehem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 17, 'David deseó entonces, y dijo: ¡Quién me diera á beber de las aguas del pozo de Beth-lehem, que está á la puerta!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 18, 'Y aquellos tres rompieron por el campo de los Filisteos, y sacaron agua del pozo de Beth-lehem, que está á la puerta, y tomaron y trajéronla á David: mas él no la quiso beber, sino que la derramó á Jehová, y dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 19, 'Guárdeme mi Dios de hacer esto: ¿había yo de beber la sangre de estos varones con sus vidas, que con peligro de sus vidas la han traído? Y no la quiso beber. Esto hicieron aquellos tres valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 20, 'Y Abisai, hermano de Joab, era cabeza de los tres, el cual blandió su lanza sobre trescientos, á los cuales hirió; y fué entre los tres nombrado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 21, 'De los tres fué más ilustre que los otros dos, y fué el principal de ellos: mas no llegó á los tres primeros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 22, 'Benaías hijo de Joiada, hijo de varón de esfuerzo, de grandes hechos, de Cabseel: él venció los dos leones de Moab: también descendió, é hirió un león en mitad de un foso en tiempo de nieve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 23, 'El mismo venció á un Egipcio, hombre de cinco codos de estatura: y el Egipcio traía una lanza como un enjullo de tejedor; mas él descendió á él con un bastón, y arrebató al Egipcio la lanza de la mano, y matólo con su misma lanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 24, 'Esto hizo Benaía hijo de Joiada, y fué nombrado entre los tres valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 25, 'Y fué el más honrado de los treinta, mas no llegó á los tres primeros. A este puso David en su consejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 26, 'Y los valientes de los ejércitos: Asael hermano de Joab, y Elchânan hijo de Dodo de Beth-lehem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 27, 'Samoth de Arori, Helles Pelonita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 28, 'Ira hijo de Acces Tecoita, Abiezer Anathothita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 29, 'Sibbecai Husatita, Ilai Ahohita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 30, 'Maharai Nethophathita, Heled hijo de Baana Nehtophathita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 31, 'Ithai hijo de Ribai de Gabaath de los hijos de Benjamín, Benaías Phirathita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 32, 'Hurai del río Gaas, Abiel Arbathonita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 33, 'Azmaveth Baharumita, Eliaba Saalbonita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 34, 'Los hijos de Asem Gizonita, Jonathán hijo de Sajé Hararita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 35, 'Ahiam hijo de Sachâr Ararita, Eliphal hijo de Ur;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 36, 'Hepher Mechêrathita, Ahía Phelonita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 37, 'Hesro Carmelita, Nahari hijo de Ezbai;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 38, 'Joel hermano de Nathán, Mibhar hijo de Agrai;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 39, 'Selec Ammonita, Naarai Berothita, escudero de Joab hijo de Sarvia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 40, 'Ira Ithreo, Yared Ithreo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 41, 'Uría Hetheo, Zabad hijo de Ahli;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 42, 'Adina hijo de Siza Rubenita, príncipe de los Rubenitas, y con él treinta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 43, 'Hanán hijo de Maachâ, y Josaphat Mithnita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 44, 'Uzzías Astarothita, Samma y Jehiel hijos de Hotham Arorita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 45, 'Jedaiel hijo de Simri, y Joha su hermano, Thisaita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 46, 'Eliel de Mahavi, Jeribai y Josabía hijos de Elnaam, e Ithma Moabita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 11, 47, 'Eliel, y Obed, y Jaasiel de Mesobia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 1, 'ESTOS son los que vinieron á David á Siclag, estando él aún encerrado por causa de Saúl hijo de Cis, y eran de los valientes ayudadores de la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 2, 'Estaban armados de arcos, y usaban de ambas manos en tirar piedras con honda, y saetas con arco. De los hermanos de Saúl de Benjamín:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 3, 'El principal Ahiezer, después Joas, hijos de Semaa Gabaathita; y Jeziel, y Pheleth, hijos de Azmaveth, y Beracah, y Jehú Anathothita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 4, 'E Ismaías Gabaonita, valiente entre los treinta, y más que los treinta; y Jeremías, Jahaziel, Joanán, Jozabad Gederathita,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 5, 'Eluzai, y Jeremoth, Bealías, Semarías, y Sephatías Haruphita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 6, 'Elcana, é Isías, y Azareel, y Joezer, y Jasobam, de Coré;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 7, 'Y Joela, y Zebadías, hijos de Jeroham de Gedor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 8, 'También de los de Gad se huyeron á David, estando en la fortaleza en el desierto, muy valientes hombres de guerra para pelear, dispuestos á hacerlo con escudo y pavés: sus rostros como rostros de leones, y ligeros como las cabras monteses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 9, 'Eser el primero, Obadías el segundo, Eliab el tercero,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 10, 'Mismana el cuarto, Jeremías el quinto,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 11, 'Attai el sexto, Eliel el séptimo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 12, 'Johanán el octavo, Elzabad el nono,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 13, 'Jeremías el décimo, Machbani el undécimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 14, 'Estos fueron capitanes del ejército de los hijos de Gad. El menor tenía cargo de cien hombres, y el mayor de mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 15, 'Estos pasaron el Jordán en el mes primero, cuando había salido sobre todas sus riberas; é hicieron huir á todos los de los valles al oriente y al poniente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 16, 'Asimismo algunos de los hijos de Benjamín y de Judá vinieron á David á la fortaleza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 17, 'Y David salió á ellos, y hablóles diciendo: Si habéis venido á mí para paz y para ayudarme, mi corazón será unido con vosotros; mas si para engañarme en pro de mis enemigos, siendo mis manos sin iniquidad, véalo el Dios de nuestros padres, y demándelo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 18, 'Entonces se envistió el espíritu en Amasai, príncipe de treinta, y dijo: Por ti, oh David, y contigo, oh hijo de Isaí. Paz, paz contigo, y paz con tus ayudadores; pues que también tu Dios te ayuda. Y David los recibió, y púsolos entre los capitanes de la cuadrilla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 19, 'También se pasaron á David algunos de Manasés, cuando vino con los Filisteos á la batalla contra Saúl, aunque no les ayudaron; porque los sátrapas de los Filisteos, habido consejo, lo despidieron, diciendo: Con nuestras cabezas se pasará á su señor Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 20, 'Así que viniendo él á Siclag, se pasaron á él de los de Manasés, Adnas, Jozabad, Michâel, Jozabad, Jediaiel, Eliú, y Sillethai, príncipes de millares de los de Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 21, 'Estos ayudaron á David contra aquella compañía; porque todos ellos eran hombres valientes, y fueron capitanes en el ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 22, 'Porque entonces todos los días venía ayuda á David, hasta hacerse un grande ejército, como ejército de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 23, 'Y este es el número de los principales que estaban á punto de guerra, y vinieron á David en Hebrón, para traspasarle el reino de Saúl, conforme á la palabra de Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 24, 'De los hijos de Judá que traían escudo y lanza, seis mil y ochocientos, á punto de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 25, 'De los hijos de Simeón, valientes y esforzados hombres para la guerra, siete mil y ciento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 26, 'De los hijos de Leví, cuatro mil y seiscientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 27, 'Asimismo Joiada, príncipe de los del linaje de Aarón, y con él tres mil y setecientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 28, 'Y Sadoc, mancebo valiente y esforzado, con veinte y dos de los principales de la casa de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 29, 'De los hijos de Benjamín hermanos de Saúl, tres mil; porque aun en aquel tiempo muchos de ellos tenían la parte de la casa de Saúl.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 30, 'Y de los hijos de Ephraim, veinte mil y ochocientos, muy valientes, varones ilustres en las casas de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 31, 'De la media tribu de Manasés, diez y ocho mil, los cuales fueron tomados por lista para venir á poner á David por rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 32, 'Y de los hijos de Issachâr, doscientos principales, entendidos en los tiempos, y que sabían lo que Israel debía hacer, cuyo dicho seguían todos sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 33, 'Y de Zabulón cincuenta mil, que salían á campaña á punto de guerra, con todas armas de guerra, dispuestos á pelear sin doblez de corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 34, 'Y de Nephtalí mil capitanes, y con ellos treinta y siete mil con escudo y lanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 35, 'De los de Dan, dispuestos á pelear, veinte y ocho mil y seiscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 36, 'Y de Aser, á punto de guerra y aparejados á pelear, cuarenta mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 37, 'Y de la otra parte del Jordán, de los Rubenitas y de los de Gad y de la media tribu de Manasés, ciento y veinte mil con toda suerte de armas de guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 38, 'Todos estos hombres de guerra, dispuestos para guerrear, vinieron con corazón perfecto á Hebrón, para poner á David por rey sobre todo Israel; asimismo todos los demás de Israel estaban de un mismo ánimo para poner á David por rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 39, 'Y estuvieron allí con David tres días comiendo y bebiendo, porque sus hermanos habían prevenido para ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 12, 40, 'Y también los que les eran vecinos, hasta Issachâr y Zabulón y Nephtalí, trajeron pan en asnos, y camellos, y mulos, y bueyes; y provisión de harina, masas de higos, y pasas, vino y aceite, bueyes y ovejas en abundancia, porque en Israel había alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 1, 'ENTONCES David tomó consejo con los capitanes de millares y de cientos, y con todos los jefes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 2, 'Y dijo David á todo el congreso de Israel: Si os parece bien y de Jehová nuestro Dios, enviaremos á todas partes á llamar nuestros hermanos que han quedado en todas las tierras de Israel, y á los sacerdotes y Levitas que están con ellos en sus ciudades y ejidos que se junten con nosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 3, 'Y traigamos el arca de nuestro Dios á nosotros, porque desde el tiempo de Saúl no hemos hecho caso de ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 4, 'Y dijo todo el congreso que se hiciese así, porque la cosa parecía bien á todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 5, 'Entonces juntó David á todo Israel, desde Sihor de Egipto hasta entrar en Hamath, para que trajesen el arca de Dios de Chîriath-jearim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 6, 'Y subió David con todo Israel á Baala de Chîriath-jearim, que es en Judá, para pasar de allí el arca de Jehová Dios que habita entre los querubines, sobre la cual su nombre es invocado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 7, 'Y lleváronse el arca de Dios de la casa de Abinadab en un carro nuevo; y Uzza y su hermano guiaban el carro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 8, 'Y David y todo Israel hacían alegrías delante de Dios con todas sus fuerzas, con canciones, arpas, salterios, tamboriles, címbalos y trompetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 9, 'Y como llegaron á la era de Chidón, Uzza extendió su mano al arca para tenerla, porque los bueyes se desmandaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 10, 'Y el furor de Jehová se encendió contra Uzza, é hiriólo, porque había extendido su mano al arca: y murió allí delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 11, 'Y David tuvo pesar, porque Jehová había hecho rotura en Uzza; por lo que llamó aquel lugar Pérez-uzza, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 12, 'Y David temió á Dios aquel día, y dijo: ¿Cómo he de traer á mi casa el arca de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 13, 'Y no trajo David el arca á su casa en la ciudad de David, sino llevóla á casa de Obed-edom Getheo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 13, 14, 'Y el arca de Dios estuvo en casa de Obed-edom, en su casa, tres meses: y bendijo Jehová la casa de Obed-edom, y todas las cosas que tenía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 1, 'E Hiram rey de Tiro envió embajadores á David, y madera de cedro, y albañiles y carpinteros, que le edificasen una casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 2, 'Y entendió David que Jehová lo había confirmado por rey sobre Israel, y que había ensalzado su reino sobre su pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 3, 'Entonces David tomó también mujeres en Jerusalem y aun engendró David hijos é hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 4, 'Y estos son los nombres de los que le nacieron en Jerusalem: Samua, Sobab, Nathán, Salomón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 5, 'Ibhar, Elisua, Eliphelet,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 6, 'Noga, Nepheg, Japhías,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 7, 'Elisama, Beel-iada y Eliphelet.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 8, 'Y oyendo los Filisteos que David había sido ungido por rey sobre todo Israel, subieron todos los Filisteos en busca de David. Y como David lo oyó, salió contra ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 9, 'Y vinieron los Filisteos y extendiéronse por el valle de Raphaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 10, 'Entonces David consultó á Dios, diciendo: ¿Subiré contra los Filisteos? ¿los entregarás en mi mano? Y Jehová le dijo: Sube, que yo los entregaré en tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 11, 'Subieron pues á Baal-perasim, y allí los hirió David. Dijo luego David: Dios rompió mis enemigos por mi mano, como se rompen las aguas. Por esto llamaron el nombre de aquel lugar Baal-perasim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 12, 'Y dejaron allí sus dioses, y David dijo que los quemasen al fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 13, 'Y volviendo los Filisteos á extenderse por el valle,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 14, 'David volvió á consultar á Dios, y Dios le dijo: No subas tras ellos, sino rodéalos, para venir á ellos por delante de los morales;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 15, 'Y así que oyeres venir un estruendo por las copas de los morales, sal luego á la batalla: porque Dios saldrá delante de ti, y herirá el campo de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 16, 'Hizo pues David como Dios le mandó, é hirieron el campo de los Filisteos desde Gabaón hasta Gezer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 14, 17, 'Y la fama de David fué divulgada por todas aquellas tierras: y puso Jehová temor de David sobre todas las gentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 1, 'HIZO también casas para sí en la ciudad de David, y labró un lugar para el arca de Dios, y tendióle una tienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 2, 'Entonces dijo David: El arca de Dios no debe ser traída sino por los Levitas; porque á ellos ha elegido Jehová para que lleven el arca de Jehová, y le sirvan perpetuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 3, 'Y juntó David á todo Israel en Jerusalem, para que pasasen el arca de Jehová á su lugar, el cual le había él preparado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 4, 'Juntó también David á los hijos de Aarón y á los Levitas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 5, 'De los hijos de Coath, Uriel el principal, y sus hermanos, ciento y veinte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 6, 'De los hijos de Merari, Asaías el principal, y sus hermanos, doscientos y viente;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 7, 'De los hijos de Gersón, Joel el principal, y sus hermanos, ciento y treinta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 8, 'De los hijos de Elisaphán, Semeías el principal, y sus hermanos, docientos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 9, 'De los hijos de Hebrón, Eliel el principal, y sus hermanos, ochenta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 10, 'De los hijos de Uzziel, Amidadab el principal, y sus hermanos, ciento y doce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 11, 'Y llamó David á Sadoc y á Abiathar, sacerdotes, y á los Levitas, Uriel, Asaías, Joel, Semeías, Eliel, y Aminadab;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 12, 'Y díjoles: Vosotros que sois los principales de padres entre los Levitas, santificaos, vosotros y vuestros hermanos, y pasad el arca de Jehová Dios de Israel al lugar que le he preparado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 13, 'Pues por no haberlo hecho así vosotros la primera vez, Jehová nuestro Dios hizo en nosotros rotura, por cuanto no le buscamos según la ordenanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 14, 'Así los sacerdotes y los Levitas se santificaron para traer el arca de Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 15, 'Y los hijos de los Levitos trajeron el arca de Dios puesta sobre sus hombros en las barras, como lo había mandado Moisés conforme á la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 16, 'Asimismo dijo David á los principales de los Levitas, que constituyesen de sus hermanos cantores, con instrumentos de música, con salterios, y arpas, y címbalos, que resonasen, y alzasen la voz con alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 17, 'Y los Levitas constituyeron á Hemán hijo de Joel; y de sus hermanos, á Asaph hijo de Berechîas; y de los hijos de Merari y de sus hermanos, á Ethán hijo de Cusaías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 18, 'Y con ellos á sus hermanos del segundo orden, á Zachârías, Ben y Jaaziel, Semiramoth, Jehiel, Unni, Eliab, Benaías, Maasías, y Mathithías, Eliphelehu, Micnías, Obed-edom, y Jehiel, los porteros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 19, 'Así Hemán, Asaph, y Ethán, que eran cantores, sonaban con címbalos de metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 20, 'Y Zachârías, Jaaziel, Semiramoth, Jehiel, Unni, Eliab, Maasías, y Benaías, con salterios sobre Alamoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 21, 'Y Mathithías, Eliphelehu, Micnías, Obed-edom, Jehiel, y Azazías, cantaban con arpas en la octava sobresaliendo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 22, 'Y Chênanías, principal de los Levitas, estaba para la entonación; pues él presidía en el canto, porque era entendido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 23, 'Y Berechîas y Elcana eran porteros del arca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 24, 'Y Sebanías, Josaphat, Nathanael, Amasai, Zachârías, Benaías, y Eliezer, sacerdotes, tocaban las trompetas delante del arca de Dios: Obed-edom y Jehías eran también porteros del arca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 25, 'David pues y los ancianos de Israel, y los capitanes de millares, fueron á traer el arca del pacto de Jehová, de casa de Obed-edom, con alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 26, 'Y ayudando Dios á los Levitas que llevaban el arca del pacto de Jehová, sacrificaban siete novillos y siete carneros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 27, 'Y David iba vestido de lino fino y también todos los Levitas que llevaban el arca, y asimismo los cantores; y Chênanías era maestro de canto entre los cantores. Llevaba también David sobre sí un ephod de lino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 28, 'De esta manera llevaba todo Israel el arca del pacto de Jehová, con júbilo y sonido de bocinas, y trompetas, y címbalos, y al son de salterios y arpas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 15, 29, 'Y como el arca del pacto de Jehová llegó á la ciudad de David, Michâl, hija de Saúl, mirando por una ventana, vió al rey David que saltaba y bailaba; y menospreciólo en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 1, 'ASI trajeron el arca de Dios, y asentáronla en medio de la tienda que David había tendido para ella: y ofrecieron holocaustos y pacíficos delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 2, 'Y como David hubo acabado de ofrecer el holocausto y los pacíficos, bendijo al pueblo en el nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 3, 'Y repartió á todo Israel, así á hombres como á mujeres, á cada uno una torta de pan, y una pieza de carne, y un frasco de vino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 4, 'Y puso delante del arca de Jehová ministros de los Levitas, para que recordasen, y confesasen, y loasen á Jehová Dios de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 5, 'Asaph el primero, el segundo después de él Zachârías, Jeiel, Semiramoth, Jehiel, Mathithías, Eliab, Benaías, Obed-edom, y Jehiel, con sus instrumentos de Salterios y arpas; mas Asaph hacía sonido con címbalos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 6, 'Benaías también y Jahaziel, sacerdotes, continuamente con trompetas delante del arca del pacto de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 7, 'Entonces, en aquel día, dió David principio á celebrar á Jehová por mano de Asaph y de sus hermanos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 8, 'Confesad á Jehová, invocad su nombre, Haced notorias en los pueblos sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 9, 'Cantad á él, cantadle salmos; Hablad de todas sus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 10, 'Gloriaos en su santo nombre; Alégrese el corazón de los que buscan á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 11, 'Buscad á Jehová y su fortaleza; Buscad su rostro continuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 12, 'Haced memoria de sus maravillas que ha obrado, De sus prodigios, y de los juicios de su boca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 13, 'Oh vosotros, simiente de Israel sus siervo, Hijos de Jacob, sus escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 14, 'Jehová, él es nuestro Dios; Sus juicios en toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 15, 'Haced memoria de su alianza perpetuamente, Y de la palabra que él mandó en mil generaciones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 16, 'Del pacto que concertó con Abraham, Y de su juramento á Isaac;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 17, 'El cual confirmó á Jacob por estatuto, Y á Israel por pacto sempiterno,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 18, 'Diciendo: A ti daré la tierra de Canaán, Suerte de vuestra herencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 19, 'Cuando erais pocos en número, Pocos y peregrinos en ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 20, 'Y andaban de nación en nación, Y de un reino á otro pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 21, 'No permitió que nadie los oprimiese: Antes por amor de ellos castigó á los reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 22, 'No toquéis, dijo, á mis ungidos, Ni hagáis mal á mis profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 23, 'Cantad á Jehová, toda la tierra, Anunciad de día en día su salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 24, 'Cantad entre las gentes su gloria, Y en todos los pueblos sus maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 25, 'Porque grande es Jehová, y digno de ser grandemente loado, Y de ser temido sobre todos los dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 26, 'Porque todos los dioses de los pueblos son nada: Mas Jehová hizo los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 27, 'Poderío y hermosura delante de él; Fortaleza y alegría en su morada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 28, 'Atribuid á Jehová, oh familias de los pueblos, Atribuid á Jehová gloria y potencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 29, 'Tributad á Jehová la gloria debida á su nombre: Traed ofrenda, y venid delante de él; Postraos delante de Jehová en la hermosura de su santidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 30, 'Temed en su presencia, toda la tierra: El mundo será aún establecido, para que no se conmueva.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 31, 'Alégrense los cielos, y gócese la tierra, Y digan en las naciones: Reina Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 32, 'Resuene la mar, y la plenitud de ella: Alégrese el campo, y todo lo que contiene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 33, 'Entonces cantarán los árboles de los bosques delante de Jehová, Porque viene á juzgar la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 34, 'Celebrad á Jehová, porque es bueno; Porque su misericordia es eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 35, 'Y decid: Sálvanos, oh Dios, salud nuestra: Júntanos, y líbranos de las gentes, Para que confesemos tu santo nombre, Y nos gloriemos en tus alabanzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 36, 'Bendito sea Jehová Dios de Israel, De eternidad á eternidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 37, 'Y dejó allí, delante del arca del pacto de Jehová, á Asaph y á sus hermanos, para que ministrasen de continuo delante del arca, cada cosa en su día:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 38, 'Y á Obed-edom y á sus hermanos, sesenta y ocho; y á Obed-edom hijo de Jeduthún, y á Asa, por porteros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 39, 'Asimismo á Sadoc el sacerdote, y á sus hermanos los sacerdotes, delante del tabernáculo de Jehová en el alto que estaba en Gabaón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 40, 'Para que sacrificasen continuamente, á mañana y tarde, holocaustos á Jehová en el altar del holocausto, conforme á todo lo que está escrito en la ley de Jehová, que él prescribió á Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 41, 'Y con ellos á Hemán y á Jeduthún, y los otros escogidos declarados por sus nombres, para glorificar á Jehová, porque es eterna su misericordia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 42, 'Con ellos á Hemán y á Jeduthún con trompetas y címbalos para tañer, y con otros instrumentos de música de Dios; y á los hijos de Jeduthún, por porteros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 16, 43, 'Y todo el pueblo se fué cada uno á su casa; y David se volvió para bendecir su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 1, 'Y ACONTECIO que morando David en su casa, dijo David al profeta Nathán: He aquí yo habito en casa de cedro, y el arca del pacto de Jehová debajo de cortinas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 2, 'Y Nathán dijo á David: Haz todo lo que está en tu corazón, porque Dios es contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 3, 'En aquella misma noche fué palabra de Dios á Nathán, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 4, 'Ve y di á David mi siervo: Así ha dicho Jehová: Tú no me edificarás casa en que habite:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 5, 'Porque no he habitado en casa alguna desde el día que saqué á los hijos de Israel hasta hoy; antes estuve de tienda en tienda, y de tabernáculo en tabernáculo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 6, 'En todo cuanto anduve con todo Israel ¿hablé una palabra á alguno de los jueces de Israel, á los cuales mandé que apacentasen mi pueblo, para decirles: Por qué no me edificáis una casa de cedro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 7, 'Por tanto, ahora dirás á mi siervo David: Así dijo Jehová de los ejércitos: Yo te tomé de la majada, de detrás del ganado, para que fueses príncipe sobre mi pueblo Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 8, 'Y he sido contigo en todo cuanto has andado, y he talado á todos tus enemigos de delante de ti, y hete hecho grande nombre, como el nombre de los grandes que son en la tiera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 9, 'Asimismo he dispuesto lugar á mi pueblo Israel, y lo he plantado para que habite por sí, y que no sea más conmovido: ni los hijos de iniquidad lo consumirán más, como antes,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 10, 'Y desde el tiempo que puse los jueces sobre mi pueblo Israel; mas humilllaré á todos tus enemigos. Hágote además saber que Jehová te ha de edificar casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 11, 'Y será que, cuando tus días fueren cumplidos para irte con tus padres, levantaré tu simiente después de ti, la cual será de tus hijos, y afirmaré su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 12, 'El me edificará casa, y yo confirmaré su trono eternalmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 13, 'Yo le seré por padre, y él me será por hijo: y no quitaré de él mi misericordia, como la quité de aquel que fué antes de ti;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 14, 'Mas yo lo confirmaré en mi casa y en mi reino eternalmente; y su trono será firme para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 15, 'Conforme á todas estas palabras, y conforme á toda esta visión, así habló Nathán á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 16, 'Y entró el rey David, y estuvo delante de Jehová, y dijo: Jehová Dios, ¿quién soy yo, y cuál es mi casa, que me has traído hasta este lugar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 17, 'Y aun esto, oh Dios, te ha parecido poco, pues que has hablado de la casa de tu siervo para más lejos, y me has mirado como á un hombre excelente, oh Jehová Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 18, '¿Qué más puede añadir David pidiendo de ti para glorificar á tu siervo? mas tú conoces á tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 19, 'Oh Jehová, por amor de tu siervo y según tu corazón, has hecho toda esta grandeza, para hacer notorias todas tus grandezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 20, 'Jehová, no hay semejante á ti, ni hay Dios sino tú, según todas las cosas que hemos oído con nuestros oídos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 21, '¿Y qué gente hay en la tierra como tu pueblo Israel, cuyo Dios fuese y se redimiera un pueblo, para hacerte nombre con grandezas y maravillas, echando las gentes de delante de tu pueblo, que tú rescataste de Egipto?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 22, 'Tú has constituído á tu pueblo Israel por pueblo tuyo para siempre; y tú, Jehová, has venido á ser su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 23, 'Ahora pues, Jehová, la palabra que has hablado acerca de tu siervo y de su casa, sea firme para siempre, y haz como has dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 24, 'Permanezca pues, y sea engrandecido tu nombre para siempre, á fin de que se diga: Jehová de los ejércitos, Dios de Israel, es Dios para Israel. Y sea la casa de tu siervo David firme delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 25, 'Porque tú, Dios mío, revelaste al oído á tu siervo que le has de edificar casa; por eso ha hallado tu siervo motivo de orar delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 26, 'Ahora pues, Jehová, tú eres el Dios que has hablado de tu siervo este bien;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 17, 27, 'Y ahora has querido bendecir la casa de tu siervo, para que permanezca perpetuamente delante de ti: porque tú, Jehová, la has bendecido, y será bendita para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 1, 'DESPUÉS de estas cosas aconteció que David hirió á los Filisteos, y los humilló; y tomó á Gath y sus villas de mano de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 2, 'También hirió á Moab; y los Moabitas fueron siervos de David trayéndole presentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 3, 'Asimismo hirió David á Adarezer rey de Soba, en Hamath, yendo él á asegurar su dominio al río de Eufrates.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 4, 'Y tomóles David mil carros, y siete mil de á caballo, y veinte mil hombres de á pie: y desjarretó David los caballos de todos los carros, excepto los de cien carros que dejó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 5, 'Y viniendo los Siros de Damasco en ayuda de Adarezer rey de Soba, David hirió de los Siros veintidós mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 6, 'Y puso David guarnición en Siria la de Damasco, y los Siros fueron hechos siervos de David, trayéndole presentes: porque Jehová salvaba á David donde quiera que iba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 7, 'Tomó también David los escudos de oro que llevaban los siervos de Adarezer, y trájolos á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 8, 'Asimismo de Thibath y de Chûn ciudades de Adarezer, tomó David muy mucho metal, de que Salomón hizo el mar de bronce, las columnas, y vasos de bronce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 9, 'Y oyendo Tou rey de Hamath, que David había deshecho todo el ejército de Adarezer, rey de Soba,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 10, 'Envió á Adoram su hijo al rey David, á saludarle y á bendecirle por haber peleado con Adarezer, y haberle vencido; porque Tou tenía guerra con Adarezer. Envióle también toda suerte de vasos de oro, de plata y de metal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 11, 'Los cuales el rey David dedicó á Jehová, con la plata y oro que había tomado de todas las naciones, de Edom, de Moab, de los hijos de Ammón, de los Filisteos, y de Amalec.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 12, 'A más de esto Abisai hijo de Sarvia hirió en el valle de la Sal dieciocho mil Idumeos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 13, 'Y puso guarnición en Edom, y todos los Idumeos fueron siervos de David: porque Jehová guardaba á David donde quiera que iba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 14, 'Y reinó David sobre todo Israel, y hacía juicio y justicia á todo su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 15, 'Y Joab hijo de Sarvia era general del ejército; y Josaphat hijo de Ahilud, canciller;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 16, 'Y Sadoc hijo de Achîtob, y Abimelec hijo de Abiathar, eran sacerdotes; y Sausa, secretario;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 18, 17, 'Y Benaías hijo de Joiada era sobre los Ceretheos y Peletheos; y los hijos de David eran los príncipes cerca del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 1, 'DESPUÉS de estas cosas aconteció que murió Naas rey de los hijos de Ammón, y reinó en su lugar su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 2, 'Y dijo David: Haré misericordia con Hanán hijo de Naas, porque también su padre hizo conmigo misericordia. Así David envió embajadores que lo consolasen de la muerte de su padre. Mas venidos los siervos de David en la tierra de los hijos de Ammón á Hanán, para consolarle,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 3, 'Los príncipes de los hijos de Ammón dijeron á Hanán: ¿A tu parecer honra David á tu padre, que te ha enviado consoladores? ¿no vienen antes sus siervos á ti para escudriñar, é inquirir, y reconocer la tierra?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 4, 'Entonces Hanán tomó los siervos de David, y rapólos, y cortóles los vestidos por medio, hasta las nalgas, y despachólos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 5, 'Fuéronse pues, y dada que fué la nueva á David de aquellos varones, él envió á recibirlos, porque estaban muy afrentados. E hízoles decir el rey: Estaos en Jericó hasta que os crezca la barba, y entonces volveréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 6, 'Y viendo los hijos de Ammón que se habían hecho odiosos á David, Hanán y los hijos de Ammón enviaron mil talentos de plata, para tomar á sueldo carros y gente de á caballo de Siria de los ríos, y de la Siria de Maachâ, y de Soba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 7, 'Y tomaron á sueldo treinta y dos mil carros, y al rey de Maachâ y á su pueblo, los cuales vinieron y asentaron su campo delante de Medeba. Y juntáronse también los hijos de Ammón de sus ciudades, y vinieron á la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 8, 'Oyéndolo David, envió á Joab con todo el ejército de los hombres valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 9, 'Y los hijos de Ammón salieron, y ordenaron su tropa á la entrada de la ciudad; y los reyes que habían venido, estaban por sí en el campo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 10, 'Y viendo Joab que la haz de la batalla estaba contra él delante y á las espaldas, escogió de todos los más aventajados que había en Israel, y ordenó su escuadrón contra los Sirios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 11, 'Puso luego el resto de la gente en mano de Abisai su hermano, ordenándolos en batalla contra los Ammonitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 12, 'Y dijo: Si los Siros fueren más fuertes que yo, tú me salvarás; y si los Ammonitas fueren más fuertes que tú, yo te salvaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 13, 'Esfuérzate, y esforcémonos por nuestro pueblo, y por las ciudades de nuestro Dios; y haga Jehová lo que bien le pareciere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 14, 'Acercóse luego Joab y el pueblo que tenía consigo, para pelear contra los Siros; mas ellos huyeron delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 15, 'Y los hijos de Ammón, viendo que los Siros habían huído, huyeron también ellos delante de Abisai su hermano, y entráronse en la ciudad. Entonces Joab se volvió á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 16, 'Y viendo los Siros que habían caído delante de Israel, enviaron embajadores, y trajeron á los Siros que estaban de la otra parte del río, cuyo capitán era Sophach, general del ejército de Adarezer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 17, 'Luego que fué dado aviso á David, juntó á todo Israel, y pasando el Jordán vino á ellos, y ordenó contra ellos su ejército. Y como David hubo ordenado su tropa contra ellos, pelearon con él los Siros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 18, 'Mas el Siro huyó delante de Israel; y mató David de los Siros siete mil hombres de los carros, y cuarenta mil hombres de á pie: asimismo mató á Sophach, general del ejército.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 19, 19, 'Y viendo los Siros de Adarezer que habían caído delante de Israel, concertaron paz con David, y fueron sus siervos; y nunca más quiso el Siro ayudar á los hijos de Ammón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 20, 1, 'Y ACONTECIO á la vuelta del año, en el tiempo que suelen los reyes salir á la guerra, que Joab sacó las fuerzas del ejército, y destruyó la tierra de los hijos de Ammón, y vino y cercó á Rabba. Mas David estaba en Jerusalem: y Joab batió á Rabba, y destruyóla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 20, 2, 'Y tomó David la corona de su rey de encima de su cabeza, y hallóla de peso de un talento de oro, y había en ella piedras preciosas; y fué puesta sobre la cabeza de David. Y Además de esto sacó de la ciudad un muy gran despojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 20, 3, 'Sacó también al pueblo que estaba en ella, y cortólos con sierras, y con trillos de hierro, y segures. Lo mismo hizo David á todas las ciudades de los hijos de Ammón. Y volvióse David con todo el pueblo á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 20, 4, 'Después de esto aconteció que se levantó guerra en Gezer con los Filisteos; é hirió Sibbecai Husathita á Sippai, del linaje de los gigantes; y fueron humillados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 20, 5, 'Y volvióse á levantar guerra con los Filisteos; é hirió Elhanán hijo de Jair á Lahmi, hermano de Goliath Getheo, el asta de cuya lanza era como un enjullo de tejedores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 20, 6, 'Y volvió á haber guerra en Gath, donde hubo un hombre de grande estatura, el cual tenía seis dedos en pies y manos, en todos veinticuatro: y también era hijo de Rapha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 20, 7, 'Denostó él á Israel, mas hiriólo Jonathán, hijo de Sima hermano de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 20, 8, 'Estos fueron hijos de Rapha en Gath, los cuales cayeron por mano de David y de sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 1, 'MAS Satanás se levantó contra Israel, é incitó á David á que contase á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 2, 'Y dijo David á Joab y á los príncipes del pueblo: Id, contad á Israel desde Beer-seba hasta Dan, y traedme el número de ellos para que yo lo sepa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 3, 'Y dijo Joab: Añada Jehová á su pueblo cien veces otros tantos. Rey señor mío, ¿no son todos estos siervos de mi señor? ¿para qué procura mi señor esto, que será pernicioso á Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 4, 'Mas el mandamiento del rey pudo más que Joab. Salió por tanto Joab, y fué por todo Israel; y volvió á Jerusalem, y dió la cuenta del número del pueblo á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 5, 'Y hallóse en todo Israel que sacaban espada, once veces cien mil; y de Judá cuatrocientos y setenta mil hombres que sacaban espada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 6, 'Entre estos no fueron contados los Levitas, ni los hijos de Benjamín, porque Joab abominaba el mandamiento del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 7, 'Asimismo desagradó este negocio á los ojos de Dios, é hirió á Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 8, 'Y dijo David á Dios: He pecado gravemente en hacer esto: ruégote que hagas pasar la iniquidad de tu siervo, porque yo he hecho muy locamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 9, 'Y habló Jehová á Gad, vidente de David, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 10, 'Ve, y habla á David, y dile: Así ha dicho Jehová: Tres cosas te propongo; escoge de ellas una que yo haga contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 11, 'Y viniendo Gad á David, díjole: Así ha dicho Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 12, 'Escógete, ó tres años de hambre; ó ser por tres meses deshecho delante de tus enemigos, y que la espada de tus adversarios te alcance; ó por tres días la espada de Jehová y pestilencia en la tierra, y que el ángel de Jehová destruya en todo el término de Israel: mira pues qué he de responder al que me ha enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 13, 'Entonces David dijo á Gad: Estoy en grande angustia: ruego que yo caiga en la mano de Jehová; porque sus misericordias son muchas en extremo, y que no caiga yo en manos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 14, 'Así Jehová dió pestilencia en Israel, y cayeron de Israel setenta mil hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 15, 'Y envió Jehová el ángel á Jerusalem para destruirla: pero estando él destruyendo, miró Jehová, y arrepintióse de aquel mal,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 16, '(21-17) Y alzando David sus ojos, vió al ángel de Jehová, que estaba entre el cielo y la tierra, teniendo un espada desnuda en su mano, extendida contra Jerusalem. Entonces David y los ancianos se postraron sobre sus rostros, cubiertos de sacos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 17, '(21-18) Y dijo David á Dios: ¿No soy yo el que hizo contar el pueblo? Yo mismo soy el que pequé, y ciertamente he hecho mal; mas estas ovejas, ¿qué han hecho? Jehová Dios mío, sea ahora tu mano contra mí, y contra la casa de mi padre, y no haya plaga en tu pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 18, '(21-19) Y el ángel de Jehová ordenó á Gad que dijese á David, que subiese y construyese un altar á Jehová en la era de Ornán Jebuseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 19, '(21-20) Entonces David subió, conforme á la palabra de Gad que le había dicho en nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 20, '(21-21) Y volviéndose Ornán vió el ángel; por lo que se escondieron cuatro hijos suyos que con él estaban. Y Ornán trillaba el trigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 21, '(21-22) Y viniendo David á Ornán, miró éste, y vió á David: y saliendo de la era, postróse en tierra á David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 22, '(21-23) Entonces dijo David á Ornán: Dame este lugar de la era, en que edifique un altar á Jehová, y dámelo por su cabal precio, para que cese la plaga del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 23, '(21-24) Y Ornán respondió á David: Tómalo para ti, y haga mi señor el rey lo que bien le pareciere: y aun los bueyes daré para el holocausto, y los trillos para leña, y trigo para el presente: yo lo doy todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 24, '(21-25) Entonces el rey David dijo á Ornán: No, sino que efectivamente la compraré por su justo precio: porque no tomaré para Jehová lo que es tuyo, ni sacrificaré holocausto que nada me cueste.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 25, '(21-26) Y dió David á Ornán por el lugar seiscientos siclos de oro por peso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 26, '(21-27) Y edificó allí David un altar á Jehová, en el que ofreció holocaustos y sacrificios pacíficos, é invocó á Jehová, el cual le respondió por fuego de los cielos en el altar del holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 27, '(21-28) Y como Jehová habló al ángel, él volvió su espada á la vaina.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 28, '(21-29) Entonces viendo David que Jehová le había oído en la era de Ornán Jebuseo, sacrificó allí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 29, '(21-30) Y el tabernáculo de Jehová que Moisés había hecho en el desierto, y el altar del holocausto, estaban entonces en el alto de Gabaón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 21, 30, '(21-31) Mas David no pudo ir allá á consultar á Dios, porque estaba espantado á causa de la espada del ángel de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 1, 'Y DIJO David: Esta es la casa de Jehová Dios, y este es el altar del holocausto para Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 2, 'Después mandó David que se juntasen los extranjeros que estaban en la tierra de Israel, y señaló de ellos canteros que labrasen piedras para edificar la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 3, 'Asimismo aparejó David mucho hierro para la clavazón de las puertas, y para las junturas; y mucho metal sin peso, y madera de cedro sin cuenta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 4, 'Porque los Sidonios y Tirios habían traído á David madera de cedro innumerable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 5, 'Y dijo David: Salomón mi hijo es muchacho y tierno, y la casa que se ha de edificar á Jehová ha de ser magnífica por excelencia, para nombre y honra en todas las tierras; ahora pues yo le aparejaré lo necesario. Y preparó David antes de su muerte en grande abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 6, 'Llamó entonces David á Salomón su hijo, y mandóle que edificase casa á Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 7, 'Y dijo David á Salomón: Hijo mío, en mi corazón tuve el edificar templo al nombre de Jehová mi Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 8, 'Mas vino á mí palabra de Jehová, diciendo: Tú has derramado mucha sangre, y has traído grandes guerras: no edificarás casa á mi nombre, porque has derramado mucha sangre en la tierra delante de mí:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 9, 'He aquí, un hijo te nacerá, el cual será varón de reposo, porque yo le daré quietud de todos sus enemigos en derredor; por tanto su nombre será Salomón; y yo daré paz y reposo sobre Israel en sus días:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 10, 'El edificará casa á mi nombre, y él me será á mí por hijo, y yo le seré por padre; y afirmaré el trono de su reino sobre Israel para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 11, 'Ahora pues, hijo mío, sea contigo Jehová, y seas prosperado, y edifiques casa á Jehová tu Dios, como él ha dicho de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 12, 'Y Jehová te dé entendimiento y prudencia, y él te dé mandamientos para Israel; y que tú guardes la ley de Jehová tu Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 13, 'Entonces serás prosperado, si cuidares de poner por obra los estatutos y derechos que Jehová mandó á Moisés para Israel. Esfuérzate pues, y cobra ánimo; no temas, ni desmayes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 14, 'He aquí, yo en mi estrechez he prevenido para la casa de Jehová cien mil talentos de oro, y un millar de millares de talentos de plata: no tiene peso el metal ni el hierro, porque es mucho. Asimismo he aprestado madera y piedra, á lo cual tú añadirás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 15, 'Tú tienes contigo muchos oficiales, canteros, albañiles, y carpinteros, y todo hombre experto en toda obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 16, 'Del oro, de la plata, del metal, y del hierro, no hay número. Levántate pues, y á la obra; que Jehová será contigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 17, 'Asimismo mandó David á todos los principales de Israel que diesen ayuda á Salomón su hijo, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 18, '¿No es con vosotros Jehová vuestro Dios, el cual os ha dado quietud de todas partes? porque él ha entregado en mi mano los moradores de la tierra, y la tierra ha sido sujetada delante de Jehová, y delante de su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 22, 19, 'Poned, pues, ahora vuestros corazones y vuestros ánimos en buscar á Jehová vuestro Dios; y levantaos, y edificad el santuario del Dios Jehová, para traer el arca del pacto de Jehová, y lo santos vasos de Dios, á la casa edificada al nombre de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 1, 'SIENDO pues David ya viejo y harto de días, hizo á Salomón su hijo rey sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 2, 'Y juntando á todos los principales de Israel, y á los sacerdotes y Levitas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 3, 'Fueron contados los Levitas de treinta años arriba; y fué el número de ellos por sus cabezas, contados uno á uno, treinta y ocho mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 4, 'De éstos, veinticuatro mil para dar prisa á la obra de la casa de Jehová; y gobernadores y jueces, seis mil;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 5, 'Además cuatro mil porteros; y cuatro mil para alabar á Jehová, dijo David, con los instrumentos que he hecho para rendir alabanzas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 6, 'Y repartiólos David en órdenes conforme á los hijos de Leví, Gersón y Coath y Merari.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 7, 'Los hijos de Gersón: Ladán, y Simi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 8, 'Los hijos de Ladán, tres: Jehiel el primero, después Zetham y Joel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 9, 'Los hijos de Simi, tres: Selomith, Haziel, y Arán. Estos fueron los príncipes de las familias de Ladán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 10, 'Y los hijos de Simi: Jahath, Zinat, Jeus, y Berías. Estos cuatro fueron los hijos de Simi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 11, 'Jahat era el primero, Zinat el segundo; mas Jeus y Berías no multiplicaron en hijos, por lo cual fueron contados por una familia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 12, 'Los hijos de Coath: Amram, Ishar, Hebrón, y Uzziel, ellos cuatro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 13, 'Los hijos de Amram: Aarón y Moisés. Y Aarón fué apartado para ser dedicado á las más santas cosas, él y sus hijos para siempre, para que quemasen perfumes delante de Jehová, y le ministrasen, y bendijesen en su nombre, para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 14, 'Y los hijos de Moisés, varón de Dios, fueron contados en la tribu de Leví.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 15, 'Los hijos de Moisés fueron Gersón y Eliezer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 16, 'Hijo de Gersón fué Sebuel el primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 17, 'E hijo de Eliezer fué Rehabía el primero. Y Eliezer no tuvo otros hijos; mas los hijos de Rehabía fueron muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 18, 'Hijo de Ishar fué Selomith el primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 19, 'Los hijos de Hebrón: Jería el primero, Amarías el segundo, Jahaziel el tercero, y Jecamán el cuarto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 20, 'Los hijos de Uzziel: Michâ el primero, é Isía el segundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 21, 'Los hijos de Merari: Mahali y Musi. Los hijos de Mahali: Eleazar y Cis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 22, 'Y murió Eleazar sin hijos, mas tuvo hijas; y los hijos de Cis, sus hermanos, las tomaron por mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 23, 'Los hijos de Musi: Mahali, Eder y Jerimoth, ellos tres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 24, 'Estos son los hijos de Leví en las familias de sus padres, cabeceras de familias en sus delineaciones, contados por sus nombres, por sus cabezas, los cuales hacían obra en el ministerio de la casa de Jehová, de veinte años arriba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 25, 'Porque David dijo: Jehová Dios de Israel ha dado reposo á su pueblo Israel, y el habitar en Jerusalem para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 26, 'Y también los Levitas no llevarán más el tabernáculo, y todos sus vasos para su ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 27, 'Así que, conforme á las postreras palabras de David, fué la cuenta de los hijos de Leví de veinte años arriba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 28, 'Y estaban bajo la mano de los hijos de Aarón, para ministrar en la casa de Jehová, en los atrios y en las cámaras, y en la purificación de toda cosa santificada, y en la demás obra del ministerio de la casa de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 29, 'Asimismo para los panes de la proposición, y para la flor de la harina para el sacrificio, y para las hojuelas sin levadura, y para la fruta de sartén, y para lo tostado, y para toda medida y cuenta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 30, 'Y para que asistiesen cada mañana todos los días á confesar y alabar á Jehová, y asimismo á la tarde;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 31, 'Y para ofrecer todos los holocaustos á Jehová los sábados, nuevas lunas, y solemnidades, por la cuenta y forma que tenían, continuamente delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 23, 32, 'Y para que tuviesen la guarda del tabernáculo del testimonio, y la guarda del santuario, y las órdenes de los hijos de Aarón sus hermanos, en el ministerio de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 1, 'TAMBIÉN los hijos de Aarón tuvieron sus repartimientos. Los hijos de Aarón: Nadab, Abiú, Eleazar é Ithamar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 2, 'Mas Nadab, y Abiú murieron antes que su padre, y no tuvieron hijos: Eleazar é Ithamar tuvieron el sacerdocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 3, 'Y David los repartió, siendo Sadoc de los hijos de Eleazar, y Ahimelech de los hijos de Ithamar, por sus turnos en su ministerio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 4, 'Y los hijos de Eleazar fueron hallados, cuanto á sus principales varones, muchos más que los hijos de Ithamar; y repartiéronlos así: De los hijos de Eleazar había dieciséis cabezas de familias paternas; y de los hijos de Ithamar por las familias de sus padres, ocho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 5, 'Repartiéronlos pues por suerte los unos con los otros: porque de los hijos de Eleazar y de los hijos de Ithamar hubo príncipes del santuario, y príncipes de la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 6, 'Y Semeías escriba, hijo de Nathanael, de los Levitas, escribiólos delante del rey y de los príncipes, y delante de Sadoc el sacerdote, y de Ahimelech hijo de Abiathar, y de los príncipes de las familias de los sacerdotes y Levitas: y adscribían una familia á Eleazar, y á Ithamar otra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 7, 'Y la primera suerte salió por Joiarib, la segunda por Jedaía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 8, 'La tercera por Harim, la cuarta por Seorim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 9, 'La quinta por Malchîas, la sexta por Miamim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 10, 'La séptima por Cos, la octava por Abías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 11, 'La nona por Jesua, la décima por Sechânía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 12, 'La undécima por Eliasib, la duodécima por Jacim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 13, 'La décimatercia por Uppa, la décimacuarta por Isebeab;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 14, 'La décimaquinta por Bilga, la décimasexta por Immer;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 15, 'La décimaséptima por Hezir, la décimaoctava por Aphses;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 16, 'La décimanona por Pethaía, la vigésima por Hezeciel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 17, 'La vigésimaprima por Jachim, la vigésimasegunda por Hamul;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 18, 'La vigésimatercia por Delaía, la vigésimacuarta por Maazía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 19, 'Estos fueron contados en su ministerio, para que entrasen en la casa de Jehová, conforme á su ordenanza, bajo el mando de Aarón su padre, de la manera que le había mandado Jehová el Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 20, 'Y de los hijos de Leví que quedaron: Subael, de los hijos de Amram; y de los hijos de Subael, Jehedías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 21, 'Y de los hijos de Rehabía, Isias el principal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 22, 'De los Ishareos, Selemoth; é hijo de Selemoth, Jath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 23, 'Y de los hijos de Hebrón; Jeria el primero, el segundo Amarías, el tercero Jahaziel, el cuarto Jecamán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 24, 'Hijo de Uzziel, Michâ; é hijo de Michâ, Samir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 25, 'Hermano de Michâ, Isía; é hijo de Isía, Zachârías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 26, 'Los hijos de Merari: Mahali y Musi; hijo de Jaazia, Benno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 27, 'Los hijos de Merari por Jaazia: Benno, y Soam, Zachûr é Ibri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 28, 'Y de Mahali, Eleazar, el cual no tuvo hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 29, 'Hijo de Cis, Jerameel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 30, 'Los hijos de Musi: Maheli, Eder y Jerimoth. Estos fueron los hijos de los Levitas conforme á las casas de sus familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 24, 31, 'Estos también echaron suertes, como sus hermanos los hijos de Aarón, delante del rey David, y de Sadoc y de Ahimelech, y de los príncipes de las familias de los sacerdotes y Levitas: el principal de los padres igualmente que el menor de sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 1, 'ASIMISMO David y los príncipes del ejército apartaron para el ministerio á los hijos de Asaph, y de Hemán, y de Jeduthún, los cuales profetizasen con arpas, salterios, y címbalos: y el número de ellos fué, de hombres idóneos para la obra de su ministerio respectivo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 2, 'De los hijos de Asaph: Zachûr, José, Methanías, y Asareela, hijos de Asaph, bajo la dirección de Asaph, el cual profetizaba á la orden del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 3, 'De Jeduthún: los hijos de Jeduthún, Gedalías, Sesi, Jesaías, Hasabías, y Mathithías, y Simi: seis, bajo la mano de su padre Jeduthún, el cual profetizaba con arpa, para celebrar y alabar á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 4, 'De Hemán: los hijos de Hemán, Buccia, Mathanía, Uzziel, Sebuel, Jerimoth, Hananías, Hanani, Eliatha, Gidalthi, Romamti-ezer, Josbecasa, Mallothi, Othir, y Mahazioth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 5, 'Todos estos fueron hijos de Hemán, vidente del rey en palabras de Dios, para ensalzar el poder suyo: y dió Dios á Hemán catorce hijos y tres hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 6, 'Y todos estos estaban bajo la dirección de su padre en la música, en la casa de Jehová, con címbalos, salterios y arpas, para el ministerio del templo de Dios, por disposición del rey acerca de Asaph, de Jeduthún, y de Hemán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 7, 'Y el número de ellos con sus hermanos instruídos en música de Jehová, todos los aptos, fué doscientos ochenta y ocho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 8, 'Y echaron suertes para los turnos del servicio, entrando el pequeño con el grande, lo mismo el maestro que el discípulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 9, 'Y la primera suerte salió por Asaph, á José: la segunda á Gedalías, quien con sus hermanos é hijos fueron doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 10, 'La tercera á Zachûr, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 11, 'La cuarta á Isri, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 12, 'La quinta á Nethanías, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 13, 'La sexta á Buccia, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 14, 'La séptima á Jesarela, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 15, 'La octava á Jesahías, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 16, 'La nona á Mathanías, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 17, 'La décima á Simi, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 18, 'La undécima á Azareel, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 19, 'La duodécima á Hasabías, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 20, 'La décimatercia á Subael, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 21, 'La décimacuarta á Mathithías, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 22, 'La décimaquinta á Jerimoth, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 23, 'La décimasexta á Hananías, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 24, 'La décimaséptima á Josbecasa, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 25, 'La décimaoctava á Hanani, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 26, 'La décimanona á Mallothi, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 27, 'La vigésima á Eliatha, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 28, 'La vigésimaprima á Othir, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 29, 'La vigésimasegunda á Giddalthi, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 30, 'La vigésimatercia á Mahazioth, con sus hijos y sus hermanos, doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 25, 31, 'La vigésimacuarta á Romamti-ezer, con sus hijos y sus hermanos, doce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 1, 'CUANTO á los repartimientos de los porteros: De los Coraitas: Meselemia hijo de Coré, de los hijos de Asaph.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 2, 'Los hijos de Meselemia: Zachârías el primogénito, Jediael el segundo, Zebadías el tercero, Jatnael el cuarto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 3, 'Elam el quinto, Johanam el sexto, Elioenai el séptimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 4, 'Los hijos de Obed-edom: Semeías el primogénito, Jozabad el segundo, Joab el tercero, el cuarto Sachâr, el quinto Nathanael;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 5, 'El sexto Anmiel, el séptimo Issachâr, el octavo Peullethai: porque Dios había bendecido á Obed-edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 6, 'También de Semeías su hijo nacieron hijos que fueron señores sobre la casa de sus padres; porque eran varones muy valerosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 7, 'Los hijos de Semeías: Othni, Raphael, Obed, Elzabad, y sus hermanos, hombres esforzados; asimismo Eliú, y Samachîas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 8, 'Todos estos de los hijos de Obed-edom: ellos con sus hijos y sus hermanos, hombres robustos y fuertes para el ministerio; sesenta y dos, de Obed-edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 9, 'Y los hijos de Meselemia y sus hermanos, dieciocho hombres valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 10, 'De Hosa, de los hijos de Merari: Simri el principal, (aunque no era el primogénito, mas su padre lo puso para que fuese cabeza;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 11, 'El segundo Hilcías, el tercero Tebelías, el cuarto Zachârías: todos los hijos de Hosa y sus hermanos fueron trece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 12, 'Entre estos se hizo la distribución de los porteros, alternando los principales de los varones en la guardia con sus hermanos, para servir en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 13, 'Y echaron suertes, el pequeño con el grande, por las casas de sus padres, para cada puerta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 14, 'Y cayó la suerte al oriente á Selemía. Y á Zachârías su hijo, consejero entendido, metieron en las suertes: y salió la suerte suya al norte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 15, 'Y por Obed-edom, al mediodía; y por sus hijos, la casa de la consulta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 16, 'Por Suppim y Hosa al occidente, con la puerta de Sallechêt al camino de la subida, guardia contra guardia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 17, 'Al oriente seis Levitas, al norte cuatro de día; al mediodía cuatro de día; y á la casa de la consulta, de dos en dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 18, 'En la cámara de los vasos al occidente, cuatro al camino, y dos en la cámara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 19, 'Estos son los repartimientos de los porteros, hijos de los Coraitas, y de los hijos de Merari.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 20, 'Y de los Levitas, Achîas tenía cargo de los tesoros de la casa de Dios, y de los tesoros de las cosas santificadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 21, 'Cuanto á los hijos de Ladán, hijos de Gersón: de Ladán, los príncipes de las familias de Ladán fueron Gersón, y Jehieli.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 22, 'Los hijos de Jehieli, Zethán y Joel su hermano, tuvieron cargo de los tesoros de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 23, 'Acerca de los Amramitas, de los Isharitas, de los Hebronitas, y de los Uzzielitas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 24, 'Sebuel hijo de Gersón, hijo de Moisés, era principal sobre los tesoros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 25, 'En orden á su hermano Eliezer, hijo de éste era Rehabía, hijo de éste Isaías, hijo de éste Joram, hijo de éste Zichri, del que fué hijo Selomith.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 26, 'Este Selomith y sus hermanos tenían cargo de todos los tesoros de todas las cosas santificadas, que había consagrado el rey David, y los príncipes de las familias, y los capitanes de millares y de cientos, y los jefes del ejército;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 27, 'De lo que habían consagrado de las guerras y de los despojos, para reparar la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 28, 'Asimismo todas las cosas que había consagrado Samuel vidente, y Saúl hijo de Cis, y Abner hijo de Ner, y Joab hijo de Sarvia: y todo lo que cualquiera consagraba, estaba bajo la mano de Selomith y de sus hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 29, 'De los Isharitas, Chenanía y sus hijos eran gobernadores y jueces sobre Israel en las obras de fuera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 30, 'De los Hebronitas, Hasabías y sus hermanos, hombres de vigor, mil y setecientos, gobernaban á Israel de la otra parte del Jordán, al occidente, en toda la obra de Jehová, y en el servicio del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 31, 'De los Hebronitas, Jerías era el principal entre los Hebronitas repartidos en sus linajes por sus familias. En el año cuarenta del reinado de David se registraron, y halláronse entre ellos fuertes y vigorosos en Jazer de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 26, 32, 'Y sus hermanos, hombres valientes, eran dos mil y setecientos, cabezas de familias, los cuales el rey David constituyó sobre los Rubenitas, Gaditas, y sobre la media tribu de Manasés, para todas las cosas de Dios, y los negocios del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 1, 'Y LOS hijos de Israel según su número, á saber, príncipes de familias, tribunos, centuriones y oficiales de los que servían al rey en todos los negocios de las divisiones que entraban y salían cada mes en todos los meses del año, eran en cada división veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 2, 'Sobre la primera división del primer mes estaba Jasobam hijo de Zabdiel; y había en su división veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 3, 'De los hijos de Phares fué él jefe de todos los capitanes de las compañías del primer mes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 4, 'Sobre la división del segundo mes estaba Dodai Ahohita: y Micloth era mayor general en su división, en la que también había veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 5, 'El jefe de la tercera división para el tercer mes era Benaías, hijo de Joiada sumo sacerdote; y en su división había veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 6, 'Este Benaías era valiente entre los treinta y sobre los treinta; y en su división estaba Amisabad su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 7, 'El cuarto jefe para el cuarto mes era Asael hermano de Joab, y después de él Zebadías su hijo; y en su división había veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 8, 'El quinto jefe para el quinto mes era Sambuth Izrita: y en su división había veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 9, 'El sexto para el sexto mes era Hira hijo de Icces, de Tecoa; y en su división veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 10, 'El séptimo para el séptimo mes era Helles Pelonita, de los hijos de Ephraim; y en su división viente y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 11, 'El octavo para el octavo mes era Sibbecai Husatita, de Zarahi; y en su división veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 12, 'El noveno para el noveno mes era Abiezer Anathothita, de los Benjamitas; y en su división veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 13, 'El décimo para el décimo mes era Maharai Nethophathita, de Zarahi; y en su división veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 14, 'El undécimo para el undécimo mes era Benaías Piratonita, de los hijos de Ephraim; y en su división veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 15, 'El duodécimo para el duodécimo mes era Heldai Nethophathita, de Othniel; y en su división veinte y cuatro mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 16, 'Asimismo sobre las tribus de Israel: el jefe de los Rubenitas era Eliezer hijo de Zichri; de los Simeonitas, Sephatías, hijo de Maachâ:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 17, 'De los Levitas, Hasabías hijo de Camuel; de los Aaronitas, Sadoc;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 18, 'De Judá, Eliú, uno de los hermanos de David; de los de Issachâr, Omri hijo de Michâel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 19, 'De los de Zabulón, Ismaías hijo de Abdías; de los de Nephtalí, Jerimoth hijo de Azriel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 20, 'De los hijos de Ephraim, Oseas hijo de Azazía; de la media tribu de Manasés, Joel hijo de Pedaía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 21, 'De la otra media tribu de Manasés en Galaad, Iddo hijo de Zachârías; de los de Benjamín, Jaaciel hijo de Abner;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 22, 'Y de Dan, Azarael hijo de Jeroam. Estos fueron los jefes de las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 23, 'Y no tomó David el número de los que eran de veinte años abajo, por cuanto Jehová había dicho que él había de multiplicar á Israel como las estrellas del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 24, 'Joab hijo de Sarvia había comenzado á contar, mas no acabó, pues por esto vino la ira sobre Israel: y así el número no fué puesto en el registro de las crónicas del rey David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 25, 'Y Azmaveth hijo de Adiel tenía cargo de los tesoros del rey; y de los tesoros de los campos, y de las ciudades, y de las aldeas y castillos, Jonathán hijo de Uzzías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 26, 'Y de los que trabajaban en la labranza de las tierras, Ezri hijo de Chêlud;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 27, 'Y de las viñas Simi Ramathita; y del fruto de las viñas para las bodegas, Zabdías Siphmita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 28, 'Y de los olivares é higuerales que había en las campiñas, Baal-hanan Gederita; y de los almacenes del aceite, Joas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 29, 'De las vacas que pastaban en Sarón, Sitrai Saronita; y de las vacas que estaban en los valles, Saphat hijo de Adlai;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 30, 'Y de los camellos, Obil Ismaelita; y de las asnas, Jedías Meronothita;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 31, 'Y de las ovejas, Jaziz Agareno. Todos estos eran superintendentes de la hacienda del rey David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 32, 'Y Jonathán, tío de David, era consejero, varón prudente y escriba; y Jehiel hijo de Hacmoni estaba con los hijos del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 33, 'Y también Achitophel era consejero del rey; y Husai Arachita amigo del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 27, 34, 'Después de Achitophel era Joiada hijo de Benaías, y Abiathar. Y Joab era el general del ejército del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 1, 'Y JUNTO David en Jerusalem á todos los principales de Israel, los príncipes de las tribus, y los jefes de las divisiones que servían al rey, los tribunos y centuriones, con los superintendentes de toda la hacienda y posesión del rey, y sus hijos, con los eunucos, los poderosos, y todos sus hombres valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 2, 'Y levantándose el rey David, puesto en pie dijo: Oidme, hermanos míos, y pueblo mío. Yo tenía en propósito edificar una casa, para que en ella reposara el arca del pacto de Jehová, y para el estrado de los pies de nuestro Dios; y había ya aprestado todo para edificar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 3, 'Mas Dios me dijo: Tú no edificarás casa á mi nombre: porque eres hombre de guerra, y has derramado mucha sangre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 4, 'Empero Jehová el Dios de Israel me eligió de toda la casa de mi padre, para que perpetuamente fuese rey sobre Israel: porque á Judá escogió por caudillo, y de la casa de Judá la familia de mi padre; y de entre los hijos de mi padre agradóse de mí para ponerme por rey sobre todo Israel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 5, 'Y de todos mis hijos (porque Jehová me ha dado muchos hijos,) eligió á mi hijo Salomón para que se siente en el trono del reino de Jehová sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 6, 'Y me ha dicho: Salomón tu hijo, él edificará mi casa y mis atrios: porque á éste me he escogido por hijo, y yo le seré á él por padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 7, 'Asimismo yo confirmaré su reino para siempre, si él se esforzare á poner por obra mis mandamientos y mis juicios, como aqueste día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 8, 'Ahora pues, delante de lo ojos de todo Israel, congregación de Jehová, y en oídos de nuestro Dios, guardad é inquirid todos los preceptos de Jehová vuestro Dios, para que poseáis la buena tierra, y la dejéis por heredad á vuestros hijos después de vosotros perpetuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 9, 'Y tú, Salomón, hijo mío, conoce al Dios de tu padre, y sírvele con corazón perfecto, y con ánimo voluntario; porque Jehová escudriña los corazones de todos, y entiende toda imaginación de los pensamientos. Si tú le buscares, lo hallarás; mas si lo dejares, él te desechará para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 10, 'Mira, pues, ahora que Jehová te ha elegido para que edifiques casa para santuario: esfuérzate, y haz la.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 11, 'Y David dió á Salomón su hijo la traza del pórtico, y de sus casas, y de sus oficinas, y de sus salas, y de sus recámaras, y de la casa del propiciatorio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 12, 'Asimismo la traza de todas las cosas que tenía en su voluntad, para los atrios de la casa de Jehová, y para todas las cámaras en derredor, para los tesoros de la casa de Dios, y para los tesoros de las cosas santificadas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 13, 'También para los órdenes de los sacerdotes y de los Levitas, y para toda la obra del ministerio de la casa de Jehová, y para todos los vasos del ministerio de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 14, 'Y dió oro por peso para lo de oro, para todos los vasos de cada servicio: y plata por peso para todos los vasos, para todos los vasos de cada servicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 15, 'Oro por peso para los candeleros de oro, y para sus candilejas; por peso el oro para cada candelero y sus candilejas: y para los candeleros de plata, plata por peso para el candelero y sus candilejas, conforme al servicio de cada candelero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 16, 'Asimismo dió oro por peso para las mesas de la proposición, para cada mesa: del mismo modo plata para las mesas de plata:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 17, 'También oro puro para los garfios y para las palanganas, y para los incensarios, y para los tazones de oro, para cada tazón por peso; y para los tazones de plata, por peso para cada tazón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 18, 'Además, oro puro por peso para el altar del perfume, y para el á manera de carro de los querubines de oro, que con las alas extendidas cubrían el arca del pacto de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 19, 'Todas estas cosas, dijo David, se me han representado por la mano de Jehová que me hizo entender todas las obras del diseño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 20, 'Dijo más David á Salomón su hijo: Anímate y esfuérzate, y ponlo por obra; no temas, ni desmayes, porque el Dios Jehová, mi Dios, será contigo: él no te dejará, ni te desamparará, hasta que acabes toda la obra para el servicio de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 28, 21, 'He aquí los órdenes de los sacerdotes y de los Levitas, para todo el ministerio de la casa de Dios, serán contigo en toda la obra: asimismo todos los voluntarios é inteligentes para cualquiera especie de industria; y los príncipes, y todo el pueblo para ejecutar todas tus órdenes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 1, 'DESPUÉS dijo el rey David á toda la asamblea: A solo Salomón mi hijo ha elegido Dios; él es joven y tierno, y la obra grande; porque la casa no es para hombre, sino para Jehová Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 2, 'Yo empero con todas mis fuerzas he preparado para la casa de mi Dios, oro para las cosas de oro, y plata para las cosas de plata, y metal para las de metal, y hierro para las de hierro, y madera para las de madera, y piedras oniquinas, y piedras preciosas, y piedras negras, y piedras de diversos colores, y toda suerte de piedras preciosas, y piedras de mármol en abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 3, 'A más de esto, por cuanto tengo mi gusto en la casa de mi Dios, yo guardo en mi tesoro particular oro y plata que, además de todas las cosas que he aprestado para la casa del santuario, he dado para la casa de mi Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 4, 'A saber, tres mil talentos de oro, de oro de Ophir, y siete mil talentos de plata afinada para cubrir las paredes de las casas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 5, 'Oro pues para las cosas de oro, y plata para las cosas de plata, y para toda la obra de manos de los oficiales. ¿Y quién quiere hacer hoy ofrenda á Jehová?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 6, 'Entonces los príncipes de las familias, y los príncipes de las tribus de Israel, tribunos y centuriones, con los superintendentes de la hacienda del rey, ofrecieron de su voluntad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 7, 'Y dieron para el servicio de la casa de Dios cinco mil talentos de oro y diez mil sueldos, y diez mil talentos de plata, y dieciocho mil talentos de metal, y cinco mil talentos de hierro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 8, 'Y todo el que se halló con piedras preciosas, diólas para el tesoro de la casa de Jehová, en mano de Jehiel Gersonita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 9, 'Y holgóse el pueblo de haber contribuído de su voluntad; porque con entero corazón ofrecieron á Jehová voluntariamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 10, 'Asimismo holgóse mucho el rey David, y bendijo á Jehová delante de toda la congregación; y dijo David: Bendito seas tú, oh Jehová, Dios de Israel nuestro padre, de uno á otro siglo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 11, 'Tuya es, oh Jehová, la magnificencia, y el poder, y la gloria, la victoria, y el honor; porque todas las cosas que están en los cielos y en la tierra son tuyas. Tuyo, oh Jehová, es el reino, y la altura sobre todos los que están por cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 12, 'Las riquezas y la gloria están delante de ti, y tú señoreas á todos: y en tu mano está la potencia y la fortaleza, y en tu mano la grandeza y fuerza de todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 13, 'Ahora pues, Dios nuestro, nosotros te confesamos, y loamos tu glorioso nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 14, 'Porque ¿quién soy yo, y quién es mi pueblo, para que pudiésemos ofrecer de nuestra voluntad cosas semejantes? porque todo es tuyo, y lo recibido de tu mano te damos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 15, 'Porque nosotros, extranjeros y advenedizos somos delante de ti, como todos nuestros padres; y nuestros días cual sombra sobre la tierra, y no dan espera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 16, 'Oh Jehová Dios nuestro, toda esta abundancia que hemos aprestado para edificar casa á tu santo nombre, de tu mano es, y todo es tuyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 17, 'Yo sé, Dios mío, que tú escudriñas los corazones, y que la rectitud te agrada: por eso yo con rectitud de mi corazón voluntariamente te he ofrecido todo esto, y ahora he visto con alegría que tu pueblo, que aquí se ha hallado ahora, ha dado para ti espontáneamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 18, 'Jehová, Dios de Abraham, de Isaac, y de Israel, nuestros padres, conserva perpetuamente esta voluntad del corazón de tu pueblo, y encamina su corazón á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 19, 'Asimismo da á mi hijo Salomón corazón perfecto, para que guarde tus mandamientos, y tus testimonios y tus estatutos, y para que haga todas las cosas, y te edifique la casa para la cual yo he hecho el apresto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 20, 'Después dijo David á toda al congregación: Bendecid ahora á Jehová vuestro Dios. Entonces toda la congregación bendijo á Jehová Dios de sus padres, é inclinándose adoraron delante de Jehová, y del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 21, 'Y sacrificaron víctimas á Jehová, y ofrecieron á Jehová holocaustos el día siguiente, mil becerros, mil carneros, mil corderos con sus libaciones, y muchos sacrificios por todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 22, 'Y comieron y bebieron delante de Jehová aquel día con gran gozo; y dieron la segunda vez la investidura del reino á Salomón hijo de David, y ungiéronlo á Jehová por príncipe, y á Sadoc por sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 23, 'Y sentóse Salomón por rey en el trono de Jehová en lugar de David su padre, y fué prosperado; y obedecióle todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 24, 'Y todos los príncipes y poderosos, y todos los hijos del rey David, prestaron homenaje al rey Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 25, 'Y Jehová engrandeció en extremo á Salomón á los ojos de todo Israel, y dióle gloria del reino, cual ningún rey la tuvo antes de él en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 26, 'Así reinó David hijo de Isaí sobre todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 27, 'Y el tiempo que reinó sobre Israel fué cuarenta años. Siete años reinó en Hebrón, y treinta y tres reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 28, 'Y murió en buena vejez, lleno de días, de riquezas, y de gloria: y reinó en su lugar Salomón su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 29, 'Y los hechos del rey David, primeros y postreros, están escritos en el libro de las crónicas de Samuel vidente, y en las crónicas del profeta Nathán, y en las crónicas de Gad vidente,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CH', '1 Crónicas', 29, 30, 'Con todo lo relativo á su reinado, y su poder, y los tiempos que pasaron sobre él, y sobre Israel, y sobre todos los reinos de aquellas tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 1, 'Y SALOMON hijo de David fué afirmado en su reino; y Jehová su Dios fué con él, y le engrandeció sobremanera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 2, 'Y llamó Salomón á todo Israel, tribunos, centuriones, y jueces, y á todos los príncipes de todo Israel, cabezas de familias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 3, 'Y fué Salomón, y con él toda esta junta, al alto que había en Gabaón; porque allí estaba el tabernáculo del testimonio de Dios, que Moisés siervo de Jehová había hecho en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 4, 'Mas David había traído el arca de Dios de Chîriath-jearim al lugar que él le había preparado; porque él le había tendido una tienda en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 5, 'Asimismo el altar de bronce que había hecho Bezaleel hijo de Uri hijo de Hur, estaba allí delante del tabernáculo de Jehová, al cual fué á consultar Salomón con aquella junta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 6, 'Subió pues Salomón allá delante de Jehová, al altar de bronce que estaba en el tabernáculo del testimonio, y ofreció sobre él mil holocaustos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 7, 'Y aquella noche apareció Dios á Salomón, y díjole: Demanda lo que quisieres que yo te dé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 8, 'Y Salomón dijo á Dios: Tú has hecho con David mi padre grande misericordia, y á mí me has puesto por rey en lugar suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 9, 'Confírmese pues ahora, oh Jehová Dios, tu palabra dada á David mi padre; porque tú me has puesto por rey sobre un pueblo en muchedumbre como el polvo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 10, 'Dame ahora sabiduría y ciencia, para salir y entrar delante de este pueblo: porque ¿quién podrá juzgar este tu pueblo tan grande?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 11, 'Y dijo Dios á Salomón: Por cuanto esto fué en tu corazón, que no pediste riquezas, hacienda, ó gloria, ni el alma de los que te quieren mal, ni pediste muchos días, sino que has pedido para ti sabiduría y ciencia para juzgar mi pueblo, sobre el cual te he puesto por rey,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 12, 'Sabiduría y ciencia te es dada; y también te daré riquezas, hacienda, y gloria, cual nunca hubo en los reyes que han sido antes de ti, ni después de ti habrá tal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 13, 'Y volvió Salomón á Jerusalem del alto que estaba en Gabaón, de ante el tabernáculo del testimonio; y reinó sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 14, 'Y juntó Salomón carros y gente de á caballo; y tuvo mil y cuatrocientos carros, y doce mil jinetes, los cuales puso en las ciudades de los carros, y con el rey en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 15, 'Y puso el rey plata y oro en Jerusalem como piedras, y cedro como cabrahigos que nacen en los campos en abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 16, 'Y sacaban caballos y lienzos finos de Egipto para Salomón; pues por contrato tomaban allí los mercaderes del rey caballos y lienzos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 1, 17, 'Y subían, y sacaban de Egipto, un carro por seiscientas piezas de plata, y un caballo por ciento y cincuenta: y así se sacaban por medio de ellos para todos los reyes de los Hetheos, y para los reyes de Siria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 1, 'DETERMINO pues Salomón edificar casa al nombre de Jehová, y otra casa para su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 2, 'Y contó Salomón setenta mil hombres que llevasen cargas, y ochenta mil hombres que cortasen en el monte, y tres mil y seiscientos que los gobernasen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 3, 'Y envió á decir Salomón á Hiram rey de Tiro: Haz conmigo como hiciste con David mi padre, enviándole cedros para que edificara para sí casa en que morase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 4, 'He aquí yo tengo que edificar casa al nombre de Jehová mi Dios, para consagrársela, para quemar perfumes aromáticos delante de él, y para la colocación continua de los panes de la proposición, y para holocaustos á mañana y tarde, y los sábados, y nuevas lunas, y festividades de Jehová nuestro Dios; lo cual ha de ser perpetuo en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 5, 'Y la casa que tengo que edificar, ha de ser grande: porque el Dios nuestro es grande sobre todos los dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 6, 'Mas ¿quién será tan poderoso que le edifique casa? Los cielos y los cielos de los cielos no le pueden comprender; ¿quién pues soy yo, que le edifique casa, sino para quemar perfumes delante de él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 7, 'Envíame pues ahora un hombre hábil, que sepa trabajar en oro, y en plata, y en metal, y en hierro, en púrpura, y en grana, y en cárdeno, y que sepa esculpir con los maestros que están conmigo en Judá y en Jerusalem, los cuales previno mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 8, 'Envíame también madera de cedro, de haya, de pino, del Líbano: porque yo sé que tus siervos entienden de cortar madera en el Líbano; y he aquí, mis siervos irán con los tuyos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 9, 'Para que me apresten mucha madera, porque la casa que tengo de edificar ha de ser grande y portentosa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 10, 'Y he aquí para los operarios tus siervos, cortadores de la madera, he dado veinte mil coros de trigo en grano, y veinte mil coros de cebada, y veinte mil batos de vino, y veinte mil batos de aceite.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 11, 'Entonces Hiram rey de Tiro respondió por letras, las que envió á Salomón: Porque Jehová amó á su pueblo, te ha puesto por rey sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 12, 'Y además decía Hiram: Bendito sea Jehová el Dios de Israel, que hizo los cielos y la tierra, y que dió al rey David hijo sabio, entendido, cuerdo y prudente, que edifique casa á Jehová, y casa para su reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 13, 'Yo pues te he enviado un hombre hábil y entendido, que fué de Hiram mi padre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 14, 'Hijo de una mujer de las hijas de Dan, mas su padre fué de Tiro; el cual sabe trabajar en oro, y plata, y metal, y hierro, en piedra y en madera, en púrpura, y en cárdeno, en lino y en carmesí; asimismo para esculpir todas figuras, y sacar toda suerte de diseño que se le propusiere, y estar con tus hombres peritos, y con los de mi señor David tu padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 15, 'Ahora pues, enviará mi señor á sus siervos el trigo y cebada, y aceite y vino, que ha dicho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 16, 'Y nosotros cortaremos en el Líbano la madera que hubieres menester, y te la traeremos en balsas por la mar hasta Joppe, y tú la harás llevar hasta Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 17, 'Y contó Salomón todos los hombres extranjeros que estaban en la tierra de Israel, después de haberlos ya contado David su padre, y fueron hallados ciento cincuenta y tres mil seiscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 2, 18, 'Y señaló de ellos setenta mil para llevar cargas, y ochenta mil que cortasen en el monte, y tres mil y seiscientos por sobrestantes para hacer trabajar al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 1, 'Y COMENZO Salomón á edificar la casa en Jerusalem, en el monte Moria que había sido mostrado á David su padre, en el lugar que David había preparado en la era de Ornán Jebuseo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 2, 'Y comenzó á edificar en el mes segundo, á dos del mes, en el cuarto año de su reinado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 3, 'Estas son las medidas de que Salomón fundó el edificio de la casa de Dios. La primera medida fué, la longitud de sesenta codos; y la anchura de veinte codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 4, 'El pórtico que estaba en la delantera de la longitud, era de veinte codos al frente del ancho de la casa, y su altura de ciento y veinte: y cubriólo por dentro de oro puro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 5, 'Y techó la casa mayor con madera de haya, la cual cubrió de buen oro, é hizo resaltar sobre ella palmas y cadenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 6, 'Cubrió también la casa de piedras preciosas por excelencia: y el oro era oro de Parvaim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 7, 'Así cubrió la casa, sus vigas, sus umbrales, sus paredes, y sus puertas, con oro; y esculpió querubines por las paredes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 8, 'Hizo asimismo la casa del lugar santísimo, cuya longitud era de veinte codos según el ancho del frente de la casa, y su anchura de veinte codos: y cubrióla de buen oro que ascendía á seiscientos talentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 9, 'Y el peso de los clavos tuvo cincuenta siclos de oro. Cubrió también de oro las salas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 10, 'Y dentro del lugar santísimo hizo dos querubines de forma de niños, los cuales cubrieron de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 11, 'El largo de las alas de los querubines era de veinte codos: porque la una ala era de cinco codos: la cual llegaba hasta la pared de la casa; y la otra ala de cinco codos, la cual llegaba al ala del otro querubín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 12, 'De la misma manera la una ala del otro querubín era de cinco codos: la cual llegaba hasta la pared de la casa; y la otra ala era de cinco codos, que tocaba al ala del otro querubín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 13, 'Así las alas de estos querubines estaban extendidas por veinte codos: y ellos estaban en pie con los rostros hacia la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 14, 'Hizo también el velo de cárdeno, púrpura, carmesí y lino, é hizo resaltar en él querubines.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 15, 'Delante de la casa hizo dos columnas de treinta y cinco codos de longitud, con sus capiteles encima, de cinco codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 16, 'Hizo asimismo cadenas en el oratorio, y púsolas sobre los capiteles de las columnas: é hizo cien granadas, las cuales puso en las cadenas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 3, 17, 'Y asentó las columnas delante del templo, la una á la mano derecha, y la otra á la izquierda; y á la de la mano derecha llamó Jachîn, y á la de la izquierda, Boaz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 1, 'HIZO además un altar de bronce de veinte codos de longitud, y veinte codos de anchura, y diez codos de altura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 2, 'También hizo un mar de fundición, el cual tenía diez codos del un borde al otro, enteramente redondo: su altura era de cinco codos, y una línea de treinta codos lo ceñía alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 3, 'Y debajo de él había figuras de bueyes que lo circundaban, diez en cada codo todo alrededor: eran dos órdenes de bueyes fundidos juntamente con el mar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 4, 'Y estaba asentado sobre doce bueyes, tres de los cuales miraban al septentrión, y tres al occidente, y tres al mediodía, y tres al oriente: y el mar asentaba sobre ellos, y todas sus traseras estaban á la parte de adentro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 5, 'Y tenía de grueso un palmo, y el borde era de la hechura del borde de un cáliz, ó flor de lis. Y hacía tres mil batos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 6, 'Hizo también diez fuentes, y puso cinco á la derecha y cinco á la izquierda, para lavar y limpiar en ellas la obra del holocausto; mas el mar era para lavarse los sacerdotes en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 7, 'Hizo asimismo diez candeleros de oro según su forma, los cuales puso en el templo, cinco á la derecha, y cinco á la izquierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 8, 'Además hizo diez mesas y púsolas en el templo, cinco á la derecha, y cinco á la izquierda: igualmente hizo cien tazones de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 9, 'A más de esto hizo el atrio de los sacerdotes, y el gran atrio, y las portadas del atrio, y cubrió las puertas de ellas de bronce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 10, 'Y asentó el mar al lado derecho hacia el oriente, enfrente del mediodía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 11, 'Hizo también Hiram calderos, y palas, y tazones; y acabó Hiram la obra que hacía al rey Salomón para la casa de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 12, 'Dos columnas, y los cordones, los capiteles sobre las cabezas de las dos columnas, y dos redes para cubrir las dos bolas de los capiteles que estaban encima de las columnas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 13, 'Cuatrocientas granadas en las dos redecillas, dos órdenes de granadas en cada redecilla, para que cubriesen las dos bolas de los capiteles que estaban encima de las columnas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 14, 'Hizo también las basas, sobre las cuales asentó las fuentes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 15, 'Un mar, y doce bueyes debajo de él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 16, 'Y calderos, y palas, y garfios; y todos sus enseres hizo Hiram su padre al rey Salomón para la casa de Jehová, de metal purísimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 17, 'Y fundiólos el rey en los llanos del Jordán, en tierra arcillosa, entre Suchôt y Seredat.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 18, 'Y Salomón hizo todos estos vasos en grande abundancia, porque no pudo ser hallado el peso del metal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 19, 'Así hizo Salomón todos los vasos para la casa de Dios, y el altar de oro, y las mesas sobre las cuales se ponían los panes de la proposición;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 20, 'Asimismo los candeleros y sus candilejas, de oro puro, para que las encendiesen delante del oratorio conforme á la costumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 21, 'Y las flores, y las lamparillas, y las despabiladeras se hicieron de oro, de oro perfecto;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 4, 22, 'También los platillos, y las jofainas, y las cucharas, y los incensarios, de oro puro. Cuanto á la entrada de la casa, sus puertas interiores para el lugar santísimo, y las puertas de la casa del templo, de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 1, 'Y ACABADA que fué toda la obra que hizo Salomón para la casa de Jehová, metió Salomón en ella las cosas que David su padre había dedicado; y puso la plata, y el oro, y todos los vasos, en los tesoros de la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 2, 'Entonces Salomón juntó en Jerusalem los ancianos de Israel, y todos los príncipes de las tribus, los cabezas de las familias de los hijos de Israel, para que trajesen el arca del pacto de Jehová de la ciudad de David, que es Sión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 3, 'Y juntáronse al rey todos los varones de Israel, á la solemnidad del mes séptimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 4, 'Y vinieron todos los ancianos de Israel, y tomaron los Levitas el arca:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 5, 'Y llevaron el arca, y el tabernáculo del testimonio, y todos los vasos del santuario que estaban en el tabernáculo: los sacerdotes y los Levitas los llevaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 6, 'Y el rey Salomón, y toda la congregación de Israel que se había á él reunido delante del arca, sacrificaron ovejas y bueyes, que por la multitud no se pudieron contar ni numerar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 7, 'Y los sacerdotes metieron el arca del pacto de Jehová en su lugar, en el oratorio de la casa, en el lugar santísimo, bajo las alas de los querubines:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 8, 'Pues los querubines extendían las alas sobre el asiento del arca, y cubrían los querubines por encima así el arca como sus barras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 9, 'E hicieron salir fuera las barras, de modo que se viesen las cabezas de las barras del arca delante del oratorio, mas no se veían desde fuera: y allí estuvieron hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 10, 'En el arca no había sino las dos tablas que Moisés había puesto en Horeb, con las cuales Jehová había hecho alianza con los hijos de Israel, después que salieron de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 11, 'Y como los sacerdotes salieron del santuario, (porque todos los sacerdotes que se hallaron habían sido santificados, y no guardaban sus veces;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 12, 'Y los Levitas cantores, todos los de Asaph, los de Hemán, y los de Jeduthún, juntamente con sus hijos y sus hermanos, vestidos de lino fino, estaban con címbalos y salterios y arpas al oriente del altar; y con ellos ciento veinte sacerdotes que tocaban trompetas:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 13, 'Sonaban pues las trompetas, y cantaban con la voz todos á una, para alabar y confesar á Jehová: y cuando alzaban la voz con trompetas y címbalos é instrumentos de música, cuando alababan á Jehová, diciendo: Porque es bueno, porque su misericordia es para siempre: la casa se llenó entonces de una nube, la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 5, 14, 'Y no podían los sacerdotes estar para ministrar, por causa de la nube; porque la gloria de Jehová había henchido la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 1, 'ENTONCES dijo Salomón: Jehová ha dicho que él habitaría en la oscuridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 2, 'Yo pues he edificado una casa de morada para ti, y una habitación en que mores para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 3, 'Y volviendo el rey su rostro, bendijo á toda la congregación de Israel: y toda la congregación de Israel estaba en pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 4, 'Y él dijo: Bendito sea Jehová Dios de Israel, el cual con su mano ha cumplido lo que habló por su boca á David mi padre, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 5, 'Desde el día que saqué mi pueblo de la tierra de Egipto, ninguna ciudad he elegido de todas las tribus de Israel para edificar casa donde estuviese mi nombre, ni he escogido varón que fuese príncipe sobre mi pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 6, 'Mas á Jerusalem he elegido para que en ella esté mi nombre, y á David he elegido para que fuese sobre mi pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 7, 'Y David mi padre tuvo en el corazón edificar casa al nombre de Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 8, 'Mas Jehová dijo á David mi padre: Respecto á haber tenido en tu corazón edificar casa á mi nombre, bien has hecho en haber tenido esto en tu corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 9, 'Empero tú no edificarás la casa, sino tu hijo que saldrá de tus lomos, él edificará casa á mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 10, 'Y Jehová ha cumplido su palabra que había dicho, pues levantéme yo en lugar de David mi padre, y heme sentado en el trono de Israel, como Jehová había dicho, y he edificado casa al nombre de Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 11, 'Y en ella he puesto el arca, en la cual está el pacto de Jehová que concertó con los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 12, 'Púsose luego Salomón delante del altar de Jehová, en presencia de toda la congregación de Israel, y extendió sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 13, 'Porque Salomón había hecho un púlpito de metal, de cinco codos de largo, y de cinco codos de ancho, y de altura de tres codos, y lo había puesto en medio del atrio: y púsose sobre él, é hincóse de rodillas delante de toda la congregación de Israel, y extendiendo sus manos al cielo, dijo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 14, 'Jehová Dios de Israel, no hay Dios semejante á ti en el cielo ni en la tierra, que guardas el pacto y la misericordia á tus siervos que caminan delante de ti de todo su corazón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 15, 'Que has guardado á tu siervo David mi padre lo que le dijiste: tú lo dijiste de tu boca, mas con tu mano lo has cumplido, como parece este día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 16, 'Ahora pues, Jehová Dios de Israel, guarda á tu siervo David mi padre lo que le has prometido, diciendo: No faltará de ti varón delante de mí, que se siente en el trono de Israel, á condición que tus hijos guarden su camino, andando en mi ley, como tú delante de mí has andado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 17, 'Ahora pues, oh Jehová Dios de Israel, verifíquese tu palabra que dijiste á tu siervo David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 18, 'Mas ¿es verdad que Dios ha de habitar con el hombre en la tierra? He aquí, los cielos y los cielos de los cielos no pueden contenerte: ¿cuánto menos esta casa que he edificado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 19, 'Mas tú mirarás á la oración de tu siervo, y á su ruego, oh Jehová Dios mío, para oir el clamor y la oración con que tu siervo ora delante de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 20, 'Que tus ojos estén abiertos sobre esta casa de día y de noche, sobre el lugar del cual dijiste, Mi nombre estará allí; que oigas la oración con que tu siervo ora en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 21, 'Asimismo que oigas el ruego de tu siervo, y de tu pueblo Israel, cuando en este lugar hicieren oración, que tú oirás desde los cielos, desde el lugar de tu morada: que oigas y perdones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 22, 'Si alguno pecare contra su prójimo, y él le pidiere juramento haciéndole jurar, y el juramento viniere delante de tu altar en esta casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 23, 'Tú oirás desde los cielos, y obrarás, y juzgarás á tus siervos, dando la paga al impío, tornándole su proceder sobre su cabeza, y justificando al justo en darle conforme á su justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 24, 'Si tu pueblo Israel cayere delante de los enemigos, por haber prevaricado contra ti, y se convirtieren, y confesaren tu nombre, y rogaren delante de ti en esta casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 25, 'Tú oirás desde los cielos, y perdonarás el pecado de tu pueblo Israel, y los volverás á la tierra que diste á ellos y á sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 26, 'Si los cielos se cerraren, que no haya lluvias por haber pecado contra ti, si oraren á ti en este lugar, y confesaren tu nombre, y se convirtieren de sus pecados, cuando los afligieres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 27, 'Tú los oirás en los cielos, y perdonarás el pecado de tus siervos y de tu pueblo Israel, y les enseñarás el buen camino para que anden en él, y darás lluvia sobre tu tierra, la cual diste por heredad á tu pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 28, 'Y si hubiere hambre en la tierra, ó si hubiere pestilencia, si hubiere tizoncillo ó añublo, langosta ó pulgón; ó si los cercaren sus enemigos en la tierra de su domicilio; cualquiera plaga ó enfermedad que sea;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 29, 'Toda oración y todo ruego que hiciere cualquier hombre, ó todo tu pueblo Israel, cualquiera que conociere su llaga y su dolor en su corazón, si extendiere sus manos á esta casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 30, 'Tú oirás desde los cielos, desde el lugar de tu habitación, y perdonarás, y darás á cada uno conforme á sus caminos, habiendo conocido su corazón; (porque solo tú conoces el corazón de los hijos de los hombres;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 31, 'Para que te teman y anden en tus caminos, todos los días que vivieren sobre la haz de la tierra que tú diste á nuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 32, 'Y también al extranjero que no fuere de tu pueblo Israel, que hubiere venido de lejanas tierras á causa de tu grande nombre, y de tu mano fuerte, y de tu brazo extendido, si vinieren, y oraren en esta casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 33, 'Tú oirás desde los cielos, desde el lugar de tu morada, y harás conforme á todas las cosas por las cuales hubiere clamado á ti el extranjero; para que todos los pueblos de la tierra conozcan tu nombre, y te teman como tu pueblo Israel, y sepan que tu nombre es invocado sobre esta casa que he edificado yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 34, 'Si tu pueblo saliere á la guerra contra sus enemigos por el camino que tú los enviares, y oraren á ti hacia esta ciudad que tú elegiste, hacia la casa que he edificado á tu nombre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 35, 'Tú oirás desde los cielos su oración y su ruego, y ampararás su derecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 36, 'Si pecaren contra ti, (pues no hay hombre que no peque,) y te airares contra ellos, y los entregares delante de sus enemigos, para que los que los tomaren los lleven cautivos á tierra de enemigos, lejos ó cerca,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 37, 'Y ellos volvieren en sí en la tierra donde fueren llevados cautivos; si se convirtieren, y oraren á ti en la tierra de su cautividad, y dijeren: Pecamos, hemos hecho inicuamente, impíamente hemos obrado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 38, 'Si se convirtieren á ti de todo su corazón y de toda su alma en la tierra de su cautividad, donde los hubieren llevado cautivos, y oraren hacia su tierra que tú diste á sus padres, hacia la ciudad que tu elegiste, y hacia la casa que he edificado á tu nombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 39, 'Tú oirás desde los cielos, desde el lugar de tu morada, su oración y su ruego, y ampararás su causa, y perdonarás á tu pueblo que pecó contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 40, 'Ahora pues, oh Dios mío, ruégote estén abiertos tus ojos, y atentos tus oídos á la oración en este lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 41, 'Oh Jehová Dios, levántate ahora para habitar en tu reposo, tú y el arca de tu fortaleza; sean, oh Jehová Dios, vestidos de salud tus sacerdotes, y gocen de bien tus santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 6, 42, 'Jehová Dios, no hagas volver el rostro de tu ungido: acuérdate de las misericordias de David tu siervo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 1, 'Y COMO Salomón acabó de orar, el fuego descendió de los cielos, y consumió el holocausto y las víctimas; y la gloria de Jehová hinchió la casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 2, 'Y no podían entrar los sacerdotes en la casa de Jehová, porque la gloria de Jehová había henchido la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 3, 'Y como vieron todos los hijos de Israel descender el fuego y la gloria de Jehová sobre la casa, cayeron en tierra sobre sus rostros en el pavimento, y adoraron, confesando á Jehová y diciendo: Que es bueno, que su misericordia es para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 4, 'Entonces el rey y todo el pueblo sacrificaron víctimas delante de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 5, 'Y ofreció el rey Salomón en sacrificio veinte y dos mil bueyes, y ciento y veinte mil ovejas; y así dedicaron la casa de Dios el rey y todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 6, 'Y los sacerdotes asistían en su ministerio; y los Levitas con los instrumentos de música de Jehová, los cuales había hecho el rey David para confesar á Jehová, que su misericordia es para siempre; cuando David alababa por mano de ellos. Asimismo los sacerdotes tañían trompetas delante de ellos, y todo Israel estaba en pie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 7, 'También santificó Salomón el medio del atrio que estaba delante de la casa de Jehová, por cuanto había ofrecido allí los holocaustos, y los sebos de los pacíficos; porque en el altar de bronce que Salomón había hecho, no podían caber los holocaustos, y el presente, y los sebos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 8, 'Entonces hizo Salomón fiesta siete días, y con él todo Israel, una grande congregación, desde la entrada de Hamath hasta el arroyo de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 9, 'Al octavo día hicieron convocación, porque habían hecho la dedicación del altar en siete días, y habían celebrado la solemnidad por siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 10, 'Y á los veintitrés del mes séptimo envió al pueblo á sus estancias, alegres y gozosos de corazón por los beneficios que Jehová había hecho á David, y á Salomón, y á su pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 11, 'Acabó pues Salomón la casa de Jehová, y la casa del rey: y todo lo que Salomón tuvo en voluntad de hacer en la casa de Jehová y en su casa, fué prosperado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 12, 'Y apareció Jehová á Salomón de noche, y díjole: Yo he oído tu oración, y he elegido para mí este lugar por casa de sacrificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 13, 'Si yo cerrare los cielos, que no haya lluvia, y si mandare á la langosta que consuma la tierra, ó si enviare pestilencia á mi pueblo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 14, 'Si se humillare mi pueblo, sobre los cuales ni nombre es invocado, y oraren, y buscaren mi rostro, y se convirtieren de sus malos caminos; entonces yo oiré desde los cielos, y perdonaré sus pecados, y sanaré su tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 15, 'Ahora estarán abiertos mis ojos, y atentos mis oídos, á la oración en este lugar:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 16, 'Pues que ahora he elegido y santificado esta casa, para que esté en ella mi nombre para siempre; y mis ojos y mi corazón estarán ahí para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 17, 'Y tú, si anduvieres delante de mí, como anduvo David tu padre, é hicieres todas las cosas que yo te he mandado, y guardares mis estatutos y mis derechos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 18, 'Yo confirmaré el trono de tu reino, como concerté con David tu padre, diciendo: No faltará varón de ti que domine en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 19, 'Mas si vosotros os volviereis, y dejareis mis estatutos y mis preceptos que os he propuesto, y fuereis y sirviereis á dioses ajenos, y los adorareis,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 20, 'Yo los arrancaré de mi tierra que les he dado; y esta casa que he santificado á mi nombre, yo la echaré de delante de mí, y pondréla por proverbio y fábula en todos los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 21, 'Y esta casa que habrá sido ilustre, será espanto á todo el que pasare, y dirá: ¿Por qué ha hecho así Jehová á esta tierra y á esta casa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 7, 22, 'Y se responderá: Por cuanto dejaron á Jehová Dios de sus padres, el cual los sacó de la tierra de Egipto, y han abrazado dioses ajenos, y los adoraron y sirvieron: por eso él ha traído todo este mal sobre ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 1, 'Y ACONTECIO que al cabo de veinte años que Salomón había edificado la casa de Jehová y su casa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 2, 'Reedificó Salomón las ciudades que Hiram le había dado, y estableció en ellas á los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 3, 'Después vino Salomón á Amath de Soba, y la tomó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 4, 'Y edificó á Tadmor en el desierto, y todas las ciudades de municiones que edificó en Hamath.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 5, 'Asimismo reedificó á Beth-oron la de arriba, y á Beth-oron la de abajo, ciudades fortificadas, de muros, puertas, y barras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 6, 'Y á Baalath, y á todas las villas de munición que Salomón tenía; también todas las ciudades de los carros y las de la gente de á caballo; y todo lo que Salomón quiso edificar en Jerusalem, y en el Líbano, y en toda la tierra de su señorío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 7, 'Y á todo el pueblo que había quedado de los Hetheos, Amorrheos, Pherezeos, Heveos, y Jebuseos, que no eran de Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 8, 'Los hijos de los que habían quedado en la tierra después de ellos, á los cuales los hijos de Israel no destruyeron del todo, hizo Salomón tributarios hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 9, 'Y de los hijos de Israel no puso Salomón siervos en su obra; porque eran hombres de guerra, y sus príncipes y sus capitanes, y comandantes de sus carros, y su gente de á caballo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 10, 'Y tenía Salomón doscientos y cincuenta principales de los gobernadores, los cuales mandaban en aquella gente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 11, 'Y pasó Salomón á la hija de Faraón, de la ciudad de David á la casa que él le había edificado; porque dijo: Mi mujer no morará en la casa de David rey de Israel, porque aquellas habitaciones donde ha entrado el arca de Jehová, son sagradas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 12, 'Entonces ofreció Salomón holocaustos á Jehová sobre el altar de Jehová, que había él edificado delante del pórtico,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 13, 'Para que ofreciesen cada cosa en su día, conforme al mandamiento de Moisés, en los sábados, en las nuevas lunas, y en las solemnidades, tres veces en el año, á saber, en la fiesta de los panes ázimos, en la fiesta de las semanas, y en la fiesta de las cabañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 14, 'Y constituyó los repartimientos de los sacerdotes en sus oficios, conforme á la ordenación de David su padre; y los Levitas por sus órdenes, para que alabasen y ministrasen delante de los sacerdotes, casa cosa en su día; asimismo los porteros por su orden á cada puerta: porque así lo había mandado David, varón de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 15, 'Y no salieron del mandamiento del rey, cuanto á los sacerdotes y Levitas, y los tesoros, y todo negocio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 16, 'Porque toda la obra de Salomón estaba preparada desde el día en que la casa de Jehová fué fundada hasta que se acabó, hasta que la casa de Jehová fué acabada del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 17, 'Entonces Salomón fué á Esion-geber, y á Eloth, á la costa de la mar en la tierra de Edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 8, 18, 'Porque Hiram le había enviado navíos por mano de sus siervos, y marineros diestros en la mar, los cuales fueron con los siervos de Salomón á Ophir, y tomaron de allá cuatrocientos y cincuenta talentos de oro, y los trajeron al rey Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 1, 'Y OYENDO la reina de Seba la fama de Salomón, vino á Jerusalem con un muy grande séquito, con camellos cargados de aroma, y oro en abundancia, y piedras preciosas, para tentar á Salomón con preguntas difíciles. Y luego que vino á Salomón, habló con él todo lo que en su corazón tenía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 2, 'Pero Salomón le declaró todas sus palabras: ninguna cosa quedó que Salomón no le declarase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 3, 'Y viendo la reina de Seba la sabiduría de Salomón, y la casa que había edificado,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 4, 'Y las viandas de su mesa, y el asiento de sus siervos, y el estado de sus criados, y los vestidos de ellos, sus maestresalas y sus vestidos, y su subida por donde subía á la casa de Jehová, no quedó más espíritu en ella.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 5, 'Y dijo al rey: Verdad es lo que había oído en mi tierra de tus cosas y de tu sabiduría;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 6, 'Mas yo no creía las palabras de ellos, hasta que he venido, y mis ojos han visto: y he aquí que ni aun la mitad de la grandeza de tu sabiduría me había sido dicha; porque tú sobrepujas la fama que yo había oído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 7, 'Bienaventurados tus hombres, y dichosos estos tus siervos, que están siempre delante de ti, y oyen tu sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 8, 'Jehová tu Dios sea bendito, el cual se ha agradado en ti para ponerte sobre su trono por rey de Jehová tu Dios: por cuanto tu Dios amó á Israel para afirmarlo perpetuamente, por eso te ha puesto por rey sobre ellos, para que hagas juicio y justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 9, 'Y dió al rey ciento y veinte talentos de oro, y gran copia de aromas, y piedras preciosas: nunca hubo tales aromas como los que dió la reina de Seba al rey Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 10, 'También los siervos de Hiram y los siervos de Salomón, que habían traído el oro de Ophir, trajeron madera de Algummim, y piedras preciosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 11, 'E hizo el rey de la madera de Algummim gradas en la casa de Jehová, y en las casas reales, y arpas y salterios para los cantores: nunca en tierra de Judá se había visto madera semejante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 12, 'Y el rey Salomón dió á la reina de Seba todo lo que ella quiso y le pidió, más de lo que había traído al rey. Después se volvió y fuése á su tierra con sus siervos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 13, 'Y el peso de oro que venía á Salomón cada un año, era seiscientos sesenta y seis talentos de oro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 14, 'Sin lo que traían los mercaderes y negociantes; y también todos los reyes de Arabia y los príncipes de la tierra traían oro y plata á Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 15, 'Hizo también el rey Salomón doscientos paveses de oro de martillo, cada uno de los cuales tenía seiscientos siclos de oro labrado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 16, 'Asimismo trescientos escudos de oro batido, teniendo cada escudo trescientos siclos de oro: y púsolos el rey en la casa del bosque del Líbano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 17, 'Hizo además el rey un gran trono de marfil, y cubriólo de oro puro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 18, 'Y había seis gradas al trono, con un estrado de oro al mismo, y brazos de la una parte y de la otra al lugar del asiento, y dos leones que estaban junto á los brazos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 19, 'Había también allí doce leones sobre las seis gradas de la una parte y de la otra. Jamás fué hecho otro semejante en reino alguno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 20, 'Toda la vajilla del rey Salomón era de oro, y toda la vajilla de la casa del bosque del Líbano, de oro puro. En los días de Salomón la plata no era de estima.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 21, 'Porque la flota del rey iba á Tharsis con los siervos de Hiram, y cada tres años solían venir las naves de Tharsis, y traían oro, plata, marfil, simios, y pavos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 22, 'Y excedió el rey Salomón á todos los reyes de la tierra en riqueza y en sabiduría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 23, 'Y todos los reyes de la tierra procuraban ver el rostro de Salomón, por oir su sabiduría, que Dios había puesto en su corazón:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 24, 'Y de éstos, cada uno traía su presente, vasos de plata, vasos de oro, vestidos, armas, aromas, caballos y acémilas, todos los años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 25, 'Tuvo también Salomón cuatro mil caballerizas para los caballos y carros, y doce mil jinetes, los cuales puso en las ciudades de los carros, y con el rey en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 26, 'Y tuvo señorío sobre todos los reyes desde el río hasta la tierra de los Filisteos, y hasta el término de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 27, 'Y puso el rey plata en Jerusalem como piedras, y cedros como los cabrahigos que nacen por las campiñas en abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 28, 'Sacaban también caballos para Salomón, de Egipto y de todas las provincias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 29, 'Lo demás de los hechos de Salomón, primeros y postreros, ¿no está todo escrito en los libros de Nathán profeta, y en la profecía de Ahías Silonita, y en las profecías del vidente Iddo contra Jeroboam hijo de Nabat?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 30, 'Y reinó Salomón en Jerusalem sobre todo Israel cuarenta años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 9, 31, 'Y durmió Salomón con sus padres, y sepultáronlo en la ciudad de David su padre: y reinó en su lugar Roboam su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 1, 'Y ROBOAM fué á Sichêm porque en Sichêm se había juntado todo Israel para hacerlo rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 2, 'Y como lo oyó Jeroboam hijo de Nabat, el cual estaba en Egipto, donde había huído á causa del rey Salomón, volvió de Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 3, 'Y enviaron y llamáronle. Vino pues Jeroboam, y todo Israel, y hablaron á Roboam, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 4, 'Tu padre agravó nuestro yugo: afloja tú, pues, ahora algo de la dura servidumbre, y del grave yugo con que tu padre nos apremió, y te serviremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 5, 'Y él les dijo: Volved á mí de aquí á tres días. Y el pueblo se fué.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 6, 'Entonces el rey Roboam tomó consejo con los viejos, que habían estado delante de Salomón su padre cuando vivía, y díjoles: ¿Cómo aconsejáis vosotros que responda á este pueblo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 7, 'Y ellos le hablaron, diciendo: Si te condujeres humanamente con este pueblo, y los agradares, y les hablares buenas palabras, ellos te servirán perpetuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 8, 'Mas él, dejando el consejo que le dieron los viejos, tomó consejo con los mancebos que se habían criado con él, y que delante de él asistían;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 9, 'Y díjoles: ¿Qué aconsejáis vosotros que respondamos á este pueblo, que me ha hablado, diciendo: Alivia algo del yugo que tu padre puso sobre nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 10, 'Entonces los mancebos que se habían criado con él, le hablaron, diciendo: Así dirás al pueblo que te ha hablado diciendo, Tu padre agravó nuestro yugo, mas tú descárganos: así les dirás: Lo más menudo mío es más grueso que los lomos de mi padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 11, 'Así que, mi padre os cargó de grave yugo, y yo añadiré á vuestro yugo: mi padre os castigó con azotes, y yo con escorpiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 12, 'Vino pues Jeroboam con todo el pueblo á Roboam al tercer día: según el rey les había mandado deciendo: Volved á mí de aquí á tres días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 13, 'Y respondióles el rey ásperamente; pues dejó el rey Roboam el consejo de los viejos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 14, 'Y hablóles conforme al consejo de los mancebos, diciendo: Mi padre agravó vuestro yugo, y yo añadiré á vuestro yugo: mi padre os castigó con azotes, y yo con escorpiones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 15, 'Y no escuchó el rey al pueblo; porque la causa era de Dios, para cumplir Jehová su palabra que había hablado, por Ahías Silonita, á Jeroboam hijo de Nabat.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 16, 'Y viendo todo Israel que el rey no les había oído, respondió el pueblo al rey, diciendo: ¿Qué parte tenemos nosotros con David, ni herencia en el hijo de Isaí? ¡Israel, cada uno á sus estancias! ¡David, mira ahora por tu casa! Así se fué todo Israel á sus estancias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 17, 'Mas reinó Roboam sobre los hijos de Israel que habitaban en las ciudades de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 18, 'Envió luego el rey Roboam á Adoram, que tenía cargo de los tributos; pero le apedrearon los hijos de Israel, y murió. Entonces se esforzó el rey Roboam, y subiendo en un carro huyó á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 10, 19, 'Así se apartó Israel de la casa de David hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 1, 'Y COMO vino Roboam á Jerusalem, juntó la casa de Judá y de Benjamín, ciento y ochenta mil hombres escogidos de guerra, para pelear contra Israel y volver el reino á Roboam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 2, 'Mas fué palabra de Jehová á Semeías varón de Dios, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 3, 'Habla á Roboam hijo de Salomón, rey de Judá, y á todos los Israelitas en Judá y Benjamín, diciéndoles:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 4, 'Así ha dicho Jehová: No subáis ni peleéis contra vuestros hermanos; vuélvase casa uno á su casa, porque yo he hecho este negocio. Y ellos oyeron la palabra de Jehová, y tornáronse, y no fueron contra Jeroboam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 5, 'Y habitó Roboam en Jerusalem, y edificó ciudades para fortificar á Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 6, 'Y edificó á Beth-lehem, y á Etham, y á Tecoa,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 7, 'Y á Beth-sur, y á Sochô, y á Adullam,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 8, 'Y á Gath, y á Maresa, y á Ziph,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 9, 'Y á Adoraim, y á Lachîs, y á Acechâ,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 10, 'Y á Sora, y á Ajalón, y á Hebrón, que eran en Judá y en Benjamín, ciudades fuertes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 11, 'Fortificó también las fortalezas, y puso en ellas capitanes, y vituallas, y vino, y aceite;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 12, 'Y en todas las ciudades, escudos y lanzas. Fortificólas pues en gran manera, y Judá y Benjamín le estaban sujetos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 13, 'Y los sacerdotes y Levitas que estaban en todo Israel, se juntaron á él de todos sus términos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 14, 'Porque los Levitas dejaban sus ejidos y sus posesiones, y se venían á Judá y á Jerusalem: pues Jeroboam y sus hijos los echaban del ministerio de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 15, 'Y él se hizo sacerdotes para los altos, y para los demonios, y para los becerros que él había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 16, 'Tras aquéllos acudieron también de todas las tribus de Israel los que habían puesto su corazón en buscar á Jehová Dios de Israel; y viniéronse á Jerusalem para sacrificar á Jehová, el Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 17, 'Así fortificaron el reino de Judá, y confirmaron á Roboam hijo de Salomón, por tres años; porque tres años anduvieron en el camino de David y de Salomón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 18, 'Y tomóse Roboam por mujer á Mahalath, hija de Jerimoth hijo de David, y á Abihail, hija de Eliab hijo de Esaí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 19, 'La cual le parió hijos: á Jeus, y á Samaria, y á Zaham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 20, 'Después de ella tomó á Maachâ hija de Absalom, la cual le parió á Abías, á Athai, Ziza, y Selomith.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 21, 'Mas Roboam amó á Maachâ hija de Absalom sobre todas sus mujeres y concubinas; porque tomó diez y ocho mujeres y sesenta concubinas, y engendró veintiocho hijos y sesenta hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 22, 'Y puso Roboam á Abías hijo de Maachâ por cabeza y príncipe de sus hermanos, porque quería hacerle rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 11, 23, 'E hízole instruir, y esparció todos sus hijos por todas las tierras de Judá y de Benjamín, y por todas las ciudades fuertes, y dióles vituallas en abundancia, y pidió muchas mujeres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 1, 'Y COMO Roboam hubo confirmado el reino, dejó la ley de Jehová, y con él todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 2, 'Y en el quinto año del rey Roboam subió Sisac rey de Egipto contra Jerusalem, (por cuanto se habían rebelado contra Jehová,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 3, 'Con mil y doscientos carros, y con sesenta mil hombres de á caballo: mas el pueblo que venía con él de Egipto, no tenía número; á saber, de Libios, Sukienos, y Etiopes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 4, 'Y tomó las ciudades fuertes de Judá, y llegó hasta Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 5, 'Entonces vino Semeías profeta á Roboam y á los príncipes de Judá, que estaban reunidos en Jerusalem por causa de Sisac, y díjoles: Así ha dicho Jehová: Vosotros me habéis dejado, y yo también os he dejado en manos de Sisac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 6, 'Y los príncipes de Israel y el rey se humillaron, y dijeron: Justo es Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 7, 'Y como vió Jehová que se habían humillado, fué palabra de Jehová á Semeías, diciendo: Hanse humillado; no los destruiré; antes los salvare en breve, y no se derramará mi ira contra Jerusalem por mano de Sisac.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 8, 'Empero serán sus siervos; para que sepan qué es servirme á mí, y servir á los reinos de las naciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 9, 'Subió pues Sisac rey de Egipto á Jerusalem, y tomó los tesoros de la casa de Jehová, y los tesoros de la casa del rey; todo lo llevó: y tomó los paveses de oro que Salomón había hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 10, 'Y en lugar de ellos hizo el rey Roboam paveses de metal, y entrególos en manos de los jefes de la guardia, los cuales custodiaban la entrada de la casa del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 11, 'Y cuando el rey iba á la casa de Jehová, venían los de la guardia, y traíanlos, y después los volvían á la cámara de la guardia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 12, 'Y como él se humilló, la ira de Jehová se apartó de él, para no destruirlo del todo: y también en Judá las cosas fueron bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 13, 'Fortificado pues Roboam, reinó en Jerusalem: y era Roboam de cuarenta y un años cuando comenzó á reinar, y diecisiete años reinó en Jerusalem, ciudad que escogió Jehová de todas las tribus de Israel, para poner en ella su nombre. Y el nombre de su madre fué Naama Ammonita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 14, 'E hizo lo malo, porque no apercibió su corazón para buscar á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 15, 'Y las cosas de Roboam, primeras y postreras, ¿no están escritas en los libros de Semeías profeta y de Iddo vidente, en la cuenta de los linajes? Y entre Roboam y Jeroboam hubo perpetua guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 12, 16, 'Y durmió Roboam con sus padres, y fué sepultado en la ciudad de David: y reinó en su lugar Abías su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 1, 'A LOS dieciocho años del rey Jeroboam, reinó Abías sobre Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 2, 'Y reinó tres años en Jerusalem. El nombre de su madre fué Michâía hija de Uriel de Gabaa. Y hubo guerra entre Abías y Jeroboam.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 3, 'Entonces ordenó Abías batalla con un ejército de cuatrocientos mil hombres de guerra valerosos y escogidos: y Jeroboam ordenó batalla contra él con ochocientos mil hombres escogidos, fuertes y valerosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 4, 'Y levantóse Abías sobre el monte de Semaraim, que es en los montes de Ephraim, y dijo: Oidme, Jeroboam y todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 5, '¿No sabéis vosotros, que Jehová Dios de Israel dió el reino á David sobre Israel para siempre, á él y á sus hijos en alianza de sal?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 6, 'Pero Jeroboam hijo de Nabat, siervo de Salomón hijo de David, se levantó y rebeló contra su señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 7, 'Y se allegaron á el hombres vanos, hijos de iniquidad, y pudieron más que Roboam hijo de Salomón, porque Roboam era mozo y tierno de corazón, y no se defendió de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 8, 'Y ahora vosotros tratáis de fortificaros contra el reino de Jehová en mano de los hijos de David, porque sois muchos, y tenéis con vosotros los becerros de oro que Jeroboam os hizo por dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 9, '¿No echasteis vosotros á los sacerdotes de Jehová, á los hijos de Aarón, y á los Levitas, y os habéis hecho sacerdotes á la manera de los pueblos de otras tierras, para que cualquiera venga á consagrarse con un becerro y siete carneros, y así sea sacerdote de los que no son dioses?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 10, 'Mas en cuanto á nosotros, Jehová es nuestro Dios, y no le hemos dejado: y los sacerdotes que ministran á Jehová son los hijos de Aarón, y los Levitas en la obra;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 11, 'Los cuales queman á Jehová los holocaustos cada mañana y cada tarde, y los perfumes aromáticos; y ponen los panes sobre la mesa limpia, y el candelero de oro con sus candilejas para que ardan cada tarde: porque nosotros guardamos la ordenanza de Jehová nuestro Dios; mas vosotros le habéis dejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 12, 'Y he aquí Dios está con nosotros por cabeza, y sus sacerdotes con las trompetas del júbilo para que suenen contra vosotros. Oh hijos de Israel, no peleéis contra Jehová el Dios de vuestros padres, porque no os sucederá bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 13, 'Pero Jeroboam hizo girar una emboscada para venir á ellos por la espalda: y estando así delante de ellos, la emboscada estaba á espaldas de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 14, 'Y como miró Judá, he aquí que tenía batalla delante y á las espaldas; por lo que clamaron á Jehová, y los sacerdotes tocaron las trompetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 15, 'Entonces los de Judá alzaron grita; y así que ellos alzaron grita, Dios desbarató á Jeroboam y á todo Israel delante de Abías y de Judá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 16, 'Y huyeron los hijos de Israel delante de Judá, y Dios los entregó en sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 17, 'Y Abías y su gente hacían en ellos gran mortandad; y cayeron heridos de Israel quinientos mil hombres escogidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 18, 'Así fueron humillados los hijos de Israel en aquel tiempo: mas los hijos de Judá se fortificaron, porque se apoyaban en Jehová el Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 19, 'Y siguió Abías á Jeroboam, y tomóle algunas ciudades, á Beth-el con sus aldeas, á Jesana con sus aldeas, y á Ephraim con sus aldeas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 20, 'Y nunca más tuvo Jeroboam poderío en los días de Abías: é hirióle Jehová, y murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 21, 'Empero se fortificó Abías; y tomó catorce mujeres, y engendró veintidós hijos, y dieciséis hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 13, 22, 'Lo demás de los hechos de Abías, sus caminos y sus negocios, está escrito en la historia de Iddo profeta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 1, 'Y DURMIO Abías con sus padres, y fué sepultado en la ciudad de David. Y reinó en su lugar su hijo Asa, en cuyos días tuvo sosiego el país por diez años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 2, 'E hizo Asa lo bueno y lo recto en los ojos de Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 3, 'Porque quitó los altares del culto ajeno, y los altos; quebró las imágenes, y taló los bosques;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 4, 'Y mandó á Judá que buscasen á Jehová el Dios de sus padres, y pusiesen por obra la ley y sus mandamientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 5, 'Quitó asimismo de todas las ciudades de Judá los altos y las imágenes, y estuvo el reino quieto delante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 6, 'Y edificó ciudades fuertes en Judá, por cuanto había paz en la tierra, y no había guerra contra él en aquellos tiempos; porque Jehová le había dado reposo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 7, 'Dijo por tanto á Judá: Edifiquemos estas ciudades, y cerquémoslas de muros con torres, puertas, y barras, ya que la tierra es nuestra: porque hemos buscado á Jehová nuestro Dios, hémosle buscado, y él nos ha dado reposo de todas partes. Edificaron pues, y fueron prosperados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 8, 'Tuvo también Asa ejército que traía escudos y lanzas: de Judá trescientos mil, y de Benjamín doscientos y ochenta mil que traían escudos y flechaban arcos; todos hombres diestros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 9, 'Y salió contra ellos Zera Etiope con un ejército de mil millares, y trescientos carros; y vino hasta Maresa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 10, 'Entonces salió Asa contra él, y ordenaron la batalla en el valle de Sephata junto á Maresa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 11, 'Y clamó Asa á Jehová su Dios, y dijo: Jehová, no tienes tú más con el grande que con el que ninguna fuerza tiene, para dar ayuda. Ayúdanos, oh Jehová Dios nuestro, porque en ti nos apoyamos, y en tu nombre venimos contra este ejército. Oh Jehová, tú eres nuestro Dios: no prevalezca contra ti el hombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 12, 'Y Jehová deshizo los Etiopes delante de Asa y delante de Judá; y huyeron los Etiopes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 13, 'Y Asa, y el pueblo que con él estaba, lo siguió hasta Gerar: y cayeron los Etiopes hasta no quedar en ellos aliento; porque fueron deshechos delante de Jehová y de su ejército. Y les tomaron muy grande despojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 14, 'Batieron también todas las ciudades alrededor de Gerar, porque el terror de Jehová fué sobre ellos: y saquearon todas las ciudades, porque había en ellas gran despojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 14, 15, 'Asimismo dieron sobre las cabañas de los ganados, y trajeron muchas ovejas y camellos, y volviéronse á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 1, 'Y FUÉ el espíritu de Dios sobre Azarías hijo de Obed;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 2, 'Y salió al encuentro á Asa, y díjole: Oidme, Asa, y todo Judá y Benjamín: Jehová es con vosotros, si vosotros fueres con él: y si le buscareis, será hallado de vosotros; mas si le dejareis, él también os dejará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 3, 'Muchos días ha estado Israel sin verdadero Dios y sin sacerdote, y sin enseñador y sin ley:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 4, 'Mas cuando en su tribulación se convirtieron á Jehová Dios de Israel, y le buscaron, él fué hallado de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 5, 'En aquellos tiempos no hubo paz, ni para el que entraba, ni para el que salía, sino muchas aflicciones sobre todos los habitadores de las tierras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 6, 'Y la una gente destruía á la otra, y una ciudad á otra ciudad: porque Dios los conturbó con todas calamidades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 7, 'Esforzaos empero vosotros, y no desfallezcan vuestras manos; que salario hay para vuestra obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 8, 'Y como oyó Asa las palabras y profecía de Obed profeta, fué confortado, y quitó las abominaciones de toda la tierra de Judá y de Benjamín, y de las ciudades que él había tomado en el monte de Ephraim; y reparó el altar de Jehová que estaba delante del pórtico de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 9, 'Después hizo juntar á todo Judá y Benjamín, y con ellos los extranjeros de Ephraim, y de Manasés, y de Simeón: porque muchos de Israel se habían pasado á él, viendo que Jehová su Dios era con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 10, 'Juntáronse pues en Jerusalem en el mes tercero del año décimoquinto del reinado de Asa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 11, 'Y en aquel mismo día sacrificaron á Jehová, de los despojos que habían traído, setecientos bueyes y siete mil ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 12, 'Y entraron en concierto de que buscarían á Jehová el Dios de sus padres, de todo su corazón y de toda su alma;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 13, 'Y que cualquiera que no buscase á Jehová el Dios de Israel, muriese, grande ó pequeño, hombre ó mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 14, 'Y juraron á Jehová con gran voz y júbilo, á son de trompetas y de bocinas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 15, 'Del cual juramento todos los de Judá se alegraron; porque de todo su corazón lo juraban, y de toda su voluntad lo buscaban: y fué hallado de ellos; y dióles Jehová reposo de todas partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 16, 'Y aun á Maachâ madre del rey Asa, él mismo la depuso de su dignidad, porque había hecho un ídolo en el bosque: y Asa deshizo su ídolo, y lo desmenuzó, y quemó en el torrente de Cedrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 17, 'Mas con todo eso los altos no eran quitados de Israel, aunque el corazón de Asa fué perfecto mientras vivió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 18, 'Y metió en la casa de Dios lo que su padre había dedicado, y lo que él había consagrado, plata y oro y vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 15, 19, 'Y no hubo guerra hasta los treinta y cinco años del reinado de Asa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 1, 'EN el año treinta y seis del reinado de Asa, subió Baasa rey de Israel contra Judá, y edificó á Rama, para no dejar salir ni entrar á ninguno al rey Asa, rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 2, 'Entonces sacó Asa la plata y el oro de los tesoros de la casa de Jehová y de la casa real, y envió á Ben-adad rey de Siria, que estaba en Damasco, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 3, 'Haya alianza entre mí y ti, como la hubo entre mi padre y tu padre; he aquí yo te he enviado plata y oro, para que vengas y deshagas la alianza que tienes con Baasa rey de Israel, á fin de que se retire de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 4, 'Y consintió Ben-adad con el rey Asa, y envió los capitanes de sus ejércitos á la ciudades de Israel: y batieron á Ion, Dan, y Abel-maim, y las ciudades fuertes de Nephtalí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 5, 'Y oyendo esto Baasa, cesó de edificar á Rama, y dejó su obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 6, 'Entonces el rey Asa tomó á todo Judá, y lleváronse de Rama la piedra y madera con que Baasa edificaba, y con ella edificó á Gibaa y Mizpa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 7, 'En aquel tiempo vino Hanani vidente á Asa rey de Judá, y díjole: Por cuanto te has apoyado en el rey de Siria, y no te apoyaste en Jehová tu Dios, por eso el ejército del rey de Siria ha escapado de tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 8, 'Los Etiopes y los Libios, ¿no eran un ejército numerosísimo, con carros y muy mucha gente de á caballo? con todo, porque te apoyaste en Jehová, él los entregó en tus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 9, 'Porque los ojos de Jehová contemplan toda la tierra, para corroborar á los que tienen corazón perfecto para con él. Locamente has hecho en esto; porque de aquí adelante habrá guerra contra ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 10, 'Y enojado Asa contra el vidente, echólo en la casa de la cárcel, porque fué en extremo conmovido á causa de esto. Y oprimió Asa en aquel tiempo algunos del pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 11, 'Mas he aquí, los hechos de Asa, primeros y postreros, están escritos en el libro de los reyes de Judá y de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 12, 'Y el año treinta y nueve de su reinado enfermó Asa de los pies para arriba, y en su enfermedad no buscó á Jehová, sino á los médicos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 13, 'Y durmió Asa con sus padres, y murió en el año cuarenta y uno de su reinado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 16, 14, 'Y sepultáronlo en sus sepulcros que él había hecho para sí en la ciudad de David;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 1, 'Y REINO en su lugar Josaphat su hijo, el cual prevaleció contra Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 2, 'Y puso ejército en todas las ciudades fuertes de Judá, y colocó gente de guarnición, en tierra de Judá, y asimismo en las ciudades de Ephraim que su padre Asa había tomado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 3, 'Y fué Jehová con Josaphat, porque anduvo en los primeros caminos de David su padre, y no buscó á los Baales;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 4, 'Sino que buscó al Dios de su padre, y anduvo en sus mandamientos, y no según las obras de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 5, 'Jehová por tanto confirmó el reino en su mano, y todo Judá dió á Josaphat presentes; y tuvo riquezas y gloria en abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 6, 'Y animóse su corazón en los caminos de Jehová, y quitó los altos y los bosques de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 7, 'Al tercer año de su reinado envió sus príncipes Ben-hail, Obdías, Zachârías, Nathaniel y Michêas, para que enseñasen en las ciudades de Judá;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 8, 'Y con ellos á los Levitas, Semeías, Nethanías, Zebadías, y Asael, y Semiramoth, y Jonathán, y Adonías, y Tobías, y Tobadonías, Levitas; y con ellos á Elisama y á Joram, sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 9, 'Y enseñaron en Judá, teniendo consigo el libro de la ley de Jehová, y rodearon por todas las ciudades de Judá enseñando al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 10, 'Y cayó el pavor de Jehová sobre todos los reinos de las tierras que estaban alrededor de Judá; que no osaron hacer guerra contra Josaphat.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 11, 'Y traían de los Filisteos presentes á Josaphat, y tributos de plata. Los Arabes también le trajeron ganados, siete mil y setecientos carneros y siete mil y setecientos machos de cabrío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 12, 'Iba pues Josaphat creciendo altamente: y edificó en Judá fortalezas y ciudades de depósitos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 13, 'Tuvo además muchas obras en las ciudades de Judá, y hombres de guerra muy valientes en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 14, 'Y este es el número de ellos según las casas de sus padres: en Judá, jefes de los millares: el general Adna, y con él trescientos mil hombres muy esforzados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 15, 'Después de él, el jefe Johanán, y con él doscientos y ochenta mil;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 16, 'Tras éste, Amasías hijo de Zichri, el cual se había ofrecido voluntariamente á Jehová, y con él doscientos mil hombres valientes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 17, 'De Benjamín, Eliada, hombre muy valeroso, y con él doscientos mil armados de arco y escudo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 18, 'Tras éste, Jozabad, y con él ciento y ochenta mil apercibidos para la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 17, 19, 'Estos eran siervos del rey, sin los que había el rey puesto en las ciudades de guarnición por toda Judea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 1, 'TENIA pues Josaphat riquezas y gloria en abundancia, y trabó parentesco con Achâb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 2, 'Y después de algunos años descendió á Achâb á Samaria; por lo que mató Achâb muchas ovejas y bueyes para él, y para la gente que con él venía: y persuadióle que fuese con él á Ramoth de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 3, 'Y dijo Achâb rey de Israel á Josaphat rey de Judá: ¿Quieres venir conmigo á Ramoth de Galaad? Y él respondió: Como yo, así también tú; y como tu pueblo, así también mi pueblo: iremos contigo á la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 4, 'Además dijo Josaphat al rey de Israel: Ruégote que consultes hoy la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 5, 'Entonces el rey de Israel juntó cuatrocientos profetas, y díjoles: ¿Iremos á la guerra contra Ramoth de Galaad, ó estaréme yo quieto? Y ellos dijeron: Sube, que Dios los entregará en mano del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 6, 'Mas Josaphat dijo: ¿Hay aún aquí algún profeta de Jehová, para que por él preguntemos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 7, 'Y el rey de Israel respondió á Josaphat: Aun hay aquí un hombre por el cual podemos preguntar á Jehová: mas yo le aborrezco, porque nunca me profetiza cosa buena, sino siempre mal. Este es Michêas, hijo de Imla. Y respondió Josaphat: No hable así el rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 8, 'Entonces el rey de Israel llamó un eunuco, y díjole: Haz venir luego á Michêas hijo de Imla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 9, 'Y el rey de Israel y Josaphat rey de Judá, estaban sentados cada uno en su trono, vestidos de sus ropas; y estaban sentados en la era á la entrada de la puerta de Samaria, y todos los profetas profetizaban delante de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 10, 'Y Sedechîas hijo de Chênaana se había hecho cuernos de hierro, y decía: Así ha dicho Jehová: Con estos acornearás á los Siros hasta destruirlos del todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 11, 'De esta manera profetizaban también todos los profetas, diciendo: Sube á Ramoth de Galaad, y sé prosperado; porque Jehová la entregará en mano del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 12, 'Y el mensajero que había ido á llamar á Michêas, le habló, diciendo: He aquí las palabras de los profetas á una boca anuncian al rey bienes; yo pues te ruego que tu palabra sea como la de uno de ellos, que hables bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 13, 'Y dijo Michêas: Vive Jehová, que lo que mi Dios me dijere, eso hablaré. Y vino al rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 14, 'Y el rey le dijo: Michêas, ¿iremos á pelear contra Ramoth de Galaad, ó estaréme yo quieto? Y él respondió: Subid, que seréis prosperados, que serán entregados en vuestras manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 15, 'Y el rey le dijo: ¿Hasta cuántas veces te conjuraré por el nombre de Jehová que no me hables sino la verdad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 16, 'Entonces él dijo: He visto á todo Israel derramado por los montes como ovejas sin pastor: y dijo Jehová: Estos no tienen señor; vuélvase cada uno en paz en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 17, 'Y el rey de Israel dijo á Josaphat: ¿No te había yo dicho que no me profetizaría bien, sino mal?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 18, 'Entonces él dijo: Oid pues palabra de Jehová: Yo he visto á Jehová sentado en su trono, y todo el ejército de los cielos estaba á su mano derecha y á su izquierda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 19, 'Y Jehová dijo: ¿Quién inducirá á Achâb rey de Israel, para que suba y caiga en Ramoth de Galaad? Y uno decía así, y otro decía de otra manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 20, 'Mas salió un espíritu, que se puso delante de Jehová, y dijo: Yo le induciré. Y Jehová le dijo: ¿De qué modo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 21, 'Y él dijo: Saldré y seré espíritu de mentira en la boca de todos los profetas. Y Jehová dijo: Incita, y también prevalece: sal, y hazlo así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 22, 'Y he aquí ahora ha puesto Jehová espíritu de mentira en la boca de estos tus profetas; mas Jehová ha decretado el mal acerca de ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 23, 'Entonces Sedechîas hijo de Chênaana se llegó á él, é hirió á Michêas en la mejilla, y dijo: ¿Por qué camino se apartó de mí el espíritu de Jehová para hablarte á ti?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 24, 'Y Michêas respondió: He aquí tú lo verás aquel día, cuando te entrarás de cámara en cámara para esconderte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 25, 'Entonces el rey de Israel dijo: Tomad á Michêas, y volvedlo á Amón gobernador de la ciudad, y á Joas hijo del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 26, 'Y diréis: El rey ha dicho así: Poned á éste en la cárcel, y sustentadle con pan de aflicción y agua de angustia, hasta que yo vuelva en paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 27, 'Y Michêas dijo: Si tú volvieres en paz, Jehová no ha hablado por mí. Dijo además: Oid lo, pueblos todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 28, 'Subió pues el rey de Israel, y Josaphat rey de Judá, á Ramoth de Galaad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 29, 'Y dijo el rey de Israel á Josaphat: Yo me disfrazaré para entrar en la batalla: mas tú vístete tus vestidos. Y disfrazóse el rey de Israel, y entró en la batalla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 30, 'Había el rey de Siria mandado á los capitanes de los carros que tenía consigo, diciendo: No peleéis con chico ni con grande, sino sólo con el rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 31, 'Y como los capitanes de los carros vieron á Josaphat, dijeron: Este es el rey de Israel. Y cercáronlo para pelear; mas Josaphat clamó, y ayudólo Jehová, y apartólos Dios de él:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 32, 'Pues viendo los capitanes de los carros que no era el rey de Israel, desistieron de acosarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 33, 'Mas disparando uno el arco á la ventura, hirió al rey de Israel entre las junturas y el coselete. El entonces dijo al carretero: Vuelve tu mano, y sácame del campo, porque estoy mal herido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 18, 34, 'Y arreció la batalla aquel día, por lo que estuvo el rey de Israel en pie en el carro enfrente de los Siros hasta la tarde; mas murió á puestas del sol.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 1, 'Y JOSAPHAT rey de Judá se volvió en paz á su casa en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 2, 'Y salióle al encuentro Jehú el vidente, hijo de Hanani, y dijo al rey Josaphat: ¿Al impío das ayuda, y amas á los que aborrecen á Jehová? Pues la ira de la presencia de Jehová será sobre ti por ello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 3, 'Empero se han hallado en ti buenas cosas, porque cortaste de la tierra los bosques, y has apercibido tu corazón á buscar á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 4, 'Habitó pues Josaphat en Jerusalem; mas daba vuelta y salía al pueblo, desde Beer-seba hasta el monte de Ephraim, y reducíalos á Jehová el Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 5, 'Y puso en la tierra jueces en todas las ciudades fuertes de Judá, por todos los lugares.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 6, 'Y dijo á los jueces: Mirad lo que hacéis: porque no juzguéis en lugar de hombre, sino en lugar de Jehová, el cual está con vosotros en el negocio del juicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 7, 'Sea pues con vosotros el temor de Jehová; guardad y haced: porque en Jehová nuestro Dios no hay iniquidad, ni acepción de personas, ni recibir cohecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 8, 'Y puso también Josaphat en Jerusalem algunos de los Levitas y sacerdotes, y de los padres de familias de Israel, para el juicio de Jehová y para las causas. Y volviéronse á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 9, 'Y mandóles, diciendo: Procederéis asimismo con temor de Jehová, con verdad, y con corazón íntegro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 10, 'En cualquier causa que viniere á vosotros de vuestros hermanos que habitan en las ciudades, entre sangre y sangre, entre ley y precepto, estatutos y derechos, habéis de amonestarles que no pequen contra Jehová, porque no venga ira sobre vosotros y sobre vuestros hermanos. Obrando así no pecaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 19, 11, 'Y he aquí Amarías sacerdote será el que os presida en todo negocio de Jehová; y Zebadías hijo de Ismael, príncipe de la casa de Judá, en todos los negocios del rey; también los Levitas serán oficiales en presencia de vosotros. Esforzaos pues, y obrad; que Jehová será con el bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 1, 'PASADAS estas cosas, aconteció que los hijos de Moab y de Ammón, y con ellos otros de los Ammonitas, vinieron contra Josaphat á la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 2, 'Y acudieron, y dieron aviso á Josaphat, diciendo: Contra ti viene una grande multitud de la otra parte de la mar, y de la Siria; y he aquí ellos están en Hasasón-tamar, que es Engedi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 3, 'Entonces él tuvo temor; y puso Josaphat su rostro para consultar á Jehová, é hizo pregonar ayuno á todo Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 4, 'Y juntáronse los de Judá para pedir socorro á Jehová: y también de todas las ciudades de Judá vinieron á pedir á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 5, 'Púsose entonces Josaphat en pie en la reunión de Judá y de Jerusalem, en la casa de Jehová, delante del atrio nuevo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 6, 'Y dijo: Jehová Dios de nuestros padres, ¿no eres tú Dios en los cielos, y te enseñoreas en todos los reinos de las Gentes? ¿no está en tu mano tal fuerza y potencia, que no hay quien te resista?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 7, 'Dios nuestro, ¿no echaste tú los moradores de aquesta tierra delante de tu pueblo Israel, y la diste á la simiente de Abraham tu amigo para siempre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 8, 'Y ellos han habitado en ella, y te han edificado en ella santuario á tu nombre, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 9, 'Si mal viniere sobre nosotros, ó espada de castigo, ó pestilencia, ó hambre, presentarnos hemos delante de esta casa, y delante de ti, (porque tu nombre está en esta casa,) y de nuestras tribulaciones clamaremos á ti, y tú nos oirás y salvarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 10, 'Ahora pues, he aquí los hijos de Ammón y de Moab, y los del monte de Seir, á la tierra de los cuales ni quisiste que pasase Israel cuando venían de la tierra de Egipto, sino que se apartasen de ellos, y no los destruyesen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 11, 'He aquí ellos nos dan el pago, viniendo á echarnos de tu heredad, que tú nos diste á poseer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 12, '¡Oh Dios nuestro! ¿no los juzgarás tú? porque en nosotros no hay fuerza contra tan grande multitud que viene contra nosotros: no sabemos lo que hemos de hacer, mas á ti volvemos nuestros ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 13, 'Y todo Judá estaba en pie delante de Jehová, con sus niños, y sus mujeres, y sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 14, 'Y estaba allí Jahaziel hijo de Zachârías, hijo de Benaías, hijo de Jeiel, hijo de Mathanías, Levita de los hijos de Asaph, sobre el cual vino el espíritu de Jehová en medio de la reunión;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 15, 'Y dijo: Oid, Judá todo, y vosotros moradores de Jerusalem, y tú, rey Josaphat. Jehová os dice así: No temáis ni os amedrentéis delante de esta tan grande multitud; porque no es vuestra la guerra, sino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 16, 'Mañana descenderéis contra ellos: he aquí que ellos subirán por la cuesta de Sis, y los hallaréis junto al arroyo, antes del desierto de Jeruel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 17, 'No habrá para qué vosotros peleéis en este caso: paraos, estad quedos, y ved la salud de Jehová con vosotros. Oh Judá y Jerusalem, no temáis ni desmayéis; salid mañana contra ellos, que Jehová será con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 18, 'Entonces Josaphat se inclinó rostro por tierra, y asimismo todo Judá y los moradores de Jerusalem se postraron delante de Jehová, y adoraron á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 19, 'Y levantáronse los Levitas de los hijos de Coath y de los hijos de Coré, para alabar á Jehová el Dios de Israel á grande y alta voz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 20, 'Y como se levantaron por la mañana, salieron por el desierto de Tecoa. Y mientras ellos salían, Josaphat estando en pie, dijo: Oidme, Judá y moradores de Jerusalem. Creed á Jehová vuestro Dios, y seréis seguros; creed á sus profetas, y seréis prosperados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 21, 'Y habido consejo con el pueblo, puso á algunos que cantasen á Jehová, y alabasen en la hermosura de la santidad, mientras que salía la gente armada, y dijesen: Glorificad á Jehová, porque su misericordia es para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 22, 'Y como comenzaron con clamor y con alabanza, puso Jehová contra los hijos de Ammón, de Moab, y del monte de Seir, las emboscadas de ellos mismos que venían contra Judá, y matáronse los unos á los otros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 23, 'Pues los hijos de Ammón y Moab se levantaron contra los del monte de Seir, para matarlos y destruirlos; y como hubieron acabado á los del monte de Seir, cada cual ayudó á la destrucción de su compañero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 24, 'Y luego que vino Judá á la atalaya del desierto, miraron hacia la multitud; mas he aquí yacían ellos en tierra muertos, que ninguno había escapado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 25, 'Viniendo entonces Josaphat y su pueblo á despojarlos, hallaron en ellos muchas riquezas entre los cadáveres, así vestidos como preciosos enseres, los cuales tomaron para sí, tantos, que no los podían llevar: tres días duró el despojo, porque era mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 26, 'Y al cuarto día se juntaron en el valle de Beracah; porque allí bendijeron á Jehová, y por esto llamaron el nombre de aquel paraje el valle de Beracah, hasta hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 27, 'Y todo Judá y los de Jerusalem, y Josaphat á la cabeza de ellos, volvieron para tornarse á Jerusalem con gozo, porque Jehová les había dado gozo de sus enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 28, 'Y vinieron á Jerusalem con salterios, arpas, y bocinas, á la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 29, 'Y fué el pavor de Dios sobre todos los reinos de aquella tierra, cuando oyeron que Jehová había peleado contra los enemigos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 30, 'Y el reino de Josaphat tuvo reposo; porque su Dios le dió reposo de todas partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 31, 'Así reinó Josaphat sobre Judá: de treinta y cinco años era cuando comenzó á reinar, y reinó veinte y cinco años en Jerusalem. El nombre de su madre fué Azuba, hija de Silhi.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 32, 'Y anduvo en el camino de Asa su padre, sin apartarse de él, haciendo lo recto en los ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 33, 'Con todo eso los altos no eran quitados; que el pueblo aun no había enderezado su corazón al Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 34, 'Lo demás de los hechos de Josaphat, primeros y postreros, he aquí están escritos en las palabras de Jehú hijo de Hanani, del cual es hecha mención en el libro de los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 35, 'Pasadas estas cosas, Josaphat rey de Judá trabó amistad con Ochôzías rey de Israel, el cual fué dado á la impiedad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 36, 'E hizo con él compañía para aparejar navíos que fuesen á Tharsis; y construyeron los navíos en Esion-geber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 20, 37, 'Entonces Eliezer hijo de Dodava de Mareosah, profetizó contra Josaphat, diciendo: Por cuanto has hecho compañía con Ochôzías, Jehová destruirá tus obras. Y los navíos se rompieron, y no pudieron ir á Tharsis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 1, 'Y DURMIO Josaphat con sus padres, y sepultáronlo con sus padres en la ciudad de David. Y reinó en su lugar Joram su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 2, 'Este tuvo hermanos, hijos de Josaphat, á Azarías, Jehiel, Zachârías, Azarías, Michâel, y Sephatías. Todos estos fueron hijos de Josaphat rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 3, 'Y su padre les había dado muchos dones de oro y de plata, y cosas preciosas, y ciudades fuertes en Judá; mas había dado el reino á Joram, porque él era el primogénito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 4, 'Fué pues elevado Joram al reino de su padre; y luego que se hizo fuerte, mató á cuchillo á todos sus hermanos, y asimismo algunos de los príncipes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 5, 'Cuando comenzó á reinar era de treinta y dos años, y reinó ocho años en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 6, 'Y anduvo en el camino de los reyes de Israel, como hizo la casa de Achâb; porque tenía por mujer la hija de Achâb, é hizo lo malo en ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 7, 'Mas Jehová no quiso destruir la casa de David, á causa de la alianza que con David había hecho, y porque le había dicho que le daría lámpara á él y á sus hijos perpetuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 8, 'En los días de éste se rebeló la Idumea, para no estar bajo el poder de Judá, y pusieron rey sobre sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 9, 'Entonces pasó Joram con sus príncipes, y consigo todos sus carros; y levantóse de noche, é hirió á los Idumeos que le habían cercado, y á todos los comandantes de sus carros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 10, 'Con todo eso Edom quedó rebelado, sin estar bajo la mano de Judá hasta hoy. También se rebeló en el mismo tiempo Libna para no estar bajo su mano; por cuanto él había dejado á Jehová el Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 11, 'Demás de esto hizo altos en los montes de Judá, é hizo que los moradores de Jerusalem fornicasen, y á ello impelió á Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 12, 'Y viniéronle letras del profeta Elías, que decían: Jehová, el Dios de David tu padre, ha dicho así: Por cuanto no has andado en los caminos de Josaphat tu padre, ni en los caminos de Asa, rey de Judá,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 13, 'Antes has andado en el camino de los reyes de Israel, y has hecho que fornicase Judá, y los moradores de Jerusalem, como fornicó la casa de Achâb; y además has muerto á tus hermanos, á la familia de tu padre, los cuales eran mejores que tú:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 14, 'He aquí Jehová herirá tu pueblo de una grande plaga, y á tus hijos y á tus mujeres, y á toda tu hacienda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 15, 'Y á ti con muchas enfermedades, con enfermedad de tus entrañas, hasta que las entrañas se te salgan á causa de la enfermedad de cada día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 16, 'Entonces despertó Jehová contra Joram el espíritu de los Filisteos, y de los Arabes que estaban junto á los Etiopes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 17, 'Y subieron contra Judá, é invadieron la tierra, y tomaron toda la hacienda que hallaron en la casa del rey, y á sus hijos, y á sus mujeres; que no le quedó hijo, sino Joachâz el menor de sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 18, 'Después de todo esto Jehová lo hirió en las entrañas de una enfermedad incurable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 19, 'Y aconteció que, pasando un día tras otro, al fin, al cabo de dos años, las entrañas se le salieron con la enfermedad, muriendo así de enfermedad muy penosa. Y no le hizo quema su pueblo, como las había hecho á sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 21, 20, 'Cuando comenzó á reinar era de treinta y dos años, y reinó en Jerusalem ocho años; y fuése sin ser deseado. Y sepultáronlo en la ciudad de David, mas no en los sepulcros de los reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 1, 'Y LOS moradores de Jerusalem hicieron rey en lugar suyo á Ochôzías su hijo menor: porque la tropa había venido con los Arabes al campo, había muerto á todos los mayores; por lo cual reinó Ochôzías, hijo de Joram rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 2, 'Cuando Ochôzías comenzó á reinar era de cuarenta y dos años, y reinó un año en Jerusalem. El nombre de su madre fué Athalía, hija de Omri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 3, 'También él anduvo en los caminos de la casa de Achâb: porque su madre le aconsejaba á obrar impíamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 4, 'Hizo pues lo malo en ojos de Jehová, como la casa de Achâb; porque después de la muerte de su padre, ellos le aconsejaron para su perdición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 5, 'Y él anduvo en los consejos de ellos, y fué á la guerra con Joram hijo de Achâb, rey de Israel, contra Hazael rey de Siria, á Ramoth de Galaad, donde los Siros hirieron á Joram.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 6, 'Y se volvió para curarse en Jezreel de las heridas que le habían hecho en Rama, peleando con Hazael rey de Siria. Y descendió Azarías hijo de Joram, rey de Judá, á visitar á Joram hijo de Achâb, en Jezreel, porque allí estaba enfermo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 7, 'Esto empero venía de Dios, para que Ochôzías fuese hollado viniendo á Joram: porque siendo venido, salió con Joram contra Jehú hijo de Nimsi, al cual Jehová había ungido para que talase la casa de Achâb.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 8, 'Y fué que, haciendo juicio Jehú con la casa de Achâb, halló á los príncipes de Judá, y á los hijos de los hermanos de Ochôzías, que servían á Ochôzías, y matólos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 9, 'Y buscando á Ochôzías, el cual se había escondido en Samaria, tomáronlo, y trajéronlo á Jehú, y le mataron; y diéronle sepultura, porque dijeron: Es hijo de Josaphat, el cual buscó á Jehová de todo su corazón. Y la casa de Ochôzías no tenía fuerzas para poder retener el reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 10, 'Entonces Athalía madre de Ochôzías, viendo que su hijo era muerto, levantóse y destruyó toda la simiente real de la casa de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 11, 'Empero Josabeth, hija del rey, tomó á Joas hijo de Ochôzías, y arrebatólo de entre los hijos del rey, que mataban, y guardóle á él y á su ama en la cámara de los lechos. Así pues lo escondió Josabeth, hija del rey Joram, mujer de Joiada el sacerdote, (porque ella era hermana de Ochôzías), de delante de Athalía, y no lo mataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 22, 12, 'Y estuvo con ellos escondido en la casa de Dios seis años. Entre tanto Athalía reinaba en el país.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 1, 'MAS el séptimo año se animó Joiada, y tomó consigo en alianza á los centuriones, Azarías hijo de Jeroam, y á Ismael hijo de Johanán, y á Azarías hijo de Obed, y á Maasías hijo de Adaías, y á Elisaphat hijo de Zichri;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 2, 'Los cuales rodeando por Judá, juntaron los Levitas de todas las ciudades de Judá, y á los príncipes de las familias de Israel, y vinieron á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 3, 'Y toda la multitud hizo alianza con el rey en la casa de Dios. Y él les dijo: He aquí el hijo del rey, el cual reinará, como Jehová lo tiene dicho de los hijos de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 4, 'Lo que habéis de hacer es: la tercera parte de vosotros, los que entran de semana, estarán de porteros con los sacerdotes y los Levitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 5, 'Y la tercera parte, á la casa del rey; y la tercera parte, á la puerta del fundamento: y todo el pueblo estará en los patios de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 6, 'Y ninguno entre en la casa de Jehová, sino los sacerdotes y Levitas que sirven: éstos entrarán, porque están consagrados; y todo el pueblo hará la guardia de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 7, 'Y los Levitas rodearán al rey por todas partes, y cada uno tendrá sus armas en la mano; y cualquiera que entrare en la casa, muera: y estaréis con el rey cuando entrare, y cuando saliere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 8, 'Y los Levitas y todo Judá lo hicieron todo como lo había mandado el sacerdote Joiada: y tomó cada uno los suyos, los que entraban de semana, y los que salían el sábado: porque el sacerdote Joiada no dió licencia á las compañías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 9, 'Dió también el sacerdote Joiada á los centuriones las lanzas, paveses y escudos que habían sido del rey David, que estaban en la casa de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 10, 'Y puso en orden á todo el pueblo, teniendo cada uno su espada en la mano, desde el rincón derecho del templo hasta el izquierdo, hacia el altar y la casa, en derredor del rey por todas partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 11, 'Entonces sacaron al hijo del rey, y pusiéronle la corona y el testimonio, é hiciéronle rey; y Joiada y sus hijos le ungieron, diciendo luego: ¡Viva el rey!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 12, 'Y como Athalía oyó el estruendo de la gente que corría, y de los que bendecían al rey, vino al pueblo á la casa de Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 13, 'Y mirando, vió al rey que estaba junto á su columna á la entrada, y los príncipes y los trompetas junto al rey, y que todo el pueblo de la tierra hacía alegrías, y sonaban bocinas, y cantaban con instrumentos de música los que sabían alabar. Entonces Athalía rasgó sus vestidos, y dijo: ¡Conjuración, conjuración!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 14, 'Y sacando el pontífice Joiada los centuriones y capitanes del ejército, díjoles: Sacadla fuera del recinto; y el que la siguiere, muera á cuchillo: porque el sacerdote había mandado que no la matasen en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 15, 'Ellos pues le echaron mano, y luego que hubo ella pasado la entrada de la puerta de los caballos de la casa del rey, allí la mataron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 16, 'Y Joiada hizo pacto entre sí y todo el pueblo y el rey, que serían pueblo de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 17, 'Después de esto entró todo el pueblo en el templo de Baal, y derribáronlo, y también sus altares; é hicieron pedazos sus imágenes, y mataron delante de los altares á Mathán, sacerdote de Baal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 18, 'Luego ordenó Joiada los oficios en la casa de Jehová bajo la mano de los sacerdotes y Levitas, según David los había distribuído en la casa de Jehová, para ofrecer á Jehová los holocaustos, como está escrito en la ley de Moisés, con gozo y cantares, conforme á la ordenación de David.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 19, 'Puso también porteros á las puertas de la casa de Jehová, para que por ninguna vía entrase ningún inmundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 20, 'Tomó después los centuriones, y los principales, y los que gobernaban el pueblo; y á todo el pueblo de la tierra, y llevó al rey de la casa de Jehová; y viniendo hasta el medio de la puerta mayor de la casa del rey, sentaron al rey sobre el trono del reino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 23, 21, 'Y todo el pueblo del país hizo alegrías: y la ciudad estuvo quieta, muerto que hubieron á Athalía á cuchillo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 1, 'DE SIETE años era Joas cuando comenzó á reinar, y cuarenta años reinó en Jerusalem. El nombre de su madre fué Sibia, de Beer-seba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 2, 'E hizo Joas lo recto en ojos de Jehová todos los días de Joiada el sacerdote.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 3, 'Y tomó para él Joiada dos mujeres; y engendró hijos é hijas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 4, 'Después de esto aconteció que Joas tuvo voluntad de reparar la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 5, 'Y juntó los sacerdotes y los Levitas, y díjoles: Salid por las ciudades de Judá, y juntad dinero de todo Israel, para que cada año sea reparada la casa de vuestro Dios; y vosotros poned diligencia en el negocio. Mas los Levitas no pusieron diligencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 6, 'Por lo cual el rey llamó á Joiada el principal, y díjole: ¿Por qué no has procurado que los Levitas traigan de Judá y de Jerusalem al tabernáculo del testimonio, la ofrenda que impuso Moisés siervo de Jehová, y de la congregación de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 7, 'Porque la impía Athalía y sus hijos habían destruído la casa de Dios, y además habían gastado en los ídolos todas las cosas consagradas á la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 8, 'Mandó pues el rey que hiciesen un arca, la cual pusieron fuera á la puerta de la casa de Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 9, 'E hicieron pregonar en Judá y en Jerusalem, que trajesen á Jehová la ofrenda que Moisés siervo de Dios había impuesto á Israel en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 10, 'Y todos los príncipes y todo el pueblo se holgaron: y traían, y echaban en el arca hasta henchirla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 11, 'Y como venía el tiempo para llevar el arca al magistrado del rey por mano de los Levitas, cuando veían que había mucho dinero, venía el escriba del rey, y el que estaba puesto por el sumo sacerdote, y llevaban el arca, y vaciábanla, y volvíanla á su lugar: y así lo hacían de día en día, y recogían mucho dinero;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 12, 'El cual daba el rey y Joiada á los que hacían la obra del servicio de la casa de Jehová, y tomaban canteros y oficiales que reparasen la casa de Jehová, y herreros y metalarios para componer la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 13, 'Hacían pues los oficiales la obra, y por sus manos fué la obra restaurada, y restituyeron la casa de Dios á su condición, y la consolidaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 14, 'Y cuando hubieron acabado, trajeron lo que quedaba del dinero al rey y á Joiada, é hicieron de él vasos para la casa de Jehová, vasos para el servicio, morteros, cucharas, vasos de oro y de plata. Y sacrificaban holocaustos continuamente en la casa de Jehová todos los días de Joiada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 15, 'Mas Joiada envejeció, y murió harto de días: de ciento y treinta años era cuando murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 16, 'Y sepultáronlo en la ciudad de David con los reyes, por cuanto había hecho bien con Israel, y para con Dios, y con su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 17, 'Muerto Joiada, vinieron los príncipes de Judá, é hicieron acatamiento al rey; y el rey los oyó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 18, 'Y desampararon la casa de Jehová el Dios de sus padres, y sirvieron á los bosques y á las imágenes esculpidas; y la ira vino sobre Judá y Jerusalem por este su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 19, 'Y envióles profetas, para que los redujesen á Jehová, los cuales les protestaron: mas ellos no los escucharon.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 20, 'Y el espíritu de Dios envistió á Zachârías, hijo de Joiada el sacerdote, el cual estando sobre el pueblo, les dijo: Así ha dicho Dios: ¿Por qué quebrantáis los mandamientos de Jehová? No os vendrá bien de ello; porque por haber dejado á Jehová, el también os dejará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 21, 'Mas ellos hicieron conspiración contra él, y cubriéronle de piedras por mandato del rey, en el patio de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 22, 'No tuvo pues memoria el rey Joas de la misericordia que su padre Joiada había hecho con él, antes matóle su hijo; el cual dijo al morir: Jehová lo vea, y lo requiera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 23, 'A la vuelta del año subió contra él el ejército de Siria; y vinieron á Judá y á Jerusalem, y destruyeron en el pueblo á todos los principales de él, y enviaron todos sus despojos al rey á Damasco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 24, 'Porque aunque el ejército de Siria había venido con poca gente, Jehová les entregó en sus manos un ejército muy numeroso; por cuanto habían dejado á Jehová el Dios de sus padres. Y con Joas hicieron juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 25, 'Y yéndose de él los Siros, dejáronlo en muchas enfermedades; y conspiraron contra él sus siervos á causa de las sangres de los hijos de Joiada el sacerdote, é hiriéronle en su cama, y murió: y sepultáronle en la ciudad de David, mas no lo sepultaron en los sepulcros de los reyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 26, 'Los que conspiraron contra él fueron Zabad, hijo de Simath Ammonita, y Jozabad, hijo de Simrith Moabita.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 24, 27, 'De sus hijos, y de la multiplicación que hizo de las rentas, y de la instauración de la casa de Jehová, he aquí está escrito en la historia del libro de los reyes. Y reinó en su lugar Amasías su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 1, 'DE VEINTICINCO años era Amasías cuando comenzó á reinar, y veintinueve años reinó en Jerusalem: el nombre de su madre fué Joaddan, de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 2, 'Hizo él lo recto en los ojos de Jehová aunque no de perfecto corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 3, 'Y luego que fué confirmado en el reino, mató á sus siervos que habían muerto al rey su padre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 4, 'Mas no mató á los hijos de ellos, según lo que está escrito en la ley en el libro de Moisés, donde Jehová mandó, diciendo: No morirán los padres por los hijos, ni los hijos por los padres; mas cada uno morirá por su pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 5, 'Juntó luego Amasías á Judá, y con arreglo á las familias púsoles tribunos y centuriones por todo Judá y Benjamín; y tomólos por lista de veinte años arriba, y fueron hallados en ellos trescientos mil escogidos para salir á la guerra, que tenían lanza y escudo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 6, 'Y de Israel tomó á sueldo cien mil hombres valientes, por cien talentos de plata.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 7, 'Mas un varón de Dios vino á él, diciéndole: Rey, no vaya contigo el ejército de Israel; porque Jehová no es con Israel, ni con todos los hijos de Ephraim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 8, 'Pero si tú vas, si lo haces, y te esfuerzas para pelear, Dios te hará caer delante de los enemigos; porque en Dios está la fortaleza, ó para ayudar, ó para derribar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 9, 'Y Amasías dijo al varón de Dios: ¿Qué pues se hará de cien talentos que he dado al ejército de Israel? Y el varón de Dios respondió: De Jehová es darte mucho más que esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 10, 'Entonces Amasías apartó el escuadrón de la gente que había venido á él de Ephraim, para que se fuesen á sus casas: y ellos se enojaron grandemente contra Judá, y volviéronse á sus casas encolerizados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 11, 'Esforzándose entonces Amasías, sacó su pueblo, y vino al valle de la Sal: é hirió de los hijos de Seir diez mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 12, 'Y los hijos de Judá tomaron vivos otros diez mil, los cuales llevaron á la cumbre de un peñasco, y de allí los despeñaron, y todos se hicieron pedazos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 13, 'Empero los del escuadrón que Amasías había despedido, porque no fuesen con él á la guerra, derramáronse sobre las ciudades de Judá, desde Samaria hasta Beth-oron, é hirieron de ellos tres mil, y tomaron un grande despojo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 14, 'Regresando luego Amasías de la matanza de los Idumeos, trajo también consigo los dioses de los hijos de Seir, y púsoselos para sí por dioses, y encorvóse delante de ellos, y quemóles perfumes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 15, 'Encendióse por tanto el furor de Jehová contra Amasías, y envió á él un profeta, que le dijo: ¿Por qué has buscado los dioses de gente, que no libraron á su pueblo de tus manos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 16, 'Y hablándole el profeta estas cosas, él le respondió: ¿Hante puesto á ti por consejero del rey? Déjate de eso: ¿por qué quieres que te maten? Y al cesar, el profeta dijo luego: Yo sé que Dios ha acordado destruirte, porque has hecho esto, y no obedeciste á mi consejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 17, 'Y Amasías rey de Judá, habido su consejo, envió á decir á Joas, hijo de Joachâz hijo de Jehú, rey de Israel: Ven, y veámonos cara á cara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 18, 'Entonces Joas rey de Israel envió á decir á Amasías rey de Judá: El cardo que estaba en el Líbano, envió al cedro que estaba en el Líbano, diciendo: Da tu hija á mi hijo por mujer. Y he aquí que las bestias fieras que estaban en el Líbano, pasaron, y hollaron el cardo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 19, 'Tú dices: He aquí he herido á Edom; y tu corazón se enaltece para gloriarte: ahora estáte en tu casa; ¿para qué te entrometes en mal, para caer tú y Judá contigo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 20, 'Mas Amasías no quiso oir; porque estaba de Dios, que los quería entregar en manos de sus enemigos, por cuanto habían buscado los dioses de Edom.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 21, 'Subió pues Joas rey de Israel, y viéronse cara á cara él y Amasías rey de Judá, en Beth-semes, la cual es de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 22, 'Pero cayó Judá delante de Israel, y huyó cada uno á su estancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 23, 'Y Joas rey de Israel prendió en Beth-semes á Amasías rey de Judá, hijo de Joas hijo de Joachâz, y llevólo á Jerusalem: y derribó el muro de Jerusalem desde la puerta de Ephraim hasta la puerta del ángulo, cuatrocientos codos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 24, 'Asimismo tomó todo el oro y plata, y todos los vasos que se hallaron en la casa de Dios en casa de Obed-edom, y los tesoros de la casa del rey, y los hijos de los príncipes, y volvióse á Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 25, 'Y vivió Amasías hijo de Joas, rey de Judá, quince años después de la muerte de Joas hijo de Joachâz rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 26, 'Lo demás de los hechos de Amasías, primeros y postreros, ¿no está escrito en el libro de los reyes de Judá y de Israel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 27, 'Desde aquel tiempo que Amasías se apartó de Jehová, maquinaron contra él conjuración en Jerusalem; y habiendo él huído á Lachîs, enviaron tras él á Lachîs, y allá lo mataron;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 25, 28, 'Y trajéronlo en caballos, y sepultáronlo con sus padres en la ciudad de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 1, 'ENTONCES todo el pueblo de Judá tomó á Uzzías, el cual era de diez y seis años, y pusiéronlo por rey en lugar de Amasías su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 2, 'Edificó él á Eloth, y la restituyó á Judá después que el rey durmió con sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 3, 'De diez y seis años era Uzzías cuando comenzó á reinar, y cincuenta y dos años reinó en Jerusalem. El nombre de su madre fué Jechôlía, de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 4, 'E hizo lo recto en los ojos de Jehová, conforme á todas las cosas que había hecho Amasías su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 5, 'Y persistió en buscar á Dios en los días de Zachârías, entendido en visiones de Dios; y en estos días que él buscó á Jehová, él le prosperó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 6, 'Y salió, y peleó contra los Filisteos, y rompió el muro de Gath, y el muro de Jabnia, y el muro de Asdod; y edificó ciudades en Asdod, y en la tierra de los Filisteos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 7, 'Y dióle Dios ayuda contra los Filisteos, y contra los Arabes que habitaban en Gur-baal, y contra los Ammonitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 8, 'Y dieron los Ammonitas presentes á Uzzías, y divulgóse su nombre hasta la entrada de Egipto; porque se había hecho altamente poderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 9, 'Edificó también Uzzías torres en Jerusalem, junto á la puerta del ángulo, y junto á la puerta del valle, y junto á las esquinas; y fortificólas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 10, 'Asimismo edificó torres en el desierto, y abrió muchas cisternas: porque tuvo muchos ganados, así en los valles como en las vegas; y viñas, y labranzas, así en los montes como en los llanos fértiles; porque era amigo de la agricultura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 11, 'Tuvo también Uzzías escuadrones de guerreros, los cuales salían á la guerra en ejército, según que estaban por lista hecha por mano de Jehiel escriba y de Maasías gobernador, y por mano de Hananías, uno de los príncipes del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 12, 'Todo el número de los jefes de familias, valientes y esforzados, era dos mil y seiscientos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 13, 'Y bajo la mano de éstos estaba el ejército de guerra, de trescientos siete mil y quinientos guerreros poderosos y fuertes para ayudar al rey contra los enemigos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 14, 'Y aprestóles Uzzías para todo el ejército, escudos, lanzas, almetes, coseletes, arcos, y hondas de tirar piedras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 15, 'E hizo en Jerusalem máquinas por industria de ingenieros, para que estuviesen en las torres y en los baluartes, para arrojar saetas y grandes piedras, y su fama se extendió lejos, porque se ayudó maravillosamente, hasta hacerse fuerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 16, 'Mas cuando fué fortificado, su corazón se enalteció hasta corromperse; porque se rebeló contra Jehová su Dios, entrando en el templo de Jehová para quemar sahumerios en el altar del perfume.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 17, 'Y entró tras él el sacerdote Azarías, y con él ochenta sacerdotes de Jehová, de los valientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 18, 'Y pusiéronse contra el rey Uzzías, y dijéronle: No á ti, oh Uzzías, el quemar perfume á Jehová, sino á los sacerdotes hijos de Aarón, que son consagrados para quemarlo: sal del santuario, por que has prevaricado, y no te será para gloria delante del Dios Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 19, 'Y airóse Uzzías, que tenía el perfume en la mano para quemarlo; y en esta su ira contra los sacerdotes, la lepra le salió en la frente delante de los sacerdotes en la casa de Jehová, junto al altar del perfume.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 20, 'Y miróle Azarías el sumo sacerdote, y todos los sacerdotes, y he aquí la lepra estaba en su frente; é hiciéronle salir apriesa de aquel lugar; y él también se dió priesa á salir, porque Jehová lo había herido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 21, 'Así el rey Uzzías fué leproso hasta el día de su muerte, y habitó en una casa apartada, leproso, por lo que había sido separado de la casa de Jehová; y Joatham su hijo tuvo cargo de la casa real, gobernando al pueblo de la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 22, 'Lo demás de los hechos de Uzzías, primeros y postreros, escribiólo Isaías profeta, hijo de Amós.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 26, 23, 'Y durmió Uzzías con sus padres, y sepultáronlo con sus padres en el campo de los sepulcros reales; porque dijeron: Leproso es. Y reinó Joatham su hijo en lugar suyo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 1, 'DE VEINTICINCO años era Joatham cuando comenzó á reinar, y dieciséis años reinó en Jerusalem. El nombre de su madre fué Jerusa, hija de Sadoc.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 2, 'E hizo lo recto en ojos de Jehová, conforme á todas las cosas que había hecho Uzzías su padre, salvo que no entró en el templo de Jehová. Y el pueblo falseaba aún.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 3, 'Edificó él la puerta mayor de la casa de Jehová, y en el muro de la fortaleza edificó mucho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 4, 'Además edificó ciudades en las montañas de Judá, y labró palacios y torres en los bosques.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 5, 'También tuvo él guerra con el rey de los hijos de Ammón, á los cuales venció; y diéronle los hijos de Ammón en aquel año cien talentos de plata, y diez mil coros de trigo, y diez mil de cebada. Esto le dieron los hijos de Ammón, y lo mismo en el segundo año, y en el tercero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 6, 'Así que Joatham fué fortificado, porque preparó sus caminos delante de Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 7, 'Lo demás de los hechos de Joatham, y todas sus guerras, y sus caminos, he aquí está escrito en el libro de los reyes de Israel y de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 8, 'Cuando comenzó á reinar era de veinticinco años, y dieciséis reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 27, 9, 'Y durmió Joatham con sus padres, y sepultáronlo en la ciudad de David; y reinó en su lugar Achâz su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 1, 'DE VEINTE años era Achâz cuando comenzó á reinar, y dieciséis años reinó en Jerusalem: mas no hizo lo recto en ojos de Jehová, como David su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 2, 'Antes anduvo en los caminos de los reyes de Israel, y además hizo imágenes de fundición á los Baales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 3, 'Quemó también perfume en el valle de los hijos de Hinnom, y quemó sus hijos por fuego, conforme á las abominaciones de las gentes que Jehová había echado delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 4, 'Asimismo sacrificó y quemó perfumes en los altos, y en los collados, y debajo de todo árbol espeso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 5, 'Por lo cual Jehová su Dios lo entregó en manos del rey de los Siros, los cuales le derrotaron, y cogieron de él una grande presa, que llevaron á Damasco. Fué también entregado en manos del rey de Israel, el cual lo batió con gran mortandad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 6, 'Porque Peca, hijo de Remalías mató en Judá en un día ciento y veinte mil, todos hombres valientes; por cuanto habían dejado á Jehová el Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 7, 'Asimismo Zichri, hombre poderoso de Ephraim, mató á Maasías hijo del rey, y á Azricam su mayordomo, y á Elcana, segundo después del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 8, 'Tomaron también cautivos los hijos de Israel de sus hermanos doscientos mil, mujeres, muchachos, y muchachas, á más de haber saqueado de ellos un gran despojo, el cual trajeron á Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 9, 'Había entonces allí un profeta de Jehová, que se llamaba Obed, el cual salió delante del ejército cuando entraba en Samaria, y díjoles: He aquí Jehová el Dios de vuestros padres, por el enojo contra Judá, los ha entregado en vuestras manos; y vosotros los habéis muerto con ira, que hasta el cielo ha llegado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 10, 'Y ahora habéis determinado sujetar á vosotros á Judá y á Jerusalem por siervos y siervas: mas ¿no habéis vosotros pecado contra Jehová vuestro Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 11, 'Oidme pues ahora, y volved á enviar los cautivos que habéis tomado de vuestros hermanos: porque Jehová está airado contra vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 12, 'Levantáronse entonces algunos varones de los principales de los hijos de Ephraim, Azarías hijo de Johanán, y Berechîas hijo de Mesillemoth, y Ezechîas hijo de Sallum, y Amasa hijo de Hadlai, contra los que venían de la guerra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 13, 'Y dijéronles: No metáis acá la cautividad; porque el pecado contra Jehová será sobre nosotros. Vosotros tratáis de añadir sobre nuestros pecados y sobre nuestras culpas, siendo asaz grande nuestro delito, y la ira del furor sobre Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 14, 'Entonces el ejército dejó los cautivos y la presa delante de los príncipes y de toda la multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 15, 'Y levantáronse los varones nombrados, y tomaron los cautivos, y vistieron del despojo á los que de ellos estaban desnudos; vistiéronlos y calzáronlos, y diéronles de comer y de beber, y ungiéronlos, y condujeron en asnos á todos los flacos, y lleváronlos hasta Jericó, ciudad de las palmas, cerca de sus hermanos; y ellos se volvieron á Samaria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 16, 'En aquel tiempo envió á pedir el rey Achâz á los reyes de Asiria que le ayudasen:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 17, 'Porque á más de esto, los Idumeos habían venido y herido á los de Judá, y habían llevado cautivos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 18, 'Asimismo los Filisteos se habían derramado por las ciudades de la llanura, y al mediodía de Judá, y habían tomado á Beth-semes, á Ajalón, Gederoth, y Sochô con sus aldeas, Timna también con sus aldeas, y Gimzo con sus aldeas; y habitaban en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 19, 'Porque Jehová había humillado á Judá por causa de Achâz rey de Israel: por cuanto él había desnudado á Judá, y rebeládose gravemente contra Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 20, 'Y vino contra él Tilgath-pilneser, rey de los Asirios: pues lo redujo á estrechez, y no lo fortificó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 21, 'Aunque despojó Achâz la casa de Jehová, y la casa real, y las de los príncipes, para dar al rey de los Asirios, con todo eso él no le ayudó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 22, 'Además el rey Achâz en el tiempo que aquél le apuraba, añadió prevaricación contra Jehová;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 23, 'Porque sacrificó á los dioses de Damasco que le habían herido, y dijo: Pues que los dioses de los reyes de Siria les ayudan, yo también sacrificaré á ellos para que me ayuden; bien que fueron éstos su ruina, y la de todo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 24, 'A más de eso recogió Achâz los vasos de la casa de Dios, y quebrólos, y cerró las puertas de la casa de Jehová, é hízose altares en Jerusalem en todos los rincones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 25, 'Hizo también altos en todas las ciudades de Judá, para quemar perfumes á los dioses ajenos, provocando así á ira á Jehová el Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 26, 'Lo demás de sus hechos, y todos sus caminos, primeros y postreros, he aquí ello está escrito en el libro de los reyes de Judá y de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 28, 27, 'Y durmió Achâz con sus padres, y sepultáronlo en la ciudad de Jerusalem: mas no le metieron en los sepulcros de los reyes de Israel; y reinó en su lugar Ezechîas su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 1, 'Y Ezechîas comenzó á reinar siendo de veinticinco años, y reinó veintinueve años en Jerusalem. El nombre de su madre fué Abía, hija de Zachârías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 2, 'E hizo lo recto en ojos de Jehová, conforme á todas las cosas que había hecho David su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 3, 'En el primer año de su reinado, en el mes primero, abrió las puertas de la casa de Jehová, y las reparó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 4, 'E hizo venir los sacerdotes y Levitas, y juntólos en la plaza oriental.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 5, 'Y díjoles: Oidme, Levitas, y santificaos ahora, y santificaréis la casa de Jehová el Dios de vuestros padres, y sacaréis del santuario la inmundicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 6, 'Porque nuestros padres se han rebelado, y han hecho lo malo en ojos de Jehová nuestro Dios; que le dejaron, y apartaron sus ojos del tabernáculo de Jehová, y le volvieron las espaldas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 7, 'Y aun cerraron las puertas del pórtico, y apagaron las lámparas; no quemaron perfume, ni sacrificaron holocausto en el santuario al Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 8, 'Por tanto la ira de Jehová ha venido sobre Judá y Jerusalem, y los ha entregado á turbación, y á execración y escarnio, como veis vosotros con vuestros ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 9, 'Y he aquí nuestros padres han caído á cuchillo, nuestros hijos y nuestras hijas y nuestras mujeres son cautivas por esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 10, 'Ahora pues, yo he determinado hacer alianza con Jehová el Dios de Israel, para que aparte de nosotros la ira de su furor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 11, 'Hijos míos, no os engañéis ahora, porque Jehová os ha escogido á vosotros para que estéis delante de él, y le sirváis, y seáis sus ministros, y le queméis perfume.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 12, 'Entonces los Levitas se levantaron, Mahath hijo de Amasai, y Joel hijo de Azarías, de los hijos de Coath; y de los hijos de Merari, Cis hijo de Abdi, y Azarías hijo de Jehaleleel; y de los hijos de Gersón, Joah hijo de Zimma, y Edén hijo de Joah;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 13, 'Y de los hijos de Elisaphán, Simri y Jehiel; y de los hijos de Asaph, Zachârías y Mathanías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 14, 'Y de los hijos de Hemán, Jehiel y Simi; y de los hijos de Jeduthún, Semeías y Uzziel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 15, 'Estos juntaron á sus hermanos, y santificáronse, y entraron, conforme al mandamiento del rey y las palabras de Jehová, para limpiar la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 16, 'Y entrando los sacerdotes dentro de la casa de Jehová para limpiarla, sacaron toda la inmundicia que hallaron en el templo de Jehová, al atrio de la casa de Jehová; la cual tomaron los Levitas, para sacarla fuera al torrente de Cedrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 17, 'Y comenzaron á santificar el primero del mes primero, y á los ocho del mismo mes vinieron al pórtico de Jehová: y santificaron la casa de Jehová en ocho días, y en el dieciséis del mes primero acabaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 18, 'Luego pasaron al rey Ezechîas y dijéronle: Ya hemos limpiado toda la casa de Jehová, el altar del holocausto, y todos sus instrumentos, y la mesa de la proposición con todos sus utensilios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 19, 'Asimismo hemos preparado y santificado todos los vasos que en su prevaricación había maltratado el rey Achâz, cuando reinaba: y he aquí están delante del altar de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 20, 'Y levantándose de mañana el rey Ezechîas reunió los principales de la ciudad, y subió á la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 21, 'Y presentaron siete novillos, siete carneros, siete corderos, y siete machos de cabrío, para expiación por el reino, por el santuario y por Judá. Y dijo á los sacerdotes hijos de Aarón, que los ofreciesen sobre el altar de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 22, 'Mataron pues los bueyes, y los sacerdotes tomaron la sangre, y esparciéronla sobre el altar; mataron luego los carneros, y esparcieron la sangre sobre el altar; asimismo mataron los corderos, y esparcieron la sangre sobre el altar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 23, 'Hicieron después llegar los machos cabríos de la expiación delante del rey y de la multitud, y pusieron sobre ellos sus manos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 24, 'Y los sacerdotes los mataron, y expiando esparcieron la sangre de ellos sobre el altar, para reconciliar á todo Israel: porque por todo Israel mandó el rey hacer el holocausto y la expiación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 25, 'Puso también Levitas en la casa de Jehová con címbalos, y salterios, y arpas, conforme al mandamiento de David, y de Gad vidente del rey, y de Nathán profeta: porque aquel mandamiento fué por mano de Jehová, por mano de sus profetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 26, 'Y los Levitas estaban con los instrumentos de David, y los sacerdotes con trompetas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 27, 'Entonces mandó Ezechîas sacrificar el holocausto en el altar; y al tiempo que comenzó el holocausto, comenzó también el cántico de Jehová, con las trompetas y los instrumentos de David rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 28, 'Y toda la multitud adoraba, y los cantores cantaban, y los trompetas sonaban las trompetas; todo hasta acabarse el holocausto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 29, 'Y como acabaron de ofrecer, inclinóse el rey, y todos los que con él estaban, y adoraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 30, 'Entonces el rey Ezechîas y los príncipes dijeron á los Levitas que alabasen á Jehová por las palabras de David y de Asaph vidente: y ellos alabaron con grande alegría, é inclinándose adoraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 31, 'Y respondiendo Ezechîas dijo: Vosotros os habéis consagrado ahora á Jehová; llegaos pues, y presentad sacrificios y alabanzas en la casa de Jehová. Y la multitud presentó sacrificios y alabanzas; y todo liberal de corazón, holocaustos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 32, 'Y fué el número de los holocaustos que trajo la congregación, setenta bueyes, cien carneros, doscientos corderos; todo para el holocausto de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 33, 'Y las ofrendas fueron seiscientos bueyes, y tres mil ovejas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 34, 'Mas los sacerdotes eran pocos, y no podían bastar á desollar los holocaustos; y así sus hermanos los Levitas les ayudaron hasta que acabaron la obra, y hasta que los sacerdotes se santificaron: porque los Levitas tuvieron mayor prontitud de corazón para santificarse, que los sacerdotes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 35, 'Así pues hubo gran multitud de holocaustos, con sebos de pacíficos, y libaciones de cada holocausto. Y quedó ordenado el servicio de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 29, 36, 'Y alegróse Ezechîas, y todo el pueblo, de que Dios hubiese preparado el pueblo; porque la cosa fué prestamente hecha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 1, 'ENVIO también Ezechîas por todo Israel y Judá, y escribió letras á Ephraim y Manasés, que viniesen á Jerusalem á la casa de Jehová, para celebrar la pascua á Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 2, 'Y había el rey tomado consejo con sus príncipes, y con toda la congregación en Jerusalem, para celebrar la pascua en el mes segundo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 3, 'Porque entonces no la podían celebrar, por cuanto no había suficientes sacerdotes santificados, ni el pueblo estaba junto en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 4, 'Esto agradó al rey y á toda la multitud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 5, 'Y determinaron hacer pasar pregón por todo Israel, desde Beer-seba hasta Dan, para que viniesen á celebrar la pascua á Jehová Dios de Israel, en Jerusalem: porque en mucho tiempo no la habían celebrado al modo que está escrito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 6, 'Fueron pues correos con letras de mano del rey y de sus príncipes por todo Israel y Judá, como el rey lo había mandado, y decían: Hijos de Israel, volveos á Jehová el Dios de Abraham, de Isaac, y de Israel, y él se volverá á las reliquias que os han quedado de la mano de los reyes de Asiria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 7, 'No seáis como vuestros padres y como vuestros hermanos, que se rebelaron contra Jehová el Dios de sus padres, y él los entregó á desolación, como vosotros veis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 8, 'No endurezcáis pues ahora vuestra cerviz como vuestros padres: dad la mano á Jehová, y venid á su santuario, el cual él ha santificado para siempre; y servid á Jehová vuestro Dios, y la ira de su furor se apartará de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 9, 'Porque si os volviereis á Jehová, vuestros hermanos y vuestros hijos hallarán misericordia delante de los que los tienen cautivos, y volverán á esta tierra: porque Jehová vuestro Dios es clemente y misericordioso, y no volverá de vosotros su rostro, si vosotros os volviereis á él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 10, 'Pasaron pues los correos de ciudad en ciudad por la tierra de Ephraim y Manasés, hasta Zabulón: mas se reían y burlaban de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 11, 'Con todo eso, algunos hombres de Aser, de Manasés, y de Zabulón, se humillaron, y vinieron á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 12, 'En Judá también fué la mano de Dios para darles un corazón para cumplir el mensaje del rey y de los príncipes, conforme á la palabra de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 13, 'Y juntóse en Jerusalem mucha gente para celebrar la solemnidad de los ázimos en el mes segundo; una vasta reunión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 14, 'Y levantándose, quitaron los altares que había en Jerusalem; quitaron también todos los altares de perfumes, y echáronlos en el torrente de Cedrón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 15, 'Entonces sacrificaron la pascua, á los catorce del mes segundo; y los sacerdotes y los Levitas se santificaron con vergüenza, y trajeron los holocaustos á la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 16, 'Y pusiéronse en su orden conforme á su costumbre, conforme á la ley de Moisés varón de Dios; los sacerdotes esparcían la sangre que recibían de manos de los Levitas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 17, 'Porque había muchos en la congregación que no estaban santificados, y por eso los Levitas sacrificaban la pascua por todos los que no se habían limpiado, para santificarlos á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 18, 'Porque una gran multitud del pueblo de Ephraim y Manasés, y de Issachâr y Zabulón, no se habían purificado, y comieron la pascua no conforme á lo que está escrito. Mas Ezechîas oró por ellos, diciendo: Jehová, que es bueno, sea propicio á todo aquel que ha apercibido su corazón para buscar á Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 19, 'A Jehová el Dios de sus padres, aunque no esté purificado según la purificación del santuario.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 20, 'Y oyó Jehová á Ezechîas, y sanó al pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 21, 'Así celebraron los hijos de Israel que se hallaron en Jerusalem, la solemnidad de los panes sin levadura por siete días con grande gozo: y alababan á Jehová todos los días los Levitas y los sacerdotes, cantando con instrumentos de fortaleza á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 22, 'Y habló Ezechîas al corazón de todos los Levitas que tenían buena inteligencia en el servicio de Jehová. Y comieron de lo sacrificado en la solemnidad por siete días, ofreciendo sacrificios pacíficos, y dando gracias á Jehová el Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 23, 'Y toda aquella multitud determinó que celebrasen otros siete días; y celebraron otros siete días con alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 24, 'Porque Ezechîas rey de Judá había dado á la multitud mil novillos y siete mil ovejas; y también los príncipes dieron al pueblo mil novillos y diez mil ovejas: y muchos sacerdotes se santificaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 25, 'Alegróse pues toda la congregación de Judá, como también los sacerdotes y Levitas, y toda la multitud que había venido de Israel; asimismo los extranjeros que habían venido de la tierra de Israel, y los que habitaban en Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 26, 'E hiciéronse grandes alegrías en Jerusalem: porque desde los días de Salomón hijo de David rey de Israel, no había habido cosa tal en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 30, 27, 'Levantándose después los sacerdotes y Levitas, bendijeron al pueblo: y la voz de ellos fué oída, y su oración llegó á la habitación de su santuario, al cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 1, 'HECHAS todas estas cosas, todos los de Israel que se habían hallado allí, salieron por las ciudades de Judá, y quebraron las estatuas y destruyeron los bosques, y derribaron los altos y los altares por todo Judá y Benjamín, y también en Ephraim y Manasés, hasta acabarlo todo. Después volviéronse todos los hijos de Israel, cada uno á su posesión y á sus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 2, 'Y arregló Ezechîas los repartimientos de los sacerdotes y de los Levitas conforme á sus órdenes, cada uno según su oficio, los sacerdotes y los Levitas para el holocausto y pacíficos, para que ministrasen, para que confesasen y alabasen á las puertas de los reales de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 3, 'La contribución del rey de su hacienda, era holocaustos á mañana y tarde, y holocaustos para los sábados, nuevas lunas, y solemnidades, como está escrito en la ley de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 4, 'Mandó también al pueblo que habitaba en Jerusalem, que diesen la porción á los sacerdotes y Levitas, para que se esforzasen en la ley de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 5, 'Y como este edicto fué divulgado, los hijos de Israel dieron muchas primicias de grano, vino, aceite, miel, y de todos los frutos de la tierra: trajeron asimismo los diezmos de todas las cosas en abundancia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 6, 'También los hijos de Israel y de Judá, que habitaban en las ciudades de Judá, dieron del mismo modo los diezmos de las vacas y de las ovejas: y trajeron los diezmos de lo santificado, de las cosas que habían prometido á Jehová su Dios, y pusiéronlos por montones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 7, 'En el mes tercero comenzaron á fundar aquellos montones, y en el mes séptimo acabaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 8, 'Y Ezechîas y los príncipes vinieron á ver los montones, y bendijeron á Jehová, y á su pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 9, 'Y preguntó Ezechîas á los sacerdotes y á los Levitas acerca de los montones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 10, 'Y respondióle Azarías, sumo sacerdote, de la casa de Sadoc, y dijo: Desde que comenzaron á traer la ofrenda á la casa de Jehová, hemos comido y saciádonos, y nos ha sobrado mucho: porque Jehová ha bendecido su pueblo, y ha quedado esta muchedumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 11, 'Entonces mandó Ezechîas que preparasen cámaras en la casa de Jehová; y preparáronlas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 12, 'Y metieron las primicias y diezmos y las cosas consagradas, fielmente; y dieron cargo de ello á Chônanías Levita, el principal, y Simi su hermano fué el segundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 13, 'Y Jehiel, Azazías, Nahath, Asael, Jerimoth, Josabad, Eliel, Ismachîas, Mahaath, y Benaías, fueron sobrestantes bajo la mano de Chônanías y de Simi su hermano, por mandamiento del rey Ezechîas y de Azarías, príncipe de la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 14, 'Y Coré hijo de Imna Levita, portero al oriente, tenía cargo de las limosnas de Dios, y de las ofrendas de Jehová que se daban, y de todo lo que se santificaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 15, 'Y á su mano estaba Edén, Benjamín, Jeshua, Semaías, Amarías, y Sechânías, en las ciudades de los sacerdotes, para dar con fidelidad á sus hermanos sus partes conforme á sus órdenes, así al mayor como al menor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 16, 'A más de los varones anotados por sus linajes, de tres años arriba, á todos los que entraban en la casa de Jehová, su porción diaria por su ministerio, según sus oficios y clases;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 17, 'También á los que eran contados entre los sacerdotes por las familias de sus padres, y á los Levitas de edad de veinte años arriba, conforme á sus oficios y órdenes;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 18, 'Asimismo á los de su generación con todos sus niños, y sus mujeres, y sus hijos é hijas, á toda la familia; porque con fidelidad se consagraban á las cosas santas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 19, 'Del mismo modo en orden á los hijos de Aarón, sacerdotes, que estaban en los ejidos de sus ciudades, por todas las ciudades, los varones nombrados tenían cargo de dar sus porciones á todos los varones de los sacerdotes, y á todo el linaje de los Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 20, 'De esta manera hizo Ezechîas en todo Judá: y ejecutó lo bueno, recto, y verdadero, delante de Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 31, 21, 'En todo cuanto comenzó en el servicio de la casa de Dios, y en la ley y mandamientos, buscó á su Dios, é hízolo de todo corazón, y fué prosperado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 1, 'DESPUÉS de estas cosas y de esta fidelidad, vino Sennachêrib rey de los Asirios, entró en Judá, y asentó campo contra las ciudades fuertes, y determinó de entrar en ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 2, 'Viendo pues Ezechîas la venida de Sennachêrib, y su aspecto de combatir á Jerusalem,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 3, 'Tuvo su consejo con sus príncipes y con sus valerosos, sobre cegar las fuentes de las aguas que estaban fuera de la ciudad; y ellos le apoyaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 4, 'Juntóse pues mucho pueblo, y cegaron todas las fuentes, y el arroyo que derrama por en medio del territorio, diciendo: ¿Por qué han de hallar los reyes de Asiria muchas aguas cuando vinieren?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 5, 'Alentóse así Ezechîas, y edificó todos los muros caídos, é hizo alzar las torres, y otro muro por de fuera: fortificó además á Millo en la ciudad de David, é hizo muchas espadas y paveses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 6, 'Y puso capitanes de guerra sobre el pueblo, é hízolos reunir así en la plaza de la puerta de la ciudad, y hablóles al corazón de ellos, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 7, 'Esforzaos y confortaos; no temáis, ni hayáis miedo del rey de Asiria, ni de toda su multitud que con él viene; porque más son con nosotros que con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 8, 'Con él es el brazo de carne, mas con nosotros Jehová nuestro Dios para ayudarnos, y pelear nuestras batallas. Y afirmóse el pueblo sobre las palabras de Ezechîas rey de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 9, 'Después de esto Sennachêrib rey de los Asirios, estando él sobre Lachîs y con él toda su potencia, envió sus siervos á Jerusalem, para decir á Ezechîas rey de Judá, y á todos los de Judá que estaban en Jerusalem:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 10, 'Así ha dicho Sennachêrib rey de los Asirios: ¿En quién confiáis vosotros para estar cercados en Jerusalem?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 11, '¿No os engaña Ezechîas para entregaros á muerte, á hambre, y á sed, diciendo: Jehová nuestro Dios nos librará de la mano del rey de Asiria?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 12, '¿No es Ezechîas el que ha quitado sus altos y sus altares, y dijo á Judá y á Jerusalem: Delante de este solo altar adoraréis, y sobre él quemaréis perfume?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 13, '¿No habéis sabido lo que yo y mis padres hemos hecho á todos los pueblos de la tierra? ¿Pudieron los dioses de las gentes de las tierras librar su tierra de mi mano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 14, '¿Qué dios hubo de todos los dioses de aquellas gentes que destruyeron mis padres, que pudiese salvar su pueblo de mis manos? ¿Por qué podrá vuestro Dios libraros de mi mano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 15, 'Ahora pues, no os engañe Ezechîas, ni os persuada tal cosa, ni le creáis; que si ningún dios de todas aquellas naciones y reinos pudo librar su pueblo de mis manos, y de las manos de mis padres, ¿cuánto menos vuestro Dios os podrá librar de mi mano?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 16, 'Y otras cosas hablaron sus siervos contra el Dios Jehová, y contra su siervo Ezechîas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 17, 'Además de todo esto escribió letras en que blasfemaba á Jehová el Dios de Israel, y hablaba contra él, diciendo: Como los dioses de las gentes de los países no pudieron librar su pueblo de mis manos, tampoco el Dios de Ezechîas librará al suyo de mis manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 18, 'Y clamaron á gran voz en judaico al pueblo de Jerusalem que estaba en los muros, para espantarlos y ponerles temor, para tomar la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 19, 'Y hablaron contra el Dios de Jerusalem, como contra los dioses de los pueblos de la tierra, obra de manos de hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 20, 'Mas el rey Ezechîas, y el profeta Isaías hijo de Amós, oraron por esto, y clamaron al cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 21, 'Y Jehová envió un ángel, el cual hirió á todo valiente y esforzado, y á los jefes y capitanes en el campo del rey de Asiria. Volvióse por tanto con vergüenza de rostro á su tierra; y entrando en el templo de su dios, allí lo mataron á cuchillo los que habían salido de sus entrañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 22, 'Así salvó Jehová á Ezechîas y á los moradores de Jerusalem de las manos de Sennachêrib rey de Asiria, y de las manos de todos: y preservólos de todas partes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 23, 'Y muchos trajeron ofrenda á Jehová á Jerusalem, y á Ezechîas rey de Judá, ricos dones; y fué muy grande delante de todas las gentes después de esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 24, 'En aquel tiempo Ezechîas enfermó de muerte: y oró á Jehová, el cual le respondió, y dióle una señal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 25, 'Mas Ezechîas no pagó conforme al bien que le había sido hecho: antes se enalteció su corazón, y fué la ira contra él, y contra Judá y Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 26, 'Empero Ezechîas, después de haberse engreído su corazón, se humilló, él y los moradores de Jerusalem; y no vino sobre ellos la ira de Jehová en los días de Ezechîas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 27, 'Y tuvo Ezechîas riquezas y gloria mucha en gran manera; é hízose de tesoros de plata y oro, de piedras preciosas, de aromas, de escudos, y de todas alhajas de desear;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 28, 'Asimismo depósitos para las rentas del grano, del vino, y aceite; establos para toda suerte de bestias, y majadas para los ganados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 29, 'Hízose también ciudades, y hatos de ovejas y de vacas en gran copia; porque Dios le había dado mucha hacienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 30, 'Este Ezechîas tapó los manaderos de las aguas de Gihón la de arriba, y encaminólas abajo al occidente de la ciudad de David. Y fué prosperado Ezechîas en todo lo que hizo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 31, 'Empero en lo de los embajadores de los príncipes de Babilonia, que enviaron á él para saber del prodigio que había acaecido en aquella tierra, Dios lo dejó, para probarle, para hacer conocer todo lo que estaba en su corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 32, 'Lo demás de los hechos de Ezechîas, y de sus misericordias, he aquí todo está escrito en la profecía de Isaías profeta, hijo de Amós, en el libro de los reyes de Judá y de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 32, 33, 'Y durmió Ezechîas con sus padres, y sepultáronlo en los más insignes sepulcros de los hijos de David, honrándole en su muerte todo Judá y los de Jerusalem: y reinó en su lugar Manasés su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 1, 'DE DOCE años era Manasés cuando comenzó á reinar, y cincuenta y cinco años reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 2, 'Mas hizo lo malo en ojos de Jehová, conforme á las abominaciones de las gentes que había echado Jehová delante de los hijos de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 3, 'Porque él reedificó los altos que Ezechîas su padre había derribado, y levantó altares á los Baales, é hizo bosques, y adoró á todo el ejército de los cielos, y á él sirvió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 4, 'Edificó también altares en la casa de Jehová, de la cual había dicho Jehová: En Jerusalem será mi nombre perpetuamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 5, 'Edificó asimismo altares á todo el ejército de los cielos en los dos atrios de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 6, 'Y pasó sus hijos por fuego en el valle de los hijos de Hinnom; y miraba en los tiempos, miraba en agüeros, era dado á adivinaciones, y consultaba pythones y encantadores: subió de punto en hacer lo malo en ojos de Jehová, para irritarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 7, 'A más de esto puso una imagen de fundición, que hizo, en la casa de Dios, de la cual había dicho Dios á David y á Salomón su hijo: En esta casa y en Jerusalem, la cual yo elegí sobre todas las tribus de Israel, pondré mi nombre para siempre:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 8, 'Y nunca más quitaré el pie de Israel de la tierra que yo entregué á vuestros padres, á condición que guarden y hagan todas las cosas que yo les he mandado, toda la ley, estatutos, y ordenanzas, por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 9, 'Hizo pues Manasés desviarse á Judá y á los moradores de Jerusalem, para hacer más mal que las gentes que Jehová destruyó delante de los hijos de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 10, 'Y habló Jehová á Manasés y á su pueblo, mas ellos no escucharon:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 11, '(33-10) por lo cual Jehová trajo contra ellos los generales del ejército del rey de los Asirios, los cuales aprisionaron con grillos á Manasés, y atado con cadenas lleváronlo á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 12, '(33-11) Mas luego que fué puesto en angustias, oró ante Jehová su Dios, humillado grandemente en la presencia del Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 13, '(33-12) Y habiendo á él orado, fué atendido; pues que oyó su oración, y volviólo á Jerusalem, á su reino. Entonces conoció Manasés que Jehová era Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 14, '(33-13) Después de esto edificó el muro de afuera de la ciudad de David, al occidente de Gihón, en el valle, á la entrada de la puerta del pescado, y cercó á Ophel, y alzólo muy alto; y puso capitanes de ejército en todas las ciudades fuertes por Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 15, '(33-14) Asimismo quitó los dioses ajenos, y el ídolo de la casa de Jehová, y todos los altares que había edificado en el monte de la casa de Jehová y en Jerusalem, y echólos fuera de la ciudad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 16, '(33-15) Reparó luego el altar de Jehová, y sacrificó sobre él sacrificios pacíficos y de alabanza; y mandó á Judá que sirviesen á Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 17, '(33-16) Empero el pueblo aun sacrificaba en los altos, bien que á Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 18, '(33-17) Lo demás de los hechos de Manasés, y su oración á su Dios, y las palabras de los videntes que le hablaron en nombre de Jehová el Dios de Israel, he aquí todo está escrito en los hechos de los reyes de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 19, '(33-18) Su oración también, y cómo fué oído, todos sus pecados, y su prevaricación, los lugares donde edificó altos y había puesto bosques é ídolos antes que se humillase, he aquí estas cosas están escritas en las palabras de los videntes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 20, '(33-19) Y durmió Manasés con sus padres, y sepultáronlo en su casa: y reinó en su lugar Amón su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 21, '(33-20) De veinte y dos años era Amón cuando comenzo á reinar, y dos años reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 22, '(33-21) E hizo lo malo en ojos de Jehová, como había hecho Manasés su padre: porque á todos los ídolos que su padre Manasés había hecho, sacrificó y sirvió Amón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 23, '(33-22) Mas nunca se humilló delante de Jehová, como se humilló Manasés su padre: antes aumentó el pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 24, '(33-23) Y conspiraron contra él sus siervos, y matáronlo en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 33, 25, '(33-24) Mas el pueblo de la tierra hirió á todos los que habían conspirado contra el rey Amón; y el pueblo de la tierra puso por rey en su lugar á Josías su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 1, 'DE OCHO años era Josías cuando comenzó á reinar, y treinta y un años reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 2, 'Este hizo lo recto en ojos de Jehová, y anduvo en los caminos de David su padre, sin apartarse á la diestra ni á la siniestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 3, 'A los ocho años de su reinado, siendo aún muchacho, comenzó á buscar al Dios de David su padre; y á los doce años comenzó á limpiar á Judá y á Jerusalem de los altos, bosques, esculturas, é imágenes de fundición.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 4, 'Y derribaron delante de él los altares de los Baales, é hizo pedazos las imágenes del sol, que estaban puestas encima; despedazó también los bosques, y las esculturas y estatuas de fundición, y desmenuzólas, y esparció el polvo sobre los sepulcros de los que las habían sacrificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 5, 'Quemó además los huesos de los sacerdotes sobre sus altares, y limpió á Judá y á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 6, 'Lo mismo hizo en las ciudades de Manasés, Ephraim, y Simeón, hasta en Nephtalí, con sus lugares asolados alrededor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 7, 'Y como hubo derribado los altares y los bosques, y quebrado y desmenuzado las esculturas, y destruído todos los ídolos por toda la tierra de Israel, volvióse á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 8, 'A los dieciocho años de su reinado, después de haber limpiado la tierra, y la casa, envió á Saphán hijo de Asalías, y á Maasías gobernador de la ciudad, y á Joah hijo de Joachâz, canciller, para que reparasen la casa de Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 9, 'Los cuales vinieron á Hilcías, gran sacerdote, y dieron el dinero que había sido metido en la casa de Jehová, que los Levitas que guardaban la puerta habían recogido de mano de Manasés y de Ephraim y de todas las reliquias de Israel, y de todo Judá y Benjamín, habiéndose después vuelto á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 10, 'Y entregáronlo en mano de los que hacían la obra, que eran sobrestantes en la casa de Jehová; los cuales lo daban á los que hacían la obra y trabajaban en la casa de Jehová, para reparar y restaurar el templo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 11, 'Daban asimismo á los oficiales y albañiles para que comprasen piedra de cantería, y madera para las trabazones, y para entabladura de las casas, las cuales habían destruído los reyes de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 12, 'Y estos hombres procedían con fidelidad en la obra: y eran sus gobernadores Jahath y Abdías, Levitas de los hijos de Merari; y Zachârías y Mesullam de los hijos de Coath, para que activasen la obra; y de los Levitas, todos los entendidos en instrumentos de música.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 13, 'También velaban sobre los ganapanes, y eran sobrestantes de los que se ocupaban en cualquier clase de obra; y de los Levitas había esribas, gobernadores, y porteros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 14, 'Y al sacar el dinero que había sido metido en la casa de Jehová, Hilcías el sacerdote halló el libro de la ley de Jehová dada por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 15, 'Y dando cuenta Hilcías, dijo á Saphán escriba: Yo he hallado el libro de la ley en la casa de Jehová. Y dió Hilcías el libro á Saphán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 16, 'Y Saphán lo llevó al rey, y contóle el negocio, diciendo: Tus siervos han cumplido todo lo que les fué dado á cargo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 17, 'Han reunido el dinero que se halló en la casa de Jehová, y lo han entregado en mano de los comisionados, y en mano de los que hacen la obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 18, 'A más de esto, declaró Saphán escriba al rey, diciendo: El sacerdote Hilcías me dió un libro. Y leyó Saphán en él delante del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 19, 'Y luego que el rey oyó las palabras de la ley, rasgó sus vestidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 20, 'Y mandó á Hilcías y á Ahicam hijo de Saphán, y á Abdón hijo de Michâ, y á Saphán escriba, y á Asaía siervo del rey, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 21, 'Andad, y consultad á Jehová de mí, y de las reliquias de Israel y de Judá, acerca de las palabras del libro que se ha hallado; porque grande es el furor de Jehová que ha caído sobre nosotros, por cuanto nuestros padres no guardaron la palabra de Jehová, para hacer conforme á todo lo que está escrito en este libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 22, 'Entonces Hilcías y los del rey fueron á Hulda profetisa, mujer de Sallum, hijo de Tikvath, hijo de Hasra, guarda de las vestimentas, la cual moraba en Jerusalem en la casa de la doctrina; y dijéronle las palabras dichas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 23, 'Y ella respondió: Jehová el Dios de Israel ha dicho así: Decid al varón que os ha enviado á mí, que así ha dicho Jehová:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 24, 'He aquí yo traigo mal sobre este lugar, y sobre los moradores de él, y todas las maldiciones que están escritas en el libro que leyeron delante del rey de Judá:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 25, 'Por cuanto me han dejado, y han sacrificado á dioses ajenos, provocándome á ira en todas las obras de sus manos; por tanto mi furor destilará sobre este lugar, y no se apagará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 26, 'Mas al rey de Judá, que os ha enviado á consultar á Jehová, así le diréis: Jehová el Dios de Israel ha dicho así: Por cuanto oiste las palabras del libro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 27, 'Y tu corazón se enterneció, y te humillaste delante de Dios al oir sus palabras sobre este lugar, y sobre sus moradores, y te humillaste delante de mí, y rasgaste tus vestidos, y lloraste en mi presencia, yo también te he oído, dice Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 28, 'He aquí que yo te recogeré con tus padres, y serás recogido en tus sepulcros en paz, y tus ojos no verán todo el mal que yo traigo sobre este lugar, y sobre los moradores de él. Y ellos refirieron al rey la respuesta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 29, 'Entonces el rey envió y juntó todos los ancianos de Judá y de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 30, 'Y subió el rey á la casa de Jehová, y con él todos los varones de Judá, y los moradores de Jerusalem, y los sacerdotes, y los Levitas, y todo el pueblo desde el mayor hasta el más pequeño; y leyó á oídos de ellos todas las palabras del libro del pacto que había sido hallado en la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 31, 'Y estando el rey en pie en su sitio, hizo alianza delante de Jehová de caminar en pos de Jehová, y de guardar sus mandamientos, sus testimonios, y sus estatutos, de todo su corazón y de toda su alma, poniendo por obra las palabras del pacto que estaban escritas en aquel libro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 32, 'E hizo que se obligaran á ello todos los que estaban en Jerusalem y en Benjamín: y los moradores de Jerusalem hicieron conforme al pacto de Dios, del Dios de sus padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 34, 33, 'Y quitó Josías todas las abominaciones de todas las tierras de los hijos de Israel, é hizo á todos los que se hallaron en Israel que sirviesen á Jehová su Dios. No se apartaron de en pos de Jehová el Dios de sus padres, todo el tiempo que él vivió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 1, 'Y JOSIAS hizo pascua á Jehová en Jerusalem, y sacrificaron la pascua á los catorce del mes primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 2, 'Y puso á los sacerdotes en sus empleos, y confirmólos en el ministerio de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 3, 'Y dijo á los Levitas que enseñaban á todo Israel, y que estaban dedicados á Jehová: Poned el arca del santuario en la casa que edificó Salomón hijo de David, rey de Israel, para que no la carguéis más sobre los hombros. Ahora serviréis á Jehová vuestro Dios, y á su pueblo Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 4, 'Apercibío según las familias de vuestros padres, por vuestros órdenes, conforme á la prescripción de David rey de Israel, y de Salomón su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 5, 'Estad en el santuario según la distribución de las familias de vuestros hermanos los hijos del pueblo, y según la división de la familia de los Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 6, 'Sacrificad luego la pascua: y después de santificaros, apercibid á vuestros hermanos, para que hagan conforme á la palabra de Jehová dada por mano de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 7, 'Y ofreció el rey Josías á los del pueblo ovejas, corderos, y cabritos de los rebaños, en número de treinta mil, y tres mil bueyes, todo para la pascua, para todos los que se hallaron presentes: esto de la hacienda del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 8, 'También sus príncipes ofrecieron con liberalidad al pueblo, y á los sacerdotes y Levitas. Hilcías, Zachârías y Jehiel, príncipes de la casa de Dios, dieron á los sacerdotes para hacer la pascua dos mil seiscientas ovejas, y trescientos bueyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 9, 'Asimismo Chônanías, y Semeías y Nathanael sus hermanos, y Hasabías, Jehiel, y Josabad, príncipes de los Levitas, dieron á los Levitas para los sacrificios de la pascua cinco mil ovejas, y quinientos bueyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 10, 'Aprestado así el servicio, los sacerdotes se colocaron en sus puestos, y asimismo los Levitas en sus órdenes, conforme al mandamiento del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 11, 'Y sacrificaron la pascua; y esparcían los sacerdotes la sangre tomada de mano de los Levitas, y los Levitas desollaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 12, 'Tomaron luego del holocausto, para dar conforme á los repartimientos por las familias de los del pueblo, á fin de que ofreciesen á Jehová, según está escrito en el libro de Moisés: y asimismo tomaron de los bueyes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 13, 'Y asaron la pascua al fuego según la costumbre: mas lo que había sido santificado lo cocieron en ollas, en calderos, y calderas, y repartiéron lo prestamente á todo el pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 14, 'Y después aderezaron para sí y para los sacerdotes; porque los sacerdotes, hijos de Aarón, estuvieron ocupados hasta la noche en el sacrificio de los holocaustos y de los sebos; por tanto, los Levitas aderezaron para sí, y para los sacerdotes hijos de Aarón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 15, 'Asimismo los cantores hijos de Asaph estaban en su puesto, conforme al mandamiento de David, de Asaph y de Hemán, y de Jeduthún vidente del rey; también los porteros estaban á cada puerta; y no era menester que se apartasen de su ministerio, porque sus hermanos los Levitas aparejaban para ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 16, 'Así fué aprestado todo el servicio de Jehová en aquel día, para hacer la pascua, y sacrificar los holocaustos sobre el altar de Jehová, conforme al mandamiento del rey Josías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 17, 'Y los hijos de Israel que se hallaron allí, hicieron la pascua en aquel tiempo, y la solemnidad de los panes sin levadura, por siete días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 18, 'Nunca tal pascua fué hecha en Israel desde los días de Samuel el profeta; ni ningún rey de Israel hizo pascua tal como la que hizo el rey Josías, y los sacerdotes y Levitas, y todo Judá é Israel, los que se hallaron allí, juntamente con los moradores de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 19, 'Esta pascua fué celebrada en el año dieciocho del rey Josías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 20, 'Después de todas estas cosas, luego de haber Josías preparado la casa, Nechâo rey de Egipto subió á hacer guerra en Carchêmis junto á Eufrates; y salió Josías contra él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 21, 'Y él le envió embajadores, diciendo: ¿Qué tenemos yo y tú, rey de Judá? Yo no vengo contra ti hoy, sino contra la casa que me hace guerra: y Dios dijo que me apresurase. Déjate de meterte con Dios, que es conmigo, no te destruya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 22, 'Mas Josías no volvió su rostro de él, antes disfrazóse para darle batalla, y no atendió á las palabras de Nechâo, que eran de boca de Dios; y vino á darle la batalla en el campo de Megiddo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 23, 'Y los archeros tiraron al rey Josías flechas; y dijo el rey á sus siervos: Quitadme de aquí, porque estoy herido gravemente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 24, 'Entonces sus siervos lo quitaron de aquel carro, y pusiéronle en otro segundo carro que tenía, y lleváronle á Jerusalem, y murió; y sepultáronle en los sepulcros de sus padres. Y todo Judá y Jerusalem hizo duelo por Josías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 25, 'Y endechó Jeremías por Josías, y todos los cantores y cantoras recitan sus lamentaciones sobre Josías hasta hoy; y las dieron por norma para endechar en Israel, las cuales están escritas en las Lamentaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 26, 'Lo demás de los hechos de Josías, y sus piadosas obras, conforme á lo que está escrito en la ley de Jehová,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 35, 27, 'Y sus hechos, primeros y postreros, he aquí está escrito en el libro de los reyes de Israel y de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 1, 'ENTONCES el pueblo de la tierra tomó á Joachâz hijo de Josías, é hiciéronle rey en lugar de su padre en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 2, 'De veinte y tres años era Joachâz cuando comenzó á reinar, y tres meses reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 3, 'Y el rey de Egipto lo quitó de Jerusalem, y condenó la tierra en cien talentos de plata y uno de oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 4, 'Y constituyó el rey de Egipto á su hermano Eliacim por rey sobre Judá y Jerusalem, y mudóle el nombre en Joacim; y á Joachâz su hermano tomó Nechâo, y llevólo á Egipto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 5, 'Cuando comenzó á reinar Joacim era de veinte y cinco años, y reinó once años en Jerusalem: é hizo lo malo en ojos de Jehová su Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 6, 'Y subió contra él Nabucodonosor rey de Babilonia, y atado con cadenas lo llevó á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 7, 'También llevó Nabucodonosor á Babilonia de los vasos de la casa de Jehová, y púsolos en su templo en Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 8, 'Lo demás de los hechos de Joacim, y las abominaciones que hizo, y lo que en él se halló, he aquí está escrito en el libro de los reyes de Israel y de Judá: y reinó en su lugar Joachîn su hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 9, 'De ocho años era Joachîn cuando comenzó á reinar, y reinó tres meses y diez días en Jerusalem: é hizo lo malo en ojos de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 10, 'A la vuelta del año el rey Nabucodonosor envió, é hízolo llevar á Babilonia juntamente con los vasos preciosos de la casa de Jehová; y constituyó á Sedecías su hermano por rey sobre Judá y Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 11, 'De veinte y un años era Sedecías cuando comenzó á reinar, y once años reinó en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 12, 'E hizo lo malo en ojos de Jehová su Dios, y no se humilló delante de Jeremías profeta, que le hablaba de parte de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 13, 'Rebelóse asimismo contra Nabucodonosor, al cual había jurado por Dios; y endureció su cerviz, y obstinó su corazón, para no volverse á Jehová el Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 14, 'Y también todos los príncipes de los sacerdotes, y el pueblo, aumentaron la prevaricación, siguiendo todas las abominaciones de las gentes, y contaminando la casa de Jehová, la cual él había santificado en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 15, 'Y Jehová el Dios de sus padres envió á ellos por mano de sus mensajeros, levantándose de mañana y enviando: porque él tenía misericordia de su pueblo, y de su habitación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 16, 'Mas ellos hacían escarnio de los mensajeros de Dios, y menospreciaban sus palabras, burlándose de sus profetas, hasta que subió el furor de Jehová contra su pueblo, y que no hubo remedio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 17, 'Por lo cual trajo contra ellos al rey de los Caldeos, que mató á cuchillo sus mancebos en la casa de su santuario, sin perdonar joven, ni doncella, ni viejo, ni decrépito; todos los entregó en sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 18, 'Asimismo todos los vasos de la casa de Dios, grandes y chicos, los tesoros de la casa de Jehová, y los tesoros del rey y de sus príncipes, todo lo llevó á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 19, 'Y quemaron la casa de Dios, y rompieron el muro de Jerusalem, y consumieron al fuego todos sus palacios, y destruyeron todos sus vasos deseables.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 20, 'Los que quedaron del cuchillo, pasáronlos á Babilonia; y fueron siervos de él y de sus hijos, hasta que vino el reino de los Persas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 21, 'Para que se cumpliese la palabra de Jehová por la boca de Jeremías, hasta que la tierra hubo gozado sus sábados: porque todo el tiempo de su asolamiento reposó, hasta que los setenta años fueron cumplidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 22, 'Mas al primer año de Ciro rey de los Persas, para que se cumpliese la palabra de Jehová por boca de Jeremías, Jehová excitó el espíritu de Ciro rey de los Persas, el cual hizo pasar pregón por todo su reino, y también por escrito, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CH', '2 Crónicas', 36, 23, 'Así dice Ciro rey de los Persas: Jehová, el Dios de los cielos, me ha dado todos los reinos de la tierra; y él me ha encargado que le edifique casa en Jerusalem, que es en Judá. ¿Quién de vosotros hay de todo su pueblo? Jehová su Dios sea con él, y suba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 1, 'Y EN el primer año de Ciro rey de Persia, para que se cumpliese la palabra de Jehová por boca de Jeremías, excitó Jehová el espíritu de Ciro rey de Persia, el cual hizo pasar pregón por todo su reino, y también por escrito, diciendo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 2, 'Así ha dicho Ciro rey de Persia: Jehová Dios de los cielos me ha dado todos los reinos de la tierra, y me ha mandado que le edifique casa en Jerusalem, que está en Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 3, '¿Quién hay entre vosotros de todo su pueblo? Sea Dios con él, y suba á Jerusalem que está en Judá, y edifique la casa á Jehová Dios de Israel, (él es el Dios,) la cual está en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 4, 'Y á cualquiera que hubiere quedado de todos los lugares donde peregrinare, los hombres de su lugar le ayuden con plata, y oro, y hacienda, y con bestias; con dones voluntarios para la casa de Dios, la cuál está en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 5, 'Entonces se levantaron los cabezas de las familias de Judá y de Benjamín, y los sacerdotes y Levitas, todos aquellos cuyo espíritu despertó Dios para subir á edificar la casa de Jehová, la cual está en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 6, 'Y todos los que estaban en sus alrededores confortaron las manos de ellos con vasos de plata y de oro, con hacienda y bestias, y con cosas preciosas, á más de lo que se ofreció voluntariamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 7, 'Y el rey Ciro sacó los vasos de la casa de Jehová, que Nabucodonosor había traspasado de Jerusalem, y puesto en la casa de sus dioses.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 8, 'Sacólos pues Ciro rey de Persia, por mano de Mitrídates tesorero, el cual los dió por cuenta á Sesbassar príncipe de Judá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 9, 'Y esta es la cuenta de ellos: treinta tazones de oro, mil tazones de plata, veinte y nueve cuchillos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 10, 'Treinta tazas de oro, cuatrocientas y diez otras tazas de plata, y mil otros vasos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 1, 11, 'Todos los vasos de oro y de plata, cinco mil y cuatrocientos. Todos los hizo llevar Sesbassar con los que subieron del cautiverio de Babilonia á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 1, 'Y ESTOS son los hijos de la provincia que subieron de la cautividad, de la transmigración que Nabucodonosor rey de Babilonia hizo traspasar á Babilonia, y que volvieron á Jerusalem y á Judá, cada uno á su ciudad:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 2, 'Los cuales vinieron con Zorobabel, Jesuá, Nehemías, Seraías, Reelaías, Mardochêo, Bilsán, Mispar, Bigvai, Rehum y Baana. La cuenta de los varones del pueblo de Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 3, 'Los hijos de Paros, dos mil ciento setenta y dos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 4, 'Los hijos de Sephatías, trescientos setenta y dos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 5, 'Los hijos de Ara, setecientos setenta y cinco;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 6, 'Los hijos de Pahath-moab, de los hijos de Josué y de Joab, dos mil ochocientos y doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 7, 'Los hijos de Elam, mil doscientos cincuenta y cuatro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 8, 'Los hijos de Zattu, novecientos cuarenta y cinco;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 9, 'Los hijos de Zachâi, setecientos y sesenta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 10, 'Los hijos de Bani, seiscientos cuarenta y dos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 11, 'Los hijos de Bebai, seiscientos veinte y tres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 12, 'Los hijos de Azgad, mil doscientos veinte y dos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 13, 'Los hijos de Adonicam, seiscientos sesenta y seis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 14, 'Los hijos de Bigvai, dos mil cincuenta y seis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 15, 'Los hijos de Adin, cuatrocientos cincuenta y cuatro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 16, 'Los hijos de Ater, de Ezechîas, noventa y ocho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 17, 'Los hijos de Besai, trescientos veinte y tres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 18, 'Los hijos de Jora, ciento y doce;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 19, 'Los hijos de Hasum, doscientos veinte y tres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 20, 'Los hijos de Gibbar, noventa y cinco;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 21, 'Los hijos de Beth-lehem, ciento veinte y tres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 22, 'Los varones de Nethopha, cincuenta y seis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 23, 'Los varones de Anathoth, ciento veinte y ocho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 24, 'Los hijos de Asmeveth, cuarenta y dos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 25, 'Los hijos de Chîriath-jearim, Cephira, y Beeroth, setecientos cuarenta y tres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 26, 'Los hijos de Rama y Gabaa, seiscientos veinte y uno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 27, 'Los varones de Michmas, ciento veinte y dos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 28, 'Los varones de Beth-el y Hai, doscientos veinte y tres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 29, 'Los hijos de Nebo, cincuenta y dos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 30, 'Los hijos de Magbis, ciento cincuenta y seis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 31, 'Los hijos del otro Elam, mil doscientos cincuenta y cuatro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 32, 'Los hijos de Harim, trescientos y veinte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 33, 'Los hijos de Lod, Hadid, y Ono, setecientos veinte y cinco;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 34, 'Los hijos de de Jericó, trescientos cuarenta y cinco;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 35, 'Los hijos de Senaa, tres mil seiscientos y treinta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 36, 'Los sacerdotes: los hijos de Jedaía, de la casa de Jesuá, novecientos setenta y tres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 37, 'Los hijos de Immer, mil cincuenta y dos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 38, 'Los hijos de Pashur, mil doscientos cuarenta y siete;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 39, 'Los hijos de Harim, mil diez y siete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 40, 'Los Levitas: los hijos de Jesuá y de Cadmiel, de los hijos de Odovías, setenta y cuatro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 41, 'Los cantores: los hijos de Asaph, ciento veinte y ocho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 42, 'Los hijos de los porteros: los hijos de Sallum, los hijos de Ater, los hijos de Talmón, los hijos de Accub, los hijos de Hatita, los hijos de Sobai; en todos, ciento treinta y nueve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 43, 'Los Nethineos: los hijos de Siha, los hijos de Hasupha, los hijos de Thabaoth,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 44, 'Los hijos de Chêros, los hijos de Siaa, los hijos de Phadón;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 45, 'Los hijos de Lebana, los hijos de Hagaba, los hijos de Accub;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 46, 'Los hijos de Hagab, los hijos de Samlai, los hijos de Hanán;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 47, 'los hijos de Giddel, los hijos de Gaher, los hijos de Reaía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 48, 'Los hijos de Resin, los hijos de Necoda, los hijos de Gazam;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 49, 'Los hijos de Uzza, los hijos de Phasea, los hijos de Besai;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 50, 'Los hijos de Asena, los hijos de Meunim, los hijos de Nephusim;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 51, 'Los hijos de Bacbuc, los hijos de Hacusa, los hijos de Harhur;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 52, 'Los hijos de Basluth, los hijos de Mehida, los hijos de Harsa;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 53, 'Los hijos de Barcos, los hijos de Sisera, los hijos de Thema;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 54, 'Los hijos de Nesía, los hijos de Hatipha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 55, 'Los hijos de los siervos de Salomón: los hijos de Sotai, los hijos de Sophereth, los hijos de Peruda;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 56, 'Los hijos de Jaala, lo hijos de Darcón, los hijos de Giddel;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 57, 'Los hijos de Sephatías, los hijos de Hatil, los hijos de Phochêreth-hassebaim, los hijos de Ami.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 58, 'Todos los Nethineos, é hijos de los siervos de Salomón, trescientos noventa y dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 59, 'Y estos fueron los que subieron de Tel-mela, Tel-harsa, Chêrub, Addan, é Immer, los cuales no pudieron mostrar la casa de sus padres, ni su linaje, si eran de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 60, 'Los hijos de Delaía, los hijos de Tobías, los hijos de Necoda, seiscientos cincuenta y dos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 61, 'Y de los hijos de los sacerdotes: los hijos de Abaía, los hijos de Cos, los hijos de Barzillai, el cual tomó mujer de las hijas de Barzillai Galaadita, y fué llamado del nombre de ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 62, 'Estos buscaron su registro de genealogías, y no fué hallado; y fueron echados del sacerdocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 63, 'Y el Tirsatha les dijo que no comiesen de las cosas más santas, hasta que hubiese sacerdote con Urim y Thummim.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 64, 'Toda la congregación, unida como un solo hombre, era de cuarenta y dos mil trescientos y sesenta,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 65, 'Sin sus siervos y siervas, los cuales eran siete mil trescientos treinta y siete: y tenían doscientos cantores y cantoras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 66, 'Sus caballos eran setecientos treinta y seis; sus mulos, doscientos cuarenta y cinco;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 67, 'Sus camellos, cuatrocientos treinta y cinco; asnos, seis mil setecientos y veinte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 68, 'Y algunos de los cabezas de los padres, cuando vinieron á la casa de Jehová la cual estaba en Jerusalem, ofrecieron voluntariamente para la casa de Dios, para levantarla en su asiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 69, 'Según sus fuerzas dieron al tesorero de la obra sesenta y un mil dracmas de oro, y cinco mil libras de plata, y cien túnicas sacerdotales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 2, 70, 'Y habitaron los sacerdotes, y los Levitas, y los del pueblo, y los cantores, y los porteros y los Nethineos, en sus ciudades; y todo Israel en sus ciudades.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 1, 'Y LLEGADO el mes séptimo, y ya los hijos de Israel en las ciudades, juntóse el pueblo como un solo hombre en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 2, 'Entonces se levantó Jesuá hijo de Josadec, y sus hermanos los sacerdotes, y Zorobabel hijo de Sealthiel, y sus hermanos, y edificaron el altar del Dios de Israel, para ofrecer sobre él holocaustos como está escrito en la ley de Moisés varón de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 3, 'Y asentaron el altar sobre sus basas, bien que tenían miedo de los pueblos de las tierras, y ofrecieron sobre él holocaustos á Jehová, holocaustos á la mañana y á la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 4, 'Hicieron asimismo la solemnidad de las cabañas, como está escrito, y holocaustos cada día por cuenta, conforme al rito, cada cosa en su día;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 5, 'Y á más de esto, el holocausto continuo, y las nuevas lunas, y todas las fiestas santificadas de Jehová, y todo sacrificio espontáneo, toda ofrenda voluntaria á Jehova.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 6, 'Desde el primer día del mes séptimo comenzaron á ofrecer holocaustos á Jehová; mas el templo de Jehová no estaba aún fundado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 7, 'Y dieron dinero á los carpinteros y oficiales; asimismo comida y bebida y aceite á los Sidonios y Tirios, para que trajesen madera de cedro del Líbano á la mar de Joppe, conforme á la voluntad de Ciro rey de Persia acerca de esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 8, 'Y en el año segundo de su venida á la casa de Dios en Jerusalem, en el mes segundo, comenzaron Zorobabel hijo de Sealthiel, y Jesuá hijo de Josadec, y los otros sus hermanos, los sacerdotes y los Levitas, y todos los que habían venido de la cautividad á Jerusalem; y pusieron á los Levitas de veinte años arriba para que tuviesen cargo de la obra de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 9, 'Jesuá también, sus hijos y sus hermanos, Cadmiel y sus hijos, hijos de Judá, como un solo hombre asistían para dar priesa á los que hacían la obra en la casa de Dios: los hijos de Henadad, sus hijos y sus hermanos, Levitas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 10, 'Y cuando los albañiles del templo de Jehová echaban los cimientos, pusieron á los sacerdotes vestidos de sus ropas, con trompetas, y á Levitas hijos de Asaph con címbalos, para que alabasen á Jehová, según ordenanza de David rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 11, 'Y cantaban, alabando y confesando á Jehová, y decían: Porque es bueno, porque para siempre es su misericordia sobre Israel. Y todo el pueblo aclamaba con grande júbilo, alabando á Jehová, porque á la casa de Jehová se echaba el cimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 12, 'Y muchos de los sacerdotes y de los Levitas y de los cabezas de los padres, ancianos que habían visto la casa primera, viendo fundar esta casa, lloraban en alta voz, mientras muchos otros daban grandes gritos de alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 3, 13, 'Y no podía discernir el pueblo el clamor de los gritos de alegría, de la voz del lloro del pueblo: porque clamaba el pueblo con grande júbilo, y oíase el ruido hasta de lejos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 1, 'Y OYENDO los enemigos de Judá y de Benjamín, que los venidos de la cautividad edificaban el templo de Jehová Dios de Israel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 2, 'Llegáronse á Zorobabel, y á los cabezas de los padres, y dijéronles: Edificaremos con vosotros, porque como vosotros buscaremos á vuestro Dios, y á él sacrificamos desde los días de Esar-haddón rey de Asiria, que nos hizo subir aquí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 3, 'Y dijóles Zorobabel, y Jesuá, y los demás cabezas de los padres de Israel: No nos conviene edificar con vosotros casa á nuestro Dios, sino que nosotros solos la edificaremos á Jehová Dios de Israel, como nos mandó el rey Ciro, rey de Persia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 4, 'Mas el pueblo de la tierra debilitaba las manos del pueblo de Judá, y los arredraban de edificar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 5, 'Cohecharon además contra ellos consejeros para disipar su consejo, todo el tiempo de Ciro rey de Persia, y hasta el reinado de Darío rey de Persia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 6, 'Y en el reinado de Assuero, en el principio de su reinado, escribieron acusaciones contra los moradores de Judá y de Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 7, 'Y en días de Artajerjes, Bislam, Mitrídates, Tabeel, y los demás sus compañeros, escribieron á Artajerjes rey de Persia; y la escritura de la carta estaba hecha en siriaco, y declarada en siriaco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 8, 'Rehum canciller, y Simsai secretario, escribieron una carta contra Jerusalem al rey Artajerjes, como se sigue.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 9, 'Entonces Rehum canciller, y Simsai secretario, y los demás sus compañeros, los Dineos, y los Apharsathachêos, Thepharleos, Apharseos, los Erchûeos, los Babilonios, Susaschêos, Dieveos, y Elamitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 10, 'Y los demás pueblos que el grande y glorioso Asnappar trasportó, é hizo habitar en las ciudades de Samaria, y los demás de la otra parte del río, etcétera, escribieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 11, 'Este es el traslado de la carta que enviaron: Al rey Artajerjes: Tus siervos de otra la parte del río, etcétera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 12, 'Sea notorio al rey, que los Judíos que subieron de tí á nosotros, vinieron á Jerusalem; y edifican la ciudad rebelde y mala, y han erigido los muros; y compuesto los fundamentos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 13, 'Ahora, notorio sea al rey, que si aquella ciudad fuere reedificada, y los muros fueren establecidos, el tributo, pecho, y rentas no darán, y el catastro de lo reyes será menoscabado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 14, 'Ya pues que estamos mantenidos de palacio, no nos es justo ver el menosprecio del rey: hemos enviado por tanto, y hécho lo saber al rey,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 15, 'Para que busque en el libro de las historias de nuestros padres; y hallarás en el libro de las historias, y sabrás que esta ciudad es ciudad rebelde, y perjudicial á los reyes y á las provincias, y que de tiempo antiguo forman en medio de ella rebeliones; por lo que esta ciudad fué destruída.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 16, 'Hacemos saber al rey, que si esta ciudad fuere edificada, y erigidos sus muros, la parte allá del río no será tuya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 17, 'El rey envió esta respuesta á Rehum canciller, y á Simsai secretario, y á los demás sus compañeros que habitan en Samaria, y á los demás de la parte allá del río: Paz, etc.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 18, 'La carta que nos enviasteis claramente fué leída delante de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 19, 'Y por mí fué dado mandamiento, y buscaron; y hallaron que aquella ciudad de tiempo antiguo se levanta contra los reyes, y se rebela, y se forma en ella sedición:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 20, 'Y que reyes fuertes hubo en Jerusalem, quienes señorearon en todo lo que está á la parte allá del río; y que tributo, y pecho, y rentas se les daba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 21, 'Ahora pues dad orden que cesen aquellos hombres, y no sea esa ciudad edificada, hasta que por mí sea dado mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 22, 'Y mirad bien que no hagáis error en esto: ¿por qué habrá de crecer el daño para perjuicio de los reyes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 23, 'Entonces, cuando el traslado de la carta del rey Artajerjes fué leído delante de Rehum, y de Simsai secretario, y sus compañeros, fueron prestamente á Jerusalem á los Judíos, é hiciéronles cesar con poder y fuerza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 4, 24, 'Cesó entonces la obra de la casa de Dios, la cual estaba en Jerusalem: y cesó hasta el año segundo del reinado de Darío rey de Persia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 1, 'Y PROFETIZARON Haggeo profeta, y Zacarías hijo de Iddo, profetas, á los Judíos que estaba en Judá y en Jerusalem yendo en nombre del Dios de Israel á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 2, 'Entonces se levantaron Zorobabel hijo de Sealthiel, y Jesuá hijo de Josadec; y comenzaron á edificar la casa de Dios que estaba en Jerusalem; y con ellos los profetas de Dios que les ayudaban.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 3, 'En aquel tiempo vino á ellos Tatnai, capitán de la parte allá del río, y Setharboznai y sus compañeros, y dijéronles así: ¿Quién os dió mandamiento para edificar esta casa, y restablecer estos muros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 4, 'Entonces les dijimos en orden á esto cuáles eran los nombres de los varones que edificaban este edificio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 5, 'Mas los ojos de su Dios fueron sobre los ancianos de los Judíos, y no les hicieron cesar hasta que el negocio viniese á Darío: y entonces respondieron por carta sobre esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 6, 'Traslado de la carta que Tatnai, capitán de la parte allá del río, y Sethar-boznai, y sus compañeros los Apharsachêos, que estaban á la parte allá del río, enviaron al rey Darío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 7, 'Enviáronle carta, y de esta manera estaba escrito en ella. Al rey Darío toda paz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 8, 'Sea notorio al rey, que fuimos á la provincia de Judea, á la casa del gran Dios, la cual se edifica de piedra de mármol; y los maderos son puestos en las paredes, y la obra se hace apriesa, y prospera en sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 9, 'Entonces preguntamos á los ancianos, diciéndoles así: ¿Quién os dió mandameinto para edificar esta casa, y para restablecer estos muros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 10, 'Y también les preguntamos sus nombres para hacértelo saber, para escribir te los nombres de los varones que estaban por cabezas de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 11, 'Y respondiéronnos, diciendo así: Nosotros somos siervos de Dios del cielo y de la tierra, y reedificamos la casa que ya muchos años antes había sido edificada, la cual edificó y fundó el gran rey de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 12, 'Mas después que nuestros padres ensañaron al Dios de los cielos, él los entregó en mano de Nabucodonosor rey de Babilonia, Caldeo, el cual destruyó esta casa, é hizo trasportar el pueblo á Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 13, 'Empero el primer año de Ciro rey de Babilonia, el mismo rey Ciro dió mandamiento para que esta casa de Dios fuese edificada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 14, 'Y también los vasos de oro y de plata de la casa de Dios, que Nabucodonosor había sacado del templo que estaba en Jerusalem, y los había metido en el templo de Babilonia, el rey Ciro los sacó del templo de Babilonia, y fueron entregados á Sesbassar, al cual había puesto por gobernador;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 15, 'Y le dijo: Toma estos vasos, ve y ponlos en el templo que está en Jerusalem; y la casa de Dios sea edificada en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 16, 'Entonces este Sesbassar vino, y puso los fundamentos de la casa de Dios que estaba en Jerusalem, y desde entonces hasta ahora se edifica, y aun no está acabada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 5, 17, 'Y ahora, si al rey parece bien, búsquese en la casa de los tesoros del rey que está allí en Babilonia, si es así que por el rey Ciro había sido dado mandamiento para edificar esta casa de Dios en Jerusalem, y envíenos á decir la voluntad del rey sobre esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 1, 'ENTONCES el rey Darío dió mandamiento, y buscaron en la casa de los libros, donde guardaban los tesoros allí en Babilonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 2, 'Y fué hallado en Achmetta, en el palacio que está en la provincia de Media, un libro, dentro del cual estaba escrito así: Memoria:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 3, 'En el año primero del rey Ciro, el mismo rey Ciro dió mandamiento acerca de la casa de Dios que estaba en Jerusalem, que fuese la casa edificada para lugar en que sacrifiquen sacrificios, y que sus paredes fuesen cubiertas; su altura de sesenta codos, y de sesenta codos su anchura;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 4, 'Los órdenes, tres de piedra de mármol, y un orden de madera nueva y que el gasto sea dado de la casa del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 5, 'Y también los vasos de oro y de plata de la casa de Dios, que Nabucodonosor sacó del templo que estaba en Jerusalem y los pasó á Babilonia, sean devueltos y vayan al templo que está en Jerusalem, á su lugar, y sean puestos en la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 6, 'Ahora pues, Tatnai, jefe del lado allá del río, Sethar-boznai, y sus compañeros los Apharsachêos que estáis á la otra parte del río, apartaos de ahí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 7, 'Dejad la obra de la casa de este Dios al principal de los Judíos, y á sus ancianos, para que edifiquen la casa de este Dios en su lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 8, 'Y por mí es dado mandamiento de lo que habéis de hacer con los ancianos de estos Judíos, para edificar la casa de este Dios: que de la hacienda del rey, que tiene del tributo de la parte allá del río, los gastos sean dados luego á aquellos varones, para que no cesen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 9, 'Y lo que fuere necesario, becerros y carneros y corderos, para holucaustos al Dios del cielo, trigo, sal, vino y aceite, conforme á lo que dijeren los sacerdotes que están en Jerusalem, déseles cada un día sin obstáculo alguno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 10, 'Para que ofrezcan olores de holganza al Dios del cielo, y oren por la vida del rey y por sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 11, 'También es dado por mí mandamiento, que cualquiera que mudare este decreto, sea derribado un madero de su casa, y enhiesto, sea colgado en él: y su casa sea hecha muladar por esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 12, 'Y el Dios que hizo habitar allí su nombre, destruya todo rey y pueblo que pusiere su mano para mudar ó destruir esta casa de Dios, la cual está en Jerusalem. Yo Darío puse el decreto: sea hecho prestamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 13, 'Entonces Tatnai, gobernador del otro lado del río, y Sethar-boznai, y sus compañeros, hicieron prestamente según el rey Darío había enviado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 14, 'Y los ancianos de los Judíos edificaban y prosperaban, conforme á la profecía de Haggeo profeta, y de Zacarías hijo de Iddo. Edificaron pues, y acabaron, por el mandamiento del Dios de Israel, y por el mandamiento de Ciro, y de Darío, y de Artajerjes rey de Persia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 15, 'Y esta casa fué acabada al tercer día del mes de Adar, que era el sexto año del reinado del rey Darío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 16, 'Y los hijos de Israel, los sacerdotes y los Levitas, y los demás que habían venido de la trasportación, hicieron la dedicación de esta casa de Dios con gozo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 17, 'Y ofrecieron en la dedicación de esta casa de Dios cien becerros, doscientos carneros, cuatrocientos corderos; y machos de cabrío en expiación por todo Israel, doce, conforme al número de las tribus de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 18, 'Y pusieron á los sacerdotes en sus clases, y á los Levitas en sus divisiones, sobre la obra de Dios que está en Jerusalem, conforme á lo escrito en el libro de Moisés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 19, 'Y los de la transmigración hicieron la pascua á los catorce del mes primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 20, 'Porque los sacerdotes y los Levitas se habían purificado á una; todos fueron limpios: y sacrificaron la pascua por todos los de la transmigración, y por sus hermanos los sacerdotes, y por sí mismos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 21, 'Y comieron los hijos de Israel que habían vuelto de la transmigración, y todos los que se habían apartado á ellos de la inmundicia de las gentes de la tierra, para buscar á Jehová Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 6, 22, 'Y celebraron la solemnidad de los panes ázimos siete días con regocijo, por cuanto Jehová los había alegrado, y convertido el corazón del rey de Asiria á ellos, para esforzar sus manos en la obra de la casa de Dios, del Dios de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 1, 'PASADAS estas cosas, en el reinado de Artajerjes rey de Persia, Esdras, hijo de Seraías, hijo de Azarías, hijo de Hilcías,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 2, 'Hijo de Sallum, hijo de Sadoc, hijo de Achîtob,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 3, 'Hijo de Amarías, hijo de Azarías, hijo de Meraioth,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 4, 'Hijo de Zeraías, hijo de Uzzi, hijo de Bucci,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 5, 'Hijo de Abisue, hijo de Phinees, hijo de Eleazar, hijo de Aarón, primer sacerdote:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 6, 'Este Esdras subió de Banilonia, el cual era escriba diligente en la ley de Moisés, que Jehová Dios de Israel había dado; y concedióle el rey, según la mano de Jehová su Dios sobre él, todo lo que pidió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 7, 'Y subieron con él á Jerusalem de los hijos de Israel, y de los sacerdotes, y Levitas, y cantores, y porteros, y Nethineos, en el séptimo año del rey Artajerjes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 8, 'Y llegó á Jerusalem en el mes quinto, el año séptimo del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 9, 'Porque el día primero del primer mes fué el principio de la partida de Babilonia, y al primero del mes quinto llegó á Jerusalem, según la buena mano de su Dios sobre él');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 10, 'Porque Esdras había preparado su corazón para inquirir la ley de Jehová, y para hacer y enseñar á Israel mandamientos y juicios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 11, 'Y este es el traslado de la carta que dió el rey Artajerjes á Esdras, sacerdote escriba, escriba de las palabras mandadas de Jehová, y de sus estatutos á Israel:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 12, 'Artajerjes, rey de los reyes, á Esdras sacerdote, escriba perfecto de la ley del Dios del cielo: Salud, etc.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 13, 'Por mí es dado mandamiento, que cualquiera que quisiere en mi reino, del pueblo de Israel y de sus sacerdotes y Levitas, ir contigo á Jerusalem, vaya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 14, 'Porque de parte del rey y de sus siete consultores eres enviado á visitar á Judea y á Jerusalem, conforme á la ley de tu Dios que está en tu mano;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 15, 'Y á llevar la plata y el oro que el rey y sus consultores voluntariamente ofrecen al Dios de Israel, cuya morada está en Jerusalem;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 16, 'Y toda la plata y el oro que hallares en toda la provincia de Babilonia, con las ofrendas voluntarias del pueblo y de los sacerdotes, que de su voluntad ofrecieren para la casa de su Dios que está en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 17, 'Comprarás pues prestamente con esta plata becerros, carneros, corderos, con sus presentes y sus libaciones, y los ofrecerás sobre el altar de la casa de vuestro Dios que está en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 18, 'Y lo que á ti y á tus hermanos pluguiere hacer de la otra plata y oro, hacedlo conforme á la voluntad de vuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 19, 'Y los vasos que te son entregados para el servicio de la casa de tu Dios, los restituirás delante de Dios en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 20, 'Y lo demás necesario para la casa de tu Dios que te fuere menester dar, daráslo de la casa de los tesoros del rey.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 21, 'Y por mí el rey Artajerjes es dado mandamiento á todos los tesoreros que están al otro lado del río, que todo lo que os demandare Esdras sacerdote, escriba de la ley del Dios del cielo, concédase le luego,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 22, 'Hasta cien talentos de plata, y hasta cien coros de trigo, y hasta cien batos de vino, y hasta cien batos de aceite; y sal sin tasa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 23, 'Todo lo que es mandado por el Dios del cielo, sea hecho prestamente para la casa del Dios del cielo: pues, ¿por qué habría de ser su ira contra el reino del rey y de sus hijos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 24, 'Y á vosotros os hacemos saber, que á todos los sacerdotes y Levitas, cantores, porteros, Nethineos y ministros de la casa de Dios, ninguno pueda imponerles tributo, ó pecho, ó renta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 25, 'Y tú, Esdras, conforme á la sabiduría de tu Dios que tienes, pon jueces y gobernadores, que gobiernen á todo el pueblo que está del otro lado del río, á todos los que tienen noticia de las leyes de tu Dios; y al que no la tuviere le enseñaréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 26, 'Y cualquiera que no hiciere la ley de tu Dios, y la ley del rey, prestamente sea juzgado, ó á muerte, ó á dasarraigo, ó á pena de la hacienda, ó á prisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 27, 'Bendito Jehová, Dios de nuestros padres, que puso tal cosa en el corazón del rey, para honrar la casa de Jehová que está en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 7, 28, 'E inclinó hacia mí su misericordia delante del rey y de sus consultores, y de todos los príncipes poderosos del rey. Y yo, confortado según la mano de mi Dios sobre mí, junté los principales de Israel para que subiesen conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 1, 'Y ESTOS son los cabezas de sus familias, y genealogía de aquellos que subieron conmigo de Babilonia, reinando el rey Artajerjes:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 2, 'De los hijos de Phinees, Gersón; de los hijos de Ithamar, Daniel; de los hijos de David, Hattus;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 3, 'De los hijos de Sechânías y de los hijos de Pharos, Zacarías, y con él, en la línea de varones, ciento y cincuenta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 4, 'De los hijos de Pahath-moab, Elioenai, hijo de Zarahi, y con él doscientos varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 5, 'De los hijos de Sechânías, el hijo de Jahaziel, y con él trescientos varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 6, 'De los hijos de Adín, Ebed, hijo de Jonathán, y con él cincuenta varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 7, 'De los hijos de Elam, Isaía, hijo de Athalías, y con él setenta varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 8, 'Y de los hijos de Sephatías, Zebadías, hijo de Michâel, y con él ochenta varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 9, 'De los hijos de Joab, Obadías, hijo de Jehiel, y con él doscientos diez y ocho varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 10, 'Y de los hijos de Solomith, el hijo de Josiphías, y con él ciento y sesenta varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 11, 'Y de los hijos de Bebai, Zacarías, hijo de Bebai, y con él veintiocho varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 12, 'Y de los hijos de Azgad, Johanán, hijo de Catán, y con él ciento y diez varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 13, 'Y de los hijos de Adonicam, los postreros, cuyos nombres son estos, Eliphelet, Jeiel, y Semaías, y con ellos sesenta varones;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 14, 'Y de los hijos de Bigvai, Utai y Zabud, y con ellos sesenta varones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 15, 'Y juntélos junto al río que viene á Ahava, y reposamos allí tres días: y habiendo buscado entre el pueblo y entre los sacerdotes, no hallé allí de los hijos de Leví.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 16, 'Entonces despaché á Eliezer, y á Ariel, y á Semaías, y á Elnathán, y á Jarib, y á Elnathán, y á Nathán, y á Zacarías, y á Mesullam, principales; asimismo á Joiarib y á Elnathán, hombres doctos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 17, 'Y enviélos á Iddo, jefe en el lugar de Casipia, y puse en boca de ellos las palabras que habían de hablar á Iddo, y á sus hermanos los Nethineos en el lugar de Casipia, para que nos trajesen ministros para la casa de nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 18, 'Y trajéronnos, según la buena mano de nuestro Dios sobre nosotros, un varón entendido de los hijos de Mahalí, hijo de Leví, hijo de Israel; y á Serabías con sus hijos y sus hermanos, dieciocho;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 19, 'Y á Hasabías, y con él á Isaía de los hijos de Merari, á sus hermanos y á sus hijos, veinte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 20, 'Y de los Nethineos, á quienes David con los príncipes puso para el ministerio de los Levitas, doscientos y veinte Nethineos: todos los cuales fueron declarados por sus nombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 21, 'Y publiqué ayuno allí junto al río de Ahava, para afligirnos delante de nuestro Dios, para solicitar de él camino derecho para nosotros, y para nuestros niños, y para toda nuestra hacienda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 22, 'Porque tuve vergüenza de pedir al rey tropa y gente de á caballo que nos defendiesen del enemigo en el camino: porque habíamos hablado al rey, diciendo: La mano de nuestro Dios es para bien sobre todos los que le buscan; mas su fortaleza y su furor sobre todos los que le dejan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 23, 'Ayunamos pues, y pedimos á nuestro Dios sobre esto, y él nos fué propicio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 24, 'Aparté luego doce de los principales de los sacerdotes, á Serebías y á Hasabías, y con ellos diez de sus hermanos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 25, 'Y peséles la plata, y el oro, y los vasos, la ofrenda que para la casa de nuestro Dios habían ofrecido el rey, y sus consultores, y sus príncipes, todos los que se hallaron en Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 26, 'Pesé pues en manos de ellos seiscientos y cincuenta talentos de plata, y vasos de plata por cien talentos, y cien talentos de oro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 27, 'Además veinte tazones de oro, de mil dracmas; y dos vasos de metal limpio muy bueno, preciados como el oro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 28, 'Y díjeles: Vosotros sois consagrados á Jehová, y santos los vasos; y la plata y el oro ofrenda voluntaria á Jehová, Dios de nuestros padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 29, 'Velad, y guardadlos, hasta que los peséis delante de los príncipes de los sacerdotes y Levitas, y de los jefes de los padres de Israel en Jerusalem, en las cámaras de la casa de Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 30, 'Los sacerdotes pues y Levitas recibieron el peso de la plata y del oro y de los vasos, para traerlo á Jerusalem á la casa de nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 31, 'Y partimos del río de Ahava el doce del mes primero, para ir á Jerusalem: y la mano de nuestro Dios fué sobre nosotros, el cual nos libró de mano de enemigo y de asechador en el camino.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 32, 'Y llegamos á Jerusalem, y reposamos allí tres días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 33, 'Al cuarto día fué luego pesada la plata, y el oro, y los vasos, en la casa de nuestro Dios, por mano de Meremoth hijo de Urías sacerdote, y con él Eleazar hijo de Phinees; y con ellos Jozabad hijo de Jesuá, y Noadías hijo de Binnui, Levitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 34, 'Por cuenta y por peso todo: y se apuntó todo aquel peso en aquel tiempo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 35, 'Los que habían venido de la cautividad, los hijos de la transmigración, ofrecieron holocaustos al Dios de Israel, doce becerros por todo Israel, noventa y seis carneros, setenta y siete corderos, doce machos cabríos por expiación: todo el holocausto á Jehová.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 8, 36, 'Y dieron los despachos del rey á sus gobernadores y capitanes del otro lado del río, los cuales favorecieron al pueblo y á la casa de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 1, 'Y ACABADAS estas cosas, los príncipes se llegaron á mí, diciendo: El pueblo de Israel, y los sacerdotes y levitas, no se han apartado de los pueblos de las tierras, de los Cananeos, Hetheos, Pherezeos, Jebuseos, Ammonitas, y Moabitas, Egipcios, y Amorrheos, haciendo conforme á sus abominaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 2, 'Porque han tomado de sus hijas para sí y para sus hijos, y la simiente santa ha sido mezclada con los pueblos de las tierras; y la mano de los príncipes y de los gobernadores ha sido la primera en esta prevaricación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 3, 'Lo cual oyendo yo, rasgué mi vestido y mi manto, y arranqué de los cabellos de mi cabeza y de mi barba, y sentéme atónito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 4, 'Y juntáronse á mí todos los temerosos de las palabras del Dios de Israel, á causa de la prevaricación de los de la transmigración; mas yo estuve sentado atónito hasta el sacrificio de la tarde.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 5, 'Y al sacrificio de la tarde levantéme de mi aflicción; y habiendo rasgado mi vestido y mi manto, postréme de rodillas, y extendí mis palmas á Jehová mi Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 6, 'Y dije: Dios mío, confuso y avergonzado estoy para levantar, oh Dios mío, mi rostro á ti: porque nuestras iniquidades se han multiplicado sobre nuestra cabeza, y nuestros delitos han crecido hasta el cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 7, 'Desde los días de nuestros padres hasta este día estamos en grande culpa; y por nuestras iniquidades nosotros, nuestros reyes, y nuestros sacerdotes, hemos sido entregados en manos de los reyes de las tierras, á cuchillo, á cautiverio, y á robo, y á confusión de rostro, como hoy día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 8, 'Y ahora como por un breve momento fué la misericordia de Jehová nuestro Dios, para hacer que nos quedase un resto libre, y para darnos estaca en el lugar de su santuario, á fin de alumbrar nuestros ojos nuestro Dios, y darnos una poca de vida en nuestra servidumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 9, 'Porque siervos éramos: mas en nuestra servidumbre no nos desamparó nuestro Dios, antes inclinó sobre nosotros misericordia delante de los reyes de Persia, para que se nos diese vida para alzar la casa de nuestro Dios, y para hacer restaurar sus asolamientos, y para darnos vallado en Judá y en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 10, 'Mas ahora, ¿qué diremos, oh Dios nuestro, después de esto? porque nosotros hemos dejado tus mandamientos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 11, 'Los cuales prescribiste por mano de tus siervos los profetas, diciendo: La tierra á la cual entráis para poseerla, tierra inmunda es á causa de la inmundicia de los pueblos de aquellas regiones, por las abominaciones de que la han henchido de uno á otro extremo con su inmundicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 12, 'Ahora pues, no daréis vuestras hijas á los hijos de ellos, ni sus hijas tomaréis para vuestros hijos, ni procuraréis su paz ni su bien para siempre; para que seáis corroborados, y comáis el bien de la tierra, y la dejéis por heredad á vuestros hijos para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 13, 'Mas después de todo lo que nos ha sobrevenido á causa de nuestras malas obras, y á causa de nuestro grande delito, ya que tú, Dios nuestro, estorbaste que fuésemos oprimidos bajo de nuestras iniquidades, y nos diste este tal efugio;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 14, '¿Hemos de volver á infringir tus mandamientos, y á emparentar con los pueblos de estas abominaciones? ¿No te ensañarías contra nosotros hasta consumirnos, sin que quedara resto ni escapatoria?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 9, 15, 'Jehová, Dios de Israel, tú eres justo: pues que hemos quedado algunossalvos, como este día, henos aquí delante de ti en nuestros delitos; porque no es posible subsistir en tu presencia á causa de esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 1, 'Y ORANDO Esdras y confesando, llorando y postrándose delante de la casa de Dios, juntóse á él una muy grande multitud de Israel, hombres y mujeres y niños; y lloraba el pueblo con gran llanto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 2, 'Entonces respondió Sechânías hijo de Jehiel, de los hijos Elam, y dijo á Esdras: Nosotros hemos prevaricado contra nuestro Dios, pues tomamos mujeres extranjeras de los pueblos de la tierra: mas hay aún esperanza para Israel sobre esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 3, 'Ahora pues hagamos pacto con nuestro Dios, que echaremos todas las mujeres y los nacidos de ellas, según el consejo del Señor, y de los que temen el mandamiento de nuestro Dios: y hágase conforme á la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 4, 'Levántate, porque á ti toca el negocio, y nosotros seremos contigo; esfuérzate, y ponlo por obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 5, 'Entonces se levantó Esdras, y juramentó á los príncipes de los sacerdotes y de los Levitas, y á todo Israel, que harían conforme á esto; y ellos juraron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 6, 'Levantóse luego Esdras de delante la casa de Dios, y fuése á la cámara de Johanán hijo de Eliasib: é ido allá, no comió pan ni bebió agua, porque se entristeció sobre la prevaricación de los de la transmigración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 7, 'É hicieron pasar pregón por Judá y por Jerusalem á todos los hijos de la transmigración, que se juntasen en Jerusalem:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 8, 'Y que el que no viniera dentro de tres días, conforme al acuerdo de los príncipes y de los ancianos, perdiese toda su hacienda, y él fuese apartado de la compañía de los de la transmigración.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 9, 'Así todos los hombres de Judá y de Benjamín se reunieron en Jerusalem dentro de tres días, á los veinte del mes, el cual era el mes noveno; y sentóse todo el pueblo en la plaza de la casa de Dios, temblando con motivo de aquel negocio, y á causa de las lluvias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 10, 'Y levantóse Esdras el sacerdote, y díjoles: Vosotros habéis prevaricado, por cuanto tomasteis mujeres extrañas, añadiendo así sobre el pecado de Israel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 11, 'Ahora pues, dad gloria á Jehová Dios de vuestros padres, y haced su voluntad, y apartaos de los pueblos de las tierras, y de las mujeres extranjeras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 12, 'Y respondió todo aquel concurso, y dijeron en alta voz: Así se haga conforme á tu palabra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 13, 'Mas el pueblo es mucho, y el tiempo lluvioso, y no hay fuerza para estar en la calle: ni la obra es de un día ni de dos, porque somos muchos los que hemos prevaricado en este negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 14, 'Estén ahora nuestro príncipes, los de toda la congregación; y todos aquellos que en nuestras ciudades hubieren tomado mujeres extranjeras, vengan á tiempos aplazados, y con ellos los ancianos de cada ciudad, y los jueces de ellas, hasta que apartemos de nosotros el furor de la ira de nuestro Dios sobre esto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 15, 'Fueron pues puestos sobre este negocio Jonathán hijo de Asael, y Jaazías hijo de Tikvah; y Mesullam y Sabethai, Levitas, les ayudaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 16, 'É hicieron así los hijos de la transmigración. Y apartados que fueron luego Esdras sacerdote, y los varones cabezas de familias en la casa de sus padres, todos ellos por sus nombres, sentáronse el primer día del mes décimo para inquirir el negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 17, 'Y concluyeron, con todos aquellos que habían tomado mujeres extranjeras, al primer día del mes primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 18, 'Y de los hijos de los sacerdotes que habían tomado mujeres extranjeras, fueron hallados estos: De los hijos de Jesuá hijo de Josadec, y de sus hermanos: Maasías, y Eliezer, y Jarib, y Gedalías;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 19, 'Y dieron su mano en promesa de echar sus mujeres, y ofrecieron como culpados un carnero de los rebaños por su delito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 20, 'Y de los hijos de Immer: Hanani y Zebadías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 21, 'Y de lo hijos de Harím, Maasiás, y Elías, y Semeías, y Jehiel, y Uzzías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 22, 'Y de los hijos de Phasur: Elioenai, Maasías, Ismael, Nathanael, Jozabad, y Elasa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 23, 'Y de los hijos de los Levitas: Jozabad, y Simi, Kelaía (este es Kelita), Pethaía, Judá y Eliezer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 24, 'Y de los cantores, Eliasib; y de los porteros: Sellum, y Telem, y Uri.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 25, 'Asimismo de Israel: De los hijos de Pharos: Ramía é Izzías, y Malchías, y Miamim, y Eleazar, y Malchías, y Benaías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 26, 'Y de los hijos de Elam: Mathanías, Zachârías, y Jehiel, y Abdi, y Jeremoth, y Elía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 27, 'Y de los hijos de Zattu: Elioenai, Eliasib, Mathanías, y Jeremoth, y Zabad, y Aziza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 28, 'Y de los hijos de Bebai: Johanán, Hananías, Zabbai, Atlai.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 29, 'Y de los hijos de Bani: Mesullam, Malluch, y Adaías, Jasub, Y Seal, y Ramoth.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 30, 'Y de los hijos de Pahath-moab: Adna, y Chêleal, Benaías, Maasías, Mathanías, Besaleel, Binnui y Manasés.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 31, 'Y de los hijos de Harim: Eliezer, Issia, Malchîas, Semeía, Simeón,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 32, 'Benjamín, Malluch, Semarías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 33, 'De los hijos de Hasum: Mathenai, Mathatha, Zabad, Eliphelet, Jeremai, Manasés, Sami.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 34, 'De los hijos de Bani: Maadi, Amram y Uel,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 35, 'Benaías, Bedías, Chêluhi,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 36, 'Vanías, Meremoth, Eliasib,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 37, 'Mathanías, Mathenai, y Jaasai,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 38, 'Y Bani, y Binnui, Simi,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 39, 'Y Selemías y Nathán y Adaías,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 40, 'Machnadbai, Sasai, Sarai,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 41, 'Azareel, y Selamías, Semarías,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 42, 'Sallum, Amarías, Joseph.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 43, 'Y de los hijos de Nebo: Jehiel, Matithías, Zabad, Zebina, Jadau, y Joel, Benaías.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('EZR', 'Esdras', 10, 44, 'Todos estos habían tomado mujeres extranjeras; y había mujeres de ellos que habían parido hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 1, 1, 'BIENAVENTURADO el varón que no anduvo en consejo de malos, Ni estuvo en camino de pecadores, Ni en silla de escarnecedores se ha sentado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 1, 2, 'Antes en la ley de Jehová está su delicia, Y en su ley medita de día y de noche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 1, 3, 'Y será como el árbol plantado junto á arroyos de aguas, Que da su fruto en su tiempo, Y su hoja no cae; Y todo lo que hace, prosperará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 1, 4, 'No así los malos: Sino como el tamo que arrebata el viento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 1, 5, 'Por tanto no se levantarán los malos en el juicio, Ni los pecadores en la congregación de los justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('PSA', 'Salmos', 1, 6, 'Porque Jehová conoce el camino de los justos; Mas la senda de los malos perecerá.');
